window.ENERGY_EXTRA = (window.ENERGY_EXTRA || []).concat([
  // ===== 东亚（6400-6431）=====
  {"id":6400,"name":"日本山形游佐町冲海上风电","en":"Yuza Offshore Wind Farm (Yamagata Round 3)","country":"日本","region":"东亚","cat":"renewable","coord":[139.75,39.05],"cap":"450MW（15MW×30台）","inv":20,"invText":"约3000亿日元（约20亿美元，估）","status":"规划","year":2030,"updated":"2024-12","owner":"丸红牵头财团（山形游佐洋上风力合同会社）","flagship":false,"desc":"日本海上风电第3轮公募山形海域中标项目，450MW固定式，2030年6月投运。","detail":"2024年12月24日，日本经产省与国交省公布海上风电第3轮公募结果：山形县游佐町冲海域由丸红、关西电力、BP Iota、东京瓦斯、丸高组成的'山形游佐洋上风力合同会社'中标，规划装机45万千瓦，安装30台西门子歌美飒15MW风机，中标电价为零溢价水平的3日元/千瓦时，计划2030年6月投运。这是丸红继秋田之后再度领衔的大型固定式海上风电，2025年已提出30台风机布置方案。","descEn":"Winning project of Japan's Round 3 offshore wind auction in the Yuza, Yamagata zone: 450 MW fixed-bottom, operation targeted for June 2030.","detailEn":"On 24 December 2024 Japan's METI and MLIT announced Round 3 offshore wind auction results: the Yuza (Yamagata) zone was won by a consortium of Marubeni, Kansai Electric, BP Iota Holdings, Tokyo Gas and Marutaka ('Yamagata Yuza Offshore Wind LLC'). The project plans 450 MW using 30 Siemens Gamesa 15 MW turbines, bid at the zero-premium level of JPY 3/kWh, with operation targeted for June 2030. It is Marubeni's second flagship fixed-bottom offshore wind lead after Akita; a 30-turbine layout plan was presented in 2025.","progress":"2024年12月中标公示，2025年提出风机布置方案，目标2030年6月投运。"},
  {"id":6401,"name":"台湾渢妙一期海上风电（Fengmiao I）","en":"Fengmiao I Offshore Wind Farm","country":"中国台湾","region":"东亚","cat":"renewable","coord":[120.2,24.35],"cap":"495MW（Vestas 15MW×33台）","inv":31,"invText":"融资约1030亿新台币（约31亿美元）","status":"在建","year":2027,"updated":"2025-03","owner":"哥本哈根基础设施基金（CIP）","flagship":false,"desc":"台湾区块开发3-1期首个完成融资关闭并开工的海上风电场，495MW，2027年底建成。","detail":"2025年3月，CIP旗下基金CI V就495MW渢妙一期海上风电达成融资关闭，从27家国际及台湾本地银行获得约1030亿新台币（约31亿美元）项目融资，并由4家出口信贷机构和台湾信保基金提供部分担保。项目位于台中外海，采用33台Vestas 15MW风机，是台湾'区块开发'3-1期首个完成融资并率先开工的项目，全部电量已与6家大型企业签订长期购电协议，计划2027年底完成建设。2025年商船三井（MOL）收购10%股权。","descEn":"First Taiwan Round 3 (block development) offshore wind project to reach financial close and start construction: 495 MW, completion by end-2027.","detailEn":"In March 2025, CIP's fund CI V reached financial close on the 495 MW Fengmiao I offshore wind farm, securing about TWD 103 billion (~USD 3.1 billion) in project finance from 27 international and Taiwanese banks, partly guaranteed by four export credit agencies and Taiwan's National Credit Guarantee Administration. Located off Taichung with 33 Vestas 15 MW turbines, it is the first of Taiwan's Round 3 block-development projects to reach financial close and begin construction; its entire output is contracted to six large corporate offtakers under long-term PPAs. Construction completion is targeted for end-2027. In 2025 MOL agreed to acquire a 10% stake.","progress":"2025年3月融资关闭并率先开工，商船三井入股10%，目标2027年底建成。"},
  {"id":6402,"name":"韩国新万金水上光伏一期","en":"Saemangeum Floating Solar Phase 1","country":"韩国","region":"东亚","cat":"renewable","coord":[126.6,35.88],"cap":"一期1.2GW（总规划2.1GW）","inv":22,"invText":"一期约3万亿韩元（约22亿美元）","status":"规划","year":2029,"updated":"2026-02","owner":"新万金开发厅/韩国水电核电（电网接入）/晓星等财团","flagship":false,"desc":"全球最大规模水上光伏：新万金围海区内规划2.1GW，一期1.2GW瞄准2029年12月商运。","detail":"韩国新万金（Saemangeum）围垦区公共水面上规划全球最大2.1GW水上光伏，分两期建设（一期1.2GW、二期0.9GW）。一期占水面约13.5平方公里，总事业费约3万亿韩元，9家参与企业分摊6600亿韩元电网接入费用，韩水原（KHNP）负责345kV送出工程。项目因电网接入和招标纠纷搁置多年后于2025年重启，原定2025年10月动工；2026年2月全罗北道、新万金开发厅、韩电、韩水原四方签署合作备忘录，确保一期按期建设，目标2029年12月商业运行。","descEn":"World's largest planned floating solar complex: 2.1 GW inside the Saemangeum seawall, with the 1.2 GW Phase 1 targeting commercial operation in December 2029.","detailEn":"Korea's Saemangeum reclamation area hosts the world's largest planned floating solar complex at 2.1 GW, built in two phases (1.2 GW + 0.9 GW). Phase 1 covers ~13.5 km2 of water surface with a total cost of about KRW 3 trillion; nine participating companies share KRW 660 billion of grid-connection costs while KHNP builds the 345 kV transmission link. After years of delay over grid access and tender disputes the project was relaunched in 2025 with groundbreaking targeted for October 2025; in February 2026 Jeollabuk-do, the Saemangeum Development Authority, KEPCO and KHNP signed an MOU to keep Phase 1 on schedule for commercial operation in December 2029.","progress":"2026年2月四方签署MOU重启推进，一期1.2GW目标2029年12月商运。"},
  {"id":6403,"name":"蒙古额尔登布仁水电站","en":"Erdeneburen Hydropower Plant","country":"蒙古","region":"东亚","cat":"renewable","coord":[91.3,48.4],"cap":"90MW（年发电3.66亿千瓦时）","inv":2.9,"invText":"EPC合同约2.86亿美元（中国进出口银行优买贷款）","status":"在建","year":2030,"updated":"2025-10","owner":"蒙古能源部（中国电建EPC总承包）","flagship":false,"desc":"蒙古最大水电项目：科布多河90MW水电站，中国电建总承包、中国进出口银行融资。","detail":"额尔登布仁水电站位于蒙古西部科布多省科布多河上，距乌兰巴托约1600公里，装机90MW、年发电量3.66亿千瓦时，建成后将是蒙古最大水电站，可解决西部五省长期依赖进口电力的问题。项目由中国电建总承包（EPC合同约2.86亿美元），资金来自中国向蒙古提供的10亿美元优惠买方信贷，2021年9月签约，工期61个月，主要建设大坝、引水隧洞、压力竖井和厂房。项目经历环评与移民争议后于2025年实质推进，2025年10月中国电建集团科技委赴现场调研指导施工与地质问题。","descEn":"Mongolia's largest hydropower project: a 90 MW plant on the Khovd River in western Mongolia, EPC by PowerChina with China Eximbank financing.","detailEn":"The Erdeneburen hydropower plant on the Khovd River in western Mongolia (about 1,600 km from Ulaanbaatar) will have 90 MW capacity generating 366 GWh/year — Mongolia's largest hydropower plant once complete, easing the western provinces' dependence on imported power. PowerChina holds the ~USD 285.5 million EPC contract, financed ~95% by a China Eximbank preferential buyer's credit drawn from a USD 1 billion soft-loan facility; the contract was signed in September 2021 with a 61-month construction period covering the dam, headrace tunnel, pressure shaft and powerhouse. After environmental and resettlement controversies the project moved into substantive construction, with a PowerChina technical committee site inspection in October 2025.","progress":"2025年项目实质性施工推进，中国电建10月赴现场督导，工期61个月。"},
  {"id":6404,"name":"日本柏崎刈羽核电站6号机重启","en":"Kashiwazaki-Kariwa Unit 6 Restart","country":"日本","region":"东亚","cat":"nuclear","coord":[138.6,37.43],"cap":"1356MW（ABWR）","inv":80,"invText":"全厂安全对策投资超1.2万亿日元（约80亿美元，估）","status":"投运","year":2026,"updated":"2026-04","owner":"东京电力","flagship":false,"desc":"福岛事故后东电首台重启机组：全球最大核电站柏崎刈羽6号机2026年恢复商运，时隔14年再向首都圈送电。","detail":"东京电力柏崎刈羽核电站（7台机组、总装机821.2万千瓦，全球最大核电站）6号机（ABWR、135.6万千瓦）于2026年1月21日重启，因控制棒操作盘电子元件问题于2月9日再次启动，2月16日开始正式发送电——时隔14年首次向首都圈供电，4月16日通过原子力规制委员会使用前确认正式转入商业运行。这是福岛事故后东电首台恢复运转的机组，全厂已投入超1.2万亿日元实施防潮堤、滤网排气等安全对策，是日本核电回归路线图的标志性事件。","descEn":"TEPCO's first reactor restart since Fukushima: Unit 6 of Kashiwazaki-Kariwa, the world's largest nuclear plant, returned to commercial operation in 2026, sending power to the Tokyo area for the first time in 14 years.","detailEn":"Unit 6 (ABWR, 1,356 MW) of TEPCO's Kashiwazaki-Kariwa plant (7 units, 8,212 MW total — the world's largest nuclear power station) was restarted on 21 January 2026; after fixing electronic components in the control-rod operation panel it was restarted again on 9 February, began full power transmission on 16 February — the first power sent to the Kanto region in 14 years — and entered commercial operation in April 2026 after the NRA's pre-service confirmation on 16 April. It is TEPCO's first reactor returned to service since the Fukushima accident; over JPY 1.2 trillion has been invested in site-wide safety countermeasures including sea walls and filtered venting, a landmark in Japan's nuclear comeback.","progress":"2026年2月16日恢复向首都圈送电，4月正式转入商业运行。"},
  {"id":6405,"name":"辽宁徐大堡核电一期（1、2号机组CAP1000）","en":"Xudabao NPP Phase I Units 1-2 (CAP1000)","country":"中国","region":"东亚","cat":"nuclear","coord":[120.53,40.35],"cap":"2×1291MW（CAP1000）","inv":67,"invText":"总投资超480亿元（约67亿美元）","status":"在建","year":2028,"updated":"2024-07","owner":"中核集团/辽宁核电","flagship":false,"desc":"中国最北端核电站：徐大堡1、2号机组采用国产化CAP1000三代技术，2028/2029年商运。","detail":"辽宁葫芦岛兴城徐大堡核电一期工程（1、2号机组）于2023年7月31日获国务院核准，采用国产化CAP1000三代非能动压水堆技术，单机容量129.1万千瓦，总投资超480亿元。1号机组2023年11月浇筑第一罐混凝土，2号机组2024年7月17日核岛FCD开工，分别计划2028年、2029年投入商业运行。徐大堡是中国目前最北端的核电站，厂区同时在建3、4号机组（俄罗斯VVER-1200），一期建成后与3、4号机组共同形成东北地区重要的清洁能源基地。","descEn":"China's northernmost nuclear plant: Xudabao Units 1-2 use domestically localized CAP1000 Gen-III technology, with commercial operation in 2028/2029.","detailEn":"Phase I (Units 1-2) of the Xudabao NPP in Xingcheng, Huludao, Liaoning was approved by the State Council on 31 July 2023, using localized CAP1000 Gen-III passive PWR technology with 1,291 MW per unit and total investment above RMB 48 billion. Unit 1 poured first concrete in November 2023 and Unit 2 achieved nuclear-island FCD on 17 July 2024; commercial operation is planned for 2028 and 2029 respectively. Xudabao is currently China's northernmost nuclear plant; Units 3-4 (Russian VVER-1200) are under construction at the same site, together forming a key clean-energy base for Northeast China.","progress":"2号机组2024年7月17日FCD开工，1、2号机组分别瞄准2028/2029年商运。"},
  {"id":6406,"name":"韩国西海岸HVDC能源高速公路","en":"Korea West Coast HVDC Energy Highway","country":"韩国","region":"东亚","cat":"grid","coord":[126.4,36.7],"cap":"8GW·海底直流620公里（4回路）","inv":80,"invText":"约11.5万亿韩元（约80亿美元）","status":"在建","year":2030,"updated":"2026-03","owner":"韩国电力公社（KEPCO）","flagship":false,"desc":"韩国最大电网工程：620公里海底HVDC把湖南地区39GW再生能源送往首都圈，首段2030年投运。","detail":"韩国'西海岸能源高速公路'是KEPCO史上最大输电工程：沿西海岸敷设4回路海底高压直流（HVDC）线路、全长620公里、输电容量8GW，把全罗道光伏和西南海上风电电力送入首尔首都圈（龙仁半导体集群等负荷中心），总投资约11.5万亿韩元（其中换流站约4.8万亿）。2025年LS电缆等开工建设世界最大容量直流海缆，GE Vernova承接换流系统；政府将新万金—首都圈首段工期提前至2030年（原2031/2036年），并计划到2030年在湖南地区额外接入27GW可再生能源。","descEn":"Korea's largest grid project: 620 km of subsea HVDC moving up to 39 GW of Honam renewables to the Seoul metro area, first segment in service by 2030.","detailEn":"The 'West Coast Energy Highway' is KEPCO's largest-ever transmission project: four subsea HVDC circuits along the west coast totaling 620 km with 8 GW capacity, carrying Jeolla solar and southwest offshore wind power to the Seoul metropolitan load centers (including the Yongin semiconductor cluster), at about KRW 11.5 trillion (~USD 8 billion, of which KRW 4.8 trillion for converter stations). In 2025 LS Cable & System began construction with the world's highest-capacity DC submarine cable and GE Vernova was contracted for the HVDC systems; the government advanced the first Saemangeum-to-metro segment to 2030 (from 2031/2036) and plans to connect an additional 27 GW of renewables in the Honam region by 2030.","progress":"2026年3月KEPCO宣布加速推进，首段目标2030年投运、累计接入39GW再生能源。","route":[[126.55,35.85],[126.3,36.7],[127.2,37.24]]},
  {"id":6407,"name":"日本大阪岬町淡轮电池储能电站","en":"Tannowa Battery Plant (Osaka)","country":"日本","region":"东亚","cat":"storage","coord":[135.15,34.32],"cap":"99MW/396MWh","inv":2,"invText":"约300亿日元（约2亿美元，估）","status":"在建","year":2028,"updated":"2025-06","owner":"关西电力/Kinden/Japan Excellent","flagship":false,"desc":"日本最大并网电池储能：大阪岬町99MW/396MWh，2025年6月开工、2028年2月商运。","detail":"关西电力、近电工业（Kinden）与Japan Excellent Infrastructure在大阪府岬町淡轮联合建设日本最大的并网电池储能电站'淡轮蓄电池发电所'，输出99MW、容量396MWh，2025年6月开工，计划2028年2月开始商业运行。项目利用关西电力旧多奈川电厂用地并网，参与日本电力批发、容量与调频辅助服务市场，是日本电网级储能从十MWh级跃升至百MWh级的标志性项目，呼应日本可再生能源占比提升带来的灵活性需求。","descEn":"Japan's largest grid-connected battery: 99 MW/396 MWh in Misaki, Osaka, construction from June 2025 with commercial operation in February 2028.","detailEn":"Kansai Electric Power, Kinden Corporation and Japan Excellent Infrastructure are jointly building the Tannowa Battery Plant in Misaki Town, Osaka Prefecture — Japan's largest grid-connected battery energy storage system at 99 MW output and 396 MWh capacity. Construction began in June 2025 with commercial operation targeted for February 2028. Sited on grid infrastructure of Kansai Electric's former Tanagawa power station, it will trade in Japan's wholesale, capacity and ancillary-service markets, marking the country's step-up from tens-of-MWh to hundreds-of-MWh grid-scale storage as renewable penetration grows.","progress":"2025年6月开工建设，目标2028年2月商业运行。"},
  {"id":6408,"name":"蒙古松基诺电网侧储能电站","en":"Songino Battery Storage Power Station","country":"蒙古","region":"东亚","cat":"storage","coord":[106.75,47.89],"cap":"80MW/200MWh","inv":1.15,"invText":"约1.15亿美元（ADB贷款1亿美元）","status":"投运","year":2024,"updated":"2024-09","owner":"蒙古能源部（ADB融资）","flagship":false,"desc":"蒙古首个电网级储能：乌兰巴托松基诺80MW/200MWh电池电站，ADB融资，2024年全面建成。","detail":"蒙古首个公用事业级电池储能电站位于乌兰巴托松基诺海尔汗区，与松基诺变电站一体建设，规模80MW/200MWh，总投资1.1495亿美元（其中亚洲开发银行贷款1亿美元、日本高水平技术基金赠款300万美元）。电站于2023年12月并网投运，剩余土建于2024年9月全部完成，可全部以可再生电力充电，每年帮助中央电网多消纳8.59亿千瓦时可再生能源、减排约84万吨二氧化碳，显著缓解蒙古对进口电力和燃煤调峰的依赖。","descEn":"Mongolia's first utility-scale BESS: 80 MW/200 MWh at the Songino substation in Ulaanbaatar, ADB-financed and fully completed in 2024.","detailEn":"Mongolia's first utility-scale battery energy storage plant sits at the Songino substation in Songino Khairkhan, Ulaanbaatar, at 80 MW/200 MWh and a total cost of USD 114.95 million (including a USD 100 million ADB loan and a USD 3 million grant from ADB's High Level Technology Fund financed by Japan). Commissioned in December 2023 with remaining civil works completed by September 2024, the cold-climate-resilient system can be charged entirely with renewable power, enabling integration of an additional 859 GWh of renewables per year into the central grid and avoiding roughly 842,000 tonnes of CO2 annually while reducing reliance on imported power and coal-based balancing.","progress":"2023年12月并网、2024年9月全部建成，成为蒙古可再生能源消纳的关键调节资源。"},
  {"id":6409,"name":"台积电高雄Fab22 2纳米基地","en":"TSMC Fab 22 Kaohsiung 2nm Gigafab","country":"中国台湾","region":"东亚","cat":"ci","coord":[120.28,22.73],"cap":"2nm晶圆6.5万片/月（2026年底目标）","inv":470,"invText":"五期总投资逾1.5万亿新台币（约470亿美元，估）","status":"投运","year":2025,"updated":"2025-12","owner":"台积电","flagship":false,"desc":"全球最先进制程基地之一：台积电高雄楠梓Fab22规划五期全数2nm及以下，P1已于2025年Q4量产。","detail":"台积电在高雄楠梓科学园区建设Fab22基地，规划P1-P5五座晶圆厂全数导入2纳米及更先进制程，总投资超过1.5万亿新台币，为高雄史上最大企业投资。P1于2025年第四季正式量产2纳米（GAA纳米片架构），P2于2025年8月进机、2026年第二季量产，P3已动工，P4/P5于2025年7月获准开工；高雄厂区月产能预计2025年底达2.5万-3万片、2026年底至2027年初增至6万-6.5万片。相比N3E，N2同功耗速度提升10-15%或同速度功耗降低25-30%，主要客户涵盖苹果、英伟达等AI芯片巨头。","descEn":"One of the world's most advanced fabs: TSMC's Fab 22 in Kaohsiung plans five phases all on 2nm-and-below, with P1 in volume production since Q4 2025.","detailEn":"TSMC is building its Fab 22 gigafab in Kaohsiung's Nanzih Science Park with five phases (P1-P5) all dedicated to 2 nm and more advanced nodes, at over TWD 1.5 trillion — the largest corporate investment in Kaohsiung's history. P1 entered 2 nm (GAA nanosheet) volume production in Q4 2025; P2 moved in equipment in August 2025 targeting Q2 2026 production; P3 is under construction and P4/P5 received construction approval in July 2025. Site capacity is expected to reach 25-30k wafers/month by end-2025 and 60-65k by end-2026/early-2027. Versus N3E, N2 offers 10-15% higher speed at iso-power or 25-30% lower power at iso-speed, serving AI-era customers such as Apple and NVIDIA.","progress":"P1于2025年Q4量产2nm，P2瞄准2026年Q2，五期梯次推进。"},
  {"id":6410,"name":"三星龙仁系统半导体国家产业园","en":"Samsung Yongin National Semiconductor Industrial Complex","country":"韩国","region":"东亚","cat":"ci","coord":[127.21,37.1],"cap":"规划6座先进晶圆厂（728万平方米）","inv":2500,"invText":"总投资约360万亿韩元（约2500亿美元）","status":"在建","year":2030,"updated":"2026-06","owner":"三星电子","flagship":true,"desc":"全球最大芯片集群核心：三星龙仁国家产业园规划6座晶圆厂、约2500亿美元投资，首厂2030年运营。","detail":"韩国'龙仁半导体国家产业园'占地728万平方米，规划由三星电子建设6座先进晶圆厂、3座电厂及60余家材料/零部件/设备伙伴入驻，总投资约360万亿韩元（约2500亿美元），是韩国'全球最大半导体集群'战略的核心。产业园方案获政府提前批准，2025年12月19日三星与韩国土地住宅公社（LH）签订购地合同，定于2026年12月举行动工仪式（较原计划提前4年），首座晶圆厂2030年投入运营，配套道路、水、电基础设施同步升级，与SK海力士龙仁集群共同构成京畿道半导体走廊。","descEn":"Core of the world's largest chip cluster: Samsung's Yongin national complex plans six fabs at ~USD 250 billion, with the first fab operating by 2030.","detailEn":"Korea's Yongin Semiconductor National Industrial Complex spans 7.28 million m2 and will house six advanced Samsung fabs, three power plants and 60+ materials/parts/equipment partners, with total investment of about KRW 360 trillion (~USD 250 billion) — the centerpiece of Korea's plan for the world's largest semiconductor cluster. The complex plan won early government approval; on 19 December 2025 Samsung signed land-purchase contracts with Korea Land & Housing Corp., with official groundbreaking set for December 2026 (four years ahead of the original June 2030 timeline) and the first fab operating by 2030, supported by upgraded roads, water and power. Together with SK hynix's Yongin cluster it forms Gyeonggi's semiconductor corridor.","progress":"2026年2月24日首座晶圆厂正式动工；6月韩国政府宣布加速龙仁产业集群，三星量产计划提前约7年、SK海力士提前约12年。"},
  {"id":6411,"name":"美光广岛新一代DRAM晶圆厂","en":"Micron Hiroshima Next-gen DRAM Fab","country":"日本","region":"东亚","cat":"ci","coord":[132.73,34.4],"cap":"1-gamma/1-delta DRAM·HBM（EUV）","inv":51,"invText":"约8000亿日元（约51亿美元），日本政府补贴最高1920亿日元","status":"在建","year":2027,"updated":"2025-11","owner":"美光科技","flagship":false,"desc":"日本首批EUV产线：美光在广岛建新DRAM厂，约51亿美元投资，2027年底投产HBM用先进存储。","detail":"美光科技在广岛县东广岛市现有Fab15旁新建DRAM晶圆厂，总投资约51亿美元，日本政府批准最高1920亿日元（约13亿美元）补贴。新厂为日本首批导入EUV光刻的存储产线，采用1-gamma制程并规划升级至1-delta，重点生产面向生成式AI、数据中心和自动驾驶的高带宽内存（HBM）等先进DRAM，2026年初动工、2027年底投产。该项目与铠侠、Rapidus等共同构成日本半导体制造复兴版图中的存储一极。","descEn":"One of Japan's first EUV production lines: Micron's new ~USD 5.1 billion DRAM fab in Hiroshima targets end-2027 operation for HBM-class advanced memory.","detailEn":"Micron is building a new DRAM fab adjacent to its existing Fab 15 in Higashihiroshima, Hiroshima Prefecture, with total investment of roughly USD 5.1 billion and approved Japanese government subsidies of up to JPY 192 billion (~USD 1.3 billion). Among the first memory lines in Japan to deploy EUV lithography, it will run 1-gamma process technology with an upgrade path to 1-delta, focused on HBM and advanced DRAM for generative AI, data centers and autonomous driving. Construction starts in early 2026 with operation targeted for end-2027, anchoring the memory pillar of Japan's semiconductor manufacturing revival alongside Kioxia and Rapidus.","progress":"2025年11月确认扩大广岛先进DRAM布局，2026年初动工、2027年底投产。"},
  {"id":6412,"name":"AWS亚太（台北）区域数据中心","en":"AWS Asia Pacific (Taipei) Region","country":"中国台湾","region":"东亚","cat":"datacenter","coord":[121.55,25.05],"cap":"3个可用区（Availability Zones）","inv":50,"invText":"承诺投资50亿美元","status":"投运","year":2025,"updated":"2025-06","owner":"亚马逊AWS","flagship":false,"desc":"AWS第15个亚太区域：2025年6月台北区域上线，承诺50亿美元建设运营本地数据中心。","detail":"亚马逊云科技（AWS）于2025年6月正式开放'亚太（台北）区域'，含3个可用区，是AWS在台湾的首个云区域、亚太第15个区域，满足台湾客户的数据驻留与低时延需求。AWS同步承诺投入50亿美元用于数据中心的持续建设、联网、运营和维护，服务半导体、制造、金融与AI应用客户，是超大规模云厂商为AI时代在亚太加码算力布局的代表性项目之一。","descEn":"AWS's 15th Asia-Pacific region: the Taipei Region launched in June 2025 with a USD 5 billion commitment to build and operate local data centers.","detailEn":"Amazon Web Services officially opened the Asia Pacific (Taipei) Region in June 2025 with three Availability Zones — its first cloud region in Taiwan and 15th in Asia Pacific — meeting local data-residency and low-latency requirements. AWS committed a further USD 5 billion for ongoing construction, connection, operation and maintenance of data centers in Taiwan, serving semiconductor, manufacturing, financial and AI customers, emblematic of hyperscalers' AI-era capacity build-out across Asia.","progress":"2025年6月正式上线3个可用区，50亿美元投资计划滚动落地。"},
  {"id":6413,"name":"平陆运河","en":"Pinglu Canal","country":"中国","region":"东亚","cat":"transport","coord":[108.75,22.2],"cap":"134.2公里5000吨级航道·3座枢纽船闸","inv":101,"invText":"总概算约727亿元（约101亿美元）","status":"在建","year":2026,"updated":"2026-06","owner":"广西平陆运河集团","flagship":true,"desc":"新中国首条通江达海大运河：134公里5000吨级航道连接西江与北部湾，2026年9月通航。","detail":"平陆运河起于广西横州市西津库区平塘江口、经钦州入北部湾，全长134.2公里，按5000吨级内河航道标准建设，新建马道、企石、青年3座双线船闸枢纽及27座桥梁，总概算约727亿元，需开挖土石方3.39亿立方米，是新中国成立以来建设的第一条通江达海大运河。2022年8月开工；截至2026年3月完成投资670.3亿元（92.2%）、土石方开挖91.6%；2026年5月28日航道主体开挖全部完成，6月初实现全线通水进入有水调试，定于2026年9月正式通航，将使西南货物经钦州港出海里程缩短约560公里，重塑西部陆海新通道物流格局。","descEn":"New China's first sea-linking canal: a 134 km, 5,000-tonne-class waterway joining the Xijiang River to the Beibu Gulf, opening to traffic in September 2026.","detailEn":"The Pinglu Canal runs 134.2 km from Pingtang estuary in Hengzhou (Xijin reservoir), Guangxi, to the Beibu Gulf at Qinzhou, built to 5,000-tonne-class inland waterway standard with three twin-lane ship-lock complexes (Madao, Qishi, Qingnian) and 27 bridges, at a budget of about RMB 72.7 billion and 339 million m3 of excavation — the first river-to-sea canal built since the founding of the PRC. Construction began in August 2022; by March 2026, RMB 67.03 billion (92.2%) was invested and 91.6% of excavation done; main-channel excavation was fully completed on 28 May 2026 and full water-filling commissioning began in early June, with official opening set for September 2026, cutting southwest China's route to sea via Qinzhou Port by about 560 km and reshaping the New Western Land-Sea Corridor.","progress":"2026年5月底主体开挖全部完成、6月全线通水调试，定于9月正式通航。","route":[[109.21,22.68],[108.88,22.4],[108.6,21.95]]},
  {"id":6414,"name":"香港北环线（古洞—锦上路）","en":"Hong Kong Northern Link","country":"中国香港","region":"东亚","cat":"transport","coord":[114.08,22.48],"cap":"主线10.7公里·5站（另设支线接皇岗口岸）","inv":40,"invText":"首期工程造价约314亿港元（约40亿美元）","status":"在建","year":2027,"updated":"2025-10","owner":"港铁公司","flagship":false,"desc":"北部都会区交通主轴：北环线古洞站2027年启用、10.7公里主线2025年10月动工、2034年通车。","detail":"港铁北环线是香港'北部都会区'的骨干铁路：第一期在东铁线落马洲支线上增设古洞站（造价约35亿港元，2027年启用）；主线全长10.7公里，连接屯马线锦上路站与古洞站，中途设凹头、牛潭尾、新田三站，于2025年10月3日动工，首期工程造价约314亿港元，计划2034年与支线同步通车；支线由新田经洲头、河套站直达深圳新皇岗口岸站，实现深港'一地两检'轨道直连。港铁采用内地施工模式压缩工期，项目将串联新田科技城与河套深港科技创新合作区。","descEn":"Backbone of Hong Kong's Northern Metropolis: Kwu Tung station opens 2027; the 10.7 km Northern Link main line broke ground in October 2025 for 2034 opening.","detailEn":"MTR's Northern Link is the rail backbone of Hong Kong's Northern Metropolis. Phase 1 adds Kwu Tung station on the East Rail Lok Ma Chau spur (about HKD 3.5 billion, opening 2027). The 10.7 km main line linking Kam Sheung Road (Tuen Ma Line) to Kwu Tung with intermediate stations at Au Tau, Ngau Tam Mei and San Tin broke ground on 3 October 2025 at a first-stage cost of about HKD 31.4 billion, targeting 2034 opening together with a spur line running via Chau Tau and the Loop to a new Huanggang Port station in Shenzhen for direct cross-border co-location clearance. MTR is adopting mainland construction methods to compress the schedule, knitting together San Tin Technopole and the Hetao Shenzhen-Hong Kong innovation zone.","progress":"主线2025年10月3日动工，古洞站2027年启用，主支线2034年同步通车。","route":[[114.063,22.435],[114.046,22.452],[114.04,22.472],[114.066,22.488],[114.1,22.503]]},
  {"id":6415,"name":"S-Oil蔚山沙欣（Shaheen）石化综合体","en":"S-Oil Shaheen Petrochemical Project","country":"韩国","region":"东亚","cat":"petro","coord":[129.35,35.43],"cap":"乙烯180万吨/年（蒸汽裂解）","inv":70,"invText":"约9.26万亿韩元（约70亿美元）","status":"在建","year":2026,"updated":"2025-02","owner":"S-Oil（沙特阿美控股63.4%）","flagship":false,"desc":"韩国史上最大单笔外商投资：阿美旗下S-Oil蔚山70亿美元'沙欣'乙烯项目2026年上半年建成。","detail":"S-Oil（沙特阿美持股63.4%）在蔚山温山工业区建设70亿美元'Shaheen（沙欣，阿拉伯语猎鹰）'石化综合体，是韩国史上最大单笔外商投资项目：核心为年产180万吨乙烯的蒸汽裂解装置及TC2C原油直接制化学品技术、聚乙烯等下游装置。2023年3月开工，由现代建设、现代工程、乐天建设、DL E&C联合施工，2024年底完成约55%，高峰期日均用工1.4万人；机械竣工与试运行定于2026年6月，2026年下半年全面商业运行，建成后将使S-Oil石化产品比重翻倍。","descEn":"Korea's largest-ever single foreign investment: Aramco-backed S-Oil's USD 7 billion Shaheen olefins complex in Ulsan completes in H1 2026.","detailEn":"S-Oil (63.4% owned by Saudi Aramco) is building the USD 7 billion Shaheen ('falcon') petrochemical complex at Onsan, Ulsan — the largest single foreign investment in Korean history. Its core is a steam cracker producing 1.8 million tonnes/year of ethylene with Aramco's TC2C crude-to-chemicals technology plus downstream polyethylene units. Construction began in March 2023 by a consortium of Hyundai E&C, Hyundai Engineering, Lotte E&C and DL E&C; the project was ~55% complete at end-2024 with workforce peaking around 14,000/day. Mechanical completion and test operation are set for June 2026 with full commercial operation in H2 2026, roughly doubling S-Oil's petrochemical yield.","progress":"2025年初工程过半、按计划推进，2026年6月机械竣工并试运行。"},
  {"id":6416,"name":"蒙古国阿勒坦希里炼油厂","en":"Mongol Refinery (Altanshiree)","country":"蒙古","region":"东亚","cat":"petro","coord":[110.46,45.52],"cap":"原油加工150万吨/年","inv":17,"invText":"约17亿美元（印度Exim贷款累计逾16亿美元，估）","status":"在建","year":2026,"updated":"2025-12","owner":"Mongol Refinery国有公司（印度Exim信贷支持）","flagship":false,"desc":"蒙古首座炼油厂：东戈壁省150万吨/年项目印度贷款建设，2026年投产，终结成品油全进口历史。","detail":"蒙古首座炼油厂位于东戈壁省阿勒坦希里苏木，由国有Mongol Refinery公司在印度政府间框架下建设，年加工原油150万吨，可生产汽油、柴油和航空煤油，满足蒙古大部分成品油需求、摆脱对俄罗斯进口的依赖。项目2018年动工，由印度进出口银行提供优惠信贷：2025年1月蒙古议会批准追加约4.64亿美元贷款覆盖超支，2025年5月生效的再一笔7亿美元信贷额度获印度央行通报；配套的530公里原油管道等基础设施提前完工。截至2025年12月项目稳步推进，瞄准2026年建成投产。","descEn":"Mongolia's first oil refinery: a 1.5 Mt/year plant in Dornogovi built with Indian credit lines, targeting 2026 commissioning to end full fuel-import dependence.","detailEn":"Mongolia's first domestic oil refinery in Altanshiree soum, Dornogovi Province, is being built by state-owned Mongol Refinery LLC under a government-to-government framework with India. With 1.5 million tonnes/year crude processing capacity producing gasoline, diesel and jet fuel, it will cover most of Mongolia's fuel demand and cut dependence on Russian imports. Construction began in 2018, financed by Export-Import Bank of India credit lines: Mongolia's parliament approved an additional ~USD 464 million loan in January 2025 to cover overruns, and a further USD 700 million LoC signed in January 2025 took effect in May 2025; supporting infrastructure including a 530 km crude pipeline finished ahead of schedule. As of December 2025 the project was on track for commissioning in 2026.","progress":"2025年印度追加逾11亿美元信贷，配套设施提前完工，瞄准2026年投产。"},
  {"id":6417,"name":"蒙古祖布奥沃铀矿（Zuuvch-Ovoo）","en":"Zuuvch-Ovoo Uranium Project","country":"蒙古","region":"东亚","cat":"mining","coord":[110.7,44.3],"cap":"铀2500吨/年（资源量近9万吨）","inv":16,"invText":"全生命周期投资约16亿美元（投产前约5亿美元）","status":"在建","year":2028,"updated":"2025-10","owner":"Badrakh Energy（Orano与蒙古MonAtom合资）","flagship":false,"desc":"蒙古首个铀矿开发：法国欧安诺16亿美元投资协议2025年签署，2028年投产、年产铀2500吨。","detail":"2025年1月17日，法国核燃料集团欧安诺（Orano）与蒙古政府在乌兰巴托签署投资协议，开发东戈壁省乌兰巴德拉赫的祖布奥沃及Dulaan Uul/Umnut铀矿床（资源量近9万吨铀）：由Orano与蒙古国营MonAtom合资的Badrakh Energy运营，采用原地浸出工艺，投产前投资约5亿美元、全生命周期约16亿美元，2028年建成投产，额定年产能约2500吨铀（约占全球当前产量4%），蒙古国通过税收、分红和权益金获得超过51%的直接收益。2025年下半年现场举行开工仪式进入建设阶段，同步建设120公里道路、100公里输电线路和千人营地。","descEn":"Mongolia's first uranium mine development: Orano's USD 1.6 billion investment agreement signed in 2025, producing 2,500 tU/year from 2028.","detailEn":"On 17 January 2025 France's Orano signed an investment agreement with the Mongolian government in Ulaanbaatar to develop the Zuuvch-Ovoo and Dulaan Uul/Umnut deposits in Ulaanbadrakh, Dornogovi (close to 90,000 tU resources). Badrakh Energy, Orano's joint venture with state-owned MonAtom, will operate the in-situ-recovery mine: ~USD 500 million invested before start-up and ~USD 1.6 billion over the mine's life, with production from 2028 at a nominal 2,500 tU/year (about 4% of current world output); over 51% of direct benefits accrue to Mongolia via taxes, dividends and royalties. A ceremony in H2 2025 marked the start of construction, alongside 120 km of roads, a 100 km transmission line and a 1,000-worker camp.","progress":"2025年下半年举行开工仪式进入建设阶段，目标2028年首批产品。"},
  {"id":6418,"name":"福建霞浦核电一期（华龙一号1、2号机组）","en":"Xiapu Nuclear Phase I (Hualong One Units 1-2)","country":"中国","region":"东亚","cat":"nuclear","coord":[120.2,26.75],"cap":"2×1212MW（规划4台华龙一号+1台600MW高温气冷堆）","inv":63,"invText":"总投资约456亿元人民币（约63亿美元）","status":"规划","year":2031,"updated":"2026-04","owner":"中国华能集团","flagship":false,"desc":"2025年4月国常会核准的华能第三个压水堆基地，霞浦厂址首期2台华龙一号，与CFR-600快堆同址。","detail":"2025年4月27日国务院常务会议核准福建霞浦核电一期工程，建设2台“华龙一号”压水堆机组，总投资约456亿元人民币。这是华能集团继石岛湾、海南昌江之后获核准的第三个压水堆核电项目，霞浦厂址远期规划4台华龙一号加1台60万千瓦高温气冷堆，与已在建的CFR-600示范快堆同址形成多堆型基地。截至2026年4月项目处于前期准备和陆域形成（场平）阶段，尚未浇筑第一罐混凝土（FCD）。","descEn":"Approved by China's State Council in April 2025, Huaneng's Xiapu Phase I adds two Hualong One PWRs alongside the CFR-600 fast reactor site in Fujian.","detailEn":"On 27 April 2025 China's State Council approved Xiapu Nuclear Phase I in Fujian: two Hualong One PWR units with total investment of about RMB 45.6 billion (~USD 6.3 bn). It is China Huaneng's third approved PWR project after Shidaowan and Changjiang. The Xiapu site is planned for four Hualong One units plus a 600 MW HTGR, co-located with the CFR-600 demonstration fast reactor. As of April 2026 the project is in site-preparation stage ahead of first concrete.","progress":"2025年4月核准，2026年场平与前期准备中，待FCD。"},
  {"id":6419,"name":"中石化中天合创乌审旗风光制氢一体化项目","en":"Sinopec Zhongtian Hechuang Wushen Banner Wind-Solar Hydrogen Project","country":"中国","region":"东亚","cat":"renewable","coord":[108.84,38.6],"cap":"绿氢3万吨/年（52台碱性电解槽），配套风电450MW+光伏236.8MW","inv":8,"invText":"约57亿元人民币（≈8亿美元）","status":"在建","year":2026,"updated":"2026-06","owner":"中石化/中天合创（中煤合资）","flagship":false,"desc":"鄂尔多斯乌审旗风光制氢一体化：年产3万吨绿氢耦合现有煤化工替代灰氢，2024年底开工，2026-2027年陆续投产。","detail":"中天合创（中石化与中煤集团合资）乌审旗风光制氢一体化项目位于内蒙古鄂尔多斯市乌审旗，依托毛乌素沙地丰富风光资源，配套风电45万千瓦、光伏23.68万千瓦，配置52台碱性电解槽，绿氢生产规模3万吨/年，总投资约57亿元。项目2024年12月18日与绿色降碳升级改造项目同步开工，2025年2月制氢厂施工招标落地，预计2026—2027年陆续投产。所产绿氢将耦合中天合创现有煤制烯烃装置、部分替代原料灰氢，在实现绿电绿氢绿氧耦合减碳的同时延伸煤化工产业链，是国内'绿氢+煤化工'耦合的标杆工程之一。","descEn":"A wind-solar-to-hydrogen project in Wushen Banner, Ordos: 30,000 t/y of green hydrogen from 52 alkaline electrolyzers coupled with existing coal-chemical plants; construction began end-2024, phased startup 2026-2027.","detailEn":"Zhongtian Hechuang (a Sinopec-China Coal JV) is building a wind-solar hydrogen integration project in Wushen Banner, Ordos, Inner Mongolia, with 450 MW of wind, 236.8 MW of solar and 52 alkaline electrolyzers producing 30,000 tonnes of green hydrogen per year, at a cost of about RMB 5.7 billion. Construction started on 18 December 2024 alongside a green decarbonization retrofit, with phased commissioning in 2026-2027. The green hydrogen will partially replace grey feedstock hydrogen in the company's coal-to-olefins complex, a benchmark for coupling green hydrogen with coal chemicals in China.","progress":"2024年12月开工，2025年2月制氢厂施工与52台电解槽采购招标完成，预计2026—2027年陆续投产。"},
  {"id":6420,"name":"JERA碧南电厂氨煤混烧改造","en":"JERA Hekinan Ammonia Co-Firing Conversion","country":"日本","region":"东亚","cat":"petro","coord":[136.97,34.84],"cap":"1000MW机组20%氨混烧（年耗氨约50万吨），2035年目标50%以上","inv":5,"invText":"约5亿美元（估，含氨接卸储运配套）","status":"在建","year":2029,"updated":"2026-06","owner":"JERA（东电-中部电力合资）","flagship":false,"desc":"全球首个大型商业燃煤机组20%氨混烧：2024年碧南4号机组示范成功，2029财年转入连续商业运行。","detail":"日本最大发电商JERA在爱知县碧南火力发电站推进全球首个大型商业燃煤机组燃料氨替代工程。2024年4—6月在100万千瓦的4号机组完成为期约两个月的20%氨混烧示范——全球首次在大型商业煤电机组实现该比例替代，结果显示NOx不高于纯煤工况、SOx下降20%、未检出N2O。JERA正改造燃烧器并建设氨接卸储运设施，目标2029财年实现20%氨混烧连续商业运行（年耗氨约50万吨），燃料氨将主要来自美国CF Blue Point等低碳氨项目；2035年混烧比例提高到50%以上，2030年前关停所有超临界以下煤电。该工程是日本'氨燃料发电'路线的旗舰示范。","descEn":"The world's first 20% ammonia co-firing on a large commercial coal unit: a successful 2024 demonstration at Hekinan Unit 4 (1 GW), moving to continuous commercial operation in FY2029.","detailEn":"JERA, Japan's largest power generator, is converting its Hekinan thermal power station in Aichi to fuel-ammonia substitution. From April to June 2024, the 1,000 MW Unit 4 ran the world's first 20% ammonia co-firing demonstration on a large commercial coal unit, showing NOx no higher than coal-only operation, 20% lower SOx and no detectable N2O. JERA is retrofitting burners and building ammonia receiving and storage facilities, targeting continuous commercial 20% co-firing in FY2029 (about 500,000 tonnes of ammonia per year, sourced partly from the US Blue Point low-carbon ammonia project), rising to 50%+ by 2035 - the flagship of Japan's ammonia-to-power roadmap.","progress":"2024年6月完成全球首次大型机组20%氨混烧示范；燃烧器与氨储运设施改造推进，目标2029财年商业化连续混烧。"},
  {"id":6421,"name":"韩国ESS中央合同市场首批储能竞标","en":"South Korea ESS Central Contract Market Auction (540MW/3.24GWh)","country":"韩国","region":"东亚","cat":"storage","coord":[127.7,36.5],"cap":"540MW/3240MWh（本土500MW/3000MWh＋济州40MW/240MWh，6小时）","inv":8,"invText":"约8亿美元（估）","status":"在建","year":2026,"updated":"2026-06","owner":"韩国电力交易所（KPX）/中标独立储能商","desc":"韩国首次全国性电网级储能集中竞标：540MW/3.24GWh（含济州岛40MW），15年容量合同，2026年底前全部投运。","detail":"韩国电力交易所（KPX）2025年11月发布ESS中央合同市场竞标，规模540MW/3240MWh：本土500MW/3000MWh（6小时）加济州岛40MW/240MWh，是韩国首次将电网级储能集中采购从济州试点扩展到全国。投标2026年1月12日截止，2026年2月中旬公布中标者，中标项目与KPX签订15年容量合同，须在2026年12月底前全部商业投运。该轮竞标确立了韩国长时储能的市场化采购机制，为后续逐年扩大的中央合同市场奠定模板，也是韩国应对核电与可再生能源并存电网灵活性缺口的关键举措。","descEn":"Korea's first nationwide grid-scale storage auction: 540MW/3.24GWh (incl. 40MW on Jeju), 15-year contracts, all online by end-2026.","detailEn":"Korea Power Exchange (KPX) launched the ESS Central Contract Market auction in November 2025 for 540MW/3,240MWh - 500MW/3,000MWh (6-hour) on the mainland plus 40MW/240MWh on Jeju Island - the first time Korea's grid-scale storage procurement expanded beyond the Jeju pilot nationwide. Bids closed January 12, 2026, winners were announced in mid-February 2026, and awarded projects sign 15-year capacity contracts with KPX with commercial operation required by December 2026. The round establishes Korea's market-based procurement template for long-duration storage.","progress":"2026年1月12日投标截止，2026年2月中旬公布中标结果；全部项目须2026年12月底前商业投运。","flagship":false},
  {"id":6422,"name":"黑龙江宝清压缩空气储能示范项目","en":"Baoqing 350MW Compressed Air Energy Storage Demonstration","country":"中国","region":"东亚","cat":"storage","coord":[132,46.4],"cap":"350MW/1750MWh（另配6MW/1.5MWh飞轮）","inv":4,"invText":"约30亿元人民币（估）","status":"在建","year":2027,"updated":"2026-06","owner":"宝清县吉能压缩空气储能有限公司","desc":"国家首批储能试点示范：我国首个350MW级人工硐室储气压缩空气储能，熔盐+热水双介质储热，2025年4月开工。","detail":"黑龙江吉能宝清350MW/1750MWh压缩空气储能示范项目位于双鸭山市宝清县七星泡镇，为国家能源局首批科技创新（储能）试点示范项目，2025年4月27日开工。项目采用'350MW压缩空气+6MW/1.5MWh飞轮'混合储能架构，压缩7小时、发电5小时，创新采用熔盐与热水双介质储热回收360℃压缩余热，膨胀发电环节零化石燃料消耗，是我国首个350MW级采用人工硐室储气库的大规模压缩空气储能电站，计划2027年底投产，投运后每年可减少弃风弃光电量约8.4亿千瓦时。","descEn":"A national first-batch storage demonstration: China's first 350MW-class CAES using artificial underground caverns, with molten salt + hot water dual-medium heat storage; construction began April 2025.","detailEn":"The Jineng Baoqing 350MW/1,750MWh compressed air energy storage demonstration project in Qixingpao Town, Baoqing County, Shuangyashan (Heilongjiang) is among the National Energy Administration's first batch of storage innovation pilots. Construction began on April 27, 2025. It pairs 350MW CAES (7-hour charge, 5-hour discharge) with a 6MW/1.5MWh flywheel, and pioneers molten salt + hot water dual-medium thermal storage recovering 360C compression heat for zero-fossil-fuel expansion. It is China's first 350MW-class CAES plant using artificial underground caverns, due end-2027, cutting curtailed wind and solar by about 840GWh per year.","progress":"2025年4月27日开工；2025—2026年设备岛成套设备、飞轮储能系统等招标推进，计划2027年底建成投产。","flagship":false},
  {"id":6423,"name":"日本北九州APL-GCI数据中心园区","en":"APL-GCI Kitakyushu Data Center Campus","country":"日本","region":"东亚","cat":"datacenter","coord":[130.87,33.88],"cap":"120 MW（首期60 MW）","inv":15,"invText":"约15亿美元（估）","status":"规划","year":2027,"updated":"2026-06","owner":"Asia Pacific Land / Global Compute Infrastructure","desc":"APL与Global Compute在福冈县北九州市开发120 MW数据中心园区，是九州承接AI算力外溢的代表项目。","detail":"Asia Pacific Land（APL）与Global Compute Infrastructure（GCI）合作在日本开发两个数据中心园区，首个落地福冈县北九州市，规划容量120 MW，2026年开工、首批60 MW预计2027年9月投运。在日本'瓦特-比特协同'政策引导下，算力正从东京、大阪外溢至电力富余的北海道与九州；北九州凭借港口、电网与半导体产业配套成为九州数据中心新集群核心。投资额未披露，按规模估算约15亿美元。","descEn":"Asia Pacific Land and Global Compute Infrastructure are developing a 120 MW data center campus in Kitakyushu, Fukuoka — a flagship of Kyushu's rise as Japan's AI compute overflow hub.","detailEn":"Asia Pacific Land (APL) and Global Compute Infrastructure (GCI) partnered to develop two data center campuses in Japan, the first a 120 MW campus in Kitakyushu, Fukuoka Prefecture: construction from 2026, with the first 60 MW operational by September 2027. Under Japan's 'Watt-Bit' policy push, compute is shifting from Tokyo/Osaka to power-rich Hokkaido and Kyushu; Kitakyushu's port, grid and semiconductor ecosystem anchor the new cluster. Investment undisclosed (est. ~$1.5bn).","progress":"2025年1月公布合作，2026年开工，首期60 MW目标2027年9月投运。","flagship":false},
  {"id":6424,"name":"OpenAI星际之门韩国数据中心（浦项·全南）","en":"OpenAI Stargate Korea Data Centers (Pohang & Jeonnam)","country":"韩国","region":"东亚","cat":"datacenter","coord":[129.36,36.02],"cap":"首期2×20 MW（远期吉瓦级）","inv":10,"invText":"首期约10亿美元（估）","status":"在建","year":2027,"updated":"2026-06","owner":"OpenAI / 三星 / SK","desc":"OpenAI与三星、SK合作在浦项与全罗南道建设星际之门韩国数据中心，2026年3月动工，首期各20 MW。","detail":"OpenAI与韩国政府及三星、SK集团合作，在韩国东南（庆尚北道浦项，三星主导）与西南（全罗南道，SK海力士主导）各建一座星际之门（Stargate）数据中心，首期容量各20 MW，2026年3月动工，远期向吉瓦级扩展。三星电子供应高性能存储芯片、三星SDS负责数据中心设计运营，三星物产/三星重工还将为浦项站点研究海上浮式数据中心方案；SK海力士签署意向，为Stargate供应HBM并大幅提升产能。该项目是OpenAI'星际之门'全球布局在东亚的首个落点。","descEn":"OpenAI, Samsung and SK are building Stargate Korea data centers in Pohang and Jeollanam-do — groundbreaking March 2026, 20 MW initial capacity each, scaling toward gigawatt class.","detailEn":"OpenAI, with the Korean government, Samsung and SK, is building two Stargate data centers in Korea: Pohang, North Gyeongsang (Samsung-led) and Jeollanam-do (SK hynix-led), each starting at 20 MW with groundbreaking in March 2026 and a path toward gigawatt scale. Samsung Electronics supplies high-performance memory, Samsung SDS handles design and operations, and Samsung C&T/Samsung Heavy Industries are studying floating offshore data center concepts for Pohang; SK hynix signed an LOI to supply HBM at sharply expanded capacity. It is Stargate's first East Asian foothold.","progress":"2026年2—3月推进动工，浦项与全南两站点首期各20 MW；三星/SK同步锁定HBM供应。","flagship":false},
  {"id":6425,"name":"桑东钨矿复产（韩国Sangdong）","en":"Sangdong Tungsten Mine Restart","country":"韩国","region":"东亚","cat":"mining","coord":[128.83,37.1],"cap":"一期年处理矿石64万吨、年产钨精矿约2300吨；二期2027年翻倍至4600吨","inv":1.5,"invText":"约1.5亿美元（估）","status":"投运","year":2025,"updated":"2026-06","owner":"Almonty Industries","desc":"停产30余年的韩国江原道桑东钨矿2025年12月复产，一期年产钨精矿约2300吨，是中国以外最大钨矿之一，西方钨供应链关键工程。","detail":"桑东（Sangdong）钨矿位于韩国江原道宁越郡，曾是全球最大钨矿之一，停产30余年后由加拿大Almonty Industries投资复产。2025年12月一期工程建成投产，首批矿石已进入破碎-磨矿-浮选流程，年处理矿石约64万吨、年产钨精矿约2300吨；规划中的二期将于2027年投产，处理能力翻倍至120万吨、钨精矿产量增至约4600吨/年。在中国收紧钨出口管制的背景下，桑东复产被视为西方关键矿产供应链『去风险』的标志性项目，使韩国重返全球钨市场核心。","descEn":"South Korea's Sangdong tungsten mine restarted in December 2025 after 30+ years: Phase 1 processes 640,000 t/y of ore for ~2,300 t/y of tungsten concentrate, with a 2027 Phase 2 doubling output — one of the largest non-China tungsten sources.","detailEn":"Sangdong in Yeongwol County, Gangwon Province, once among the world's largest tungsten mines, has been brought back into production by Canada's Almonty Industries after more than three decades. Phase 1 was commissioned in December 2025, with crushing, milling and flotation ramping up to 640,000 t/y of ore and roughly 2,300 t/y of tungsten concentrate; a Phase 2 expansion due in 2027 doubles throughput to 1.2 Mt/y and output to ~4,600 t/y. Amid Chinese export controls, Sangdong is a flagship of Western critical-minerals de-risking, returning Korea to the heart of the global tungsten market.","progress":"2025年12月一期投产、开始商业化采矿，二期扩建规划2027年投产。","flagship":false},
  {"id":6426,"name":"吉林石化炼油化工转型升级（120万吨乙烯）","en":"Jilin Petrochemical Refining-to-Chemicals Transformation (1.2 Mtpa Ethylene)","country":"中国","region":"东亚","cat":"petro","coord":[126.6,43.92],"cap":"新增120万吨/年乙烯、56万吨/年丙烯（乙烯总产能达190万吨/年）","inv":47,"invText":"339亿元人民币（约47亿美元）","status":"投运","year":2025,"updated":"2026-06","owner":"中国石油吉林石化","desc":"总投资339亿元的东北炼化转型示范工程：新建120万吨/年乙烯采用国产CBL裂解技术，2025年8月底一次开车成功，吉林石化乙烯总产能升至190万吨/年。","detail":"吉林石化炼油化工转型升级项目总投资339亿元，是国内传统炼化企业绿色低碳转型和中国石油与吉林省深化合作的示范工程，核心为新建120万吨/年乙烯装置，采用自主CBL裂解技术与LECT分离技术，设备国产化率96%。2025年4月30日120万吨乙烯等10套主装置高标准中交；8月28日裂解炉投料，8月31日产出合格乙烯，实现一次开车成功。全面投产后吉林石化乙烯总产能达190万吨/年，年增产聚合级丙烯约56万吨，并联产裂解碳四、氢气等20余种化工原料，配套ABS、双酚A、苯酚丙酮等下游装置，带动吉林市万亿级化工产业集群。","descEn":"A RMB 33.9bn refining-to-chemicals showcase in northeast China: the new 1.2 Mtpa ethylene cracker using domestic CBL technology started up successfully at end-August 2025, lifting Jilin Petrochemical's ethylene capacity to 1.9 Mtpa.","detailEn":"PetroChina Jilin Petrochemical's RMB 33.9 billion transformation project centers on a new 1.2 Mtpa ethylene plant using domestically developed CBL cracking and LECT separation technology (96% local equipment). Ten main units reached mechanical completion on 30 April 2025; the cracker was fed on 28 August and produced on-spec ethylene on 31 August 2025 at the first attempt. The project lifts site ethylene capacity to 1.9 Mtpa, adds ~560,000 t/y of propylene and feeds downstream ABS, bisphenol-A and phenol/acetone units.","progress":"2025年8月31日：新建120万吨/年乙烯装置产出合格乙烯、一次开车成功，乙烯总产能升至190万吨/年；下游双酚A、苯酚丙酮等装置陆续投产。","flagship":false},
  {"id":6427,"name":"独山子石化塔里木二期120万吨乙烯","en":"Dushanzi Petrochemical Tarim Phase II Ethylene Project","country":"中国","region":"东亚","cat":"petro","coord":[86.06,41.68],"cap":"120万吨/年乙烯及11套主装置（含2×45万吨全密度聚乙烯、45万吨聚丙烯）","inv":36,"invText":"256.56亿元人民币（约36亿美元）","status":"在建","year":2026,"updated":"2026-06","owner":"中国石油独山子石化","desc":"国家\"十四五\"重点工程：库尔勒上库高新区新建120万吨/年乙烯及11套主装置，总投资256.56亿元，2026年6月底中交、9月底投产。","detail":"独山子石化塔里木二期120万吨/年乙烯项目位于新疆库尔勒上库高新技术产业开发区石化产业园，总投资256.56亿元，占地约4644亩，是国家\"十四五\"规划重点项目和中国石油在疆最大炼化新建工程。建设120万吨/年乙烯装置及2×45万吨/年全密度聚乙烯、30万吨/年低密度聚乙烯、45万吨/年聚丙烯等11套主装置，自主技术应用率超99%、设备国产化率超98%，并配套国内首套低浓度二氧化碳捕集装置，乙烯装置碳排放强度降低42%、年减碳21.12万吨。2023年12月乙烯装置开工，计划2026年6月30日中交、9月30日投产，是西部炼化绿色转型标杆，将带动南疆化工下游产业集群。","descEn":"A national 14th Five-Year Plan flagship in Korla, Xinjiang: a RMB 25.7bn, 1.2 Mtpa ethylene complex with 11 main units, due for mechanical completion in June 2026 and startup by end-September 2026.","detailEn":"PetroChina Dushanzi Petrochemical's Tarim Phase II ethylene project in the Korla Shangku High-tech Zone covers a 1.2 Mtpa cracker plus 11 main units, including two 450,000 t/y full-density PE lines, 300,000 t/y LDPE and 450,000 t/y PP, with >99% self-developed technology and >98% domestic equipment. It features China's first low-concentration CO2 capture unit, cutting the cracker's carbon intensity by 42% (211,200 t/y). Construction began in December 2023; mechanical completion is planned for 30 June 2026 and startup by 30 September 2026.","progress":"2025年底基本建成，按计划2026年6月30日实现中交、9月30日投料生产；多项关键节点提前达成，进入收官冲刺阶段。","flagship":false},
  {"id":6428,"name":"成渝中线高速铁路","en":"Chengdu-Chongqing Central High-Speed Railway","country":"中国","region":"东亚","cat":"transport","coord":[105.3,29.95],"cap":"292公里 / 设计时速350公里（预留400公里提速条件）","inv":102,"invText":"总投资733亿元人民币（约102亿美元）","status":"在建","year":2027,"updated":"2026-06","owner":"国铁集团·川渝两省市","flagship":true,"desc":"成渝双核间第四条铁路通道，全线292公里、设计时速350公里并预留400公里提速条件，2027年通车后成都—重庆50分钟直达。","detail":"成渝中线高铁自成都站引出，经简阳、乐至、安岳、大足至重庆，正线全长292公里，总投资733亿元，设计时速350公里，其中简州—大足石刻段按预留400公里时速提速条件建设，是我国技术标准最高的高铁之一，也是成渝地区双城经济圈“双核直连”的标志性工程。截至2026年5月，全线41座隧道全部贯通，四川段总体进度超80%，成都站改扩建进入站房结构施工阶段，预计2027年建成通车，届时成渝双核实现50分钟通达。","descEn":"The fourth rail corridor between Chengdu and Chongqing: 292 km designed for 350 km/h with provisions for 400 km/h, cutting the twin-city journey to 50 minutes from 2027.","detailEn":"The Chengdu-Chongqing Central HSR runs 292 km from Chengdu via Jianyang, Lezhi, Anyue and Dazu to Chongqing, with a total investment of RMB 73.3 billion (about USD 10.2 billion). Designed for 350 km/h with a 400 km/h-ready section between Jianzhou and Dazu Shike, it is one of China's highest-spec railways and the flagship link of the Chengdu-Chongqing twin-city economic circle. By May 2026 all 41 tunnels had been holed through and the Sichuan section passed 80% completion; opening is targeted for 2027, bringing the two cores within 50 minutes.","progress":"2026-05：全线41座隧道全部贯通，四川段总体进度逾80%，成都站枢纽工程进入第三阶段站房结构施工，瞄准2027年建成通车。","route":[[104.07,30.66],[104.55,30.39],[105.71,29.7],[106.55,29.57]]},
  {"id":6429,"name":"沈白高铁（沈阳—长白山）","en":"Shenyang-Baihe (Changbaishan) High-Speed Railway","country":"中国","region":"东亚","cat":"transport","coord":[126,41.9],"cap":"430公里 / 设计时速350公里","inv":80,"invText":"总投资约580亿元人民币（约80亿美元，估）","status":"投运","year":2025,"updated":"2026-06","owner":"国铁集团·辽吉两省","desc":"沈佳高铁沈白段，全长430公里、时速350公里，2025年9月28日开通，沈阳至长白山最快1小时53分，抚顺、通化、白山迈入高铁时代。","detail":"沈白高铁（沈佳高铁沈白段）自沈阳北站引出，经辽宁抚顺、吉林通化、白山，终至延边安图县二道白河镇长白山站，全长430公里，设计时速350公里，是国家“十四五”规划重点项目和东北东部山区首条350公里级高铁。2025年9月28日开通运营后，北京朝阳至长白山最快4小时33分、沈阳北至长白山1小时53分，结束了抚顺、通化、白山不通高铁的历史，为长白山冰雪旅游和东北东部振兴铺就“黄金跑道”。投资约580亿元人民币（估）。","descEn":"The 430-km, 350-km/h Shenyang-Baihe HSR opened on 28 September 2025, putting Changbaishan within 1h53m of Shenyang and bringing Fushun, Tonghua and Baishan onto China's HSR grid.","detailEn":"The Shenyang-Baihe section of the Shenyang-Jiamusi HSR runs 430 km from Shenyang North via Fushun, Tonghua and Baishan to Changbaishan station in Erdaobaihe, Yanbian. A key project of China's 14th Five-Year Plan and the first 350 km/h line through the mountainous eastern Northeast, it opened on 28 September 2025, cutting Beijing-Changbaishan to 4h33m and Shenyang-Changbaishan to 1h53m, energizing Changbai Mountain winter tourism. Investment is roughly RMB 58 billion (about USD 8 billion, estimated).","progress":"2025-09：9月28日正式开通运营，沈阳北至长白山最快1小时53分；2026年初进入首个完整冰雪旅游季，客流旺盛。","route":[[123.43,41.81],[124.94,41.88],[125.94,41.73],[128.1,42.41]],"flagship":false},
  {"id":6430,"name":"釜山加德岛新机场","en":"Gadeokdo New Airport (Busan)","country":"韩国","region":"东亚","cat":"transport","coord":[128.82,35.02],"cap":"3500米跑道 / 海陆两栖布置（韩国首座部分浮海机场）","inv":78,"invText":"总事业费约10.7万亿韩元（约78亿美元）","status":"规划","year":2026,"updated":"2026-06","owner":"韩国国土交通部·加德岛新机场建设公团","desc":"釜山西南海域的韩国第二大门户机场，总投资约10.7万亿韩元，2026年与大宇建设牵头联合体议标推进场地工程，目标2035年开港。","detail":"加德岛新机场是韩国为釜山—蔚山—庆南东南经济圈规划的新门户枢纽，选址釜山加德岛及其外海，跨海陆布置3500米跑道，是韩国首座部分填海/浮体式机场，定位承接金海机场国际客货并服务釜山世博会候选城市远景。项目总事业费2025年12月上调至约10.7万亿韩元。因两轮招标均只有单一投标人流标，建设公团2026年2月转入与大宇建设牵头联合体的议标程序，场地工程工期约106个月，目标2035年开港；配套的蔚山—加德岛铁路联络线已获批、瞄准2035年同步通车。","descEn":"South Korea's second gateway airport off Busan: a 10.7-trillion-won part-reclaimed, part-floating airport with a 3,500 m runway, moving to a negotiated contract with a Daewoo E&C consortium in 2026 for a 2035 opening.","detailEn":"Gadeokdo New Airport is the planned gateway hub for the Busan-Ulsan-South Gyeongsang region, sited on and off Gadeok Island with a 3,500 m runway spanning land and sea — Korea's first partly floating airport. The project budget was raised to about KRW 10.7 trillion in December 2025. After two failed tenders with single bidders, the construction authority moved in February 2026 to a negotiated contract with a Daewoo E&C-led consortium; site works will take about 106 months, targeting a 2035 opening, with an approved Ulsan-Gadeokdo rail link timed to match.","progress":"2026-02：场地工程两轮招标流标后转入与大宇建设联合体议标；2025-12总事业费上调至约10.7万亿韩元，目标2035年开港。","flagship":false},
  {"id":6431,"name":"日本北海道桧山冲海上风电（第4轮促进区）","en":"Hokkaido Hiyama Offshore Wind (Japan Round 4 Promotion Zone)","country":"日本","region":"东亚","cat":"renewable","coord":[139.6,42.3],"cap":"910MW–1.14GW（促进区面积3.22万公顷）","inv":35,"invText":"约35亿美元（估）","status":"规划","year":2026,"updated":"2026-06","owner":"待定（METI/国交省第4轮公开招标）","desc":"日本第4轮海上风电最大场址：北海道桧山冲910MW–1.14GW促进区已指定，招标在即。","detail":"桧山冲场址位于北海道西南部濑棚、八云、江差、上之国町外海，促进区面积达3.22万公顷，按经产省评估可支撑910MW至1.14GW装机，是日本《再生能源海域利用法》第4轮（Round 4）招标中规模最大的区块，也是迄今日本单体最大的海上风电招标场址；同批指定的松前冲场址（3710公顷）可支撑250–320MW。两区块已于2025年7月30日正式指定为促进区域。原定2025年10月14日启动的第4轮招标因规则修订（引入差价合约等机制）推迟，预计2026年完成开发商遴选，建成后将成为北海道海上风电基地化开发的起点。","descEn":"Japan's largest offshore wind auction site to date: the Hiyama zone off southwest Hokkaido (910 MW-1.14 GW) was designated a promotion zone in July 2025 ahead of the Round 4 tender.","detailEn":"The Hiyama site off Setana, Yakumo, Esashi and Kaminokuni in southwest Hokkaido covers 32,160 ha and can host 910 MW-1.14 GW per METI - the largest single offshore wind auction area in Japan's Round 4 under the Renewable Sea Area Utilization Act, alongside the smaller Matsumae zone (250-320 MW). Both were formally designated promotion zones on 30 July 2025. The Round 4 tender, originally set for 14 October 2025, was postponed amid guideline changes (including a CfD-style mechanism), with developer selection expected in 2026.","progress":"2025年7月30日与松前冲一并正式指定为促进区域；原定2025年10月启动的第4轮招标因引入CfD等规则修订推迟，预计2026年遴选开发商。","flagship":false},

  // ===== 东南亚（6440-6461）=====
  {"id":6440,"name":"越南宁顺一号核电站","en":"Ninh Thuan 1 Nuclear Power Plant","country":"越南","region":"东南亚","cat":"nuclear","coord":[108.94,11.4],"cap":"2×1200MW（VVER-1200压水堆）","inv":132,"invText":"约132亿美元（估，按工贸部5500美元/千瓦测算）","status":"规划","year":2031,"updated":"2026-03","owner":"越南电力集团(EVN)/俄罗斯国家原子能公司(Rosatom)","flagship":true,"desc":"越南重启的首座核电站，Rosatom承建2台VVER-1200机组，目标2031年底前并网。","detail":"2024年11月越南国会通过第174号决议重启搁置八年的宁顺核电计划，2025年6月通过新《原子能法》（2026年1月生效）将核电列为国家战略。2026年3月23日越俄签署政府间协议，由Rosatom在宁顺省福定乡建设2台120万千瓦VVER-1200机组（参考列宁格勒二期），EVN任业主，目标2031年底前投运。工贸部按5500美元/千瓦测算，宁顺两厂共4GW总投资至少220亿美元；宁顺二号由越南油气集团(PVN)另行推进。","descEn":"Vietnam's revived first nuclear power plant: Rosatom will build two VVER-1200 units at Phuoc Dinh, targeting grid connection before end-2031.","detailEn":"In November 2024 Vietnam's National Assembly passed Resolution 174 restarting the Ninh Thuan nuclear program shelved in 2016, and a new Atomic Energy Law took effect in January 2026. On 23 March 2026 Vietnam and Russia signed an intergovernmental agreement for Rosatom to build two 1,200 MW VVER-1200 units at Phuoc Dinh (referencing Leningrad II), with EVN as investor and operation targeted before end-2031. The Ministry of Industry and Trade estimates at least $22 billion for the two Ninh Thuan plants (4 GW) at $5,500/kW; Ninh Thuan 2 is assigned to PetroVietnam.","progress":"2026年3月越俄签署政府间协议，Rosatom确定承建2台VVER-1200机组，可研更新中。"},
  {"id":6441,"name":"印尼ThorCon克拉萨岛熔盐堆核电站","en":"ThorCon Kelasa Island Molten Salt Reactor Plant","country":"印度尼西亚","region":"东南亚","cat":"nuclear","coord":[107.07,-2.64],"cap":"500MW（2×250MW熔盐堆TMSR-500）","inv":12,"invText":"约12亿美元（估）","status":"规划","year":2031,"updated":"2025-08","owner":"ThorCon Power Indonesia","flagship":false,"desc":"印尼史上首个核电站许可申请项目：ThorCon拟在邦加勿里洞克拉萨岛建500MW熔盐堆，2031年满功率。","detail":"新加坡ThorCon International旗下PT Thorcon Power Indonesia向印尼核监管机构BAPETEN提交场址评估文件，成为印尼历史上首个核电站许可申请方；2025年8月BAPETEN批准其场址评估方案。项目位于邦加勿里洞省中邦加县克拉萨岛，采用2台250MW低浓铀熔盐堆组成500MW示范电站（船厂模块化建造后整体运抵），计划2027年取得场址许可与设计批准后开工，2031年达到满功率，有望成为东南亚首个SMR。印尼已将核电目标提前至2029—2030年并网。","descEn":"Indonesia's first-ever nuclear plant licence application: ThorCon plans a 500 MW molten salt reactor on Kelasa Island, Bangka Belitung, full power by 2031.","detailEn":"PT Thorcon Power Indonesia, a unit of Singapore-based ThorCon International, became the first nuclear power licence applicant in Indonesia's history, and in August 2025 regulator BAPETEN approved its site evaluation plan for Kelasa Island in Central Bangka. The 500 MW demonstration plant uses two 250 MW low-enriched-uranium molten salt reactors built shipyard-style and delivered to site. Construction could start in 2027 after site licensing and design approval, with full power by 2031 — potentially Southeast Asia's first SMR as Indonesia fast-tracks nuclear to 2029-2030.","progress":"2025年8月BAPETEN批准场址评估方案，下一步申请场址许可与设计批准，拟2027年开工。"},
  {"id":6442,"name":"越南—新马海上风电跨境送电项目","en":"Vietnam-Singapore/Malaysia Offshore Wind Export Project","country":"越南—新加坡","region":"东南亚","cat":"grid","coord":[107.4,9.6],"cap":"2.3GW海上风电+跨境海底电缆（对新加坡输电1.2GW）","inv":70,"invText":"约70亿美元（估，含风电场与海缆）","status":"规划","year":2030,"updated":"2025-05","owner":"越南油气技术服务公司(PTSC)/胜科工业(Sembcorp)/马来西亚MY Energy联合体","flagship":false,"desc":"PTSC与胜科在头顿外海建2.3GW海上风电，经海底电缆向新加坡输电1.2GW、并经马来半岛电网送马。","detail":"2025年5月26日东盟峰会期间，国家能源(TNB)与马国油组成的MY Energy联合体同越南PTSC—新加坡胜科(Sembcorp)联合体交换合作协议，评估经新建海底电缆及马来半岛电网向马、新出口越南可再生电力。PTSC与胜科拟在巴地头顿外海2030年前建成2.3GW海上风电，对应新加坡能源市场管理局已有条件批准的1.2GW越南清洁电力进口配额（新加坡目标2035年进口约6GW低碳电力）。2025年年中起部署漂浮激光雷达开展海上风资源与海况测量，研究2026年三季度完成。","descEn":"PTSC and Sembcorp plan 2.3 GW of offshore wind off Ba Ria-Vung Tau with a new subsea cable exporting 1.2 GW to Singapore and power to Malaysia via the peninsular grid.","detailEn":"On 26 May 2025, at the ASEAN Summit, the MY Energy Consortium (TNB and Petronas) exchanged agreements with the PTSC-Sembcorp consortium to assess exporting Vietnamese renewable power to Malaysia and Singapore via a new subsea cable and the Peninsular Malaysia grid. PTSC and Sembcorp plan to build 2.3 GW of offshore wind off Ba Ria-Vung Tau by 2030, matching Singapore EMA's conditional approval of 1.2 GW of imports from Vietnam (Singapore targets ~6 GW of low-carbon imports by 2035). FLiDAR wind and metocean surveys began in mid-2025, with studies due by Q3 2026.","progress":"2025年5月马、越、新三方联合体签署合作协议，年中起部署FLiDAR测风，研究2026年三季度完成。"},
  {"id":6443,"name":"越南奇英海上风电场（河静省）","en":"Ky Anh Offshore Wind Farm (Ha Tinh)","country":"越南","region":"东南亚","cat":"renewable","coord":[106.45,18.05],"cap":"400MW（47台5—8.5MW风机，年发电约10.5亿千瓦时）","inv":6.5,"invText":"17.05万亿越南盾（约6.47亿美元）","status":"规划","year":2028,"updated":"2026-04","owner":"河静省人民委员会（投资者遴选中）","flagship":false,"desc":"河静省批准的400MW近海/滩涂风电项目，总投资约6.5亿美元，目标2028年四季度商运。","detail":"河静省批准奇英风电项目投资政策，场址横跨奇春、奇英、奇康等乡的陆域与海域，规划装机400MW，拟安装47台单机5—8.5MW风机，年发电约10.53亿千瓦时（容量系数30.1%），经66/500kV升压站及500kV双回线接入国家电网。项目总投资17.05万亿越南盾（约6.47亿美元），运营期50年；计划2026年三季度前完成行政手续，最迟2026年四季度开工，2028年四季度全部建成并商业运营。河静省工贸厅正牵头公开遴选投资者。","descEn":"A 400 MW onshore-nearshore wind project approved by Ha Tinh province with about $647 million investment, targeting commercial operation by Q4 2028.","detailEn":"Ha Tinh province approved the investment policy for the Ky Anh wind power project spanning land and sea areas of Ky Xuan, Ky Anh and Ky Khang communes: 400 MW from 47 turbines of 5-8.5 MW each, generating about 1,053 GWh a year (30.1% capacity factor), connected via a 66/500 kV substation and a double-circuit 500 kV line. Total investment is VND 17.05 trillion (~$647 million) over a 50-year term. Administrative procedures are due by Q3 2026, construction must start by Q4 2026, and full commercial operation is slated for Q4 2028; investor selection is underway.","progress":"河静省已批准投资政策并启动投资者遴选，要求最迟2026年四季度开工。"},
  {"id":6444,"name":"印尼卡扬河梯级水电站","en":"Kayan Cascade Hydropower Project","country":"印度尼西亚","region":"东南亚","cat":"renewable","coord":[116.95,2.55],"cap":"9GW（卡扬河5座梯级大坝，一期900MW）","inv":178,"invText":"约178亿美元","status":"在建","year":2027,"updated":"2024-06","owner":"PT Kayan Hydro Energy","flagship":true,"desc":"北加里曼丹卡扬河5座梯级大坝共9GW、投资178亿美元，建成将是东南亚最大水电综合体。","detail":"PT Kayan Hydro Energy主导的卡扬梯级水电项目拟在北加里曼丹省卡扬河上建设5座梯级大坝，总装机9GW、总投资约178亿美元，建成后将成为东南亚最大水电综合体，为新首都努山塔拉及北加里曼丹绿色工业园(KIPI)供应绿电。项目一期（卡扬一级，约900MW）正建设进场道路、导流明渠等辅助工程，首台机组目标2027年前后投产；电建集团与住友商事先后退出后，开发方表示项目仍在推进，搬迁安置与环境影响争议待解。","descEn":"Five cascading dams on the Kayan River in North Kalimantan totalling 9 GW and ~$17.8 billion - Southeast Asia's largest hydropower complex if completed.","detailEn":"Led by PT Kayan Hydro Energy, the Kayan Cascade plans five dams on the Kayan River in North Kalimantan with a combined 9 GW and about $17.8 billion investment - Southeast Asia's largest hydro complex if fully built - to power the new capital Nusantara and the KIPI green industrial estate. Phase 1 (Kayan 1, ~900 MW) is building access roads and a river diversion channel, with first commissioning targeted around 2027. PowerChina and Sumitomo have withdrawn, but the developer says the project is moving ahead amid resettlement and environmental concerns.","progress":"一期大坝进场道路与导流渠等辅助工程施工中，开发方称项目在合作伙伴退出后仍继续推进。"},
  {"id":6445,"name":"菲律宾棉兰老—米沙鄢联网工程（MVIP）","en":"Mindanao-Visayas Interconnection Project (MVIP)","country":"菲律宾","region":"东南亚","cat":"grid","coord":[123.38,9],"cap":"HVDC 450MW（可扩至900MW），184公里海缆+526公里架空线","inv":9.2,"invText":"约520亿比索（约9.2亿美元）","status":"投运","year":2024,"updated":"2024-01","owner":"菲律宾国家电网公司(NGCP)","flagship":false,"desc":"菲律宾史上首次将吕宋、米沙鄢、棉兰老三大电网物理互联的高压直流工程，2024年1月正式投运。","detail":"2024年1月26日，马科斯总统出席棉兰老—米沙鄢联网工程(MVIP)通电仪式，菲律宾吕宋、米沙鄢、棉兰老三大电网首次实现物理互联。工程由NGCP投资约520亿比索（约9.2亿美元），以184回路公里高压直流海底电缆连接北三宝颜省达皮丹与宿务桑坦德，并配套526回路公里架空线路，初期输送能力450MW、可扩至900MW。2023年4月30日首次从棉兰老向米沙鄢送电22.5MW，随后逐步升至满负荷，显著提升全国电力互济与供电可靠性。","descEn":"The HVDC link that for the first time physically connected the Philippines' Luzon, Visayas and Mindanao grids, commercially energized in January 2024.","detailEn":"On 26 January 2024 President Marcos led the ceremonial switch-on of NGCP's ~PHP 52 billion (~$0.92 billion) Mindanao-Visayas Interconnection Project, physically uniting the Luzon, Visayas and Mindanao grids for the first time in Philippine history. The link runs a 184 circuit-km HVDC submarine cable from Dapitan, Zamboanga del Norte to Santander, Cebu plus 526 circuit-km of overhead lines, initially carrying 450 MW and expandable to 900 MW. First power of 22.5 MW flowed in April 2023 before ramping to full capacity, boosting nationwide reliability and power sharing.","progress":"2024年1月正式商业通电，450MW满负荷运行，三大电网实现互济。","route":[[123.42,8.58],[123.33,9.43]]},
  {"id":6446,"name":"马来西亚MyBeST电网级储能首批项目","en":"Malaysia MyBeST Grid-Scale BESS Programme (Phase 1)","country":"马来西亚","region":"东南亚","cat":"storage","coord":[102.1,3.7],"cap":"400MW/1600MWh（4个100MW/400MWh电网侧储能站）","inv":4.5,"invText":"约4.5亿美元（估）","status":"规划","year":2027,"updated":"2025-12","owner":"马来西亚能源委员会(Suruhanjaya Tenaga)招标/中标财团","flagship":false,"desc":"马来西亚首次竞争性电网储能招标：半岛4个100MW/400MWh电站共1.6GWh，2027年投运。","detail":"马来西亚能源委员会2024年11月启动该国首个竞争性电网级储能招标MyBeST，在马来半岛建设4个各100MW/400MWh的并网电池储能站，合计400MW/1600MWh，计划2027年投运。2025年12月19日从28家申请者中公布入围名单，四家中标方各采用不同电池技术路线，以在半岛电网与气候条件下检验多种储能配置的实际性能。项目旨在减少化石燃料调峰依赖、降低系统运行成本，支撑国家能源转型路线图(NETR)目标。","descEn":"Malaysia's first competitive grid-scale BESS tender: four 100 MW/400 MWh plants totalling 1.6 GWh in Peninsular Malaysia, to be commissioned in 2027.","detailEn":"Launched in November 2024 by the Energy Commission (Suruhanjaya Tenaga), MyBeST is Malaysia's inaugural competitive solicitation for grid-connected battery storage: four 100 MW/400 MWh projects totalling 400 MW/1,600 MWh in Peninsular Malaysia, due for commissioning in 2027. On 19 December 2025 bidders were shortlisted from 28 applicants, each proposing a different battery supplier to benchmark diverse BESS configurations under local grid and climate conditions. The programme aims to cut reliance on fossil peaking plants and lower system costs in support of the National Energy Transition Roadmap.","progress":"2025年12月公布入围中标名单（28选4），各站目标2027年并网投运。"},
  {"id":6447,"name":"菲律宾南北通勤铁路（NSCR）","en":"North-South Commuter Railway (Clark-Calamba)","country":"菲律宾","region":"东南亚","cat":"transport","coord":[120.98,14.79],"cap":"147公里、36座车站（克拉克—马尼拉—卡兰巴）","inv":154,"invText":"8736亿比索（约154亿美元）","status":"在建","year":2028,"updated":"2025-07","owner":"菲律宾交通部（JICA/ADB融资）","flagship":true,"desc":"ADB在亚太最大融资基建项目：147公里、36站的吕宋南北通勤铁路，2028年部分通车。","detail":"南北通勤铁路(NSCR)自打拉省新克拉克城经马尼拉至内湖省卡兰巴，全长147公里、设36座车站，总投资8736亿比索（约154亿美元），由JICA（42%）、ADB（38%）与菲政府（20%）共同融资，是ADB迄今在亚太地区融资规模最大的基建项目。截至2025年6月，马洛洛斯—克拉克段(MCRP)完成42.4%；2025年7月政府批准2293.2亿比索的运营维护PPP，在克拉克、瓦伦苏埃拉、卡兰巴设车辆段。计划2028年分段投入运营，2032年全线开通，建成后克拉克机场至马尼拉车程缩至约1小时。","descEn":"ADB's largest-ever infrastructure financing in Asia-Pacific: a 147 km, 36-station commuter railway from Clark to Calamba on Luzon, partial operations from 2028.","detailEn":"The North-South Commuter Railway runs 147 km from New Clark City in Tarlac through Metro Manila to Calamba, Laguna with 36 stations. The PHP 873.6 billion (~$15.4 billion) cost is financed by JICA (42%), ADB (38%) and the Philippine government (20%) - ADB's largest infrastructure financing in Asia-Pacific to date. As of June 2025 the Malolos-Clark section was 42.4% complete, and in July 2025 a PHP 229.3 billion O&M PPP was approved with depots at Clark, Valenzuela and Calamba. Partial operations are targeted for 2028 and full service by 2032.","progress":"马洛洛斯—克拉克段2025年6月完成42.4%，2025年7月批准2293亿比索运维PPP，目标2028年部分通车。","route":[[120.62,15.31],[120.99,14.65],[121.17,14.21]]},
  {"id":6448,"name":"泰国三机场高速铁路","en":"Don Mueang-Suvarnabhumi-U-Tapao Three-Airport High-Speed Railway","country":"泰国","region":"东南亚","cat":"transport","coord":[100.78,13.4],"cap":"224公里，设计时速250公里（廊曼—素万那普—乌塔保）","inv":65,"invText":"2245亿泰铢（约65亿美元）","status":"规划","year":2026,"updated":"2026-01","owner":"泰国国家铁路局(SRT)/Asia Era One（正大集团牵头，50年特许）","flagship":false,"desc":"连接曼谷廊曼、素万那普与乌塔保三机场的224公里高铁，PPP合同修订后拟2026年签约开工。","detail":"三机场高铁连接曼谷廊曼、素万那普与东部经济走廊(EEC)乌塔保机场，全长约224公里、设计时速250公里，投资约2245亿泰铢（约65亿美元），由泰国国铁(SRT)授予正大集团牵头的Asia Era One财团50年特许经营。项目因融资与土地交付问题延宕五年未开工，SRT拟将机场快线(ARL)特许费重组并把政府支持款改为'边建边付'模式，计划2026年6月报内阁审议修订合同、7月签约、8月发出开工令(NTP)。该线是EEC旗舰基建，建成后乌塔保至曼谷车程约1小时。","descEn":"A 224 km, 250 km/h high-speed rail linking Bangkok's Don Mueang and Suvarnabhumi airports with U-Tapao in the EEC; revised PPP contract targeted for signing in 2026.","detailEn":"The Three-Airport High-Speed Rail links Don Mueang, Suvarnabhumi and U-Tapao airports over ~224 km at 250 km/h, costing about THB 224.5 billion (~$6.5 billion) under a 50-year concession granted by the State Railway of Thailand to Asia Era One, the CP Group-led consortium. Stalled for five years over financing and land handover, the project's PPP contract is being amended - restructuring Airport Rail Link concession payments and shifting state support to build-and-pay-as-you-go - with Cabinet review targeted for June 2026, signing in July 2026 and notice to proceed by August 2026. It is the EEC's flagship infrastructure scheme.","progress":"SRT计划2026年6月将修订后的PPP合同报内阁、7月签约、8月发开工令，项目延宕五年后寻求重启。","route":[[100.6,13.92],[100.75,13.69],[101.01,12.68]]},
  {"id":6449,"name":"印尼乐天LINE石化综合体","en":"Lotte Chemical Indonesia LINE Petrochemical Complex","country":"印度尼西亚","region":"东南亚","cat":"petro","coord":[106.02,-5.97],"cap":"乙烯100万吨/年、丙烯52万吨/年、聚丙烯35万吨/年、丁二烯14万吨/年、BTX 40万吨/年","inv":39.5,"invText":"39.5亿美元","status":"投运","year":2025,"updated":"2025-10","owner":"乐天化学(Lotte Chemical)/Lotte Chemical Titan","flagship":false,"desc":"韩国乐天化学投资39.5亿美元的万丹芝勒贡石化综合体，2025年10月全面商业投产。","detail":"乐天化学印尼新乙烯项目(LINE)位于万丹省芝勒贡，占地110公顷，总投资39.5亿美元，2022年开工、2025年5月机械竣工，2025年10月15日起全面商业生产。综合体年产乙烯100万吨、丙烯52万吨、聚丙烯35万吨、丁二烯14万吨、BTX 40万吨，是印尼数十年来最大石化外资项目之一，预计将印尼石化自给率从44%提升至约90%，每年创造约20亿美元经济价值，并强化乐天在东南亚的烯烃布局。","descEn":"Lotte Chemical's $3.95 billion petrochemical complex in Cilegon, Banten, in full commercial production since October 2025.","detailEn":"The LINE (Lotte Chemical Indonesia New Ethylene) complex sits on a 110-hectare site in Cilegon, Banten. Built from 2022 with a total investment of $3.95 billion, it was mechanically completed in May 2025 and has been in full commercial operation since 15 October 2025, producing 1 million t/y of ethylene, 520,000 t/y of propylene, 350,000 t/y of polypropylene, 140,000 t/y of butadiene and 400,000 t/y of BTX. One of Indonesia's largest petrochemical FDI projects, it is expected to lift petrochemical self-sufficiency from 44% toward 90% and generate about $2 billion in annual economic value.","progress":"2025年10月15日起全面商业投产，年产乙烯100万吨。"},
  {"id":6450,"name":"东帝汶大日升气田与Timor LNG开发","en":"Greater Sunrise Gas Field & Timor LNG Development","country":"东帝汶","region":"东南亚","cat":"petro","coord":[128.1,-9.45],"cap":"2C资源量5.3万亿立方英尺天然气+2.26亿桶凝析油；规划LNG约500万吨/年","inv":100,"invText":"约100亿美元（估，概念遴选阶段）","status":"规划","year":2032,"updated":"2025-11","owner":"Woodside(33.44%，作业者)/Timor Gap(56.56%)/大阪燃气(10%)","flagship":false,"desc":"Woodside与东帝汶推进将大日升气田气源引至东帝汶建设约500万吨/年LNG厂，最早2032年首船LNG。","detail":"大日升(Greater Sunrise)涵盖帝汶海Sunrise与Troubadour气田，2C资源量约5.3万亿立方英尺天然气和2.26亿桶凝析油，合资方为Woodside（作业者，33.44%）、Timor Gap（56.56%）与大阪燃气（10%）。2025年11月Woodside与东帝汶石油矿产资源部签署合作协议，推进'东帝汶LNG'概念成熟化——新建约500万吨/年LNG厂并配套国内供气与氦提取装置，2026年年中完成概念遴选，最早2032—2035年产首船LNG。","descEn":"Woodside and Timor-Leste are maturing a ~5 Mtpa Timor-based LNG concept for the Greater Sunrise fields, with concept selection targeted by mid-2026 and first LNG as early as 2032-2035.","detailEn":"Greater Sunrise comprises the Sunrise and Troubadour fields in the Timor Sea, holding 2C resources of about 5.3 Tcf of gas and 226 MMbbl of condensate, owned by Woodside (operator, 33.44%), Timor Gap (56.56%) and Osaka Gas (10%). In November 2025 Woodside signed a cooperation agreement with Timor-Leste's Ministry of Petroleum and Mineral Resources to mature a greenfield ~5 Mtpa Timor-based LNG concept (TLNG) with a domestic gas facility and helium extraction plant. Concept selection is targeted by mid-2026, and subject to investment decisions, first LNG could come as early as 2032-2035 - a nation-defining project for Timor-Leste.","progress":"2025年11月Woodside与东帝汶签署TLNG概念合作协议，目标2026年年中完成概念遴选。"},
  {"id":6451,"name":"柬埔寨波东沙哥LNG燃气电站","en":"Botum Sakor 900 MW LNG-to-Power Project","country":"柬埔寨","region":"东南亚","cat":"petro","coord":[103.2,10.98],"cap":"900MW（2×450MW）+LNG接收码头（20万立方米储罐）+36公里230kV送出线","inv":13.4,"invText":"13.4亿美元","status":"在建","year":2027,"updated":"2024-10","owner":"皇家集团(Royal Group Power)","flagship":false,"desc":"柬埔寨首个LNG接收与燃气发电一体化项目：国公省900MW电站，13.4亿美元，2027年分批投运。","detail":"2024年10月16日，皇家集团旗下Royal Group Power在国公省波东沙哥区为900MW天然气电站举行奠基仪式，矿产能源大臣Keo Rattanak出席。项目投资13.4亿美元，建设2台450MW燃机，第一台计划2027年4月、第二台2027年12月投运；配套建设可靠泊18.5万立方米LNG船的接收码头、20万立方米LNG储罐及36公里230kV送出线路，将使柬埔寨首次进口海运LNG并将天然气纳入电力结构，是该国迄今最大发电设施，缓解依赖进口电力的局面。","descEn":"Cambodia's first integrated LNG import and gas-fired power project: a 900 MW plant in Koh Kong by Royal Group, $1.34 billion, phased operation in 2027.","detailEn":"On 16 October 2024 Royal Group Power broke ground on a 900 MW natural gas power plant in Botum Sakor district, Koh Kong province, attended by Mines and Energy Minister Keo Rattanak. The $1.34 billion project features two 450 MW turbines - the first due online in April 2027 and the second in December 2027 - plus a jetty for 185,000 m3 LNG carriers, a 200,000 m3 LNG storage tank and a 36 km 230 kV transmission line. It would bring Cambodia its first seaborne LNG cargo and introduce gas into the power mix at utility scale, becoming the country's largest generation facility.","progress":"2024年10月奠基开工，首台450MW机组计划2027年4月投运。"},
  {"id":6452,"name":"马来西亚AT&S居林IC载板厂","en":"AT&S Kulim IC Substrate Plant","country":"马来西亚","region":"东南亚","cat":"ci","coord":[100.55,5.42],"cap":"高端IC载板（供AMD数据中心处理器）","inv":18,"invText":"一期17亿欧元（约18亿美元）","status":"投运","year":2025,"updated":"2025-05","owner":"奥特斯(AT&S)","flagship":false,"desc":"奥地利AT&S在吉打居林建成东南亚首座IC载板厂，一期投资17亿欧元，2025年5月量产供货AMD。","detail":"奥地利电路板与载板巨头AT&S在吉打州居林高科技园建设其史上最大单厂投资项目——东南亚首座IC载板制造厂，一期投资约17亿欧元（85亿林吉特），是马来西亚2021年最大外资项目之一。园区两年建成，2024年1月落成、2024年四季度投线，2025年5月正式启动大规模量产，截至当时已投入约50亿林吉特（10亿欧元）。工厂为AMD数据中心处理器供应高端IC载板，使马来西亚在AI芯片先进封装供应链中占据关键环节，并与英特尔、英飞凌等共同强化槟城—居林半导体走廊。","descEn":"AT&S's first Southeast Asian plant and SEA's first IC substrate factory, in Kulim Hi-Tech Park: EUR 1.7 billion Phase 1, high-volume production since May 2025 supplying AMD.","detailEn":"Austria's AT&S built Southeast Asia's first IC substrate manufacturing plant at Kulim Hi-Tech Park, Kedah - its largest single-plant investment ever, with a Phase 1 budget of ~EUR 1.7 billion (RM8.5 billion) and one of Malaysia's biggest FDI wins of 2021. The campus was completed in two years, inaugurated in January 2024, started production in Q4 2024 and reached high-volume manufacturing in May 2025, by which time about RM5 billion (EUR 1 billion) had been invested. It supplies high-end IC substrates for AMD's data-center processors, anchoring Malaysia in the advanced-packaging supply chain for AI chips.","progress":"2025年5月启动大规模量产，向AMD供应数据中心处理器IC载板。"},
  {"id":6453,"name":"印尼七丘地下铜金矿（Tujuh Bukit）","en":"Tujuh Bukit Underground Copper-Gold Project","country":"印度尼西亚","region":"东南亚","cat":"mining","coord":[114.03,-8.6],"cap":"达产年处理矿石2400万吨，年产铜超11.2万吨、黄金36.6万盎司","inv":12.5,"invText":"10—15亿美元（不含冶炼厂）","status":"规划","year":2030,"updated":"2025-07","owner":"默迪卡铜金(Merdeka Copper Gold)/PT Bumi Suksesindo","flagship":false,"desc":"默迪卡铜金在东爪哇外南梦开发的印尼最大在研铜矿之一，地下开采投资10—15亿美元。","detail":"七丘(Tujuh Bukit/Tumpang Pitu)铜金矿位于东爪哇外南梦县，由默迪卡铜金子公司PT Bumi Suksesindo运营，是印尼当前在研最大铜资源之一：探明+控制资源量提升至7.55亿吨（较此前增加71%），矿体位于地表以下逾百米。地下块崩开采可研(FS)目标2025年底完成，开发投资估算10—15亿美元（不含冶炼厂），达产后年处理矿石2400万吨，年产铜逾11.2万吨、黄金36.6万盎司，服务年限超30年，可使印尼铜产量提升10%—15%。现有氧化矿堆浸金矿已在产。","descEn":"One of Indonesia's largest copper developments: Merdeka Copper Gold's $1-1.5 billion underground block-cave project at Tujuh Bukit, East Java, with feasibility study due late 2025.","detailEn":"The Tujuh Bukit (Tumpang Pitu) copper-gold deposit in Banyuwangi, East Java, operated by Merdeka Copper Gold's PT Bumi Suksesindo, is among Indonesia's largest copper resources under development, with indicated resources raised 71% to 755 million tonnes. The underground block-cave feasibility study is targeted for completion by late 2025, with development capex estimated at $1-1.5 billion excluding a smelter. At full rates it would process 24 Mt of ore a year for over 112,000 t of copper and 366,000 oz of gold annually across a 30+ year life, lifting national copper output by 10-15%. An oxide gold heap-leach operation is already producing on site.","progress":"地下开采可行性研究目标2025年底完成，控制资源量增至7.55亿吨。"},
  {"id":6454,"name":"字节跳动马来西亚AI中心与柔佛数据中心","en":"ByteDance Malaysia AI Hub & Johor Data Centers","country":"马来西亚","region":"东南亚","cat":"datacenter","coord":[103.51,1.7],"cap":"区域AI中心+柔佛Sedenak数据中心扩建","inv":21,"invText":"约100亿林吉特（约21亿美元，另含15亿林吉特柔佛扩建）","status":"在建","year":2026,"updated":"2024-06","owner":"字节跳动(ByteDance System Sdn Bhd)","flagship":false,"desc":"字节跳动拟投约100亿林吉特把马来西亚打造为区域AI中心，并追加15亿林吉特扩建柔佛数据中心。","detail":"2024年6月，马来西亚投贸部长扎夫鲁会见TikTok副总裁后宣布，字节跳动拟投资约100亿林吉特（约21亿美元）在马来西亚发展人工智能，将其打造为东南亚AI中心，并追加15亿林吉特扩建柔佛州数据中心设施。字节跳动已通过子公司ByteDance System Sdn Bhd在柔佛古来Sedenak科技园运营数据中心，承载TikTok等业务的区域算力。该投资与微软、谷歌、英伟达—YTL等共同推动柔佛成为东南亚数据中心新枢纽，柔佛州数据中心规划容量已迈向5800MW。","descEn":"ByteDance plans roughly RM10 billion (~$2.1 billion) to make Malaysia a regional AI hub, plus RM1.5 billion to expand its Johor data center footprint at Sedenak Tech Park.","detailEn":"In June 2024 Malaysia's investment minister Tengku Zafrul announced, after meeting TikTok's vice president, that ByteDance would invest about RM10 billion (~$2.1 billion) in AI development to position Malaysia as Southeast Asia's AI hub, with a further RM1.5 billion to expand its Johor data center facilities. ByteDance already operates a data center at Sedenak Tech Park in Kulai through ByteDance System Sdn Bhd, hosting regional compute for TikTok. Alongside Microsoft, Google and the YTL-NVIDIA campus, the investment cements Johor's rise toward a planned 5,800 MW of data-center capacity.","progress":"Sedenak基地扩建推进中，柔佛规划数据中心容量向5800MW扩张。"},
  {"id":6455,"name":"菲律宾首座SMR核电项目（Meralco）","en":"Philippines First SMR Project (Meralco)","country":"菲律宾","region":"东南亚","cat":"nuclear","coord":[121,14.6],"cap":"首期SMR数百MW级（选型中）","inv":20,"invText":"约20亿美元（估）；美国USTDA已资助270万美元路线图研究","status":"规划","year":2026,"updated":"2026-03","owner":"Meralco PowerGen（MGEN）","flagship":false,"desc":"菲律宾迈向首核：2025年设独立核监管机构PhilATOM，2026年美方资助Meralco SMR选型，韩水原签合作备忘录。","detail":"菲律宾正推进该国首座核电站建设：2025年9月马科斯总统签署《国家核能安全法》（RA 12305）设立独立监管机构PhilATOM，能源部计划2026年起受理核电许可申请。2026年2月美国贸发署（USTDA）向Meralco旗下MGEN提供270万美元技术援助，评估美国先进SMR堆型并编制菲首座SMR实施路线图；2026年3月韩水原核电（KHNP）、韩国进出口银行与Meralco签署涵盖技术转让、人才培养、可行性研究与融资支持的合作备忘录。巴丹老厂修复亦在评估之列。","descEn":"The Philippines moves toward its first nuclear plant: regulator PhilATOM created in 2025, a USTDA-funded SMR roadmap for Meralco in February 2026, and a KHNP financing/technology MoU in March 2026.","detailEn":"The Philippines is advancing its first nuclear power plant. President Marcos signed the National Nuclear Energy Safety Act (RA 12305) in September 2025, creating the independent regulator PhilATOM, with license applications to be accepted from 2026. In February 2026 USTDA granted USD 2.7 m to Meralco PowerGen to assess US SMR designs and draft a roadmap for the country's first SMR; in March 2026 KHNP, Korea Eximbank and Meralco signed an MoU covering technology transfer, workforce, feasibility studies and financing. Rehabilitating the mothballed Bataan plant is also under study.","progress":"2026年2月获USTDA资助开展SMR选型，3月与KHNP签合作备忘录。"},
  {"id":6456,"name":"越南宁顺二号核电站","en":"Ninh Thuan 2 Nuclear Power Plant (Vietnam)","country":"越南","region":"东南亚","cat":"nuclear","coord":[109.18,11.72],"cap":"规划2台大型机组（约2×1000~1200MW）","inv":110,"invText":"约110亿美元（估）","status":"规划","year":2035,"updated":"2026-01","owner":"越南国家油气集团（PetroVietnam/PVN）","flagship":false,"desc":"越南重启核电的第二厂址：2025年2月指定PVN为业主，日本2026年初退出后法韩美竞逐，目标2035年投运。","detail":"越南2024年11月国会通过第174号决议重启宁顺核电计划后，2025年2月总理指定越南电力集团（EVN）和越南油气集团（PVN）分别担任宁顺一号、二号业主。宁顺二号位于宁海县永海乡，规划两台大型机组、目标2035年前投运。原合作方日本因工期过紧于2025年11月决定、2026年1月正式退出，法国、韩国、美国表达接续意向；2025年8月韩国电力公社（KEPCO）已与PVN签署人才培养合作备忘录。投资估算约110亿美元。","descEn":"Vietnam's second revived nuclear site: PetroVietnam was named investor in February 2025; after Japan's early-2026 exit, France, Korea and the USA are vying, with operation targeted by 2035.","detailEn":"After Vietnam's National Assembly passed Resolution 174 in November 2024 reviving the Ninh Thuan nuclear program, the PM in February 2025 assigned EVN and PetroVietnam as investors for Ninh Thuan 1 and 2 respectively. Ninh Thuan 2 at Vinh Hai is planned for two large units targeting operation by 2035. Japan, the original partner, withdrew in January 2026 citing the tight schedule; France, South Korea and the USA have expressed interest, and KEPCO signed a workforce MoU with PVN in August 2025. Investment is estimated at ~USD 11 bn.","progress":"2025年2月定PVN为业主；日本2026年1月退出，合作方重新遴选中。"},
  {"id":6457,"name":"印尼廖内—新加坡绿电海底电缆（Singa Renewables）","en":"Indonesia Riau-Singapore Green Power Subsea Cable (Singa Renewables)","country":"印度尼西亚—新加坡","region":"东南亚","cat":"grid","coord":[104.2,0.9],"cap":"1GW 输电（配套大型光伏+储能）","inv":30,"invText":"约30亿美元（估，含电源侧）","status":"规划","year":2029,"updated":"2026-06","owner":"TotalEnergies/RGE（Singa Renewables）","desc":"道达尔与RGE合资的Singa Renewables获新加坡EMA有条件许可，从印尼廖内省经海底电缆向新加坡输送1GW低碳电力。","detail":"2025年5月28日，在法国总统马克龙与印尼总统普拉博沃见证下，道达尔能源与RGE在雅加达签署共同投资协议，由对半合资的Singa Renewables公司在印尼廖内省开发\"光伏+电池储能+海底电缆\"一体化项目，并获得新加坡能源市场管理局（EMA）1GW低碳电力进口有条件许可（Conditional Licence）。双方还与新加坡能源互联公司（SGEI）签署谅解备忘录，共同开发跨境海底互联电缆。截至2025年10月，新加坡已向11个项目发放共8.35GW进口许可，本项目是印尼方向6个升级为有条件许可的项目之一，目标2029年前后投运。","descEn":"Singa Renewables, a TotalEnergies-RGE 50/50 JV, won an EMA Conditional Licence to import 1 GW of low-carbon power from Riau, Indonesia to Singapore via a subsea cable, backed by a hybrid solar + BESS plant.","detailEn":"Signed in Jakarta on 28 May 2025 before Presidents Macron and Prabowo, the co-investment agreement covers a hybrid solar farm + battery storage + subsea cable scheme in Riau Province. Singapore's EMA granted Singa Renewables a Conditional Licence for 1 GW of imports, and an MoU with Singapore Energy Interconnections (SGEI) covers joint development of the subsea interconnector. It is one of six Indonesian projects upgraded to Conditional Licences among 8.35 GW of approved imports, targeting operation around 2029.","progress":"2025年5月签署共同投资协议并获EMA有条件许可；与SGEI签署海缆共同开发备忘录，推进海底互联工程设计。","route":[[103,0.4],[104.2,0.9],[103.85,1.29]],"flagship":false},
  {"id":6458,"name":"菲律宾甲米地PLDT 100MW超大规模数据中心","en":"PLDT Trece Martires 100MW Hyperscale Data Center, Cavite","country":"菲律宾","region":"东南亚","cat":"datacenter","coord":[120.87,14.28],"cap":"100 MW（分五期、每期20 MW）","inv":7,"invText":"400亿比索（约7亿美元）","status":"规划","year":2028,"updated":"2026-06","owner":"PLDT（ePLDT）","desc":"PLDT计划在甲米地省特雷塞马蒂雷斯建设其第12座、容量100 MW的菲律宾最大数据中心，2026年开工、2028年建成。","detail":"菲律宾电信巨头PLDT宣布建设其第12座、也是最大的一座超大规模数据中心：选址甲米地省特雷塞马蒂雷斯（Trece Martires），IT容量最高100 MW，投资约400亿比索，分五期、每期20 MW建设，2026年开工、2028年建成。该项目在VITRO圣罗莎AI超算中心之后进一步扩大PLDT的AI算力版图，呼应菲律宾数字化部'18 GW数据中心扩张、领跑东盟'的远景规划，瞄准超大规模云商与AI企业客户。","descEn":"PLDT plans its 12th and largest data center — up to 100 MW at Trece Martires, Cavite — with construction from 2026 and completion by 2028.","detailEn":"Philippine telecom giant PLDT announced its 12th and largest hyperscale data center at Trece Martires, Cavite: up to 100 MW of IT capacity costing about PHP 40 billion, built in five 20 MW phases with construction starting 2026 and completion by 2028. Following its VITRO Santa Rosa AI supercomputing facility, the project expands PLDT's AI compute footprint and aligns with the DICT's vision of an 18 GW data center build-out to lead ASEAN, targeting hyperscalers and AI enterprises.","progress":"2026年敲定设计蓝图并开工，分五期建设，目标2028年投运。","flagship":false},
  {"id":6459,"name":"胡志明市地铁1号线（滨城—仙泉）","en":"Ho Chi Minh City Metro Line 1 (Ben Thanh-Suoi Tien)","country":"越南","region":"东南亚","cat":"transport","coord":[106.75,10.82],"cap":"19.7公里 / 14座车站（3座地下）","inv":17,"invText":"总投资43.7万亿越南盾（约17亿美元）","status":"投运","year":2024,"updated":"2026-06","owner":"胡志明市城铁管理局（MAUR）·日本ODA","desc":"越南第一大城市首条地铁，滨城—仙泉线全长19.7公里，历时12年建设后于2024年12月22日开通，开通4天客流近40万人次。","detail":"胡志明市地铁1号线自市中心滨城市场至东部仙泉主题公园，全长19.7公里，设14座车站（含滨城、歌剧院、巴顺3座地下站），采用日本车辆与信号系统，由日本ODA贷款支持、总投资43.7万亿越南盾（约17亿美元）。项目2012年开工、多次延期，2024年12月22日正式开通，是胡志明市首条地铁，开通前4天即运送39.5万人次。该线为后续2号线等线网建设提供了运营范本，也是日本在东南亚轨道交通的标志性交付。","descEn":"Vietnam's largest city opened its first metro on 22 December 2024: the 19.7-km, 14-station Ben Thanh-Suoi Tien line, built over 12 years with Japanese ODA at a cost of VND 43.7 trillion (USD 1.7 billion).","detailEn":"HCMC Metro Line 1 runs 19.7 km from Ben Thanh market to Suoi Tien park with 14 stations, three of them underground (Ben Thanh, Opera House, Ba Son). Financed largely by Japanese ODA at VND 43.7 trillion (about USD 1.7 billion) with Japanese rolling stock and systems, it broke ground in 2012 and finally opened on 22 December 2024 as the city's first metro, carrying 395,000 riders in its first four days and setting the template for Line 2 and the wider network.","progress":"2024-12：12月22日正式开通运营，首4天客流39.5万人次；2025年起进入常态化运营并衔接2号线前期工程。","route":[[106.698,10.77],[106.722,10.788],[106.756,10.801],[106.809,10.875]],"flagship":false},
  {"id":6460,"name":"巴丹—甲米地跨海大桥","en":"Bataan-Cavite Interlink Bridge","country":"菲律宾","region":"东南亚","cat":"transport","coord":[120.65,14.4],"cap":"全长32.15公里（海上段约26公里）跨马尼拉湾通道","inv":39,"invText":"总投资39.1亿美元（亚行21亿+亚投行11.4亿美元贷款）","status":"在建","year":2030,"updated":"2026-06","owner":"菲律宾公共工程与公路部（DPWH）","desc":"横跨马尼拉湾口的32公里跨海通道，建成后为全球最长跨海桥之一，巴丹—甲米地车程由5小时缩至45分钟；总投资39.1亿美元，目标2030年完工。","detail":"巴丹—甲米地跨海大桥自吕宋岛巴丹省马里韦莱斯跨越马尼拉湾口至甲米地省纳伊克，全长32.15公里、其中约26公里位于海上，建成后将是全球最长跨海桥梁之一，使绕行马尼拉的5小时车程缩短至45分钟，重塑马尼拉湾两岸产业布局。项目总投资约39.1亿美元，采用多批次融资：亚洲开发银行提供21亿美元、亚投行联合融资11.4亿美元、菲政府出资约6.6亿美元。2025年9月一期土建8家国际承包商递交标书，马科斯总统确认2025年内开工，计划2030年3月建成，是菲律宾“加快建设”旗舰计划的最大单体工程。","descEn":"A 32.15-km crossing of Manila Bay — one of the world's longest sea bridges — cutting Bataan-Cavite travel from five hours to 45 minutes, financed by USD 3.91 billion from ADB, AIIB and the Philippine government for completion by 2030.","detailEn":"The Bataan-Cavite Interlink Bridge spans 32.15 km from Mariveles in Bataan across the mouth of Manila Bay to Naic in Cavite, with about 26 km over water — set to rank among the world's longest marine bridges and to shrink the five-hour drive around Manila to 45 minutes. The USD 3.91 billion cost is funded by a USD 2.1 billion ADB multi-tranche facility, USD 1.14 billion from AIIB and about USD 664 million from Manila. Eight international contractors bid for phase 1 in September 2025, President Marcos confirmed a 2025 construction start, and completion is targeted for March 2030.","progress":"2025-09：一期土建8家国际承包商投标，马科斯总统确认年内开工；亚行/亚投行贷款到位，目标2030年3月建成。","route":[[120.49,14.435],[120.62,14.39],[120.76,14.32]],"flagship":false},
  {"id":6461,"name":"老挝季风（Monsoon）600MW风电场","en":"Monsoon Wind Power Project","country":"老挝","region":"东南亚","cat":"renewable","coord":[107.25,15.42],"cap":"600MW（133台风机，年发电约17亿千瓦时）","inv":9.5,"invText":"约9.5亿美元","status":"投运","year":2025,"updated":"2026-06","owner":"Impact Energy Asia/ACEN/三菱商事","desc":"东盟最大陆上风电场、老挝首个风电项目，600MW全部跨境送电越南。","detail":"季风风电场位于老挝南部色贡省达旺县与阿速坡省桑赛县交界高原，装机600MW、共133台风机，是老挝首个风电项目，也是东盟目前最大的陆上风电场。项目2023年4月开工，2025年8月22日实现商业运行，成为亚洲首个跨境可再生能源项目：电力经71公里500千伏专用输电线（老挝段27公里、越南段44公里）送入越南Thanh My变电站，年发电约17亿千瓦时，25年运营期可减排二氧化碳超3250万吨。亚开行牵头多边融资，项目创造逾1600个就业岗位并设立每年110万美元的社区发展基金。","descEn":"ASEAN's largest onshore wind farm and Laos' first wind project; all 600 MW exported cross-border to Vietnam.","detailEn":"Located on the Dak Cheung (Sekong) / Sanxay (Attapeu) plateau in southern Laos, the 600 MW Monsoon wind farm comprises 133 turbines and is Laos' first wind project and ASEAN's largest onshore wind farm. Construction began in April 2023 and commercial operation was achieved on 22 August 2025, making it Asia's first cross-border renewable project: power flows via a 71 km 500 kV line to Vietnam's Thanh My substation, generating about 1.7 TWh a year. ADB led the multilateral financing package.","progress":"2025年8月22日实现商业运行（COD），经71公里500kV跨境输电线向越南送电，年发电约17亿千瓦时；2025年11月举行投运庆典。","flagship":false},

  // ===== 南亚（6470-6490）=====
  {"id":6470,"name":"上锡昂多功能水电项目","en":"Siang Upper Multipurpose Project","country":"印度","region":"南亚","cat":"renewable","coord":[94.9,28.4],"cap":"11000 MW（拟建，库容90亿立方米）","inv":135,"invText":"≈135亿美元（₹1.13万亿卢比，估）","status":"规划","year":2030,"updated":"2025-07","owner":"NHPC（印度国家水电公司）/ NEEPCO","flagship":true,"desc":"印度在阿鲁纳恰尔邦锡昂河上规划的1.1万MW巨型水电站，建成将是南亚次大陆最大水电工程。","detail":"上锡昂多功能项目（SUMP）位于阿鲁纳恰尔邦上锡昂地区，规划装机11000MW，水库库容约90亿立方米，估算造价1.13万亿卢比（约135亿美元），由NHPC与NEEPCO联合推进。项目除发电外还承担防洪与维持雅鲁藏布江下游全年径流的战略功能，被视为对上游中国墨脱水电工程的对冲。2025年项目进入预可研（PFR）阶段：Riew村98户签署谅解备忘录支持勘测，但流域内仍存在部分村落反对，征地与环评为后续主要变量。","descEn":"India's planned 11,000 MW mega hydropower dam on the Siang river in Arunachal Pradesh — the largest hydro project ever planned in the subcontinent.","detailEn":"The Siang Upper Multipurpose Project (SUMP) in Upper Siang, Arunachal Pradesh, is planned at 11,000 MW with a 9 billion m3 reservoir and an estimated cost of Rs 1.13 lakh crore (~$13.5bn), jointly developed by NHPC and NEEPCO. Beyond power generation it is framed as flood mitigation and a strategic counter to China's Medog dam upstream. In 2025 the project entered the pre-feasibility stage, with Riew village signing an MoU backing surveys amid continuing local opposition elsewhere in the valley.","progress":"2025年7月阿邦首席部长检视项目；Riew村98户签署备忘录支持预可研勘测，PFR编制启动。"},
  {"id":6471,"name":"布迪甘达基水电站","en":"Budhi Gandaki Hydroelectric Project","country":"尼泊尔","region":"南亚","cat":"renewable","coord":[84.8,27.9],"cap":"1200 MW（6×200MW，263米高双曲拱坝）","inv":27.7,"invText":"≈27.7亿美元（基础造价，尼政府自主投资）","status":"规划","year":2028,"updated":"2026-02","owner":"Budhigandaki Jalbidhyut Company（尼泊尔政府全资）","flagship":false,"desc":"尼泊尔最大的水库式水电项目：1200MW、263米高拱坝，2026年政府批准投资模式，拟2028年开工。","detail":"布迪甘达基水电站位于廓尔喀与达丁县交界的布迪甘达基河，为尼泊尔最大蓄水式水电工程：263米高双曲拱坝、6台200MW法兰西斯机组、两回400kV外送线路，基础造价27.7亿美元（约4000亿卢比），工期8年。项目酝酿数十年后于2025-2026年迎来转折：能源部长加辛推动敲定投资模式，2026年2月内阁批准由政府主导的融资框架；征地已完成约90%，补偿发放426.5亿卢比，预计2028年开工。","descEn":"Nepal's largest storage-type hydropower project: 1,200 MW with a 263 m double-arch dam; the government approved its investment modality in 2026, targeting construction from 2028.","detailEn":"The Budhi Gandaki project on the Budhi Gandaki river between Gorkha and Dhading is Nepal's largest storage hydro scheme: a 263 m double-curvature arch dam, six 200 MW Francis units and two 400 kV transmission lines, with a base cost of $2.77bn and an 8-year build. After decades of delay, the cabinet approved the government-led investment modality in February 2026; land acquisition is ~90% complete with Rs 42.65bn compensation paid, and construction is expected to start around 2028.","progress":"2026年2月尼内阁批准投资模式，征地完成约90%，项目正式迈向2028年开工。"},
  {"id":6472,"name":"普那桑楚二期水电站","en":"Punatsangchhu-II Hydroelectric Project","country":"不丹","region":"南亚","cat":"renewable","coord":[89.9,27.35],"cap":"1020 MW（6×170MW径流式）","inv":10,"invText":"≈10亿美元（印度政府30%赠款+70%贷款，造价随工期上调，估）","status":"投运","year":2025,"updated":"2025-11","owner":"普那桑楚二期水电管理局（印度-不丹政府间项目）","flagship":false,"desc":"印度援建的不丹最大新增电源：1020MW径流式水电站2025年全部并网，使不丹发电能力提升约40%。","detail":"普那桑楚二期水电站位于不丹旺杜波德朗宗的普那桑楚河，装机1020MW（6×170MW），为印度政府全额出资的政府间项目（30%赠款+70%贷款）。六台机组于2024年12月至2025年8月间相继并网，2025年11月莫迪与不丹国王共同为项目落成揭幕，使不丹全国发电能力一举提升近40%，电力经跨境通道售往印度，是印不清洁能源合作的旗舰工程。投运首年已向不丹电网输送逾13亿度电。","descEn":"Bhutan's largest new power source, built with Indian funding: the 1,020 MW run-of-river plant was fully commissioned in 2025, lifting Bhutan's generation capacity by ~40%.","detailEn":"The Punatsangchhu-II plant on the Punatsangchhu river in Wangdue Phodrang has six 170 MW units (1,020 MW total), fully funded by the Government of India (30% grant, 70% loan). All six units were synchronized between December 2024 and August 2025, and PM Modi and the Bhutanese King inaugurated the project in November 2025. It raises Bhutan's generation capacity by nearly 40%, with surplus power exported to India — the flagship of India-Bhutan clean-energy cooperation.","progress":"2025年8月末台机组并网、11月印不两国领导人共同揭幕，项目全面投运并已发电逾13亿度。"},
  {"id":6473,"name":"法蒂克查里 200MW 光伏电站","en":"Fatikchhari 200 MW Solar Power Project","country":"孟加拉国","region":"南亚","cat":"renewable","coord":[91.78,22.69],"cap":"200 MW（并网于132/33kV法蒂克查里变电站）","inv":1.5,"invText":"≈1.5亿美元（估）","status":"在建","year":2027,"updated":"2026-01","owner":"Confidence Enterprises（孟加拉Confidence集团）","flagship":false,"desc":"孟加拉临时政府重启光伏招标后的最大单体项目：吉大港法蒂克查里200MW电站，2026年1月签署PPA。","detail":"法蒂克查里光伏电站是孟加拉国临时政府重启可再生能源采购后签约的最大单体项目。2024年8月临时政府上台后取消了34座、共5681MW的未招标电站审批，开发商接受下调电价后，11个光伏项目于2025年12月恢复批准；2026年1月底BPDB与七个项目（合计523MW）签署20年购电协议，其中Confidence Enterprises开发的200MW电站接入吉大港法蒂克查里132/33kV变电站，规模居首，投资估算约1.5亿美元，标志着孟加拉公用事业级光伏在政局变动后重新启动。","descEn":"The largest single project in Bangladesh's relaunched solar procurement: a 200 MW plant at Fatikchhari, Chittagong, with its PPA signed in January 2026.","detailEn":"Fatikchhari Solar is the biggest single award since Bangladesh's interim government relaunched utility-scale renewables procurement. After canceling 5,681 MW of unsolicited plants in 2024, the government reinstated 11 solar projects in December 2025 at reduced tariffs; in January 2026 BPDB signed 20-year PPAs with seven projects totaling 523 MW. Confidence Enterprises' 200 MW plant, connecting to the Fatikchhari 132/33 kV substation in Chittagong, is the largest of the batch, with investment estimated around $150m.","progress":"2026年1月底BPDB与含本项目在内的7个光伏项目（523MW）正式签署20年购电协议。"},
  {"id":6474,"name":"特赫里抽水蓄能电站","en":"Tehri Pumped Storage Plant","country":"印度","region":"南亚","cat":"storage","coord":[78.48,30.38],"cap":"1000 MW（4×250MW变速机组）","inv":7.3,"invText":"≈7.3亿美元（约606亿卢比，估）","status":"投运","year":2026,"updated":"2026-04","owner":"THDC India（印度国家电力NTPC子公司）","flagship":false,"desc":"印度首座变速抽水蓄能电站：特赫里大坝1000MW抽蓄四台机组2025-2026年全部投入商运。","detail":"特赫里抽水蓄能电站位于北阿坎德邦特赫里水电综合体，利用特赫里水库为上库、科泰什瓦尔水库为下库，装机1000MW（4×250MW），是印度首座采用变速机组的抽蓄电站，也是央企实施的最大抽蓄项目。四台机组分别于2025年6月、7月、12月和2026年4月相继宣布商业运行，使特赫里水电综合体总装机达2400MW，成为北印电网重要的调峰与新能源消纳枢纽，投资约606亿卢比。","descEn":"India's first variable-speed pumped storage plant: all four 250 MW units at the Tehri dam complex entered commercial operation between 2025 and 2026.","detailEn":"The 1,000 MW Tehri PSP (4x250 MW) in Uttarakhand uses the Tehri reservoir as upper and Koteshwar as lower reservoir. It is India's first variable-speed pumped storage facility and the largest built by a central PSU. Units I-IV were declared commercially operational in June 2025, July 2025, December 2025 and April 2026 respectively, taking the Tehri hydro complex to 2,400 MW and making it a key peaking and renewables-balancing hub for the northern grid, at a cost of roughly Rs 6,000 crore.","progress":"2026年4月第四台机组商运，1000MW全容量投运，特赫里水电综合体总装机达2400MW。"},
  {"id":6475,"name":"孟买库杜斯—阿雷 1000MW 城市直流入城工程","en":"Kudus-Aarey 1000 MW HVDC Link (Mumbai)","country":"印度","region":"南亚","cat":"grid","coord":[72.88,19.16],"cap":"1000 MW VSC柔性直流，30km架空+50km地下电缆","inv":8.4,"invText":"≈8.4亿美元（约700亿卢比，估）","status":"投运","year":2026,"updated":"2026-04","owner":"阿达尼能源方案（AEMIL）","flagship":false,"desc":"全球最大城市直流入城工程之一：阿达尼建成库杜斯—阿雷1000MW柔直通道，为孟买引入域外绿电。","detail":"为弥补2020年10月孟买大停电暴露的供电短板，阿达尼能源方案子公司AEMIL建设库杜斯—阿雷1000MW高压直流输电工程，2026年4月投运。线路含30公里架空线与50公里地下电缆走廊，采用VSC柔性直流技术并建成全球首座紧凑型直流换流站，可在高密度城区内精准控制潮流、提升电压稳定性。工程使孟买外受电能力大幅提升，是全球规模最大的城市直流入城工程之一，投资约700亿卢比。","descEn":"One of the world's largest urban HVDC infeeds: Adani's 1,000 MW VSC link from Kudus to Aarey brings external clean power into Mumbai.","detailEn":"Conceived after Mumbai's October 2020 blackout, the Kudus-Aarey 1,000 MW HVDC link built by Adani Energy Solutions' subsidiary AEMIL was commissioned in April 2026. It combines a 30 km overhead line with a 50 km underground cable corridor, uses voltage-source-converter technology and includes the world's first compact HVDC substation. The link sharply raises Mumbai's import capability and grid resilience, ranking among the largest urban HVDC infeeds globally, at a cost of about Rs 7,000 crore.","progress":"2026年4月全线投运，孟买都会区新增1000MW外受电通道。","route":[[72.93,19.47],[72.88,19.16]]},
  {"id":6476,"name":"CASA-1000 中亚—南亚输电工程","en":"CASA-1000 Central Asia-South Asia Transmission Project","country":"阿富汗—巴基斯坦","region":"南亚","cat":"grid","coord":[69.2,34.5],"cap":"1300 MW 输送能力，±500kV直流，跨境线路逾1200km（阿富汗段575km）","inv":12,"invText":"≈12亿美元（世界银行牵头融资）","status":"在建","year":2027,"updated":"2025-12","owner":"四国国家电网（NTDC/DABS/Barqi Tojik等），世界银行牵头","flagship":false,"desc":"连接吉尔吉斯-塔吉克水电与阿富汗、巴基斯坦的12亿美元跨境直流工程，阿富汗段2024年复工。","detail":"CASA-1000是把吉尔吉斯斯坦和塔吉克斯坦夏季富余水电送往阿富汗、巴基斯坦的跨区域输电工程，总投资约12亿美元，由世界银行牵头融资。2025年4月吉塔间485公里500kV交流线与直流换流站完工；因2021年阿富汗变局停摆的575公里阿富汗段于2024年复工，截至2025年12月已完成铁塔310基（23%）、放线18.2公里，计划2026年底建成、次年全系统带电，巴基斯坦端换流站位于瑙谢拉，输送能力1300MW。","descEn":"A $1.2bn cross-border HVDC scheme linking Kyrgyz and Tajik hydropower to Afghanistan and Pakistan; the Afghan section resumed construction in 2024.","detailEn":"CASA-1000 exports summer hydropower surpluses from Kyrgyzstan and Tajikistan to Afghanistan and Pakistan, with ~$1.2bn financing led by the World Bank. The 485 km 500 kV AC line and HVDC converter stations between Kyrgyzstan and Tajikistan were completed by April 2025. Afghanistan's 575 km section, halted after August 2021, resumed in 2024; by December 2025, 310 towers (23%) and 18.2 km of stringing were done. Completion is targeted for late 2026, with full 1,300 MW system energization the following year via the Nowshera converter station in Pakistan.","progress":"吉塔段2025年4月完工；阿富汗段复工后至2025年12月完成铁塔23%，全系统拟2027年带电。","route":[[69.1,38.1],[69.2,34.5],[70.45,34.43],[71.98,34.02]]},
  {"id":6477,"name":"阿塔尔大桥（孟买跨海大桥 MTHL）","en":"Atal Setu / Mumbai Trans Harbour Link","country":"印度","region":"南亚","cat":"transport","coord":[72.95,18.99],"cap":"21.8km六车道跨海通道（海上16.5km），日通行能力7万辆","inv":21,"invText":"≈21亿美元（约1784亿卢比）","status":"投运","year":2024,"updated":"2024-01","owner":"MMRDA（L&T-IHI、大林组等承建，JICA贷款）","flagship":false,"desc":"印度最长跨海大桥：21.8公里的孟买—新孟买阿塔尔大桥2024年1月通车，造价约21亿美元。","detail":"阿塔尔大桥（孟买跨海通道MTHL）自南孟买休里跨越塔那湾至新孟买奇尔莱，全长21.8公里（海上段16.5公里）、双向六车道，是印度最长桥梁与最长跨海大桥，造价1784.3亿卢比（约21亿美元），由JICA提供主要贷款、L&T-IHI联合体等承建。2024年1月12日莫迪揭幕通车，孟买至新孟买车程从逾2小时缩至约20分钟，日设计通行7万辆，并与新孟买国际机场、孟买—浦那走廊形成联动，是孟买都会区扩容的骨干工程。","descEn":"India's longest sea bridge: the 21.8 km Atal Setu linking Mumbai and Navi Mumbai opened in January 2024 at a cost of about $2.1bn.","detailEn":"Atal Setu (Mumbai Trans Harbour Link) runs 21.8 km from Sewri in South Mumbai across Thane Creek to Chirle in Navi Mumbai, with 16.5 km over the sea and six lanes. Built for Rs 17,843 crore (~$2.1bn) with JICA loans and contractors including the L&T-IHI consortium, it is India's longest bridge and longest sea bridge. PM Modi opened it on 12 January 2024; it cuts the Mumbai-Navi Mumbai journey from over two hours to ~20 minutes, handles up to 70,000 vehicles/day and anchors the metro region's eastward expansion alongside the new Navi Mumbai airport.","progress":"2024年1月12日通车，已成为孟买—新孟买间主干通道，与2025年投运的新孟买机场联动。"},
  {"id":6478,"name":"马尔代夫维拉纳国际机场扩建","en":"Velana International Airport Expansion (Maldives)","country":"马尔代夫","region":"南亚","cat":"transport","coord":[73.53,4.19],"cap":"新一号航站楼7.8万㎡，年旅客吞吐能力150万→750万人次","inv":10,"invText":"≈10亿美元（新航站楼5.85亿美元）","status":"投运","year":2025,"updated":"2025-07","owner":"马尔代夫机场公司（MACL），沙特Binladin集团承建","flagship":false,"desc":"马尔代夫史上最大基建：10亿美元维拉纳机场扩建的新一号航站楼2025年7月启用，吞吐能力升至750万人次。","detail":"维拉纳国际机场扩建是马尔代夫最大的基础设施工程，总投资约10亿美元，其中新一号航站楼造价5.85亿美元，由阿布扎比、沙特、科威特和OPEC基金等提供优惠贷款、沙特Binladin集团承建。新航站楼建筑面积7.8万平方米，为马尔代夫最大建筑，2025年7月26日（独立60周年）启用，机场年旅客处理能力从150万人次跃升至750万人次；配套新跑道、海上飞机码头与货运设施已先期投用，为旅游业扩容奠定枢纽基础。","descEn":"The Maldives' biggest infrastructure programme: the $1bn Velana airport expansion opened its new Terminal 1 in July 2025, lifting capacity to 7.5 million passengers a year.","detailEn":"The Velana International Airport expansion is the Maldives' largest-ever infrastructure undertaking, worth about $1bn in total, including a $585m new Terminal 1 built by Saudi Binladin Group with concessional loans from Abu Dhabi, Saudi Arabia, Kuwait and the OPEC Fund. The 78,000 m2 terminal — the country's largest building — opened on 26 July 2025, the 60th Independence Day, raising annual passenger capacity from 1.5 to 7.5 million; a new runway, seaplane terminal and cargo facilities were commissioned earlier.","progress":"新一号航站楼2025年7月26日正式启用，机场年吞吐能力提升至750万人次。"},
  {"id":6479,"name":"ONGC KG-DWN-98/2 深水油气开发","en":"ONGC KG-DWN-98/2 Cluster-2 Deepwater Development","country":"印度","region":"南亚","cat":"petro","coord":[82.5,16.3],"cap":"峰值原油4.5万桶/日、天然气1000万方/日以上","inv":50.7,"invText":"≈50.7亿美元（开发资本支出）","status":"投运","year":2024,"updated":"2024-06","owner":"ONGC（印度石油天然气公司）","flagship":false,"desc":"印度国油50亿美元深水旗舰：孟加拉湾KG-98/2区块Cluster-2于2024年1月产出首油。","detail":"KG-DWN-98/2区块位于安得拉邦海岸约35公里外的孟加拉湾，水深300-3200米，是ONGC迄今最具挑战的深水开发项目，Cluster-2阶段资本支出约50.7亿美元。项目经多年延期后于2024年1月产出首油，依托FPSO『Armada Sterling V』生产，设计峰值原油4.5万桶/日、天然气逾1000万立方米/日，全生命周期可采原油约2352万吨、天然气507亿方，是印度提升本土油气产量、降低进口依存度的关键工程。","descEn":"ONGC's $5bn deepwater flagship: Cluster-2 of the KG-DWN-98/2 block in the Bay of Bengal achieved first oil in January 2024.","detailEn":"Block KG-DWN-98/2 lies ~35 km off the Andhra Pradesh coast in 300-3,200 m of water and is ONGC's most challenging deepwater development, with Cluster-2 capex of about $5.07bn. After years of delay, first oil flowed in January 2024 through the FPSO Armada Sterling V, with design peaks of 45,000 bpd of crude and over 10 mmscmd of gas; lifetime recovery is put at 23.5 mt of oil and 50.7 bcm of gas. The project is central to India's push to lift domestic output and cut import dependence.","progress":"2024年1月产出首油并持续爬产，目标峰值4.5万桶/日原油与逾1000万方/日天然气。"},
  {"id":6480,"name":"索巴丹纳维 LNG 联合循环电站","en":"Sobadhanavi LNG Combined Cycle Power Plant","country":"斯里兰卡","region":"南亚","cat":"petro","coord":[79.87,7.02],"cap":"350 MW（220MW燃机+130MW汽机联合循环）","inv":4.8,"invText":"≈4.8亿美元（估）","status":"投运","year":2025,"updated":"2025-09","owner":"Lakdhanavi / LTL控股（Sobadhanavi Ltd）","flagship":false,"desc":"斯里兰卡首座以LNG为主燃料的电站：350MW索巴丹纳维联合循环机组2025年9月全面投运。","detail":"索巴丹纳维电站位于科伦坡以北克拉瓦拉皮提亚，是斯里兰卡首座按LNG主燃料设计的电站，也是该国最大IPP项目之一，由LTL控股旗下Lakdhanavi开发，投资约4.8亿美元。一期220MW西门子F级燃机开式循环2024年8月28日投运；二期利用余热的130MW汽轮机于2025年9月17日并网，全厂350MW联合循环建成，标志着斯里兰卡电源结构从燃油向更清洁的燃气/LNG转型，后续LNG采购与接收设施正在推进。","descEn":"Sri Lanka's first power plant designed for LNG: the 350 MW Sobadhanavi combined-cycle plant reached full operation in September 2025.","detailEn":"Located at Kerawalapitiya north of Colombo, Sobadhanavi is Sri Lanka's first plant designed to run on LNG as primary fuel and among its largest IPPs, developed by LTL Holdings' Lakdhanavi for roughly $480m. The 220 MW Siemens F-class gas turbine entered open-cycle service on 28 August 2024, and the 130 MW steam turbine completed the 350 MW combined cycle on 17 September 2025, anchoring the country's shift from oil-fired generation to cleaner gas while LNG procurement and import facilities advance.","progress":"2025年9月17日130MW汽机并网，350MW联合循环全面建成投运。"},
  {"id":6481,"name":"TAPI 跨国天然气管道（阿富汗段）","en":"TAPI Gas Pipeline (Afghanistan Section)","country":"阿富汗","region":"南亚","cat":"petro","coord":[62.2,34.35],"cap":"设计年输气330亿立方米，全长约1814km（阿富汗段816km）","inv":100,"invText":"全线≈100亿美元（土库曼Turkmengaz主导）","status":"在建","year":2026,"updated":"2025-06","owner":"TAPI Pipeline Company（Turkmengaz主导，四国参股）","flagship":true,"desc":"土库曼—阿富汗—巴基斯坦—印度天然气管道阿富汗段2024年9月开工，赫拉特段2025年过半。","detail":"TAPI管道全长约1814公里、设计年输气330亿立方米，把土库曼加尔金内什气田的天然气经阿富汗、巴基斯坦送抵印度，全线投资约100亿美元。停滞多年的阿富汗段（816公里）于2024年9月动工，截至2025年6月赫拉特段完成52%：累计铺管约80公里、其中36.3公里已埋设，平整路由126公里、修筑施工便道108公里，计划2026年底通气至赫拉特市，随后向坎大哈和巴基斯坦延伸，是阿富汗当前最大的在建能源工程。","descEn":"The Afghan section of the Turkmenistan-Afghanistan-Pakistan-India gas pipeline broke ground in September 2024; the Herat stretch passed the halfway mark in 2025.","detailEn":"The ~1,814 km TAPI pipeline is designed to carry 33 bcm/year of Turkmen gas from Galkynysh through Afghanistan and Pakistan to India, with total corridor investment of about $10bn. Afghanistan's long-stalled 816 km section began construction in September 2024; by June 2025 the Herat segment was 52% complete, with ~80 km of pipe laid (36.3 km buried), 126 km of route prepared and 108 km of service roads built. Gas is to reach Herat city by end-2026 before the line extends toward Kandahar and Pakistan — Afghanistan's largest active energy project.","progress":"截至2025年中赫拉特段完成约52%、铺管80公里，计划2026年底通气至赫拉特。","route":[[62.3,35.3],[62.2,34.35],[62.1,32.4],[64.4,31.6],[65.7,31.6],[67,30.2],[71.5,30.2],[74,30.4]]},
  {"id":6482,"name":"贾姆肖罗 660MW 超临界燃煤电站","en":"Jamshoro 660 MW Supercritical Coal Power Plant","country":"巴基斯坦","region":"南亚","cat":"petro","coord":[68.28,25.43],"cap":"660 MW 超临界机组（80%进口次烟煤+20%塔尔褐煤掺烧）","inv":15,"invText":"≈15亿美元（估，ADB牵头融资）","status":"投运","year":2025,"updated":"2025-05","owner":"Jamshoro Power Company（GENCO-I），CMEC-Descon承建","flagship":false,"desc":"亚开行融资、中企承建的巴基斯坦660MW超临界燃煤机组2025年5月投运，为信德省最大国有新机组。","detail":"贾姆肖罗电站5号机组位于信德省贾姆肖罗既有油气电厂厂址，为660MW超临界燃煤机组，采用80%进口次烟煤与20%塔尔褐煤掺烧，由亚洲开发银行牵头融资、中国机械设备工程（CMEC）与Descon联合承建，投资约15亿美元。机组2025年5月完成试运行正式投入商运，是巴基斯坦国有发电板块最大的新增机组；但受全国10-12GW过剩装机拖累，投运后半年平均调度率仅约6%，凸显巴电力行业的容量过剩与购电成本压力。","descEn":"Pakistan's ADB-financed, Chinese-built 660 MW supercritical coal unit at Jamshoro entered service in May 2025 — the largest new state-owned unit.","detailEn":"Unit 5 at the Jamshoro power complex in Sindh is a 660 MW supercritical coal unit burning a blend of 80% imported subbituminous coal and 20% Thar lignite, financed by an ADB-led package and built by a CMEC-Descon consortium for roughly $1.5bn. It completed trial operation and was commissioned in May 2025 as the largest new unit in Pakistan's state generation fleet — yet with the grid carrying a 10-12 GW surplus, its dispatch averaged only ~6% in the first six months, underscoring the sector's overcapacity strains.","progress":"2025年5月完成试运行投入商运，但受电网过剩影响投运初期调度率偏低。"},
  {"id":6483,"name":"Digital Connexion 金奈 MAA10 数据中心园区","en":"Digital Connexion MAA10 Data Center Campus (Chennai)","country":"印度","region":"南亚","cat":"datacenter","coord":[80.16,13.11],"cap":"园区规划100MW IT容量，首期MAA10为20MW（机柜密度最高70kW）","inv":10,"invText":"≈10亿美元（园区全建成，估）","status":"在建","year":2024,"updated":"2024-02","owner":"Digital Connexion（信实工业-Brookfield-Digital Realty合资）","flagship":false,"desc":"信实、Brookfield与Digital Realty三方合资的首个项目：金奈安巴图尔100MW AI数据中心园区首期投运。","detail":"Digital Connexion是信实工业、Brookfield与Digital Realty组建的三方合资公司，金奈安巴图尔工业区10.5英亩园区为其首发项目，规划四栋数据中心楼、合计100MW IT容量。首期MAA10楼高七层、约1.82万平方米，提供20MW容量，2024年初投运，支持最高70kW/机柜的AI高密度负载；选址毗邻多条海缆登陆站，瞄准金奈成为印度数据中心新高地的窗口期，园区全建成投资估算约10亿美元，后续孟买园区同步推进。","descEn":"The first project of the Reliance-Brookfield-Digital Realty JV: a 100 MW AI-ready data center campus in Chennai's Ambattur, with phase one live.","detailEn":"Digital Connexion — the three-way JV of Reliance Industries, Brookfield and Digital Realty — launched its first campus on 10.5 acres in Chennai's Ambattur Industrial Estate, planned at four buildings totaling 100 MW of IT capacity. The first facility, MAA10, a seven-storey 196,000 sq ft building offering 20 MW, went live in early 2024 and supports AI densities up to 70 kW per rack. Sited near multiple submarine cable landings, the campus (est. ~$1bn at full build) positions Chennai as India's next data-center hub, with a Mumbai campus to follow.","progress":"首期MAA10（20MW）2024年初投运，园区向100MW满配滚动扩建。"},
  {"id":6484,"name":"马鲁蒂铃木卡尔科达整车基地","en":"Maruti Suzuki Kharkhoda Manufacturing Plant","country":"印度","region":"南亚","cat":"ci","coord":[76.91,28.88],"cap":"一期25万辆/年已投产，三期合计75万辆/年（2029年）","inv":31,"invText":"≈31亿美元（三期累计约2600亿卢比，估）","status":"在建","year":2025,"updated":"2025-03","owner":"马鲁蒂铃木（Maruti Suzuki India）","flagship":false,"desc":"印度最大车企的新整车基地：哈里亚纳邦卡尔科达工厂2025年2月投产，远期产能75万辆/年。","detail":"马鲁蒂铃木在哈里亚纳邦索尼帕特县卡尔科达建设的新整车基地是其继古尔冈、马内萨尔之后的第三大生产枢纽。一期工厂投资约1100亿卢比，2025年2月投产，年产能25万辆；二期同等规模在建，2025年3月董事会再批准741亿卢比建设第三工厂，三期合计75万辆/年产能拟2029年建成，累计投资约2.6万crore卢比（约31亿美元）。基地主打SUV及出口车型，是印度乘用车制造扩张周期的代表性项目。","descEn":"India's largest carmaker's new manufacturing hub: the Kharkhoda plant in Haryana started production in February 2025, scaling to 750,000 vehicles a year.","detailEn":"Maruti Suzuki's Kharkhoda site in Sonipat, Haryana is its third major hub after Gurgaon and Manesar. The first plant (~Rs 11,000 crore) began commercial production in February 2025 at 250,000 vehicles/year; a second identical plant is under construction, and in March 2025 the board approved a Rs 7,410 crore third plant, taking site capacity to 750,000 units/year by 2029 with cumulative investment of roughly Rs 26,000 crore (~$3.1bn). The site focuses on SUVs and exports, emblematic of India's passenger-vehicle capacity boom.","progress":"一期2025年2月投产，二期在建，2025年3月董事会批准第三工厂，2029年达75万辆/年。"},
  {"id":6485,"name":"锡尔马尔露天煤矿","en":"Siarmal Opencast Coal Mine","country":"印度","region":"南亚","cat":"mining","coord":[83.7,21.9],"cap":"峰值产能5000万吨/年，可采储量10.91亿吨","inv":44,"invText":"MDO 25年合同额≈44亿美元（₹3.68万crore）","status":"投运","year":2024,"updated":"2025-03","owner":"Mahanadi Coalfields（印度煤炭公司子公司），Dilip Buildcon任MDO","flagship":false,"desc":"印度煤炭公司体系首个投产的MDO大矿：奥迪沙锡尔马尔露天煤矿产量爬坡，峰值将达5000万吨/年。","detail":"锡尔马尔露天煤矿位于奥迪沙邦松德尔格尔县伊布河谷煤田，归印度煤炭公司子公司Mahanadi Coalfields所有，可采储量10.91亿吨、峰值产能5000万吨/年，建成后将跻身印度最大煤矿之列。项目采用矿山开发运营商（MDO）模式，由Dilip Buildcon获得25年、合同额3.68万crore卢比（约44亿美元）的开发运营合同，是煤炭公司体系首个落地投产的MDO项目：FY24投产首年产煤720万吨，FY25达1270万吨，计划FY29前后达到5000万吨峰值。","descEn":"Coal India's first operating MDO mega-mine: the Siarmal opencast mine in Odisha is ramping toward a 50 Mtpa peak capacity.","detailEn":"The Siarmal opencast project in the Ib Valley coalfield of Sundargarh, Odisha, owned by Coal India subsidiary Mahanadi Coalfields, holds 1,091 mt of mineable reserves with a 50 Mtpa peak capacity — set to rank among India's largest mines. Under the mine-developer-and-operator model, Dilip Buildcon holds the 25-year, Rs 36,819 crore (~$4.4bn) contract, the first MDO project in the Coal India system to become operational: output hit 7.2 mt in FY24 and 12.7 mt in FY25, with the 50 Mtpa peak targeted around FY29.","progress":"FY25产量达1270万吨、超额完成合同目标，向FY29年5000万吨峰值产能爬坡。"},
  {"id":6486,"name":"Hygenco戈帕尔普尔绿氨项目","en":"Hygenco Gopalpur Green Ammonia Project","country":"印度","region":"南亚","cat":"renewable","coord":[84.92,19.3],"cap":"绿氨110万吨/年（三期；一期22万吨/年，600吨/日）","inv":25,"invText":"约25亿美元（三期合计，估）","status":"在建","year":2027,"updated":"2026-06","owner":"Hygenco（HHP Five）/塔塔钢铁SEZ","flagship":false,"desc":"2025年6月奥迪沙邦首席部长主持开工：塔塔钢铁SEZ戈帕尔普尔园区110万吨/年绿氨基地，一期2027年商运。","detail":"印度绿氢开发商Hygenco旗下HHP Five公司与塔塔钢铁特别经济区签订约束性协议，在奥迪沙邦戈帕尔普尔工业园建设大型绿氢绿氨项目，规划总产能110万吨/年绿氨，分三期实施：一期22万吨/年（600吨/日）目标2027年商业运营，二期2029年再增22万吨，三期2030年后扩至110万吨。2025年1月项目获法国必维国际检验集团欧盟RED III（RFNBO）预认证——印度第二个获此认证的绿氨项目；2025年6月由奥迪沙邦首席部长主持开工奠基。产品瞄准欧洲、日韩出口市场，与同园区的ACME、Avaada项目共同使戈帕尔普尔成为印度绿氨出口枢纽。","descEn":"Groundbroken in June 2025 at Tata Steel SEZ's Gopalpur Industrial Park, Odisha: a 1.1 Mtpa green ammonia base in three phases, with Phase 1 (220 ktpa, 600 tpd) targeting commercial operations in 2027.","detailEn":"Hygenco's subsidiary HHP Five signed a binding agreement with Tata Steel SEZ to build a large green hydrogen/ammonia project at Gopalpur Industrial Park, Odisha, planned at 1.1 million tonnes per year of green ammonia in three phases: Phase 1 of 220 ktpa (600 tpd) targeting commercial operations in 2027, Phase 2 adding 220 ktpa by 2029, and Phase 3 scaling to 1.1 Mtpa beyond 2030. In January 2025 it became India's second green ammonia project to secure EU RED III (RFNBO) pre-certification by Bureau Veritas; Odisha's Chief Minister launched construction in June 2025. Output targets European, Japanese and Korean export markets, making Gopalpur - alongside ACME and Avaada - India's green ammonia export hub.","progress":"2025年1月获欧盟RFNBO预认证，6月正式开工建设；一期600吨/日装置目标2027年商运。"},
  {"id":6487,"name":"印度—中东（沙特/阿联酋）海底电力互联（OSOWOG一期）","en":"India-Middle East (Saudi/UAE) Subsea Power Interconnection (OSOWOG Phase 1)","country":"印度—沙特阿拉伯","region":"南亚","cat":"grid","coord":[69,21.5],"cap":"约1700km海底电缆 / 首期2GW","inv":108,"invText":"约9000亿卢比（约108亿美元，估，含沙特与阿联酋两线）","status":"规划","year":2030,"updated":"2026-06","owner":"Power Grid Corporation of India（POWERGRID）","desc":"印度\"一个太阳一个世界一个电网\"（OSOWOG）首期：经阿拉伯海海底电缆连接印度西海岸与沙特、阿联酋电网。","detail":"依据2023年10月印沙两国签署的电力互联与电力贸易谅解备忘录，印度国家电网公司（POWERGRID）启动印度西海岸—沙特东海岸约1700公里海底电缆互联可行性研究，规划首期输送2GW，沙特线估算造价约4700亿卢比（约56亿美元）；连同印度—阿联酋线，印度电力部长2025年表示总投资约9000亿卢比量级（约108亿美元，估）。该工程是印度发起的OSOWOG全球电网互联倡议的第一阶段，旨在实现南亚与中东可再生能源跨时区互济，减少对昂贵储能的依赖。2025年6月报道称沙特与阿联酋拟自印度进口绿电，研究工作推进中。","descEn":"Phase 1 of India's One Sun One World One Grid (OSOWOG): subsea HVDC cables across the Arabian Sea linking India's west coast with the grids of Saudi Arabia and the UAE.","detailEn":"Under MoUs on grid interconnection and power trade signed with Saudi Arabia in October 2023, POWERGRID has begun feasibility studies for a roughly 1,700 km subsea cable from India's west coast to eastern Saudi Arabia, initially carrying 2 GW at an estimated INR 470 billion (about USD 5.6 billion); together with an India-UAE link, India's power minister put total investment near INR 900 billion (about USD 10.8 billion, est.). The first phase of the OSOWOG initiative, it aims to share renewable power across time zones between South Asia and the Gulf, with studies advancing as of mid-2025.","progress":"2025年：可行性研究启动，印度电力部长确认拟投资约9万亿卢比建设至沙特与阿联酋的海底互联，沙特、阿联酋拟自印度进口绿电。","route":[[50.1,26.4],[56.5,26],[62,22],[69,21.5]],"flagship":false},
  {"id":6488,"name":"NTPC火电厂址电池储能集群","en":"NTPC Thermal Stations BESS Cluster (2,334MWh)","country":"印度","region":"南亚","cat":"storage","coord":[79.36,21.47],"cap":"2334MWh（库德吉/穆达/索拉普尔/巴尔/拉马贡达姆等5邦火电厂址）","inv":3.5,"invText":"约3.5亿美元（估）","status":"规划","year":2027,"updated":"2026-06","owner":"NTPC","desc":"印度NTPC在5邦火电厂址布置2334MWh电池储能，2026年3月完成竞拍，利用既有升压站与并网点快速落地。","detail":"印度国家火电公司（NTPC）2026年3月底完成火电厂址电池储能EPC竞拍，总规模2334MWh，分布于卡纳塔克邦库德吉、马哈拉施特拉邦穆达与索拉普尔、比哈尔邦巴尔、特伦甘纳邦拉马贡达姆等既有火电站内，GR Infraprojects、Enviro Infra、Solarworld与NTPC GE电力服务等分获各厂址标段。项目利用火电厂现成的升压站与并网点，建设周期短，是NTPC约4GWh火电厂址储能计划的首批落地，支撑印度2030年储能装机目标。","descEn":"NTPC auctioned 2,334MWh of BESS at thermal plant sites across five Indian states in March 2026, leveraging existing switchyards and grid connections.","detailEn":"India's NTPC concluded an EPC auction in late March 2026 for 2,334MWh of battery storage at its existing thermal power stations across Karnataka (Kudgi), Maharashtra (Mouda, Solapur), Bihar (Barh) and Telangana (Ramagundam). Winners include GR Infraprojects (400MWh at Mouda), Enviro Infra Engineers (480MWh Kudgi, 100MWh Ramagundam), Solarworld Energy Solutions (264MWh Solapur) and NTPC GE Power Services (400MWh Barh). Using the plants' existing switchyards and grid connections shortens delivery; this is the first tranche of NTPC's ~4GWh thermal-site storage plan supporting India's 2030 storage targets.","progress":"2026年3月31日公布竞拍结果，多家EPC分获各厂址标段；依托既有并网设施预计2027年起分批投运。","flagship":false},
  {"id":6489,"name":"鲁普沙800MW联合循环电站","en":"Rupsha 800MW Combined Cycle Power Plant","country":"孟加拉国","region":"南亚","cat":"petro","coord":[89.53,22.73],"cap":"800MW（2×400MW）","inv":10,"invText":"约10亿美元（ADB贷款5亿美元）","status":"在建","year":2026,"updated":"2026-06","owner":"NWPGCL（EPC：上海电气/安萨尔多）","desc":"亚行出资5亿美元支持的孟加拉西南部最大燃气电站：库尔纳鲁普沙2×400MW联合循环机组，上海电气/安萨尔多EPC，并网调试阶段。","detail":"鲁普沙800MW联合循环电站位于孟加拉国西南部库尔纳市鲁普沙河畔，由国有西北电力公司（NWPGCL）开发，亚洲开发银行提供5亿美元主权贷款，是孟西南地区最大的燃气电源项目。上海电气牵头、联合意大利安萨尔多能源的联合体2019年11月中标EPC合同，建设2×400MW燃气联合循环机组，配套天然气接入与输电送出工程，远期可使用再气化LNG。项目经历疫情停工后于2024年基本完成主体工程并进入调试，受国家气源紧张影响并网进度有所推迟，全面商运后将显著缓解库尔纳地区缺电并支撑南部电网。","descEn":"ADB-backed ($500m loan) 2x400MW gas-fired combined cycle plant on the Rupsha river in Khulna, built by Shanghai Electric/Ansaldo for NWPGCL — southwest Bangladesh's largest gas power project, now in commissioning.","detailEn":"The Rupsha 800MW CCGT in Khulna, developed by state-owned NWPGCL with a $500 million ADB loan, is southwest Bangladesh's largest gas-fired power project. A Shanghai Electric-led consortium with Ansaldo Energia won the EPC contract in November 2019 for two 400MW blocks plus gas and transmission interconnections. After pandemic delays, physical works were largely completed by 2024 and the plant entered commissioning, though full commercial operation has slipped on national gas-supply constraints.","progress":"2024年底主体工程完工进入调试，受孟加拉气源供应紧张影响商运进度推迟；全面投运后将成为孟西南部最大燃气电源。","flagship":false},
  {"id":6490,"name":"巴基斯坦科哈拉（Kohala）1124MW水电站","en":"Kohala Hydropower Project (1,124 MW)","country":"巴基斯坦","region":"南亚","cat":"renewable","coord":[73.5,34.09],"cap":"1124MW径流式（年发电约48亿千瓦时）","inv":24,"invText":"约24亿美元","status":"规划","year":2027,"updated":"2026-06","owner":"中国三峡集团（CTG南亚投资）","desc":"中巴经济走廊最大水电投资：杰赫勒姆河1124MW径流电站，融资关闭期限延至2027年9月。","detail":"科哈拉水电站位于巴控克什米尔（AJK）穆扎法拉巴德附近的杰赫勒姆河上，装机1124MW、年发电约48亿千瓦时，总投资约24亿美元，是中国三峡集团在巴基斯坦最大的单笔投资、中巴经济走廊（CPEC）旗舰能源项目，中资银团曾承诺16亿美元买方信贷。项目因电价审批与监管评估一度停滞，2024年8月巴方宣布重启；巴私营电力基础设施委员会已将支持函（LoS）项下融资关闭期限延长36个月至2027年9月30日，三峡南亚公司正按需求增长重排分期开发时间表并重审设计与融资结构，以确保具有竞争力的电价。","descEn":"CPEC's largest hydropower investment: a 1,124 MW run-of-river plant on the Jhelum River; financial-close deadline extended to September 2027.","detailEn":"The Kohala HPP on the Jhelum River near Muzaffarabad (AJK) will generate about 4.8 TWh a year from 1,124 MW, with a cost of about US$2.4 bn - China Three Gorges' largest investment in Pakistan and a CPEC flagship. After delays over tariff and regulatory reviews, Pakistan moved to revive the project in August 2024, and the financial-close date under the Letter of Support was extended 36 months to 30 September 2027 while CTG South Asia re-phases the timeline and reworks design and financing for a competitive tariff.","progress":"2024年8月巴方宣布重启停滞三年的项目；融资关闭期限获批延长36个月至2027年9月30日，三峡南亚正重审设计、成本与融资结构。","flagship":false},

  // ===== 中亚（6500-6512）=====
  {"id":6500,"name":"乌兹别克斯坦吉扎克核电站","en":"Jizzakh Integrated Nuclear Power Plant (VVER-1000 + RITM-200N SMR)","country":"乌兹别克斯坦","region":"中亚","cat":"nuclear","coord":[66.77,40.56],"cap":"2×1000MW VVER-1000 + 2×55MW RITM-200N，合计约2110MW","inv":95,"invText":"基准合同额95亿美元（不含本地化部分）","status":"在建","year":2029,"updated":"2026-06","owner":"乌兹别克原子能署（Uzatom）/俄罗斯国家原子能公司（Rosatom）总包","flagship":true,"desc":"中亚首个开工的一体化核电站：2台VVER-1000大堆+2台RITM-200N小堆同址建设，基准合同额95亿美元。","detail":"乌兹别克斯坦首座核电站，位于吉扎克州福里什区艾达尔湖畔。2025年9月乌原子能署与Rosatom确定\"2大+2小\"一体化配置：2台百万千瓦级VVER-1000三代+机组与2台55MW RITM-200N小型模块堆同址建设，为全球首例。2025年10月小堆场地开挖启动，2026年3月浇筑小堆首罐混凝土，2026年6月5日米尔济约耶夫与普京共同宣布主体工程开工。2026年3月签署的合同基准金额95亿美元（上限，不含约30%本地化）。首台小堆拟2029年底临界，两台大堆分别于2033/2035年投运。","descEn":"Central Asia's first NPP under construction: 2 VVER-1000 large units plus 2 RITM-200N SMRs on one site in Jizzakh, base contract $9.5bn.","detailEn":"Uzbekistan's first nuclear power plant, sited beside Lake Aydar in Forish district, Jizzakh region. In September 2025 Uzatom and Rosatom fixed an integrated configuration unique worldwide: two Gen-3+ VVER-1000 units plus two 55 MW RITM-200N small modular reactors on a single site. SMR excavation began in October 2025, first concrete for the SMR foundation was poured in March 2026, and on 5 June 2026 Presidents Mirziyoyev and Putin jointly launched main construction. The contract signed in March 2026 carries a base (maximum) price of $9.5bn excluding ~30% localization. First SMR criticality is slated for late 2029, with the VVER-1000 units following in 2033 and 2035.","progress":"2026年6月5日两国总统共同启动主体工程建设，小堆反应堆厂房基坑开挖完成、首罐混凝土已浇筑。"},
  {"id":6501,"name":"跨里海绿色能源走廊海底电缆","en":"Caspian Green Energy Corridor Subsea Interconnector","country":"哈萨克斯坦—乌兹别克斯坦—阿塞拜疆","region":"中亚","cat":"grid","coord":[51.17,43.64],"cap":"拟1.5GW跨里海高压直流海缆","inv":20,"invText":"约20亿美元（估，可研阶段）","status":"规划","year":2030,"updated":"2026-04","owner":"Green Corridor Union LLC（KEGOC×乌国家电网×AzerEnergy）","flagship":false,"desc":"哈乌阿三国共建的跨里海绿电外送走廊：高压海底电缆连接阿克套与巴库，拟向欧洲输送1.5GW中亚风光电力。","detail":"2024年11月COP29期间哈萨克斯坦、乌兹别克斯坦、阿塞拜疆三国元首签署绿色能源战略伙伴协定，核心为一条跨里海高压直流海底电缆，将中亚风光基地电力经阿塞拜疆、格鲁吉亚输往欧洲，输电能力约1.5GW。三国电网公司（KEGOC、乌国家电网、AzerEnergy）已注册成立Green Corridor Union合资公司；亚行支持、意大利CESI牵头的一期可研于2026年1月启动；哈萨克斯坦议会2026年3—4月完成协定批准。线路造价待可研确定，市场估算约20亿美元，目标2030年前后具备送电条件。","descEn":"Trilateral Kazakhstan–Uzbekistan–Azerbaijan green corridor: an HVDC subsea cable across the Caspian from Aktau toward Baku to export ~1.5 GW of Central Asian renewables to Europe.","detailEn":"At COP29 in November 2024 the presidents of Kazakhstan, Uzbekistan and Azerbaijan signed a strategic green-energy partnership centred on a high-voltage subsea cable across the Caspian Sea, carrying about 1.5 GW of Central Asian wind and solar power onward via Azerbaijan and Georgia to Europe. Grid operators KEGOC, NEG Uzbekistan and AzerEnergy have incorporated the Green Corridor Union JV; an ADB-backed Phase-I feasibility study led by Italy's CESI kicked off in January 2026, and Kazakhstan's parliament ratified the agreement in March–April 2026. Costs (market estimates around $2bn) will be fixed by the study, targeting operation around 2030.","progress":"2026年1月亚行支持的一期可研启动（CESI牵头），3—4月哈萨克斯坦议会批准三国协定，合资公司Green Corridor Union已注册运营。","route":[[51.17,43.64],[49.55,40.6]]},
  {"id":6502,"name":"哈萨克斯坦巴克特—阿亚古兹铁路","en":"Bakhty–Ayagoz Railway (3rd China–Kazakhstan Rail Crossing)","country":"哈萨克斯坦","region":"中亚","cat":"transport","coord":[81.6,47.3],"cap":"272公里双线铁路，对华跨境运能新增约2000万吨/年","inv":12,"invText":"5775亿坚戈（约12亿美元）","status":"在建","year":2027,"updated":"2025-05","owner":"哈萨克斯坦铁路（KTZ）/Global Trans Company（PPP投资）","flagship":false,"desc":"中哈第三条跨境铁路：272公里双线新线连接阿亚古兹与边境巴克特口岸，2027年通车后对华运能从2800万吨增至约4800万吨/年。","detail":"哈萨克斯坦阿拜州272公里巴克特—阿亚古兹双线铁路2025年1月实质开工，投资约5775亿坚戈（约12亿美元），采用PPP模式、Global Trans Company为主要投资人。线路自阿亚古兹向东南至中哈边境巴克特，与中国塔城（楚呼楚）接轨，开通中哈第三个铁路口岸（继多斯特克—阿拉山口、阿腾科里—霍尔果斯之后），计划2027年投运，使中哈铁路年过货能力由2800万吨提升至约4800万吨，并在口岸配套规划976公顷陆港（对标霍尔果斯东大门经济特区）。","descEn":"Kazakhstan's third rail link to China: a new 272 km double-track line from Ayagoz to the Bakhty border crossing, lifting China-Kazakhstan rail capacity from 28 to ~48 Mt/yr from 2027.","detailEn":"Construction of the 272 km double-track Bakhty–Ayagoz railway in Kazakhstan's Abai region began in January 2025, at a cost of KZT 577.5bn (~$1.2bn) under a PPP with Global Trans Company as lead investor. Running south-east from Ayagoz to Bakhty on the Chinese border, it connects to Tacheng (Chuguchak) in Xinjiang and opens Kazakhstan's third rail border crossing with China after Dostyk-Alashankou and Altynkol-Khorgos. Due in service in 2027, it will raise annual cross-border rail capacity from 28 to about 48 million tonnes, supported by a planned 976-hectare dry port modelled on the Khorgos Eastern Gate SEZ.","progress":"2025年1月正式开工，路基与站场工程推进中，口岸配套976公顷陆港同步规划，目标2027年建成通车。","route":[[80.43,47.96],[82.74,46.66]]},
  {"id":6503,"name":"新塔什干国际机场","en":"New Tashkent International Airport","country":"乌兹别克斯坦","region":"中亚","cat":"transport","coord":[69.13,41.12],"cap":"2000万人次/年、货邮12.9万吨/年（一期）","inv":25,"invText":"一期25亿美元","status":"在建","year":2028,"updated":"2025-10","owner":"沙特Vision Invest×日本双日×韩国仁川机场联合体","flagship":true,"desc":"中亚在建最大机场：塔什干州扬吉尤尔以东新建枢纽，一期投资25亿美元、年吞吐2000万人次，2025年10月奠基。","detail":"2025年10月16日米尔济约耶夫总统出席奠基仪式，中亚规模最大的新机场在塔什干州扬吉尤尔以东约7公里动工。一期投资25亿美元，含航站楼与飞行区，年旅客吞吐能力2000万人次、货邮12.9万吨，每小时30架次起降、14条登机廊桥、62个机位。项目由沙特Vision Invest、日本双日（拟累计投资10亿美元）与仁川国际机场公司联合体以PPP模式投资建设运营，仁川机场输出\"K-机场\"运营模式，目标2028年前后建成投用，并将成为乌首个全绿电运行机场。","descEn":"Central Asia's largest airport project: a new $2.5bn (phase 1) hub east of Yangiyul near Tashkent for 20m passengers/yr, broke ground in October 2025.","detailEn":"On 16 October 2025 President Mirziyoyev launched construction of Central Asia's largest airport, 7 km east of Yangiyul in Tashkent region. The $2.5bn first phase covers the terminal complex and airfield, sized for 20 million passengers and 129,000 tonnes of cargo a year, 30 movements per hour, 14 jet bridges and 62 aircraft stands. A consortium of Saudi Arabia's Vision Invest, Japan's Sojitz (planning up to $1bn of investment) and Incheon International Airport Corporation will build and operate it under a PPP, bringing the 'K-airport' operating model; opening is targeted around 2028, as Uzbekistan's first fully renewables-powered airport.","progress":"2025年10月16日奠基开工，沙日韩联合体推进一期航站楼与飞行区建设，目标2028年前后投用。"},
  {"id":6504,"name":"卡拉姆卡斯海—哈扎尔海上油气开发","en":"Kalamkas-Sea & Khazar Offshore Oil and Gas Development","country":"哈萨克斯坦","region":"中亚","cat":"petro","coord":[50.4,44.3],"cap":"可采储量原油约4850万吨、天然气190亿立方米","inv":60,"invText":"直接投资逾60亿美元","status":"在建","year":2028,"updated":"2025-10","owner":"哈萨克国家油气KMG×俄罗斯卢克石油（各50%）","flagship":false,"desc":"里海哈萨克水域卡拉姆卡斯海、哈扎尔、阿乌埃佐夫油气田联合开发，投资逾60亿美元，2028—2029年出首油。","detail":"哈萨克国家油气公司KMG与卢克石油各持股50%，联合开发里海哈萨克斯坦水域的卡拉姆卡斯海、哈扎尔及阿乌埃佐夫油气田，可采储量约4850万吨原油和190亿立方米天然气，直接投资超过60亿美元，可创造2000余个就业岗位。项目于2025年10月正式启动实施，最终投资决定安排在2025年四季度；海上平台2026年起在哈国内船厂开建，浅水区物流是主要工程挑战。计划2028—2029年实现商业出油，是继卡沙甘之后里海哈萨克水域最大的新建海上开发项目。","descEn":"Joint KMG-Lukoil development of the Kalamkas-Sea, Khazar and Auezov fields in the Kazakh Caspian: >$6bn investment, first oil 2028-29.","detailEn":"KazMunayGas and Lukoil, 50/50 partners, are jointly developing the Kalamkas-Sea, Khazar and Auezov fields in the Kazakh sector of the Caspian Sea, holding recoverable reserves of about 48.5 million tonnes of oil and 19 bcm of gas. Direct investment exceeds $6bn, creating over 2,000 jobs. Implementation formally began in October 2025 with FID scheduled for Q4 2025; offshore platform fabrication starts at Kazakh shipyards in 2026, with the shallow Caspian posing the main logistics challenge. Commercial first oil is targeted for 2028-29 — the largest new offshore development in Kazakh waters since Kashagan.","progress":"2025年10月项目启动实施、四季度作最终投资决定，海上平台2026年起在哈国内船厂开工建造。"},
  {"id":6505,"name":"土库曼巴什1574MW联合循环电站","en":"Turkmenbashi (Balkan) 1,574 MW Combined-Cycle Power Plant","country":"土库曼斯坦","region":"中亚","cat":"petro","coord":[53,40.15],"cap":"1574MW燃气联合循环（4台燃机+2台汽机）","inv":10,"invText":"约10亿美元（估；已获5.86亿美元出口信贷融资担保）","status":"在建","year":2027,"updated":"2024-11","owner":"土库曼国家电力（Türkmenenergo）/土耳其恰勒克能源总承包","flagship":false,"desc":"土库曼斯坦第二座联合循环电站：巴尔坎州土库曼巴什区1574MW燃气电站，恰勒克能源总包，2027年5月投运。","detail":"土库曼斯坦第二座大型联合循环电站，位于巴尔坎州土库曼巴什区（基扬雷一带），装机1574MW，配置4台GE燃气轮机和2台汽轮机，发电效率较常规燃气机组大幅提升并兼顾对阿富汗、伊朗等邻国送电。2023年11月奠基，土耳其恰勒克能源（Çalik Enerji）总承包，工期40个月，计划2027年5月投运。恰勒克已获德国商业银行与瑞士出口信贷机构共5.86亿美元融资担保，项目总投资估算约10亿美元，是土库曼电力外送多元化战略的核心工程。","descEn":"Turkmenistan's second combined-cycle plant: 1,574 MW gas-fired CCGT in Turkmenbashi district, Balkan province, built by Çalik Enerji for commissioning in May 2027.","detailEn":"Turkmenistan's second large combined-cycle power plant, located in the Turkmenbashi district of Balkan province near Kiyanly, will install four GE gas turbines and two steam turbines totalling 1,574 MW, sharply raising fuel efficiency and supporting electricity exports to Afghanistan, Iran and other neighbours. Ground was broken in November 2023; Turkey's Çalik Enerji is general contractor on a 40-month schedule with commissioning due in May 2027. Çalik has secured $586m of facility guarantees from Commerzbank and the Swiss export credit agency, against an estimated total cost of around $1bn — a core asset of Turkmenistan's power-export diversification drive.","progress":"土建与设备安装推进中，恰勒克能源获5.86亿美元国际融资担保，按40个月工期计划2027年5月投运。"},
  {"id":6506,"name":"巴库塔钨矿","en":"Bakuta Tungsten Mine","country":"哈萨克斯坦","region":"中亚","cat":"mining","coord":[77.98,44.45],"cap":"2025年采选矿石330万吨/年，2027年扩至495万吨/年；WO₃资源量23.15万吨","inv":2.5,"invText":"累计资本开支超13亿元人民币（约2.5亿美元，估）","status":"投运","year":2025,"updated":"2025-08","owner":"佳鑫国际资源（江西铜业集团为主要股东）","flagship":false,"desc":"全球最大露天钨矿投产：哈萨克阿拉木图州巴库塔钨矿2024年11月出矿、2025年二季度商业化生产，江铜系佳鑫国际运营。","detail":"巴库塔钨矿位于哈萨克斯坦阿拉木图州克尔布拉克区（赛雷奥泽克附近），按三氧化钨储量计为全球最大露天钨矿、单体设计产能全球第一，矿石资源量约1.095亿吨、平均WO₃品位0.211%（折合23.15万吨）。由江西铜业集团为主要股东的佳鑫国际资源开发，2024年11月建成投产，2025年计划采选330万吨矿石并于二季度进入商业化生产，2027年产能拟扩至495万吨/年。公司2025年8月28日在港交所主板和阿斯塔纳国际交易所\"一带一路\"板挂牌，为中哈关键矿产合作标志性项目。","descEn":"World's largest open-pit tungsten mine by WO3 reserves: Bakuta in Almaty region began production in Nov 2024, reaching commercial output in Q2 2025 under Jiangxi Copper-backed Jiaxin International.","detailEn":"The Bakuta tungsten mine in Kerbulak district, Almaty region (near Saryozek) is the world's largest open-pit tungsten mine by WO3 reserves and the largest single-mine design capacity, with ~109.5 Mt of resources grading 0.211% WO3 (231,500 t contained). Developed by Jiaxin International Resources, whose main shareholder is Jiangxi Copper Group, it started production in November 2024, plans to mine and process 3.3 Mt of ore in 2025 with commercial production from Q2, and will expand to 4.95 Mt/yr by 2027. Jiaxin listed on the HKEX main board and AIX Belt-and-Road board on 28 August 2025 — a flagship China-Kazakhstan critical-minerals venture.","progress":"2025年二季度进入商业化生产，运营方佳鑫国际8月28日在港交所及阿斯塔纳国际交易所上市，2027年产能拟扩至495万吨/年。"},
  {"id":6507,"name":"阿尔马雷克铜冶炼厂新建项目","en":"Almalyk MMC New Copper Smelter Complex","country":"乌兹别克斯坦","region":"中亚","cat":"ci","coord":[69.62,40.86],"cap":"年产阴极铜30万吨、硫酸180万吨","inv":25,"invText":"约25亿美元","status":"在建","year":2028,"updated":"2025-12","owner":"阿尔马雷克矿冶联合体（Almalyk MMC）","flagship":false,"desc":"乌兹别克新建30万吨阴极铜冶炼综合体（区别于3号选矿厂扩建），投资约25亿美元，芬兰美卓提供核心工艺设备。","detail":"阿尔马雷克矿冶联合体（AMMC）150亿美元扩产计划的核心冶炼环节：在阿尔马雷克现有厂区新建年产30万吨阴极铜、180万吨硫酸的铜冶炼综合体，投资约25亿美元，与约什利克-1矿和3号选矿厂（采选环节）配套，使乌阴极铜产能2030年前从14.8万吨提升至40万吨/年。芬兰美卓（Metso）签署框架协议提供闪速熔炼等核心工艺装备，订单已分三批落地（2024年四季度1.46亿欧元、2025年一季度5000万欧元、四季度7000万欧元）；中国恩菲、中国进出口银行亦在洽谈渣处理等环节合作。","descEn":"A new 300,000 t/yr cathode copper smelter (distinct from the MOF-3 concentrator) at Almalyk, Uzbekistan — ~$2.5bn, with Metso supplying core flash-smelting technology.","detailEn":"The smelting centrepiece of Almalyk MMC's $15bn expansion: a new copper smelter complex at the existing Almalyk site producing 300,000 t/yr of copper cathodes and 1.8 Mt/yr of sulphuric acid, costing about $2.5bn. Paired with the Yoshlik-I mine and MOF-3 concentrator, it will lift Uzbekistan's cathode output from 148,000 to 400,000 t/yr by 2030. Finland's Metso signed a frame agreement for flash smelting and related process technology, with orders booked in three tranches (EUR146m in Q4 2024, EUR50m in Q1 2025, EUR70m in Q4 2025); China Nerin Engineering and China Eximbank are in talks over the slag-processing package.","progress":"冶炼厂建设推进，美卓2025年四季度再落地7000万欧元第三批工艺设备订单；配套3号选矿厂一期已于2026年3月投产。"},
  {"id":6508,"name":"吉尔吉斯斯坦伊塞克湖1GW光伏电站","en":"Issyk-Kul 1 GW Solar PV Park (Toru-Aigyr)","country":"吉尔吉斯斯坦","region":"中亚","cat":"renewable","coord":[76.35,42.59],"cap":"1GW光伏","inv":10,"invText":"约10亿美元（估）","status":"规划","year":2027,"updated":"2025-02","owner":"中国电力国际发展×中铁二十局（各50%）","flagship":false,"desc":"吉尔吉斯斯坦最大光伏项目：伊塞克湖州托鲁艾格尔1GW光伏，中国电力国际与中铁二十局共同开发，拟2027年并网。","detail":"吉尔吉斯斯坦能源部与中国电力国际发展签署协议，在伊塞克湖州托鲁艾格尔村建设1GW光伏电站，为该国迄今最大的太阳能项目，由中国电力国际与中铁二十局各持股50%开发，投资估算约10亿美元。项目可大幅缓解吉国冬季电力短缺并改善依赖水电的电源结构，配套还包括2025年2月签署的60万千瓦风光投资协议。吉政府高层已就建设方案举行多轮磋商，行业数据库预计2026年开工、2027年投入商业运行。","descEn":"Kyrgyzstan's largest solar project: a 1 GW PV park at Toru-Aigyr on Lake Issyk-Kul, developed 50/50 by China Power International Development and China Railway 20th Bureau, targeting 2027 COD.","detailEn":"Kyrgyzstan's Ministry of Energy signed an agreement with China Power International Development for a 1 GW solar plant at Toru-Aigyr village in the Issyk-Kul region — the country's largest solar project to date, developed 50/50 with China Railway 20th Bureau Group at an estimated cost of about $1bn. It would ease Kyrgyzstan's winter power deficit and diversify a hydro-dominated mix; related agreements in February 2025 added 600 MW of wind and solar. After repeated high-level talks on the construction scheme, industry trackers expect construction from 2026 and commercial operation in 2027.","progress":"吉政府与中方投资人完成建设方案最后磋商，配套600MW风光投资协议2025年2月签署，预计2026年开工、2027年并网。"},
  {"id":6509,"name":"吉尔吉斯斯坦卡扎尔曼水电梯级","en":"Kazarman Hydropower Cascade (1,160 MW)","country":"吉尔吉斯斯坦","region":"中亚","cat":"renewable","coord":[74.04,41.4],"cap":"4座梯级电站共1160MW，年发电量44.6亿千瓦时","inv":21,"invText":"约20.8亿美元","status":"规划","year":2028,"updated":"2025-08","owner":"Orta Asya投资控股（土耳其İhlas集团）；原中国电建西北院联合体","flagship":false,"desc":"纳伦河卡扎尔曼4级水电梯级（阿拉布加600MW等共1160MW），投资约21亿美元，2025年8月改由土耳其财团签署投资协议。","detail":"卡扎尔曼水电梯级位于吉尔吉斯斯坦贾拉拉巴德州纳伦河干流，含阿拉布加（600MW）、卡拉布隆1、卡拉布隆2和托古兹托罗4座电站，总装机1160MW、年发电量44.6亿千瓦时，总投资约20.8亿美元，是吉国仅次于坎巴拉塔-1的水电开发项目。2023年7月曾与中国电建西北院、绿色黄金能源及中铁二十局联合体签署投资协议；2025年8月11日吉政府改与土耳其İhlas集团旗下Orta Asya（中亚）投资控股签署新投资协议，欧亚开发银行亦与其建立战略合作，计划2027—2028年起分批投运。","descEn":"A 4-plant, 1,160 MW cascade on the Naryn River at Kazarman (Ala-Buga 600 MW etc.), ~$2.1bn; in August 2025 Kyrgyzstan re-signed the investment agreement with Turkey's Ihlas-owned Orta Asya Investment Holding.","detailEn":"The Kazarman cascade on the Naryn River in Jalal-Abad region comprises four plants — Ala-Buga (600 MW), Kara-Bulung-1, Kara-Bulung-2 and Toguz-Toro — totalling 1,160 MW and 4.46 TWh/yr, at an estimated $2.08bn, Kyrgyzstan's biggest hydro scheme after Kambarata-1. An investment agreement was first signed in July 2023 with a Chinese consortium (PowerChina Northwest, Green Gold Energy, China Railway 20th Bureau); on 11 August 2025 the government re-signed with Orta Asya Investment Holding, a subsidiary of Turkey's Ihlas Holding, which has also teamed up with the Eurasian Development Bank. Phased commissioning is planned from 2027-28.","progress":"2025年8月11日吉政府与土耳其İhlas旗下Orta Asya投资控股签署新投资协议，欧亚开发银行加入战略合作，前期工程筹备中。"},
  {"id":6510,"name":"乌兹别克斯坦上普斯凯姆水电站","en":"Upper (Yukori) Pskem Hydropower Plant","country":"乌兹别克斯坦","region":"中亚","cat":"renewable","coord":[70.45,41.95],"cap":"160MW，年发电量4.84亿千瓦时","inv":3.65,"invText":"3.65亿美元","status":"在建","year":2029,"updated":"2025-03","owner":"乌兹别克水电（Uzbekhydroenergo），与中国南方电网国际合作","flagship":false,"desc":"普斯凯姆河梯级龙头电站：160MW上普斯凯姆水电站2025年3月奠基，投资3.65亿美元，年发电4.84亿千瓦时。","detail":"上普斯凯姆水电站位于塔什干州博斯坦利克区普斯凯姆河上游，装机160MW、年发电量4.84亿千瓦时，投资3.65亿美元，可满足约16.1万户家庭用电，2025年3月10日举行奠基仪式。项目是乌兹别克水电公司58亿美元水电扩张计划（3.6GW储备项目）中普斯凯姆河梯级开发的龙头工程，乌方与中国南方电网国际就该电站及下游霍吉肯特抽水蓄能项目建立联合开发合作。建成后将增强乌电网调峰能力并带动梯级后续电站（含404MW普斯凯姆水电站）开发。","descEn":"Lead plant of the Pskem river cascade: the 160 MW, $365m Upper Pskem HPP broke ground in March 2025, generating 484 GWh/yr for ~161,000 households.","detailEn":"The Upper (Yukori) Pskem HPP in Bostanlyk district, Tashkent region, on the upper Pskem River, will install 160 MW generating 484 GWh a year — enough for about 161,000 households — at a cost of $365m; the groundbreaking ceremony was held on 10 March 2025. It is the lead scheme of the Pskem cascade within Uzbekhydroenergo's $5.8bn, 3.6 GW hydropower expansion pipeline, developed in cooperation with China Southern Power Grid International, which is also partnering on the downstream Khojikent pumped-storage plant. The plant will strengthen peak regulation and unlock further cascade stages including the 404 MW Pskem HPP.","progress":"2025年3月10日奠基开工，引水系统与坝址土建展开，与南方电网国际的联合开发合作同步推进。"},
  {"id":6511,"name":"乌兹别克斯坦霍吉肯特抽水蓄能电站","en":"Khojikent Pumped-Storage Power Plant","country":"乌兹别克斯坦","region":"中亚","cat":"storage","coord":[69.7,41.51],"cap":"200MW抽水蓄能","inv":4,"invText":"约4亿美元（估）","status":"规划","year":2030,"updated":"2025-01","owner":"乌兹别克水电×中国南方电网国际（联合开发）","flagship":false,"desc":"中亚首批抽水蓄能项目：乌兹别克与中国南方电网国际联合开发塔什干州霍吉肯特200MW抽蓄电站。","detail":"霍吉肯特抽水蓄能电站位于塔什干州博斯坦利克区恰尔瓦克水库—奇尔奇克河水系，装机200MW，是中亚首批抽水蓄能电站之一。2025年1月乌兹别克水电公司与中国南方电网国际在广州签署联合实施协议（JDA），双方同步推进上普斯凯姆常规水电与本项目，并研究普斯凯姆河600MW抽蓄等后续工程。项目建成后将为乌快速增长的风光装机提供调峰填谷与转动惯量支撑，投资估算约4亿美元，原计划2025年内举行奠基，目标2030年前后投运。","descEn":"One of Central Asia's first pumped-storage plants: the 200 MW Khojikent PSPP in Tashkent region, jointly developed by Uzbekhydroenergo and China Southern Power Grid International.","detailEn":"The Khojikent pumped-storage plant, on the Charvak reservoir-Chirchik river system in Bostanlyk district, Tashkent region, will install 200 MW as one of Central Asia's first PSPPs. In January 2025 Uzbekhydroenergo and China Southern Power Grid International signed a joint implementation agreement in Guangzhou, advancing it together with the Upper Pskem HPP and studying a further 600 MW PSPP on the Pskem river. The plant will provide peak-shaving and inertia for Uzbekistan's fast-growing wind and solar fleet; investment is estimated around $400m, with groundbreaking planned from 2025 and operation targeted around 2030.","progress":"2025年1月乌水电与南网国际签署联合实施协议，可研与奠基筹备推进中。"},
  {"id":6512,"name":"乌兹别克斯坦Firebird英伟达AI数据中心","en":"Firebird-NVIDIA AI Data Center Uzbekistan","country":"乌兹别克斯坦","region":"中亚","cat":"datacenter","coord":[69.33,41.34],"cap":"规划125—250MW（可扩展）","inv":20,"invText":"约20亿美元（估）","status":"规划","year":2028,"updated":"2026-04","owner":"Firebird×英伟达，乌数字技术部支持","flagship":false,"desc":"英伟达与Firebird向乌方提出125—250MW大型AI数据中心方案，为乌打造区域AI算力枢纽的旗舰候选项目。","detail":"2026年4月底乌兹别克斯坦数字技术部长谢尔马托夫与英伟达全球AI基础设施副总裁及Firebird总裁会谈，后者正式提出在乌建设125—250MW、可进一步扩展的大型AI数据中心计划。Firebird为美亚资本支持的AI云基础设施商，已在亚美尼亚与英伟达共建AI工厂。该项目与乌\"主权云\"战略及IT Park生态衔接，乌政府同期还推进与英伟达的工业AI卓越中心合作。项目尚处方案与选址磋商阶段，投资按同类项目估算约20亿美元，若落地将成为中亚最大AI算力设施之一。","descEn":"NVIDIA and Firebird have proposed a 125-250 MW (expandable) AI data center in Uzbekistan — a flagship candidate for the country's regional AI-compute hub ambitions.","detailEn":"In late April 2026 Uzbekistan's Minister of Digital Technologies Sherzod Shermatov met NVIDIA's VP for global AI infrastructure and the leadership of Firebird, which formally proposed a large-scale AI data center of 125-250 MW with room for further expansion. Firebird, an AI-cloud infrastructure firm already building an NVIDIA-based AI factory in Armenia, would anchor the project within Uzbekistan's sovereign-cloud strategy and IT Park ecosystem; the government is in parallel advancing an Industrial AI Excellence Center with NVIDIA. The project is at the proposal/siting stage; investment is estimated around $2bn by analogy with comparable builds — potentially one of Central Asia's largest AI-compute facilities.","progress":"2026年4月英伟达与Firebird向乌数字技术部正式提出125—250MW数据中心建设方案，选址与合作框架磋商中。"},

  // ===== 中东（6520-6539）=====
  {"id":6520,"name":"沙特杜韦欣核电站","en":"Duwaiheen Nuclear Power Plant","country":"沙特阿拉伯","region":"中东","cat":"nuclear","coord":[51.5,24.6],"cap":"2×1400MW 大型压水堆","inv":120,"invText":"约120亿美元（估）","status":"规划","year":2027,"updated":"2026-06","owner":"沙特电力采购公司(SPPC)/K.A.CARE","flagship":false,"desc":"沙特首座大型商用核电站，选址卡塔尔与阿联酋边界之间的海湾沿岸，规划2台140万千瓦压水堆，中韩法俄四家竞标。","detail":"杜韦欣核电站是沙特和平利用核能计划的旗舰工程，选址东部省海湾沿岸卡塔尔与阿联酋边界之间，规划建设2台1400MW级大型压水堆，采用传统设计-建造（DB）模式。中核集团、法国EDF、韩国KEPCO/KHNP与俄罗斯Rosatom四家供应商已提交标书，项目招标自2022年启动后多次延期，2025年沙特电力采购公司又收到项目咨询顾问（advisory）标书，授标程序持续推进。该项目与沙特2030愿景下的核电起步计划和美沙民用核能谈判深度绑定，是海湾地区继巴拉卡之后第二个大型商用核电项目。","descEn":"Saudi Arabia's first large commercial nuclear plant: two 1.4GW PWRs on the Gulf coast between the Qatar and UAE borders, with CNNC, EDF, KEPCO and Rosatom bidding.","detailEn":"The Duwaiheen NPP is the flagship of Saudi Arabia's civil nuclear program, sited on the Gulf coast between the Qatar and UAE borders. The tender covers two 1,400MW-class PWRs under a design-and-build model. CNNC, EDF, KEPCO/KHNP and Rosatom submitted bids; after repeated deadline extensions since 2022, SPPC received advisory-services bids in 2025 as the award process advances. The project is closely tied to Vision 2030 and US-Saudi civil nuclear talks, and would be the Gulf's second large commercial NPP after Barakah.","progress":"2025年沙特电力采购公司收到项目咨询服务标书，中法韩俄四家技术供应商竞标持续评审中。"},
  {"id":6521,"name":"阿布扎比海上油田HVDC输电工程（Lightning项目）","en":"ADNOC-TAQA Project Lightning Subsea HVDC","country":"阿联酋","region":"中东","cat":"grid","coord":[53.47,24.1],"cap":"3.2GW 双回海底高压直流（HVDC-VSC）","inv":38,"invText":"38亿美元","status":"在建","year":2026,"updated":"2026-06","owner":"ADNOC/TAQA/KEPCO/九州电力/EDF","flagship":false,"desc":"中东首个海底高压直流输电系统：两回独立HVDC链路将阿布扎比陆上电网3.2GW清洁电力送往ADNOC海上油田，替代海上燃气轮机。","detail":"Lightning项目由ADNOC与TAQA联合发起，总投资约38亿美元，建设中东北非首个海底高压直流（HVDC-VSC）输电系统：两回独立海底直流链路及换流站，总容量3.2GW，将陆上电网的核电与光伏电力送至Das岛等海上油气设施，替代现役海上燃气轮机，预计使ADNOC海上作业碳足迹降逾30%。项目以SPV模式融资，ADNOC与TAQA各持股30%，KEPCO牵头财团（KEPCO/九州电力/EDF）持股40%并负责建设运营。2025年初项目通过关键节点，正向全面投运推进。","descEn":"MENA's first subsea HVDC system: two independent 3.2GW links carrying clean grid power from onshore Abu Dhabi to ADNOC's offshore fields, replacing offshore gas turbines.","detailEn":"Project Lightning, sponsored by ADNOC and TAQA at ~$3.8bn, is MENA's first subsea HVDC-VSC transmission system: two independent subsea DC links and converter stations with 3.2GW total capacity, delivering nuclear and solar power from the onshore grid to Das Island and other offshore facilities. It will cut the carbon footprint of ADNOC's offshore operations by over 30%. Financed via an SPV (ADNOC 30%, TAQA 30%, KEPCO-led consortium with Kyushu Electric and EDF 40%), the project passed a key milestone in early 2025 as it moves toward full operation.","progress":"2025年1月项目通过关键里程碑，海底电缆与换流站进入收尾调试，向全面商运推进。","route":[[53.47,24.1],[52.87,25.15]]},
  {"id":6522,"name":"科威特祖尔北二、三期独立水电项目","en":"Az-Zour North Phase 2 & 3 IWPP","country":"科威特","region":"中东","cat":"renewable","coord":[48.37,28.71],"cap":"2700MW 燃气联合循环 + 120 MIGD（约54.6万立方米/日）反渗透海水淡化","inv":41,"invText":"41亿美元","status":"在建","year":2029,"updated":"2026-06","owner":"ACWA Power/海湾投资公司(GIC)/科威特水电与可再生能源部","flagship":false,"desc":"科威特最大水电联产项目：2700MW燃气联合循环+日产54.6万吨海淡，ACWA-GIC财团2026年2月签署25年购电购水协议。","detail":"祖尔北二、三期独立水电项目（IWPP）位于科威特城以南约100公里的一期厂区旁，净发电容量不低于2700MW（燃气联合循环、轻油备用），配套120 MIGD（约54.6万立方米/日）反渗透海淡装置，建成后为科威特最大电水联产设施。总投资超40亿美元，ACWA与海湾投资公司（GIC）合计持股40%，科威特公私合营局持股60%；2026年2月正式签署25年期能源转换与购水协议。EPC由山东电建三公司（SEPCO-III）牵头，GE Vernova供应燃机，ACWA负责25年运维。","descEn":"Kuwait's largest power and water plant: 2,700MW CCGT plus 120 MIGD SWRO desalination; the ACWA-GIC consortium signed a 25-year ECWPA in February 2026.","detailEn":"The Az-Zour North Phase 2 & 3 IWPP, adjacent to Phase 1 some 100km south of Kuwait City, will deliver at least 2,700MW of net CCGT capacity (gasoil backup) and 120 MIGD (~545,500 m3/day) of SWRO desalination, making it Kuwait's largest power-water facility. Total investment exceeds $4bn; ACWA Power and GIC jointly hold 40% with KAPP holding 60%. The 25-year Energy Conversion and Water Purchase Agreement was signed in February 2026. SEPCO-III leads the EPC consortium, GE Vernova supplies the gas turbines, and ACWA will operate the plant for 25 years.","progress":"2026年2月ACWA-GIC财团与科威特水电部正式签署25年期购电购水协议，SEPCO-III牵头EPC启动建设。"},
  {"id":6523,"name":"约旦—伊拉克电网互联工程","en":"Jordan-Iraq Electricity Interconnection","country":"约旦—伊拉克","region":"中东","cat":"grid","coord":[41.09,34.37],"cap":"400kV/330kV 跨国输电线；一期40MW已送电，二期输送150-200MW","inv":1.5,"invText":"约1.5亿美元（估）","status":"在建","year":2026,"updated":"2026-06","owner":"约旦国家电力公司(NEPCO)/伊拉克电力部","flagship":false,"desc":"约旦里沙至伊拉克盖姆的跨国电力互联：一期2024年初已向鲁特拜送电40MW，二期400kV线路将输送150-200MW。","detail":"约旦—伊拉克电网互联工程连接约旦东部里沙（Al-Risha）变电站与伊拉克安巴尔省盖姆（Al-Qaim）变电站，是伊拉克电网摆脱对伊朗电力依赖、融入阿拉伯电网的重要一步。一期工程2024年一季度投运，以132kV向伊拉克鲁特拜地区送电40MW；二期建设330kV跨境线路并扩建盖姆132/400kV与里沙33/132/400kV变电站，输送能力提升至150-200MW。约旦侧土建已完成95%，约方表示400kV里沙侧已具备带电条件，伊方收尾工程持续推进，两国2025年8月续签供电协议。","descEn":"Cross-border link from Jordan's Risha substation to Iraq's Al-Qaim: phase 1 delivered 40MW to Rutbah from early 2024; phase 2 (400kV) lifts transfer to 150-200MW.","detailEn":"The Jordan-Iraq interconnection links the Al-Risha substation in eastern Jordan with Al-Qaim in Iraq's Anbar province, a key step in diversifying Iraq's power imports and tying it into the Arab grid. Phase 1, operational since Q1 2024, supplies 40MW at 132kV to the Rutbah area. Phase 2 adds a 330kV cross-border line and expands the Al-Qaim 132/400kV and Risha 33/132/400kV substations, raising capacity to 150-200MW. Jordan's NEPCO completed 95% of civil works and declared the 400kV Risha side ready for energization, while Iraq finishes its section; the two countries extended their supply agreement in August 2025.","progress":"一期40MW自2024年初持续送电；二期约旦侧土建完成95%，2025年8月两国续签供电协议，伊方盖姆侧收尾中。","route":[[38.2,32.45],[41.09,34.37]]},
  {"id":6524,"name":"叙利亚5000MW电站群（UCC财团）","en":"Syria 5,000MW Power Plants Program (UCC Consortium)","country":"叙利亚","region":"中东","cat":"renewable","coord":[36.72,34.73],"cap":"4座燃气联合循环共4000MW + 4座光伏共1000MW（德尔祖尔300MW/阿勒颇300MW/霍姆斯200MW/Widian Al-Rabee 200MW）","inv":70,"invText":"约70亿美元","status":"在建","year":2028,"updated":"2026-06","owner":"卡塔尔UCC控股/Power International(美)/Kalyon/Cengiz(土)","flagship":true,"desc":"叙利亚战后能源重建旗舰：卡塔尔UCC牵头财团特许建设运营8座电站共5000MW（4气电+4光伏），总投资约70亿美元。","detail":"2025年11月叙利亚能源部与卡塔尔UCC控股牵头财团（含美国Power International、土耳其Kalyon与Cengiz）签署最终特许经营协议，建设运营8座电站共5000MW，为该国首个一揽子PPP能源项目：4座燃气联合循环电站共4000MW，4座光伏共1000MW，分布于德尔祖尔、阿勒颇（各300MW）与霍姆斯、Widian Al-Rabee（各200MW）。项目源自2025年5月的70亿美元备忘录，2025年12月起陆续开工，建成后将基本重建战争摧毁的发电能力。","descEn":"Syria's post-war energy flagship: a Qatar UCC-led consortium will build and operate eight plants totalling 5GW (4 CCGT + 4 solar) under a ~$7bn concession signed in November 2025.","detailEn":"In November 2025 Syria's Ministry of Energy signed final concession agreements with an international consortium led by Qatar's UCC Holding (with Power International USA, Kalyon and Cengiz of Turkiye) to build and operate eight power plants totalling 5,000MW - Syria's first integrated PPP energy program. It comprises four CCGT plants totalling 4,000MW and four solar plants totalling 1,000MW at Deir Ezzor (300MW), Aleppo (300MW), Homs (200MW) and Widian Al-Rabee (200MW). Stemming from a $7bn MoU signed in May 2025, construction began rolling out from December 2025, launching Syria's national energy rehabilitation program.","progress":"2025年11月签署最终特许经营协议，首批电站2025年12月起开工建设。"},
  {"id":6525,"name":"BP基尔库克油气田群再开发","en":"BP Kirkuk Oil & Gas Redevelopment","country":"伊拉克","region":"中东","cat":"petro","coord":[44.35,35.47],"cap":"初期开发超30亿桶油当量；基尔库克Baba/Avanah穹丘及Bai Hassan、Jambur、Khabbaz油田，增产5-10万桶/日","inv":250,"invText":"约250亿美元（全周期估算）","status":"在建","year":2025,"updated":"2026-06","owner":"BP/伊拉克北方石油公司","flagship":true,"desc":"BP与伊拉克2025年敲定基尔库克巨型油气田群再开发，覆盖油气电水一体化，全周期投资约250亿美元。","detail":"2025年2月BP与伊拉克政府就基尔库克油气田群再开发达成最终协议，3月获联邦政府正式批准生效。初期阶段覆盖基尔库克油田Baba与Avanah两大穹丘及邻近的Bai Hassan、Jambur、Khabbaz三个油田，可采资源超30亿桶油当量，合同区及周边远景资源量最高达200亿桶油当量；范围横跨石油、天然气、电力与水务，并含勘探投资选项。全周期投资估算约250亿美元，预计未来数年将基尔库克产量提升5-10万桶/日。BP已于2025年启动现场评估与修复作业，这是其重返伊拉克北部的标志性项目。","descEn":"BP and Iraq finalized the giant Kirkuk redevelopment in 2025 - an integrated oil, gas, power and water program with estimated lifetime investment of ~$25bn.","detailEn":"In February 2025 BP reached a final agreement with Iraq for the redevelopment of the Kirkuk fields, ratified by the federal government in March. The initial phase covers the Baba and Avanah domes of the Kirkuk field plus the adjacent Bai Hassan, Jambur and Khabbaz fields, targeting over 3 billion boe, with wider resource potential up to 20 billion boe across the contract area. The scope spans oil, gas, power and water, with exploration options. Estimated total investment is ~$25bn, expected to lift Kirkuk output by 50,000-100,000 b/d in coming years. BP began field assessments in 2025, marking its return to northern Iraq.","progress":"2025年3月合同获伊拉克联邦政府批准生效，BP已启动油田现场评估与修复作业。"},
  {"id":6526,"name":"纳杰夫1GW光伏电站（ACWA）","en":"Najaf 1GW Solar PV Plant (ACWA Power)","country":"伊拉克","region":"中东","cat":"renewable","coord":[44.34,31.99],"cap":"1000MW 光伏","inv":8,"invText":"约8亿美元（估）","status":"规划","year":2028,"updated":"2026-06","owner":"ACWA Power/伊拉克电力部","flagship":false,"desc":"沙特ACWA Power中标伊拉克中部纳杰夫1000MW光伏电站，系伊拉克12GW太阳能计划核心项目之一。","detail":"2025年1月伊拉克电力部授予沙特ACWA Power纳杰夫1000MW光伏电站项目，厂址位于巴格达以南约160公里的纳杰夫省，以与伊方合资模式建设运营，购电合同已签署。2025年4月伊拉克电力部长与ACWA代表敲定合同程序路线图，加快推进这一战略项目。该电站与道达尔巴士拉沙姆斯1GW光伏、巴比伦-卡尔巴拉525MW等项目同属伊拉克12GW太阳能计划，旨在缓解长期电力短缺、降低对进口气电依赖。投资按同类规模估算约8亿美元。","descEn":"Saudi Arabia's ACWA Power was awarded a 1,000MW solar IPP in Najaf, central Iraq - a core project of Iraq's 12GW solar program.","detailEn":"In January 2025 Iraq's Ministry of Electricity awarded ACWA Power a 1,000MW solar plant in Najaf province, ~160km south of Baghdad, to be built and operated as a joint venture with the Iraqi side; a power purchase contract has been signed. In April 2025 the minister and ACWA agreed a roadmap to expedite contracting. Alongside TotalEnergies' 1GW Shams Basra plant and a 525MW Babil-Karbala project, it anchors Iraq's 12GW solar program to ease chronic power shortages. Investment is estimated at ~$0.8bn based on comparable projects.","progress":"2025年4月伊拉克电力部与ACWA敲定合同程序路线图，项目进入融资与设计前期阶段。"},
  {"id":6527,"name":"塔尔图斯港现代化改造（DP World）","en":"Tartus Port Modernization (DP World)","country":"叙利亚","region":"中东","cat":"transport","coord":[35.88,34.89],"cap":"30年特许经营；集装箱码头及多用途泊位整体升级","inv":8,"invText":"8亿美元","status":"在建","year":2025,"updated":"2026-06","owner":"迪拜环球港务集团(DP World)","flagship":false,"desc":"DP World获叙利亚第二大港塔尔图斯30年特许经营权，投资8亿美元升级改造，2025年11月正式接管运营。","detail":"2025年7月13日，迪拜环球港务集团（DP World）与叙利亚海陆港口总局在大马士革签署塔尔图斯港30年特许经营协议，叙总统沙拉出席见证，承诺投资8亿美元对港口基础设施进行现代化改造，将其打造为连接南欧、中东与北非的区域贸易枢纽。塔尔图斯是叙利亚第二大港和地中海重要门户，经历十余年战乱后基础设施严重失修。2025年11月12日DP World完成接管并正式开始运营，升级工程提速推进，是叙利亚经济重新融入全球贸易体系的标志性外资项目。","descEn":"DP World signed a 30-year concession for Syria's Tartus Port with an $800m modernization commitment, commencing operations in November 2025.","detailEn":"On 13 July 2025 DP World signed a 30-year concession with Syria's General Authority for Land and Sea Ports in Damascus, witnessed by President Ahmed Al-Sharaa, committing $800m to modernize Tartus Port into a regional trade hub linking Southern Europe, the Middle East and North Africa. Tartus, Syria's second-largest port and key Mediterranean gateway, suffered over a decade of underinvestment during the war. DP World formally took over and commenced operations on 12 November 2025, accelerating the upgrade - a landmark foreign investment in Syria's economic reintegration.","progress":"2025年11月12日DP World正式接管塔尔图斯港并开始运营，8亿美元升级改造工程提速推进。"},
  {"id":6528,"name":"多拉海上气田开发（沙特—科威特中立区）","en":"Dorra Offshore Gas Field Development","country":"沙特—科威特","region":"中东","cat":"petro","coord":[49.4,28.8],"cap":"天然气约10亿立方英尺/日（沙科均分）+凝析油；储量约20万亿立方英尺气、3.1亿桶油","inv":100,"invText":"约100亿美元（估）","status":"规划","year":2029,"updated":"2026-06","owner":"哈夫吉联合作业公司(KJO：沙特阿美湾区作业+科威特海湾石油)","flagship":false,"desc":"沙特-科威特中立区海上多拉气田开发：4个EPC包总额约100亿美元招标中，目标日产10亿立方英尺天然气两国均分。","detail":"多拉（Dorra/Durra）气田位于沙特-科威特分治中立区近海，1965年发现，估计蕴藏约20万亿立方英尺天然气与3.1亿桶石油，伊朗以'Arash'之名主张部分权益但沙科坚持联合开发。项目由两国合资的哈夫吉联合作业公司（KJO）主导，计划日产约10亿立方英尺天然气并由两国均分，开发总投资最高约100亿美元，拆分为3个海上EPC包与1个陆上哈夫吉气体处理厂包，2024年8月发标。项目管理咨询（PMC）标2025年11月截标，各EPC包投标截止延至2026年1-4月，授标后进入全面建设。","descEn":"Development of the Dorra offshore gas field in the Saudi-Kuwait Neutral Zone: ~$10bn across four EPC packages targeting 1 Bcf/d of gas split equally between the two countries.","detailEn":"The Dorra field, discovered in 1965 in the offshore Saudi-Kuwait Neutral Zone, holds an estimated 20 Tcf of gas and 310 million barrels of oil; Iran claims part of it as 'Arash' but Riyadh and Kuwait City maintain joint development rights. Al-Khafji Joint Operations (KJO) leads the project, targeting ~1 Bcf/d split equally. The development, valued at up to $10bn, is divided into three offshore EPC packages and one onshore Khafji gas plant package, tendered from August 2024. PMC bids were due November 2025 and EPC bid deadlines were extended to January-April 2026, after which full construction follows.","progress":"PMC标2025年11月截标，主体EPC包与哈夫吉气厂包投标截止延至2026年1-4月，授标在即。"},
  {"id":6529,"name":"阿卡巴—安曼海水淡化与输水工程","en":"Aqaba-Amman Water Desalination and Conveyance Project","country":"约旦","region":"中东","cat":"ci","coord":[35.01,29.43],"cap":"年产约3亿立方米海水淡化 + 450公里输水管线 + 配套光伏（供能约28%）","inv":60,"invText":"约60亿美元","status":"规划","year":2030,"updated":"2026-06","owner":"Meridiam/苏伊士集团/万喜/Orascom/约旦水利灌溉部","flagship":false,"desc":"约旦国家级生命线工程：红海阿卡巴海淡厂经450公里管线向安曼年输水3亿立方米，总投资约60亿美元，2026年初融资关闭。","detail":"阿卡巴—安曼海淡输水工程（AAWDCP）是严重缺水的约旦的国家级生命线项目：在红海之滨阿卡巴建设世界级反渗透海淡厂（年产约3亿立方米），经450公里管线翻越逾千米高差送水至安曼，配套光伏满足约28%能耗。2025年1月Meridiam-苏伊士牵头财团（含万喜、Orascom）与约旦水利灌溉部签署30年特许经营协议，总投资约60亿美元，由绿色气候基金、EBRD、AIIB、IFC及多国赠贷组合融资（含美国2.03亿美元赠款）；融资关闭预计2026年初，建设期约4年，目标2029-2030年通水。","descEn":"Jordan's national lifeline: a Red Sea desalination plant at Aqaba delivering ~300 million m3/year to Amman via a 450km conveyor, at ~$6bn with financial close due in early 2026.","detailEn":"The AAWDCP is a lifeline project for Jordan, one of the world's most water-scarce countries: a world-scale SWRO plant at Aqaba (~300 million m3/year) feeding a 450km conveyor climbing over 1,000m to Amman, with a solar farm covering ~28% of its energy needs. In January 2025 a Meridiam-Suez-led consortium (with Vinci and Orascom) signed a 30-year concession with the Ministry of Water and Irrigation. The ~$6bn financing blends the Green Climate Fund, EBRD, AIIB, IFC and bilateral grants/loans, including a $203m US grant in 2025; financial close is expected in early 2026, with ~4 years of construction targeting first water by 2029-2030.","progress":"2025年1月签署30年特许经营协议，美方提供2.03亿美元赠款，融资关闭预计2026年初后随即开工。","route":[[35.01,29.43],[35.93,31.95]]},
  {"id":6530,"name":"亚丁光伏电站（一、二期）","en":"Aden Solar PV Plant (Phases 1 & 2)","country":"也门","region":"中东","cat":"renewable","coord":[44.98,12.85],"cap":"一期120MW已投运 + 二期120MW在建，合计240MW","inv":2,"invText":"约2亿美元（估，阿联酋出资）","status":"在建","year":2026,"updated":"2026-06","owner":"马斯达尔(Masdar)/也门电力部","flagship":false,"desc":"也门首座大型光伏电站：马斯达尔承建的亚丁120MW一期2024年7月投运，二期120MW扩建2025年开工、2026年商运。","detail":"亚丁光伏电站是战乱中的也门首座并网大型光伏项目，由阿联酋马斯达尔承建、阿联酋政府出资。一期120MW于2024年7月投运，日均为15-17万户家庭供电，大幅缓解亚丁地区燃油发电短缺与高电价压力。2025年5月二期120MW扩建启动，将安装超19.4万块光伏板，年发电约2.47亿千瓦时，可再覆盖68.7万户家庭，计划2026年商运；两期合计240MW，每年减排二氧化碳近28.5万吨，是也门电力系统重建与中东最不发达地区能源转型的标志性工程。","descEn":"Yemen's first utility-scale solar plant: Masdar's 120MW phase 1 in Aden came online in July 2024; a UAE-funded 120MW phase 2 began in 2025 for 2026 operation.","detailEn":"The Aden solar plant is war-torn Yemen's first grid-scale PV project, built by Masdar with UAE funding. Phase 1 (120MW) was inaugurated in July 2024, powering 150,000-170,000 households daily and easing Aden's chronic fuel-based power crisis. Phase 2, launched in May 2025, adds another 120MW with over 194,000 panels generating ~247GWh annually for up to 687,000 homes, targeting commercial operation in 2026. The combined 240MW facility will avoid almost 285,000 tonnes of CO2 per year - a landmark in rebuilding Yemen's power system.","progress":"二期120MW扩建2025年5月开工，超19.4万块光伏板安装中，计划2026年商运，总装机将达240MW。"},
  {"id":6531,"name":"巴林Bapco炼厂现代化工程（BMP）","en":"Bapco Modernization Program (Sitra Refinery)","country":"巴林","region":"中东","cat":"petro","coord":[50.61,26.13],"cap":"炼能由26.7万桶/日提升至40.5万桶/日","inv":70,"invText":"约70亿美元","status":"在建","year":2026,"updated":"2026-06","owner":"Bapco Energies（TechnipFMC等EPC，道达尔技术支持）","flagship":false,"desc":"巴林史上最大工业项目：70亿美元将百年Sitra炼厂炼能提升至40.5万桶/日，2024年底投料、最后装置2026年初投产。","detail":"Bapco炼厂现代化工程（BMP）是巴林史上最大工业投资，耗资约70亿美元升级近百年历史的Sitra炼厂，炼能从26.7万桶/日提至最终40.5万桶/日（超出原定38万桶目标），并提高中间馏分收率、降低硫排放；EPC由TechnipFMC-三星-Tecnimont联合体承建，2024年道达尔受邀提供运营优化支持。2024年12月巴林国王主持落成，前端常减压装置随即投料；加氢裂化、渣油加氢等后端装置2025年陆续开车，最后一批装置预计2026年初投产，全面达产后跻身海湾大型炼厂行列。","descEn":"Bahrain's largest-ever industrial project: a $7bn upgrade lifting the century-old Sitra refinery from 267,000 to 405,000 b/d, inaugurated in December 2024 with final units due by early 2026.","detailEn":"The Bapco Modernization Program is Bahrain's biggest industrial investment: a ~$7bn upgrade of the century-old Sitra refinery raising capacity from 267,000 b/d to a final 405,000 b/d (above the original 380,000 b/d target), boosting middle-distillate yields and cutting sulphur emissions. Built by a TechnipFMC-Samsung-Tecnimont consortium, with TotalEnergies brought in for operational support in 2024. King Hamad inaugurated the program in December 2024 as front-end crude units started up; the hydrocracker and residue units came online through 2025, with the last units due by late 2025-early 2026.","progress":"前端装置2024年底投料、后端加氢裂化2025年开车，最后装置预计2026年初投产，最终炼能确定为40.5万桶/日。"},
  {"id":6532,"name":"布什尔核电站2、3号机组","en":"Bushehr NPP Units 2 & 3","country":"伊朗","region":"中东","cat":"nuclear","coord":[50.89,28.83],"cap":"2×1057MW VVER-1000压水堆","inv":100,"invText":"约100亿美元（2014年合同）","status":"在建","year":2029,"updated":"2026-06","owner":"俄罗斯国家原子能公司(Rosatom)/伊朗原子能组织(AEOI)","flagship":false,"desc":"俄罗斯Rosatom在伊朗布什尔续建2台VVER-1000机组，2号机组反应堆设备完成逾60%，目标2029年投运。","detail":"布什尔核电站2、3号机组是俄伊2014年约100亿美元合同下的扩建工程，采用2台1057MW VVER-1000压水堆。2号机组2019年浇筑第一罐混凝土，2024年安装堆芯熔融物捕集器，2025年初完成内层安全壳第三层吊装；Rosatom称2号机组反应堆设备制造完成逾60%、蒸汽发生器约50%，关键设备拟于2026年起发运，伊方提出2029年投运目标。现场约3000名建设者中含700名俄方专家，Rosatom将布什尔续建列为最高优先级海外项目，伊以冲突背景下项目仍持续推进。","descEn":"Rosatom is building two more VVER-1000 units at Iran's Bushehr plant; Unit 2's reactor equipment is over 60% complete, targeting operation around 2029.","detailEn":"Bushehr Units 2 & 3 are the ~$10bn expansion under the 2014 Russia-Iran contract, deploying two 1,057MW VVER-1000 PWRs. Unit 2 saw first concrete in 2019, core catcher installation in 2024, and the third tier of the inner containment installed in early 2025. Rosatom reports the Unit 2 reactor is over 60% complete and steam generators ~50%, with key equipment shipments due from 2026; Iran targets 2029 for operation. About 3,000 workers, including 700 Russian specialists, are on site, and Rosatom calls the project a top priority despite regional conflict risks.","progress":"2号机组内层安全壳第三层2025年初吊装完成，反应堆设备制造逾60%，关键设备2026年起发运。"},
  {"id":6533,"name":"苏哈尔联合太阳能多晶硅厂（United Solar）","en":"United Solar Polysilicon Plant, Sohar","country":"阿曼","region":"中东","cat":"ci","coord":[56.58,24.45],"cap":"10万吨/年多晶硅（可支撑约40GW光伏组件）","inv":16,"invText":"16亿美元","status":"投运","year":2026,"updated":"2026-06","owner":"United Solar Holding（IFC等参投）","flagship":false,"desc":"中东首座大型多晶硅厂：苏哈尔自贸区16亿美元、年产10万吨项目2026年2月投产，填补区域光伏上游空白。","detail":"联合太阳能（United Solar Holding）在阿曼苏哈尔港自贸区投资16亿美元建设中东首座大规模多晶硅工厂，2024年3月奠基，规划年产能10万吨，可支撑约40GW光伏组件制造。项目获IFC等多边机构与投资人逾9亿美元融资支持（2026年1月落地），2026年2月正式投产，成为中东目前唯一在运的多晶硅制造设施。该厂背靠中国多晶硅技术与团队，瞄准美欧对华光伏供应链多元化需求，将阿曼嵌入全球光伏上游供应链，是海湾'后石油'工业多元化的代表项目。","descEn":"The Middle East's first large polysilicon plant: a $1.6bn, 100,000 t/yr facility in Sohar Freezone that began production in February 2026.","detailEn":"United Solar Holding invested $1.6bn in the Middle East's first large-scale polysilicon plant at Oman's Sohar Port and Freezone. Ground broke in March 2024; the plant targets 100,000 tonnes/year - enough for ~40GW of solar modules. Backed by over $900m in financing arranged with IFC and partners (January 2026), production launched in February 2026, making it the region's only operational polysilicon facility. Built on Chinese polysilicon technology and aimed at supply-chain diversification demand from US and European module buyers, it embeds Oman in the global solar upstream.","progress":"2026年1月获IFC牵头逾9亿美元融资，2026年2月正式投产，为中东唯一在运多晶硅厂。"},
  {"id":6534,"name":"梅赫迪阿巴德铅锌矿开发","en":"Mehdiabad Lead-Zinc Mine Development","country":"伊朗","region":"中东","cat":"mining","coord":[54.78,31.47],"cap":"远期锌精矿80万吨/年+铅银精矿8万吨/年；矿床储量约7.16亿吨，约占全球锌储量5%","inv":15,"invText":"约15亿美元（估）","status":"在建","year":2027,"updated":"2026-06","owner":"伊朗矿业开发与更新组织(IMIDRO)/Mobin矿业财团","flagship":false,"desc":"全球最大未充分开发锌矿之一：伊朗亚兹德省梅赫迪阿巴德分期露天开发，远期年产80万吨锌精矿。","detail":"梅赫迪阿巴德矿床位于伊朗中部亚兹德省，估算资源量约7.16亿吨，约占全球锌储量5%，为世界最大铅锌矿床之一，由IMIDRO授予Mobin财团分期露天开发。扩建工程2023年完成约55%，一期新增20万吨/年锌精矿产能，远期目标锌精矿80万吨/年、铅银精矿8万吨/年，并配套规划中东最大铅锌冶炼厂。2023/24伊朗历年综合体产量同比增长40.3%至42.1万吨（含30.3万吨氧化锌与11.8万吨重晶石）。在制裁限制设备与融资的背景下项目仍持续推进，全周期投资估算约15亿美元。","descEn":"One of the world's largest underdeveloped zinc deposits: staged open-pit development at Mehdiabad in Yazd province, targeting 800,000 t/yr of zinc concentrate at full build-out.","detailEn":"The Mehdiabad deposit in Iran's Yazd province holds ~716 million tonnes of resources - roughly 5% of global zinc reserves - making it one of the world's largest lead-zinc deposits, developed in stages as an open pit by the Mobin consortium under IMIDRO. The expansion was ~55% complete in 2023, with phase 1 adding 200,000 t/yr of zinc concentrate toward an ultimate 800,000 t/yr of zinc and 80,000 t/yr of lead-silver concentrate, plus plans for the Middle East's largest lead-zinc smelter. Output rose 40.3% to 421,000 tonnes in the 2023/24 Iranian year. Development continues despite sanctions constraints; lifetime investment is estimated at ~$1.5bn.","progress":"2023/24年度综合体产量同比增40.3%至42.1万吨，一期20万吨/年锌精矿扩产装置陆续建成投产。"},
  {"id":6535,"name":"绿色能源阿曼绿氢项目（GEO）","en":"Green Energy Oman (GEO)","country":"阿曼","region":"中东","cat":"renewable","coord":[56.9,20.1],"cap":"至多25GW风光发电制氢，全规模年产约180万吨绿氢","inv":300,"invText":"约300亿美元（全规模估算）","status":"规划","year":2030,"updated":"2026-06","owner":"壳牌(35%，运营方)/OQ/InterContinental Energy/EnerTech","flagship":false,"desc":"阿曼最大绿氢规划项目之一：壳牌牵头，中部省最多25GW风光制氢、年产180万吨，投资约300亿美元，2030年代初投产。","detail":"绿色能源阿曼（GEO）是该国签约的最大绿氢项目之一，选址中部省（Al Wusta）至佐法尔一带，规划以最多25GW风光电解海水制氢，全规模年产约180万吨绿氢，总投资约300亿美元。壳牌2023年入股35%出任运营牵头方，伙伴包括阿曼OQ、InterContinental Energy与科威特EnerTech。项目已与氢能主管机构Hydrom签订土地与开发协议，正推进风光资源评估与FEED，目标2030年代初投产，为阿曼2030年百万吨绿氢目标中体量最大的项目之一。","descEn":"One of Oman's largest contracted green hydrogen ventures: Shell-led, up to 25GW of wind and solar in Al Wusta producing ~1.8 Mt/yr of green hydrogen, ~$30bn, targeting early-2030s startup.","detailEn":"Green Energy Oman (GEO) is among the largest green hydrogen projects signed in Oman, spanning Al Wusta toward Dhofar. It plans up to 25GW of wind and solar powering seawater-fed electrolysis to produce ~1.8 million tonnes of green hydrogen per year at full scale, with investment of ~$30bn. Shell took a 35% stake in 2023 as lead operating partner, alongside OQ, InterContinental Energy and Kuwait's EnerTech. Land and development agreements are in place with Hydrom, with resource assessment and FEED under way for an early-2030s startup. As of late 2025, GEO is one of seven Omani green hydrogen projects on track toward a combined 1 Mt/yr by 2030.","progress":"壳牌确认项目瞄准2030年代初投产，风光资源评估与FEED推进中；阿曼7个绿氢项目2025年底均按计划推进。"},
  {"id":6536,"name":"卡塔尔QAFCO-7蓝氨工厂","en":"QAFCO Ammonia-7 Blue Ammonia Plant","country":"卡塔尔","region":"中东","cat":"petro","coord":[51.55,24.99],"cap":"蓝氨120万吨/年，配套CCS","inv":12,"invText":"约12亿美元（EPC约10亿美元）","status":"在建","year":2026,"updated":"2026-06","owner":"卡塔尔能源/QAFCO","flagship":false,"desc":"全球最大单体蓝氨工厂：梅赛义德工业城年产120万吨，CO2捕集封存，2026年二季度投产。","detail":"卡塔尔能源（QatarEnergy）与卡塔尔化肥公司（QAFCO）的Ammonia-7项目位于梅赛义德工业城，是全球最大的单体蓝氨工厂，年产能120万吨。生产过程中产生的二氧化碳被捕集并注入地下封存，蓝氨可用常规船舶运输，供电厂氨混烧发电等低碳应用，主要瞄准日韩市场。蒂森克虏伯Uhde与CCC联合体承担约10亿美元EPC合同，2024年11月全面开工建设，2026年4月前后投产，由QAFCO一体化运营。项目是卡塔尔在LNG之外布局清洁燃料出口的旗舰工程，也是中东蓝氨产业化的标志性项目。","descEn":"The world's largest single-train blue ammonia plant at Mesaieed Industrial City, Qatar: 1.2 Mtpa with CCS, startup around Q2 2026.","detailEn":"QatarEnergy and Qatar Fertiliser Company's Ammonia-7 project in Mesaieed Industrial City is the world's largest single blue ammonia facility at 1.2 million tonnes per year. CO2 generated during production is captured and sequestered underground; the blue ammonia can be shipped conventionally for low-carbon power generation, targeting Japanese and Korean co-firing markets. A thyssenkrupp Uhde-CCC consortium holds the ~$1 billion EPC contract; full construction started in November 2024 with startup around April 2026, operated by QAFCO. It is Qatar's flagship clean-fuel export venture beyond LNG.","progress":"2024年11月开工，2026年4月前后投产（卡塔尔能源指引2026年二季度出氨）。"},
  {"id":6537,"name":"土耳其—伊拉克400kV电力互联扩容（吉兹雷—基西克）","en":"Turkey-Iraq 400kV Interconnection Expansion (Cizre-Kisik)","country":"土耳其—伊拉克","region":"中东","cat":"grid","coord":[42.7,36.5],"cap":"400kV跨境线 / 600MW（自300MW倍增）","inv":1.5,"invText":"约1.5亿美元（估）","status":"投运","year":2025,"updated":"2026-06","owner":"伊拉克电力部/Alifrin（土耳其）","desc":"土耳其经尼尼微省400kV线向伊拉克送电，2025年签约扩容至600MW，成为伊拉克接入欧洲电网体系的北通道。","detail":"在2024年8月落成的115公里土耳其—伊拉克北部输电线基础上，伊拉克电力部于2025年6月4日与土耳其Alifrin公司签约，将经尼尼微省\"吉兹雷—基西克\"400kV线的互联能力由300MW倍增至600MW，首阶段300MW并网、一个月内达到满容量，采用\"照付实取\"（Take and Pay）模式。2026年5月土方宣布互联工程全面完成。该通道直接改善伊拉克北部供电，并借助土耳其与欧洲电网（ENTSO-E）同步的地位，为伊拉克电网多元化和与欧洲体系联通提供战略支点。","descEn":"Turkey supplies Iraq via a 400 kV line through Nineveh; a 2025 deal doubled capacity to 600 MW, giving Iraq a northern gateway toward the European grid system.","detailEn":"Building on a 115 km Turkey-northern Iraq line inaugurated in August 2024, Iraq's electricity ministry signed a contract with Turkey's Alifrin on 4 June 2025 to double the Cizre-Kisik 400 kV interconnection from 300 MW to 600 MW, with the first 300 MW flowing immediately and full capacity within a month under a take-and-pay model. In May 2026 Turkey announced completion of the interconnection works. The corridor bolsters supply to northern Iraq and, through Turkey's synchronization with ENTSO-E, strategically links Iraq toward the European power system.","progress":"2025年6月签约扩容至600MW并实现首批300MW送电；2026年5月土方宣布互联工程全面完成。","route":[[42.19,37.33],[42.68,36.42],[43,36.34]],"flagship":false},
  {"id":6538,"name":"以色列1.5GW电网级储能竞标群","en":"Israel 1.5GW Grid-Scale Storage Tender (11 projects)","country":"以色列","region":"中东","cat":"storage","coord":[34.95,30.6],"cap":"约1500MW/6000MWh＋（11个高压接网项目，含Enlight 300MW/约1.9GWh、Ormat 300MW/1.2GWh）","inv":8.4,"invText":"约30亿谢克尔（≈8.4亿美元）","status":"在建","year":2027,"updated":"2026-06","owner":"以色列电力管理局/Enlight/Ormat等","desc":"以色列2025年2月一次性授出1.5GW高压电网储能（11项目），Enlight、Ormat等中标，2027—2028年投运。","detail":"以色列电力管理局（IEA）2025年2月完成全国高压电网储能竞标，一次性向分布于三个区域的11个项目授出约1.5GW容量，容量电价折合约49—74美元/kWh·年。主要中标者包括Enlight（南部内盖夫Neot Smadar与Ohad两站，300MW/约1300—1900MWh）和Ormat（两站合计300MW/1200MWh，15年固定价代储协议）等。项目群总投资约30亿谢克尔（约8.4亿美元），要求2027年起陆续投运、最迟2028年并网，将成为以色列光伏高占比电网的核心调节资源。","descEn":"Israel awarded 1.5GW of high-voltage grid storage across 11 projects in February 2025 to Enlight, Ormat and others, with operations due 2027-2028.","detailEn":"Israel's Electricity Authority concluded a national high-voltage storage tender in February 2025, awarding about 1.5GW across 11 projects in three regions, from 29 proposals by 11 bidders, at capacity tariffs equivalent to roughly USD 49-74 per kWh-year. Key winners include Enlight (Neot Smadar and Ohad in the southern Negev, 300MW storing 1,300-1,900MWh) and Ormat (two facilities totaling 300MW/1,200MWh under 15-year fixed-price tolling agreements). With total investment of about ILS 3 billion (~USD 840 million), projects must begin operating from 2027 and connect by 2028, becoming the backbone flexibility resource of Israel's solar-heavy grid.","progress":"2025年2月授标11个项目；中标项目进入建设期，要求2027年起投运、最迟2028年全部并网。","flagship":false},
  {"id":6539,"name":"阿布扎比Masdar全天候光储巨型项目","en":"Abu Dhabi 24/7 Round-the-Clock Solar + Storage Gigaproject (Masdar/EWEC)","country":"阿联酋","region":"中东","cat":"renewable","coord":[54.4,24],"cap":"5.2GW光伏 + 19GWh储能（持续输出1GW基荷）","inv":60,"invText":"超60亿美元（AED 220亿+）","status":"在建","year":2027,"updated":"2026-06","owner":"Masdar/EWEC","flagship":true,"desc":"全球首个吉瓦级\"全天候\"光储一体化项目：5.2GW光伏+19GWh全球最大电池储能，全年24小时输出1GW清洁基荷。","detail":"马斯达尔（Masdar）与阿联酋水电公司（EWEC）联合开发的全球首个吉瓦级\"全天候\"可再生能源项目，将5.2GW光伏电站与19GWh电池储能系统（全球最大）耦合，全年7×24小时稳定输出1GW清洁基荷电力，占地约90平方公里（约1.5个曼哈顿）。项目2025年1月阿布扎比可持续发展周期间宣布，2025年10月正式动工，计划2027年投运，总投资超60亿美元，年减排二氧化碳约570万吨，创造逾1万个就业岗位，为AI数据中心等高耗能产业提供全天候绿电范本。","descEn":"World's first gigascale round-the-clock renewable project: 5.2 GW of solar PV plus a 19 GWh battery (world's largest) delivering 1 GW of 24/7 clean baseload.","detailEn":"Developed by Masdar with EWEC, this is the world's first gigascale round-the-clock renewable project, pairing a 5.2 GW solar PV plant with a 19 GWh battery energy storage system (the world's largest) to deliver a constant 1 GW of clean baseload across roughly 90 km2 of Abu Dhabi desert. Announced in January 2025 and broken ground in October 2025, it targets operation in 2027 with over US$6 bn of investment, saving about 5.7 Mt of CO2 a year.","progress":"2025年10月正式动工（全球首个吉瓦级全天候光储项目），计划2027年投运；AI驱动的预测与电池管理系统将实现1GW全天候基荷输出。"},

  // ===== 非洲（6545-6577）=====
  {"id":6545,"name":"南非库贝赫核电站延寿工程","en":"Koeberg Nuclear Power Station Long-Term Operation","country":"南非","region":"非洲","cat":"nuclear","coord":[18.43,-33.68],"cap":"1860MW（两台机组各延寿20年）","inv":13,"invText":"约250亿兰特（≈13亿美元）","status":"投运","year":2025,"updated":"2025-11","owner":"Eskom","flagship":false,"desc":"非洲唯一在运核电站完成两台机组20年延寿，1号机组获批运行至2044年、2号机组至2045年。","detail":"库贝赫核电站是非洲大陆唯一商运核电站（2×946MW压水堆，1984/85年投运）。Eskom自2010年起推进长期运行（LTO）计划，核心为法马通蒸汽发生器更换等大修改造，总投入约210–250亿兰特。2024年7月南非国家核监管局（NNR）批准1号机组延寿20年至2044年；2025年11月6日2号机组同获20年延寿至2045年11月。两台机组合计1860MW基荷电力得以保留，2025年2号机组曾连续241天满功率运行，为南非电网稀缺的稳定低碳电源。","descEn":"Africa's only operating nuclear plant completed 20-year life extensions for both units; Unit 1 licensed to 2044 and Unit 2 to 2045.","detailEn":"Koeberg (2x946MW PWR, online 1984/85) is the only commercial nuclear station in Africa. Eskom's Long-Term Operation programme, centred on Framatome steam generator replacements, cost about R21-25bn. The National Nuclear Regulator granted Unit 1 a 20-year extension to 2044 in July 2024 and Unit 2 to November 2045 on 6 November 2025, preserving 1,860MW of baseload low-carbon power; Unit 2 ran 241 consecutive days at full output in 2025.","progress":"2025年11月2号机组获批延寿20年至2045年，两台机组LTO计划全部完成。"},
  {"id":6546,"name":"加纳恩苏班核电项目（NuScale小堆）","en":"Ghana Nsuban Nuclear Power Project (NuScale SMR)","country":"加纳","region":"非洲","cat":"nuclear","coord":[-2.35,4.98],"cap":"924MW（NuScale VOYGR-12小型模块堆）","inv":50,"invText":"约50亿美元（估，未正式披露）","status":"规划","year":2034,"updated":"2025-12","owner":"Nuclear Power Ghana / Regnum Technology / NuScale","flagship":false,"desc":"加纳首座核电站：西部省恩苏班厂址部署NuScale VOYGR-12小型模块堆，目标2034年前后投运。","detail":"加纳核电公司（NPG）2023年选定西部省恩苏班为首选厂址（中部省奥博坦备选），2024年8月与美国Regnum Technology签约部署一座NuScale VOYGR-12多模块小堆电站（12×77MW，合计924MW）。2025年2月IAEA完成对加纳的首次厂址与外部事件设计审查（SEED），认可其选址符合安全标准；政府目标2027–2028年完成征地并开工，2034年前后并网，使加纳成为西非首个核电国家。投资额未正式披露，业界估算约50亿美元。","descEn":"Ghana's first nuclear power plant: a NuScale VOYGR-12 SMR (924MW) at the Nsuban site in Western Region, targeting operation around 2034.","detailEn":"Nuclear Power Ghana selected Nsuban (Western Region) as preferred site in 2023 and in August 2024 signed with US-based Regnum Technology to deploy a NuScale VOYGR-12 multi-module SMR plant (12x77MW, 924MW). An IAEA SEED mission in February 2025 endorsed the site-selection process. Ghana targets land acquisition and groundbreaking around 2027-28 and start-up around 2034, which would make it West Africa's first nuclear power nation. Cost undisclosed, estimated near $5bn.","progress":"2025年2月IAEA完成首次厂址审查并认可选址流程，项目向2027–2028年开工推进。"},
  {"id":6547,"name":"Cassava-英伟达南非AI工厂","en":"Cassava-Nvidia AI Factory South Africa","country":"南非","region":"非洲","cat":"datacenter","coord":[28.13,-25.93],"cap":"首期3000块英伟达GPU（泛非计划共1.5万块）","inv":7.2,"invText":"7.2亿美元（英伟达-Cassava泛非AI工厂计划）","status":"投运","year":2025,"updated":"2026-03","owner":"Cassava Technologies（与英伟达合作）","flagship":false,"desc":"非洲首座英伟达AI工厂：2025年6月3000块GPU在约翰内斯堡上线，提供全非首个GPU即服务。","detail":"泛非科技集团Cassava Technologies（Strive Masiyiwa创办）与英伟达2025年3月宣布合作，在非洲部署总额约7亿美元的AI基础设施。首期2025年6月在南非约翰内斯堡（Africa Data Centres园区）上线3000块英伟达GPU，建成非洲大陆首座'AI工厂'并推出首个GPU即服务（GPUaaS）平台；未来3–4年再部署1.2万块GPU，扩展至埃及、尼日利亚、肯尼亚和摩洛哥。该项目是英伟达在非洲的首次直接基础设施落地，瞄准主权AI与本地大模型训练需求。","descEn":"Africa's first Nvidia AI factory: 3,000 GPUs went live in Johannesburg in June 2025, launching the continent's first GPU-as-a-service.","detailEn":"Pan-African group Cassava Technologies and Nvidia announced a ~$700m partnership in March 2025 to build AI-ready infrastructure across Africa. The first phase deployed 3,000 Nvidia GPUs at Cassava's Johannesburg (Africa Data Centres) campus by June 2025 - the continent's first 'AI factory' and first GPU-as-a-service platform - with 12,000 more GPUs planned over 3-4 years across Egypt, Nigeria, Kenya and Morocco. It is Nvidia's first direct infrastructure deployment in Africa, targeting sovereign AI workloads.","progress":"2026年3月宣布向肯尼亚、尼日利亚、埃及扩展AI工厂网络，南非首期已商业运营。"},
  {"id":6548,"name":"微软南非云与AI基础设施扩建","en":"Microsoft South Africa Cloud & AI Infrastructure Expansion","country":"南非","region":"非洲","cat":"datacenter","coord":[28.05,-26.15],"cap":"GPU增强型数据中心扩容（约翰内斯堡/开普敦）","inv":3,"invText":"新增54亿兰特（≈3亿美元，此前已投200亿兰特）","status":"在建","year":2027,"updated":"2025-03","owner":"微软","flagship":false,"desc":"微软2025年3月宣布追加54亿兰特，2027年底前扩建南非AI与云数据中心。","detail":"微软2025年3月在约翰内斯堡宣布（南非总统拉马福萨出席），将在2027年底前追加投资54亿兰特（约2.97亿美元），扩建配备先进GPU的AI数据中心，承接AI训练与推理负载。此前三年微软已投入200亿兰特在约翰内斯堡和开普敦建成南非首批企业级超大规模数据中心区域。配套计划还包括为5万人支付云架构、AI与网络安全等高需求数字技能认证考试费用，巩固南非作为非洲云计算枢纽的地位。","descEn":"Microsoft announced an additional R5.4bn in March 2025 to expand GPU-equipped AI and cloud datacenters in South Africa by end-2027.","detailEn":"Announced in Johannesburg in March 2025 with President Ramaphosa attending, Microsoft will invest a further R5.4bn (~$297m) by the end of 2027 to build additional GPU-equipped datacenters for AI workloads, on top of R20bn invested over the prior three years establishing South Africa's first enterprise-grade hyperscale regions in Johannesburg and Cape Town. Microsoft will also fund technical certification exams for 50,000 people in cloud, AI and cybersecurity skills.","progress":"2025年3月宣布追加投资，GPU数据中心扩建推进中，目标2027年底完成。"},
  {"id":6549,"name":"莫桑比克-马拉维400千伏联网工程（MOMA）","en":"Mozambique-Malawi 400kV Interconnector (MOMA)","country":"莫桑比克—马拉维","region":"非洲","cat":"grid","coord":[34.3,-15.55],"cap":"400kV·142公里","inv":1.54,"invText":"1.54亿美元","status":"在建","year":2026,"updated":"2025-12","owner":"莫桑比克EDM / 马拉维ESCOM（世行、KfW、欧投行融资）","flagship":false,"desc":"马拉维首条区域联网线：太特Matambo至Phombeya 400kV线路，结束马拉维电网'孤岛'状态。","detail":"莫桑比克-马拉维（MOMA）联网工程包括太特省Matambo新建400kV变电站及一条142公里400kV输电线，接入马拉维Phombeya变电站，总投资1.54亿美元，由世界银行、德国复兴信贷银行（KfW）和欧洲机构融资。马拉维是南部非洲电力池中最后一个未与邻国联网的成员，工程建成后首期可从莫桑比克进口50MW电力，缓解马拉维严重缺电，并打通南部非洲区域电力贸易新通道。2025年底进入收尾调试阶段。","descEn":"Malawi's first regional grid link: a 142km 400kV line from Matambo (Tete) to Phombeya, ending Malawi's grid isolation with initial 50MW imports.","detailEn":"The $154m MOMA interconnection comprises a new 400kV substation at Matambo in Mozambique's Tete province and a 142km 400kV line to Malawi's Phombeya substation, funded by the World Bank, KfW and European institutions. Malawi was the last Southern African Power Pool member without a cross-border link; the line enables initial imports of 50MW from Mozambique, easing chronic shortages and opening regional power trade. Commissioning entered final stages in late 2025.","progress":"2025年12月工程接近完工，预计2026年初正式送电、马拉维开始进口50MW。","route":[[33.62,-16.16],[34.96,-14.98]]},
  {"id":6550,"name":"赞比亚-刚果（金）卡伦比拉-科卢韦齐互联线","en":"Kalumbila-Kolwezi 330kV Interconnector (Zambia-DRC)","country":"赞比亚—刚果（金）","region":"非洲","cat":"grid","coord":[25.8,-11.7],"cap":"330kV·约200公里","inv":2.7,"invText":"约2.7亿美元","status":"规划","year":2028,"updated":"2026-05","owner":"Enterprise Power DRC（IFC牵头融资）","flagship":false,"desc":"连接赞比亚西北省与刚果金铜钴矿带的330kV私营跨境输电线，输送能力最高700MW。","detail":"卡伦比拉-科卢韦齐互联项目（KKIP）为一条约200公里、330kV跨境输电线，连接赞比亚西北省卡伦比拉（第一量子矿区）与刚果（金）卢阿拉巴省科卢韦齐铜钴矿带，热稳定极限700MW，首期输送约460MW。项目由私营开发商Enterprise Power DRC主导，IFC于2024年11月受聘牵头安排融资，总投资约2.5–2.7亿美元；2025年5月赞比亚能源监管局核准项目，建设期约30个月。建成后将为两国缺电的矿业重镇提供关键电力通道，支撑铜钴增产。","descEn":"A privately developed 200km, 330kV cross-border line linking Zambia's Kalumbila mining hub with the DRC's Kolwezi copper-cobalt belt, rated up to 700MW.","detailEn":"The Kalumbila-Kolwezi Interconnector (KKIP) is a ~200km 330kV line connecting Kalumbila in Zambia's North-Western Province to Kolwezi in DRC's Lualaba copper-cobalt heartland, with a 700MW thermal limit and ~460MW initial capacity. Developer Enterprise Power DRC mandated the IFC as lead arranger in November 2024; Zambia's energy regulator approved the $250-270m project in May 2025, with ~30 months of construction to follow financial close. It will supply power-short mining regions on both sides of the border.","progress":"2025年5月获赞比亚监管核准，2026年刚果金政府寻求入股，融资关闭后开工。","route":[[25.33,-12.26],[25.47,-10.72]]},
  {"id":6551,"name":"马拉维姆帕塔曼加水电站","en":"Mpatamanga Hydropower Storage Project","country":"马拉维","region":"非洲","cat":"renewable","coord":[34.53,-15.52],"cap":"358.5MW（年发电量约1544GWh）","inv":15,"invText":"超15亿美元（马拉维史上最大外商投资）","status":"规划","year":2030,"updated":"2025-05","owner":"EDF/SN Malawi（Scatec·BII·Norfund·TotalEnergies）与马拉维政府","flagship":false,"desc":"马拉维史上最大投资项目：希雷河358.5MW调峰水电站，世行2025年5月批准3.5亿美元赠款。","detail":"姆帕塔曼加水电储能项目（MHSP）位于希雷河峡谷，含309MW调峰电站和下游52MW调节电站，总装机358.5MW、年发电约1544GWh，可使马拉维发电能力近乎翻倍。项目由EDF与SN Malawi（Scatec、英国国际投资BII、Norfund、TotalEnergies持股）联合马拉维政府以PPP模式开发，总成本超15亿美元，为马拉维史上最大外商直接投资。2025年5月15日世界银行批准3.5亿美元IDA赠款，IFC同步支持，目标2030年前后投运，将为超100万户家庭供电并支撑矿业负荷。","descEn":"Malawi's largest-ever investment: a 358.5MW peaking hydropower plant on the Shire River; the World Bank approved a $350m grant in May 2025.","detailEn":"The Mpatamanga Hydropower Storage Project comprises a 309MW peaking plant and a 52MW downstream regulating plant on the Shire River (358.5MW total, ~1,544GWh/yr), nearly doubling Malawi's generation capacity. Developed as a PPP by EDF and SN Malawi (Scatec, BII, Norfund, TotalEnergies) with the Government of Malawi, the >$1.5bn scheme is Malawi's largest-ever FDI. The World Bank approved a $350m IDA grant on 15 May 2025; commissioning is targeted around 2030, powering over one million households.","progress":"2025年5月世行批准3.5亿美元赠款，项目向最终投资决定与开工推进。"},
  {"id":6552,"name":"坦桑尼亚卡科诺水电站","en":"Kakono Hydropower Project","country":"坦桑尼亚","region":"非洲","cat":"renewable","coord":[31.35,-1.25],"cap":"87.8MW（年发电量约524GWh）","inv":3.5,"invText":"约3.5亿美元（含AfDB/欧盟/法开署3亿美元融资）","status":"在建","year":2028,"updated":"2025-06","owner":"TANESCO","flagship":false,"desc":"卡盖拉河87.8MW水电站，非行、欧盟与法开署融资3亿美元，支撑坦桑西北部电网。","detail":"卡科诺水电站位于坦桑尼亚西北部卡盖拉省（距布科巴约90公里、近乌干达边境）的卡盖拉河上，装机87.8MW，年发电量约524GWh，并配套220kV送出线路。非洲开发银行、欧盟和法国开发署联合提供3亿美元贷款/赠款，业主为国家电力公司TANESCO。项目是坦桑'十三五'发展规划重点电源之一，可替代昂贵柴油发电、改善西北湖区供电可靠性，目标2028年底前投入商运。2025年项目处于施工监理与EPC采购推进阶段。","descEn":"An 87.8MW hydropower plant on the Kagera River in northwest Tanzania, financed with $300m from AfDB, the EU and AFD, targeting commissioning by 2028.","detailEn":"The Kakono plant on the Kagera River in Kagera Region (90km west of Bukoba, near the Uganda border) will provide 87.8MW and ~524GWh annually with an associated 220kV transmission line. The African Development Bank, EU and AFD provide $300m in financing; TANESCO is the implementing utility. The project displaces costly diesel generation and improves reliability in the Lake Zone, with commercial operation targeted by end-2028. Procurement and supervision services advanced through 2025.","progress":"2025年EPC与施工监理采购推进，目标2028年底投运。"},
  {"id":6553,"name":"乌干达标准轨铁路（马拉巴-坎帕拉段）","en":"Uganda Standard Gauge Railway (Malaba-Kampala)","country":"乌干达","region":"非洲","cat":"transport","coord":[33.5,0.5],"cap":"273公里电气化标准轨（设计时速120公里）","inv":29,"invText":"27亿欧元（≈29亿美元）","status":"在建","year":2028,"updated":"2025-06","owner":"乌干达政府（EPC：土耳其Yapi Merkezi）","flagship":false,"desc":"乌干达首条标准轨铁路：马拉巴至坎帕拉273公里电气化线，土耳其Yapi Merkezi承建，2028年通车。","detail":"乌干达与土耳其Yapi Merkezi签订27亿欧元EPC合同，新建马拉巴（肯尼亚边境）经托罗罗、金贾至坎帕拉的273公里电气化标准轨铁路，采用UIC60钢轨、25吨轴重、设计时速120公里，工期48个月。穆塞韦尼总统2024年11月主持开工，2025年3月肯乌两国签署协议承诺2028年前贯通内罗毕-坎帕拉标轨通道，届时蒙巴萨港至坎帕拉货运时间从14小时级压缩、物流成本降约35%。该线与肯尼亚SGR西延工程衔接，是东非北方走廊一体化的关键一环。","descEn":"Uganda's first standard gauge railway: a 273km electrified line from Malaba to Kampala built by Yapi Merkezi under a EUR2.7bn EPC contract, opening by 2028.","detailEn":"Uganda signed a EUR2.7bn EPC contract with Turkey's Yapi Merkezi for the 273km electrified standard gauge line from Malaba via Tororo and Jinja to Kampala (UIC60 rail, 25t axle load, 120km/h design speed, 48-month schedule). President Museveni launched construction in November 2024, and a March 2025 Kenya-Uganda agreement commits both countries to completing the Nairobi-Kampala link by 2028, cutting freight costs by ~35%. The line anchors the East African Northern Corridor's integration with the Kenyan SGR extension.","progress":"2024年11月开工，2025年征地与土建全面铺开，目标2028年与肯尼亚段贯通。","route":[[34.17,0.63],[33.21,0.43],[32.58,0.32]]},
  {"id":6554,"name":"跨卡拉哈里铁路（博茨瓦纳-纳米比亚）","en":"Trans-Kalahari Railway (Botswana-Namibia)","country":"博茨瓦纳—纳米比亚","region":"非洲","cat":"transport","coord":[20.5,-23.3],"cap":"约1500公里重载铁路","inv":110,"invText":"约110亿美元（估，N$2000亿）","status":"规划","year":2027,"updated":"2025-10","owner":"博茨瓦纳/纳米比亚政府（PPP模式）","flagship":false,"desc":"搁置16年后重启：博茨瓦纳经卡拉哈里至纳米比亚沃尔维斯湾港的1500公里重载铁路，2027年开工。","detail":"跨卡拉哈里铁路（TKR）规划全长约1500公里，从博茨瓦纳（含Mmamabula煤田）横穿卡拉哈里沙漠直达纳米比亚沃尔维斯湾深水港，为博茨瓦纳煤炭、铜矿及区域货物提供绕开南非拥堵港口的出海通道，估算投资约110亿美元（N$2000亿）。两国2025年8月15日在马翁签署新协议加速推进；按2025年10月罗安达基建峰会披露的时间表，可研2026年4月完成后即启动国际招标，2027年4月完成评标授标、5月以PPP模式开工。已有十余家国际财团递交意向。","descEn":"Revived after 16 years: a ~1,500km heavy-haul railway from Botswana across the Kalahari to Namibia's Walvis Bay port, with construction targeted from 2027 under a PPP.","detailEn":"The Trans-Kalahari Railway would run ~1,500km from Botswana (including the Mmamabula coalfields) across the Kalahari to the deep-water port of Walvis Bay, giving Botswana's coal and copper exports a route bypassing South Africa's congested ports, at an estimated cost of ~$11bn (N$200bn). Ministers signed a fresh bilateral agreement on 15 August 2025 in Maun; per the October 2025 Luanda summit timeline, the feasibility study concludes April 2026, RFPs run to September 2026, awards by April 2027 and construction starts May 2027 as a PPP. Over a dozen international groups have submitted bids.","progress":"2025年8月两国签署新推进协议，可研2026年4月完成，目标2027年5月开工。","route":[[25.91,-24.65],[22,-23.3],[17.08,-22.57],[14.51,-22.96]]},
  {"id":6555,"name":"阿比让地铁1号线","en":"Abidjan Metro Line 1","country":"科特迪瓦","region":"非洲","cat":"transport","coord":[-4.02,5.35],"cap":"37公里·18座车站（日客流设计54万人次）","inv":15,"invText":"约15亿美元（法国融资）","status":"在建","year":2027,"updated":"2025-02","owner":"科特迪瓦政府（承建：布伊格/阿尔斯通/Colas/Keolis法国财团）","flagship":false,"desc":"撒哈拉以南非洲最大公共交通项目之一：阿比让南北向37公里城市铁路，2027年通车。","detail":"阿比让地铁1号线南北贯穿经济首都阿比让，从阿尼亚马至机场所在的波尔布埃，全长约37公里、首期18座车站，服务7个市镇，由法国政府融资约15亿美元，布伊格、阿尔斯通、Colas、Keolis等法国企业联合实施。2025年2月交通部长通报：老SITARAIL米轨改线基本完成、土方工程结束、埃布里耶潟湖上的高架桥施工中，4431栋征拆建筑已拆除4417栋。线路设计日客流约54万人次，目标2027年载客运营，是撒哈拉以南非洲在建最大城市轨道项目。","descEn":"One of Sub-Saharan Africa's largest transit projects: a 37km north-south urban rail line across Abidjan with 18 stations, opening in 2027.","detailEn":"Abidjan Metro Line 1 runs ~37km from Anyama to Port-Bouet (airport), serving seven communes with 18 stations initially, financed by France (~$1.5bn) and built by a Bouygues/Alstom/Colas/Keolis team. By February 2025 the SITARAIL track relocation was nearly complete, earthworks finished, the Ebrie Lagoon viaduct under construction and 4,417 of 4,431 buildings cleared. Designed for ~540,000 daily passengers, commercial launch is targeted for 2027 - the largest urban rail project under construction in Sub-Saharan Africa.","progress":"2025年2月土方完成、潟湖高架桥施工中，目标2027年通车。"},
  {"id":6556,"name":"科特迪瓦Baleine油气田三期","en":"Baleine Field Phase 3 (Cote d'Ivoire)","country":"科特迪瓦","region":"非洲","cat":"petro","coord":[-4.85,4.85],"cap":"15万桶/日原油+2亿立方英尺/日天然气（全场达产）","inv":50,"invText":"未披露（业界估约50亿美元）","status":"在建","year":2029,"updated":"2026-05","owner":"Eni（37.25%）/ Vitol / Petroci / SOCAR","flagship":true,"desc":"2026年5月FID：新建FPSO将Baleine原油产量从6万桶/日提升至15万桶/日，气产量全部供应国内。","detail":"Baleine是几内亚湾近年最大油气发现（Eni 2021年发现，2023年8月创纪录快速投产），也是全球首个宣称'净零排放（范围1+2）'的上游开发项目。2026年5月25日Eni与合作伙伴在阿比让批准三期最终投资决定：新建一艘高规格FPSO，将全场原油产能从约6万桶/日提至15万桶/日、天然气从8000万提至2亿立方英尺/日，气全部供应国内电网，巩固科特迪瓦区域能源枢纽地位。股东为Eni（37.25%）、Vitol（30%）、国家石油Petroci（22.75%）与阿塞拜疆SOCAR（10%）。投资额未披露，业界估算约50亿美元。","descEn":"FID taken in May 2026: a new FPSO will lift Baleine output from 60,000 to 150,000 bbl/d of oil and to 200 MMcf/d of gas, all gas going to the domestic grid.","detailEn":"Baleine, Eni's 2021 Gulf of Guinea discovery fast-tracked to production in August 2023, is billed as the world's first net-zero (Scope 1+2) upstream development. On 25 May 2026 Eni and partners approved the Phase 3 FID in Abidjan: a new high-spec FPSO will raise field capacity from ~60,000 to 150,000 bbl/d of oil and from 80 to 200 MMcf/d of gas, all allocated to Cote d'Ivoire's power sector. Partners: Eni 37.25%, Vitol 30%, Petroci 22.75%, SOCAR 10%. Capex undisclosed, estimated around $5bn.","progress":"2026年5月25日三期FID获批，新FPSO进入建造阶段。"},
  {"id":6557,"name":"安哥拉Quiluma-Maboqueiro天然气项目","en":"Angola New Gas Consortium (Quiluma & Maboqueiro)","country":"安哥拉","region":"非洲","cat":"petro","coord":[11.9,-6.3],"cap":"3.3亿立方英尺/日（合LNG约200万吨/年）","inv":30,"invText":"约30亿美元（估）","status":"投运","year":2026,"updated":"2026-03","owner":"Azule Energy（运营，37.4%）/ 雪佛龙CABGOC / Sonangol / TotalEnergies","flagship":false,"desc":"安哥拉首个非伴生气开发项目2026年3月投产，为索约Angola LNG厂提供稳定气源。","detail":"新天然气联合体（NGC）开发的Quiluma和Maboqueiro浅水气田是安哥拉首个非伴生天然气项目，包括两座海上井口平台、Kivinca Nvemba新建陆上气体处理厂及索约Angola LNG厂改造。Quiluma气田2026年3月17日投产，初期产量1.5亿立方英尺/日，2026年底达产3.3亿立方英尺/日，相当于年增约200万吨LNG原料气，显著提升Angola LNG开工率并延长其经济寿命。股东为运营方Azule Energy（bp/Eni合资，37.4%）、雪佛龙CABGOC（31%）、Sonangol（19.8%）和TotalEnergies（11.8%）。","descEn":"Angola's first non-associated gas development started production in March 2026, feeding the Angola LNG plant at Soyo.","detailEn":"The New Gas Consortium's Quiluma and Maboqueiro shallow-water fields are Angola's first non-associated gas development: two wellhead platforms, a new onshore gas plant at Kivinca Nvemba and upgrades to the Angola LNG facility at Soyo. First gas flowed on 17 March 2026 at 150 MMcf/d, ramping to 330 MMcf/d by end-2026 - equivalent to ~2 Mtpa of LNG feedstock, materially lifting Angola LNG utilization. Partners: operator Azule Energy (37.4%), Chevron's CABGOC (31%), Sonangol (19.8%), TotalEnergies (11.8%).","progress":"2026年3月17日Quiluma气田投产，年底目标达产3.3亿立方英尺/日。"},
  {"id":6558,"name":"几内亚宁巴铁矿","en":"Nimba Iron Ore Project (Guinea)","country":"几内亚","region":"非洲","cat":"mining","coord":[-8.45,7.58],"cap":"一期1500万吨/年，2027年扩至3000万吨/年高品位铁矿","inv":34,"invText":"约34亿美元（含利比里亚铁路港口改造6亿美元）","status":"在建","year":2027,"updated":"2025-09","owner":"Ivanhoe Atlantic（HPX，Robert Friedland）","flagship":true,"desc":"弗里德兰旗下几内亚东南部高品位铁矿，借道利比里亚铁路出海，首期1500万吨/年。","detail":"宁巴铁矿位于几内亚东南部宁巴山区，矿石品位高（DSO级，铁品位约62%以上），由Robert Friedland控制的Ivanhoe Atlantic（原HPX）开发，矿山开发成本约27.7亿美元，另投约6亿美元升级利比里亚既有铁路与布坎南港作为出海通道——区别于西芒杜的几内亚境内全新铁路方案。2025年利比里亚政府正式授予铁路与港口使用权，项目获世行集团MIGA/IFC支持意向并完成2亿美元融资，先期工程持续推进；一期目标1500万吨/年，2027年前后提升至3000万吨/年。矿区毗邻世界自然遗产地，环境审批要求严格。","descEn":"Friedland's high-grade DSO iron ore mine in southeast Guinea, exporting via upgraded Liberian rail to Buchanan port; 15 Mtpa initially, 30 Mtpa by ~2027.","detailEn":"The Nimba project in Guinea's southeast holds high-grade (>62% Fe) DSO ore, developed by Robert Friedland's Ivanhoe Atlantic (formerly HPX) at ~$2.77bn mine capex plus ~$600m to upgrade Liberia's existing railway and Buchanan port - a contrast to Simandou's greenfield Trans-Guinean route. Liberia granted rail and port access in 2025; the project drew World Bank Group (MIGA/IFC) backing interest and raised $200m, with early works ongoing. Phase 1 targets 15 Mtpa, ramping toward 30 Mtpa around 2027. Strict environmental conditions apply near the UNESCO World Heritage site.","progress":"2025年利比里亚授予铁路港口通行权，先期工程推进，首期出矿目标2026–2027年。"},
  {"id":6559,"name":"尼日尔达萨铀矿","en":"Dasa Uranium Mine (Niger)","country":"尼日尔","region":"非洲","cat":"mining","coord":[7.3,17.85],"cap":"处理矿石1000吨/日（约450万磅U3O8/年达产）","inv":4.25,"invText":"4.25亿美元","status":"在建","year":2026,"updated":"2025-12","owner":"Global Atomic（与尼日尔政府合资SOMIDA）","flagship":false,"desc":"尼日尔数十年来首个新建铀矿：加拿大Global Atomic开发的地下矿，2026年投料试产。","detail":"达萨铀矿位于尼日尔阿加德兹省（阿尔利特以南约105公里）的Tim Mersoi盆地，为高品位地下铀矿，由加拿大Global Atomic与尼日尔政府合资的SOMIDA公司开发，项目总投资约4.25亿美元，配套建设1000吨/日处理厂和制酸厂。2025年井下开拓超1200米、五个中段同时作业，处理厂设备与酸厂部件经尼日利亚陆运到场；计划2026年上半年首采矿石、下半年处理厂带料调试。在政变后法国Orano资产被接管的背景下，达萨是尼日尔军政府时期仍在推进的最大西方矿业投资，60%银行融资仍在落实中。","descEn":"Niger's first new uranium mine in decades: Global Atomic's high-grade underground Dasa mine targets first ore in H1 2026 and plant commissioning in H2 2026.","detailEn":"The Dasa deposit in the Tim Mersoi Basin (~105km south of Arlit, Agadez region) is a high-grade underground uranium mine developed by SOMIDA, Global Atomic's JV with the Niger state, at ~$425m total cost including a 1,000 t/d processing plant and acid plant. By 2025 over 1,200m of underground development was complete across five levels, with plant equipment arriving via Nigeria. First ore is targeted for H1 2026 and plant commissioning H2 2026. Dasa is the largest Western mining investment still advancing under Niger's junta, with 60% bank financing being finalized.","progress":"2025年底井下开拓超1200米、设备陆续到场，2026年投料调试。"},
  {"id":6560,"name":"纳米比亚埃坦戈铀矿","en":"Etango Uranium Project (Namibia)","country":"纳米比亚","region":"非洲","cat":"mining","coord":[14.78,-22.62],"cap":"350万磅U3O8/年（一期Etango-8）","inv":3.5,"invText":"约3.5亿美元","status":"在建","year":2028,"updated":"2025-12","owner":"Bannerman Energy","flagship":false,"desc":"澳企Bannerman在纳米比亚埃龙戈铀矿带的露天堆浸铀矿，早期工程过半，2028年首产。","detail":"埃坦戈铀矿位于纳米比亚埃龙戈省斯瓦科普蒙德附近的世界级铀矿带（毗邻Rossing与Husab），由澳交所上市的Bannerman Energy开发，一期Etango-8方案为露天开采+堆浸工艺，年产约350万磅U3O8，矿山寿命15年以上，可扩产。截至2025年12月已投入约5.456亿纳元（约4850万澳元）早期工程：施工电源送电、高压辊磨机完成出厂验收并运抵现场、堆浸场与破碎站土方大面积推进，承包商用工超120人、2026年初将增至约400人。公司在锁定承购与战略融资后做出全面建设FID，首批铀产品目标2028年。","descEn":"Bannerman Energy's open-pit heap-leach uranium mine near Swakopmund in Namibia's Erongo uranium province; early works well advanced, first output targeted 2028.","detailEn":"Etango, adjacent to the Rossing and Husab mines in Namibia's Erongo uranium belt, is being developed by ASX-listed Bannerman Energy. The Etango-8 phase is an open-pit, heap-leach operation producing ~3.5 Mlb U3O8 annually over a 15+ year life with expansion options. By December 2025 ~N$545.6m of early works were complete: construction power energized, the HPGR tertiary crusher delivered after factory acceptance, and bulk earthworks advanced on the heap leach pad and crusher areas, with the contractor workforce of 120+ Namibians set to reach ~400 in early 2026. Full FID follows offtake and financing; first production targeted 2028.","progress":"2025年底早期工程投入超5.4亿纳元，高压辊磨机到场，2028年首产铀。"},
  {"id":6561,"name":"摩洛哥ONEE电网侧储能计划","en":"Morocco ONEE 1,600MWh Grid-Scale BESS Programme","country":"摩洛哥","region":"非洲","cat":"storage","coord":[-6.58,34.26],"cap":"1600MWh（全国10个站点）","inv":3,"invText":"约3亿美元（估）","status":"规划","year":2026,"updated":"2025-04","owner":"ONEE（摩洛哥国家水电办公室）","flagship":false,"desc":"摩洛哥首个大规模电网侧储能：ONEE在凯尼特拉、塞塔特等10个站点部署1600MWh电池。","detail":"摩洛哥国家水电办公室（ONEE）2025年4月启动全国电网侧储能计划国际招标，在凯尼特拉、塞塔特等10个战略站点部署总计1600MWh电池储能系统，用于平抑快速增长的风光出力波动、提供调频与备用，是摩洛哥迄今最大规模的电网储能采购，多家中国储能企业参与竞标，估算投资约3亿美元，目标合同签订后18个月内投运。与之配套，MASEN同期获世行支持在努尔瓦尔扎扎特建设储能试验场。该计划是摩洛哥2030年可再生能源占比52%目标的关键灵活性支撑。","descEn":"Morocco's first large grid-scale storage: ONEE is procuring 1,600MWh of BESS across ten strategic sites including Kenitra and Settat, with an 18-month delivery timeline.","detailEn":"Morocco's national utility ONEE launched an international tender in April 2025 for 1,600MWh of battery energy storage across ten strategic grid nodes including Kenitra and Settat - the country's largest storage procurement to date, drawing bids from multiple Chinese suppliers, at an estimated ~$300m. Commissioning is targeted within 18 months of award, providing flexibility for Morocco's 52%-renewables-by-2030 target; in parallel MASEN won World Bank backing for a storage testbed at Noor Ouarzazate.","progress":"2025年4月国际招标发出，中企积极竞标，目标18个月内建成投运。"},
  {"id":6562,"name":"BTR摩洛哥正负极材料工厂","en":"BTR New Material Morocco Cathode & Anode Plants","country":"摩洛哥","region":"非洲","cat":"ci","coord":[-5.7,35.66],"cap":"负极材料6万吨/年+正极材料5万吨/年","inv":6,"invText":"约60亿迪拉姆（≈6亿美元，两厂合计）","status":"在建","year":2026,"updated":"2025-05","owner":"贝特瑞新材料（BTR）","flagship":false,"desc":"全球负极材料龙头贝特瑞在丹吉尔科技城建正负极双厂，供应福特等欧美车企。","detail":"深圳贝特瑞（BTR New Material，全球锂电负极材料出货量第一）在摩洛哥穆罕默德六世丹吉尔科技城布局两座工厂：5万吨/年正极材料厂和3.635亿美元、6万吨/年负极材料厂，合计投资约60亿迪拉姆（约6亿美元）。负极厂瞄准美欧市场关税与IRA本地化要求，福特拟签署含1.2亿美元预付款的供货协议。两厂2025年加快建设，目标2026年二季度起陆续投产，达产后年营收目标10亿美元。项目与国轩、中伟（COBCO）、雅化-LG等共同将摩洛哥推向全球电池材料新枢纽。","descEn":"BTR, the world's top anode maker, is building twin cathode (50kt) and anode (60kt) plants at Tangier Tech City, supplying Ford and Western carmakers.","detailEn":"Shenzhen-based BTR New Material, the world's largest lithium-battery anode producer, is building two plants at Mohammed VI Tangier Tech City: a 50,000 t/y cathode plant and a $363.5m, 60,000 t/y anode plant - about MAD6bn (~$600m) combined. The anode plant targets US/EU tariff and IRA localization rules, with Ford expected to sign a supply deal including a $120m prepayment. Construction accelerated through 2025 with production from Q2 2026 and a $1bn annual revenue target, cementing Morocco's rise as a global battery-materials hub alongside Gotion, CNGR's COBCO and Yahua-LG.","progress":"2025年两厂加快建设，负极厂目标2026年二季度投产。"},
  {"id":6563,"name":"埃塞俄比亚戈德丹格特化肥综合体","en":"Dangote Gode Urea Fertilizer Complex (Ethiopia)","country":"埃塞俄比亚","region":"非洲","cat":"ci","coord":[43.55,5.95],"cap":"尿素300万吨/年","inv":25,"invText":"25亿美元","status":"规划","year":2029,"updated":"2025-11","owner":"丹格特集团（60%）/ 埃塞俄比亚投资控股（40%）","flagship":false,"desc":"丹格特与埃塞政府25亿美元共建戈德300万吨/年尿素厂，气源来自欧加登Calub/Hilala气田。","detail":"2025年8月28日尼日利亚丹格特集团与埃塞俄比亚投资控股（EIH）签署协议，在索马里州戈德（Gode）建设25亿美元尿素化肥综合体，丹格特持股60%、EIH持股40%。工厂年产尿素300万吨，建成后将跻身全球前五大尿素单体基地，气源经管道直连欧加登盆地Calub和Hilala气田（中国保利协鑫开发）。2025年11月丹格特签约Saipem、印度EIL等推进尼日利亚与埃塞两地化肥扩建工程设计，建设周期约40个月。项目将把长期依赖进口化肥的埃塞俄比亚转变为区域化肥出口国。","descEn":"Dangote Group and Ethiopia signed a $2.5bn deal for a 3 Mtpa urea complex at Gode, fed by pipeline from the Calub and Hilala gas fields.","detailEn":"On 28 August 2025 Nigeria's Dangote Group and Ethiopian Investment Holdings agreed to build a $2.5bn urea complex at Gode in the Somali Region (Dangote 60%, EIH 40%). At 3 million tonnes per year it would rank among the world's five largest urea plants, with feedstock piped from the Poly-GCL-developed Calub and Hilala gas fields in the Ogaden Basin. In November 2025 Dangote engaged Saipem and India's EIL for engineering on its Nigeria and Ethiopia fertilizer expansions; construction is scheduled to take ~40 months, turning fertilizer-importing Ethiopia into a regional exporter.","progress":"2025年8月签署合资协议、11月Saipem/EIL获工程设计合同，建设周期约40个月。"},
  {"id":6564,"name":"OMVG 冈比亚河流域四国225kV互联环网","en":"OMVG 225kV Interconnection Loop (Senegal-Gambia-Guinea-Bissau-Guinea)","country":"塞内加尔—冈比亚—几内亚比绍—几内亚","region":"非洲","cat":"grid","coord":[-15,13],"cap":"1677km 225kV环网 / 800MW输送能力 / 15座变电站","inv":7.2,"invText":"约7.22亿美元","status":"投运","year":2025,"updated":"2026-06","owner":"OMVG（冈比亚河开发组织）","desc":"连接塞内加尔、冈比亚、几内亚比绍、几内亚四国的1677公里225kV输电环网，将几内亚水电送往区域电网。","detail":"OMVG能源项目由冈比亚河开发组织牵头、世界银行与非洲开发银行等出资，建设1677公里225kV跨国输电环网与15座225/30kV变电站，输送能力800MW，把几内亚卡莱塔与苏阿皮蒂水电站的清洁电力输往塞内加尔、冈比亚和几内亚比绍。截至2025年环网已基本建成投运：几内亚年外送电量达11.74亿千瓦时，跨境交易容量从2015年的零提升至34万千伏安；2025年2月冈比亚首条国家级225kV输变电工程（布里卡马—贾邦段）落成，大班珠尔地区接入区域环网。","descEn":"A 1,677 km, 225 kV transmission ring linking Senegal, The Gambia, Guinea-Bissau and Guinea, evacuating Guinean hydropower across the sub-region.","detailEn":"Led by the Gambia River Basin Development Organisation (OMVG) and financed by the World Bank, AfDB and others, the project built a 1,677 km 225 kV cross-border ring with fifteen 225/30 kV substations and 800 MW transfer capability, delivering power from Guinea's Kaleta and Souapiti hydro plants to Senegal, The Gambia and Guinea-Bissau. By 2025 the ring is substantially operational: Guinea exports about 1,174 GWh a year, cross-border trade capacity has grown from zero in 2015 to 340 MVA, and in February 2025 The Gambia inaugurated its first national 225 kV infrastructure (Brikama-Jabang) in the Greater Banjul Area.","progress":"环网2025年基本建成：几内亚年外送11.74亿千瓦时；2025年2月冈比亚布里卡马—贾邦225kV段落成投运。","route":[[-13.1,10.4],[-15.6,11.9],[-16.65,13.27],[-16.07,14.15],[-13.67,13.77]],"flagship":false},
  {"id":6565,"name":"莫桑比克泰马内—马普托400kV输电主干线（STE一期）","en":"Temane-Maputo 400kV Transmission Backbone (STE Phase 1), Mozambique","country":"莫桑比克","region":"非洲","cat":"grid","coord":[34,-23.8],"cap":"563km 400kV单回交流 + 3座新建变电站","inv":5.5,"invText":"约5.51亿美元","status":"在建","year":2027,"updated":"2026-06","owner":"STE/EDM（莫桑比克国家输电公司）","desc":"莫桑比克国家输电骨干网（STE）一期：维兰库卢—希布托—马塔拉内—马普托563公里400kV输电线。","detail":"泰马内输电项目（TTP）是莫桑比克一体化输电骨干系统（STE）的旗舰一期工程，沿海岸走廊新建维兰库卢—希布托—马塔拉内—马普托563公里400kV单回交流线路，配套新建维兰库卢、希布托、马塔拉内3座400kV变电站并扩建马普托变电站，总投资约5.51亿美元，由世界银行、非洲开发银行等联合融资，旨在把泰马内气电与北部水电送往南部负荷中心、打通南部非洲电力池（SAPP）南北通道。截至2025年11月，STE已支付5860万美元用于沿线征地补偿与安置（涉及2736处农田），线路工程全面推进。","descEn":"Phase 1 of Mozambique's integrated transmission backbone (STE): a 563 km, 400 kV line from Vilanculos via Chibuto and Matalane to Maputo.","detailEn":"The Temane Transmission Project (TTP), flagship first phase of Mozambique's STE backbone, builds a 563 km single-circuit 400 kV HVAC line from Vilanculos to Maputo with three new 400 kV substations (Vilanculos, Chibuto, Matalane) and an expanded Maputo substation. Costing about USD 551 million and co-financed by the World Bank and AfDB, it evacuates Temane gas-fired power and links the SAPP north-south corridor. By November 2025 STE had spent USD 58.6 million on resettlement and compensation covering 2,736 affected farms, with line construction in full swing.","progress":"2025年11月：征地补偿与安置支出达5860万美元，线路与3座变电站施工全面推进，目标2027年前后投运。","route":[[35.31,-22],[33.53,-24.69],[32.75,-25.6],[32.59,-25.96]],"flagship":false},
  {"id":6566,"name":"ZIZABONA 津赞博纳四国互联工程","en":"ZIZABONA Interconnector (Zimbabwe-Zambia-Botswana-Namibia)","country":"津巴布韦—赞比亚—博茨瓦纳—纳米比亚","region":"非洲","cat":"grid","coord":[25.85,-17.9],"cap":"422km 400kV（初期330kV运行）/ 首期300MW","inv":3,"invText":"约3亿美元（估）","status":"规划","year":2028,"updated":"2026-06","owner":"ZESA/ZESCO/BPC/NamPower","desc":"南部非洲电力池西部走廊：以维多利亚瀑布为枢纽，新建422公里400kV线路连接津、赞、博、纳四国电网。","detail":"ZIZABONA工程由津巴布韦、赞比亚、博茨瓦纳、纳米比亚四国电力公司联合开发，新建422公里400kV输电线（初期按330kV运行、首期输送300MW）：万盖—穆库尼（115公里）、维多利亚瀑布—潘达马滕加（76公里）、穆库尼—赞比西（231公里），在南部非洲电力池（SAPP）内打通西部输电走廊，缓解中部走廊拥塞并为纳米比亚、博茨瓦纳输入赞比西河水电。博、纳、津三国环评已完成；非洲开发银行2024年1月聘请顾问更新可研与环评，项目结构化推进，目标2025年融资关闭、2026—2028年建设、2028年起投运。","descEn":"The SAPP western corridor: 422 km of new 400 kV lines hubbed on Victoria Falls linking the grids of Zimbabwe, Zambia, Botswana and Namibia.","detailEn":"Jointly developed by ZESA, ZESCO, BPC and NamPower, ZIZABONA builds 422 km of 400 kV lines (initially operated at 330 kV, transferring 300 MW): Hwange-Mukuni (115 km), Victoria Falls-Pandamatenga (76 km) and Mukuni-Zambezi (231 km), creating a western transmission corridor in the Southern African Power Pool to decongest the central corridor. ESIAs are complete in Botswana, Namibia and Zimbabwe; the AfDB procured consultants in January 2024 to update feasibility and ESIA studies. Financial close was targeted for 2025, construction for 2026-2028 and operation from 2028.","progress":"三国环评完成，非行2024年起更新可研；项目结构化与融资推进，目标2026年开工、2028年投运。","route":[[26.5,-18.37],[25.85,-17.88],[24.28,-17.5]],"flagship":false},
  {"id":6567,"name":"Scatec埃及光储基荷项目（1.95GW/3.9GWh）","en":"Scatec Egypt 1.95GW Solar + 3.9GWh BESS Baseload Complex","country":"埃及","region":"非洲","cat":"storage","coord":[32.5,25.7],"cap":"1950MW光伏＋3900MWh电池储能（1座光储基荷+2座独立储能）","inv":20,"invText":"约20亿美元（估）","status":"规划","year":2028,"updated":"2026-06","owner":"Scatec","desc":"非洲最大光储项目：Scatec与埃及EETC签25年美元PPA，1.95GW光伏+3.9GWh储能提供全天候基荷绿电，年发电约60亿度。","detail":"挪威Scatec于2026年1月与埃及输电公司（EETC）签署里程碑式购电协议：总规模1.95GW光伏加3.9GWh电池储能，包括一座提供全天候基荷绿电的光储一体化电站和两座提供电网稳定服务的独立储能电站，是非洲最大的光伏+储能项目组合，也是Scatec史上最大投资。项目采用25年期美元计价、主权担保的'按发电量付费'PPA，年发电量约6000GWh，独立于其已并网的Obelisk项目，与埃及为4GWh储能融资的国家计划相衔接，缓解夏季高峰缺电。","descEn":"Africa's largest solar-plus-storage portfolio: Scatec signed a 25-year USD PPA with Egypt's EETC for 1.95GW solar + 3.9GWh BESS delivering round-the-clock baseload green power, about 6,000GWh per year.","detailEn":"Norway's Scatec signed a landmark PPA with the Egyptian Electricity Transmission Company (EETC) in January 2026 for 1.95GW of solar and 3.9GWh of battery storage - one integrated solar-BESS hybrid delivering around-the-clock renewable baseload power plus two standalone BESS plants providing grid stability services. It is Africa's largest solar-and-storage installation and the largest investment in Scatec's history, under a 25-year, USD-denominated, sovereign-guaranteed pay-as-produced PPA yielding about 6,000GWh annually. Separate from Scatec's operating Obelisk project (1.1GW + 200MWh), it dovetails with Egypt's plan to commission 600MW of storage by summer 2026 and finance 4GWh of BESS.","progress":"2026年1月11日签署PPA；项目推进融资关闭，埃及政府2026年5月承诺为全国合计4GWh储能项目融资，光储基荷电站预计2028年前后分期投运。","flagship":false},
  {"id":6568,"name":"尼日利亚拉各斯Kasi Cloud莱基数据中心园区","en":"Kasi Cloud Lekki Hyperscale Campus, Lagos","country":"尼日利亚","region":"非洲","cat":"datacenter","coord":[3.62,6.44],"cap":"规划100 MW（首期5.5 MW）","inv":2.5,"invText":"2.5亿美元","status":"投运","year":2026,"updated":"2026-06","owner":"Kasi Cloud / 尼日利亚主权投资局（NSIA）","desc":"西非首个具备超大规模与AI能力的数据中心园区在拉各斯莱基投运，规划IT容量100 MW。","detail":"Kasi Cloud在拉各斯莱基（Lekki）建成西非首个'hyperscale-ready'、可承载AI算力的数据中心园区，2026年5月正式投运，首期5.5 MW，整个园区按约100 MW IT容量规划。项目投资2.5亿美元，获尼日利亚主权投资局（NSIA）支持，毗邻多条国际海缆登陆站，定位为西非云与AI流量枢纽。在尼日利亚电网薄弱背景下，园区自建燃气+光伏混合供电保障可用性。","descEn":"West Africa's first hyperscale-ready, AI-capable data center campus opened in Lekki, Lagos, with a 100 MW design capacity.","detailEn":"Kasi Cloud commissioned West Africa's first hyperscale-ready, AI-capable data center campus in Lekki, Lagos in May 2026 — 5.5 MW in phase one, scaling toward roughly 100 MW of critical IT capacity. The $250m project is backed by the Nigeria Sovereign Investment Authority (NSIA) and sits near multiple subsea cable landings, positioning it as West Africa's cloud and AI traffic hub, with on-site gas + solar hybrid power to offset grid weakness.","progress":"2026年5月园区落成投运，首期5.5 MW上线，二期扩容推进中。","flagship":false},
  {"id":6569,"name":"肯尼亚Nxtra塔图城数据中心","en":"Nxtra by Airtel Tatu City Data Center, Nairobi","country":"肯尼亚","region":"非洲","cat":"datacenter","coord":[36.95,-1.13],"cap":"44 MW","inv":1.5,"invText":"约1.5亿美元（估）","status":"在建","year":2027,"updated":"2026-06","owner":"Nxtra by Airtel（Airtel Africa）","desc":"Airtel Africa旗下Nxtra在内罗毕近郊塔图城新建44 MW超大规模数据中心，2027年初投运。","detail":"Airtel Africa数据中心子公司Nxtra by Airtel于2025年9月在肯尼亚塔图城（Tatu City，内罗毕以北经济特区）开工建设44 MW数据中心，预计2027年一季度投运，建成后将是东非容量最大的数据中心之一。项目面向超大规模云商与AI工作负载，配套可再生能源供电，与Nxtra在拉各斯（Eko Atlantic）的园区共同构成其泛非数字基础设施网络。投资额未单独披露，按同类规模估算约1.5亿美元。","descEn":"Airtel Africa's Nxtra broke ground on a 44 MW hyperscale data center at Tatu City near Nairobi, due online in early 2027.","detailEn":"Nxtra by Airtel, Airtel Africa's data center arm, started construction in September 2025 on a 44 MW facility at Tatu City, the special economic zone north of Nairobi, with commissioning targeted for Q1 2027 — set to be among East Africa's largest. Designed for hyperscale cloud and AI workloads with renewable power, it pairs with Nxtra's Lagos (Eko Atlantic) campus in a pan-African digital infrastructure network. Investment undisclosed (est. ~$150m).","progress":"2025年9月开工，目标2027年第一季度投运。","flagship":false},
  {"id":6570,"name":"基通巴铜矿（赞比亚中矿资源）","en":"Kitumba Copper Mine","country":"赞比亚","region":"非洲","cat":"mining","coord":[26.92,-15.08],"cap":"年处理矿石450万吨、年产精炼铜5万吨","inv":6,"invText":"约6亿美元","status":"在建","year":2026,"updated":"2026-06","owner":"中矿资源（Sinomine）","desc":"中矿资源在赞比亚中央省穆姆布瓦区建设的露天铜矿与湿法冶炼一体化项目，2026年9月投产，年产精炼铜5万吨。","detail":"基通巴铜矿位于赞比亚中央省穆姆布瓦区，是中矿资源2023年收购后快速推进的绿地铜矿项目，总投资约6亿美元。项目2025年4月正式启动剥离施工，建设期约1.5年，计划2026年9月产出首批铜，年处理矿石450万吨、年产精炼铜约5万吨，矿山服务年限11年。项目配套建设50兆瓦光伏电站，自用之余余电上网，并创造约2500个就业岗位，是赞比亚『2031年300万吨铜产量』国家目标下的代表性新建矿山之一。","descEn":"Sinomine's $600m greenfield copper mine in Mumbwa, Central Zambia; stripping began April 2025, first refined copper due September 2026 at 50,000 t/y.","detailEn":"The Kitumba copper project in Zambia's Mumbwa district is Sinomine Resource Group's flagship African copper build. Stripping started in April 2025 with an 18-month construction schedule targeting first production in September 2026. The mine will process 4.5 Mt of ore annually for about 50,000 t of refined copper over an 11-year life, supported by a 50 MW solar plant and roughly 2,500 jobs, contributing to Zambia's 3 Mt/y copper ambition.","progress":"2025年4月启动剥离施工，计划2026年9月投产，配套50MW光伏电站同步建设。","flagship":false},
  {"id":6571,"name":"莫泰奥铜矿（博茨瓦纳Motheo）","en":"Motheo Copper Mine","country":"博茨瓦纳","region":"非洲","cat":"mining","coord":[22,-21.9],"cap":"年处理矿石520万吨、年产铜约5万吨（T3+A4双坑）","inv":4,"invText":"约4亿美元（含A4扩建）","status":"投运","year":2025,"updated":"2026-06","owner":"Sandfire Resources","desc":"澳企Sandfire在博茨瓦纳卡拉哈里铜矿带开发的T3/A4露天铜矿，2023年投产后扩至520万吨/年处理能力，2025年达产年产铜5万吨。","detail":"莫泰奥（Motheo）铜矿位于博茨瓦纳西部卡拉哈里铜矿带，由澳大利亚Sandfire Resources开发，开采T3与A4两个矿床。项目2023年8月正式开业，随即推进扩建：2023年10月A4矿坑开始采矿，12月完成球磨机调试，处理能力由320万吨/年提升至520万吨/年，2025年达到年产铜约5万吨的设计水平。Motheo与邻国纳米比亚的矿山共同确立了卡拉哈里铜矿带作为全球新兴铜产区的地位，也是博茨瓦纳经济摆脱钻石单一依赖的重要支点。","descEn":"Sandfire Resources' T3/A4 open-pit copper mine on Botswana's Kalahari Copper Belt: opened 2023, expanded to 5.2 Mtpa processing with the A4 pit, reaching ~50,000 t/y of copper in 2025.","detailEn":"Motheo, in western Botswana's Kalahari Copper Belt, is developed by Australia's Sandfire Resources across the T3 and A4 deposits. Officially opened in August 2023, the operation expanded quickly: A4 mining began in October 2023 and the ball-mill commissioning that December lifted processing capacity from 3.2 to 5.2 Mtpa, reaching about 50,000 t/y of copper in 2025. Motheo anchors the Kalahari Copper Belt as an emerging global copper district and supports Botswana's diversification beyond diamonds.","progress":"A4矿坑与520万吨/年扩建完成，2025年达产约5万吨铜/年。","flagship":false},
  {"id":6572,"name":"安赛乐米塔尔利比里亚铁矿二期扩建","en":"ArcelorMittal Liberia Phase 2 Expansion","country":"利比里亚","region":"非洲","cat":"mining","coord":[-8.6,7.45],"cap":"年产能由500万吨提升至2000万吨，西非首座铁矿石选厂（66%品位精矿）","inv":18,"invText":"18亿美元","status":"投运","year":2025,"updated":"2026-06","owner":"安赛乐米塔尔（ArcelorMittal）","desc":"安赛乐米塔尔投资18亿美元扩建利比里亚宁巴县铁矿：西非首座铁矿石选厂2024年四季度产出首批精矿，2025年底爬坡至2000万吨/年。","detail":"安赛乐米塔尔利比里亚二期扩建围绕宁巴县耶克帕/托卡德矿区展开，总投资由14亿美元上调至18亿美元，建成西非首座大型铁矿石选厂，可将低品位赤铁矿提纯为铁含量66%以上的高品位磁铁精矿。选厂2024年四季度产出首批精矿，2025年年中正式落成，年底爬坡至2000万吨/年运行产能，使利比里亚铁矿石产量从500万吨提升至2000万吨，并配套扩建矿山铁路与布坎南港物流体系，是利比里亚史上最大的私人投资项目，重塑该国在全球高品位铁矿供应链中的地位。","descEn":"ArcelorMittal's $1.8bn Phase 2 in Nimba County built West Africa's first iron-ore concentrator: first concentrate in Q4 2024, inaugurated mid-2025, ramping to a 20 Mtpa run-rate by end-2025 — quadrupling Liberia's iron-ore output.","detailEn":"ArcelorMittal Liberia's Phase 2 expansion around the Yekepa/Tokadeh mines in Nimba County, with capex revised from $1.4bn to $1.8bn, delivered West Africa's first large iron-ore concentrator, upgrading low-grade hematite to magnetite concentrate above 66% Fe. First concentrate came in Q4 2024, the plant was inaugurated in mid-2025, and the operation is ramping to a 20 Mtpa run-rate — quadrupling national output from 5 Mt — alongside upgraded rail and the port of Buchanan. It is the largest private investment in Liberia's history.","progress":"2024年四季度产出首批精矿，2025年年中选厂落成，年底爬坡至2000万吨/年。","flagship":false},
  {"id":6573,"name":"尼日利亚UTM浮式LNG（Yoho气田）","en":"UTM FLNG (Yoho Field, Nigeria)","country":"尼日利亚","region":"非洲","cat":"petro","coord":[7.8,4],"cap":"280万吨/年LNG＋30万吨/年LPG","inv":50,"invText":"约50亿美元（估）","status":"规划","year":2028,"updated":"2026-06","owner":"UTM Offshore（78%）/NNPC（20%）/三角洲州政府（8%）","desc":"尼日利亚首个浮式LNG项目：UTM在OML 104 Yoho气田部署280万吨/年FLNG，回收放空气，2024年获建造许可，目标2028年建成。","detail":"UTM FLNG是尼日利亚首个浮式液化天然气项目，部署于阿夸伊博姆州外海OML 104区块Yoho油气田，将目前放空燃烧的伴生气变现，日处理天然气1.76亿立方英尺，年产LNG 280万吨、LPG约30万吨及凝析油。UTM Offshore持股78%，国家石油公司NNPC持20%，三角洲州政府持8%。项目2024年3月进入EPCIC（设计采购建造安装调试）阶段，同年9月获联邦政府颁发尼日利亚首张FLNG建造许可证，计划2028年建成调试、次年投产，是尼日利亚天然气变现与减少放空燃烧战略的标志性工程。","descEn":"Nigeria's first floating LNG project: UTM Offshore's 2.8 mtpa FLNG at the Yoho field (OML 104) will monetize flared gas; licensed to construct in 2024, targeting completion in 2028.","detailEn":"UTM FLNG, moored at the Yoho field offshore Akwa Ibom (OML 104), will process 176 MMscf/d of currently flared associated gas into 2.8 mtpa of LNG plus ~300,000 t/y of LPG and condensate. UTM Offshore holds 78%, NNPC 20% and Delta State 8%. The project moved into EPCIC in March 2024 and received Nigeria's first FLNG License to Construct in September 2024, targeting commissioning in 2028 and production the following year.","progress":"2024年9月：获尼日利亚联邦政府FLNG建造许可证（全国首张），项目处于EPCIC推进与融资落实阶段，目标2028年建成。","flagship":false},
  {"id":6574,"name":"哈西鲁迈勒气田三期增压工程","en":"Hassi R'Mel Gas Boosting Phase III (Stage 2)","country":"阿尔及利亚","region":"非洲","cat":"petro","coord":[3.27,32.93],"cap":"维持1.88亿立方米/日产量平台（20台压缩机组）","inv":23,"invText":"23亿美元（EPC合同额）","status":"在建","year":2027,"updated":"2026-06","owner":"Sonatrach（EPC：Tecnimont/贝克休斯）","desc":"Sonatrach 2024年5月授予Tecnimont/贝克休斯23亿美元EPC合同，为非洲最大气田哈西鲁迈勒新建3座增压站、20台压缩机组，稳住对欧供气。","detail":"哈西鲁迈勒是非洲最大天然气田、阿尔及利亚对欧洲供气（经Transmed等管道）的核心气源。随地层压力衰减，Sonatrach启动三期增压工程（阶段2）：2024年5月与Tecnimont（Maire集团）/贝克休斯联合体签署约23亿美元EPC合同（Tecnimont份额约17亿美元），在气田中、北、南三个区域新建3座增压站，安装20台基于Frame 5燃机与BCL压缩机的压缩机组，并改造现有集气管网、新建3套凝析油脱汞装置。工期39个月（约2027年底建成），目标将气田产量平台稳定在1.88亿标方/日，对意大利及欧洲能源安全具有战略意义。","descEn":"Sonatrach awarded Tecnimont/Baker Hughes a $2.3bn EPC contract in May 2024 for three new boosting stations and 20 compression trains at Africa's largest gas field, securing supply to Europe.","detailEn":"Hassi R'Mel is Africa's largest gas field and the anchor of Algeria's pipeline exports to Europe. Phase III–Stage 2 of the boosting program, awarded in May 2024 to a Tecnimont (Maire)/Baker Hughes consortium for ~$2.3 billion ($1.7bn to Tecnimont), adds three compression stations (Centre, North, South) with 20 Frame 5/BCL compression trains, rehabilitates the gas gathering network and adds three condensate demercurization units. Completion is due within 39 months, holding the field's plateau at 188 MMsm3/d.","progress":"2024年5月签署EPC合同后进入实施阶段，工期39个月，预计2027年建成投用，维持1.88亿立方米/日产量平台。","flagship":false},
  {"id":6575,"name":"卡诺—马拉迪标轨铁路","en":"Kano-Maradi Standard Gauge Railway","country":"尼日利亚—尼日尔","region":"非洲","cat":"transport","coord":[7.8,12.8],"cap":"干线284公里（含支线全长约387公里）标准轨","inv":18,"invText":"合同额约18.2亿美元（另获非洲开发银行3.5亿美元融资）","status":"在建","year":2026,"updated":"2026-06","owner":"尼日利亚联邦交通部·Mota-Engil承建","desc":"尼日利亚卡诺经卡齐纳至尼日尔马拉迪的284公里跨境标轨铁路，葡企Mota-Engil史上最大合同（约18亿美元），蒂努布政府目标2026年建成。","detail":"卡诺—马拉迪标轨铁路自尼日利亚北部商业重镇卡诺经吉加瓦、卡齐纳州至边境吉比亚，跨境延至尼日尔南部马拉迪，干线284公里（含杜采支线全长约387公里），是西非内陆国尼日尔通往尼日利亚铁路网和拉各斯港的关键走廊。项目2021年签约，由葡萄牙Mota-Engil以约18.2亿美元承建——其公司史上最大合同，并另签9.16亿美元机车车辆供应协议；2024年10月尼日利亚获非洲开发银行3.5亿美元融资补缺口。卡诺—道拉首段原定2025年完工，蒂努布总统2025年5月宣布全线目标2026年建成，建成后将重塑萨赫勒内陆物流格局。","descEn":"A 284-km cross-border standard-gauge line from Kano via Katsina to Maradi in Niger — Mota-Engil's largest-ever contract at about USD 1.82 billion, backed by a USD 350 million AfDB loan, targeted for completion in 2026.","detailEn":"The Kano-Maradi SGR runs from Kano through Jigawa and Katsina states to the border at Jibiya and on to Maradi in southern Niger, with a 284-km mainline (about 387 km including the Dutse branch), giving landlocked Niger a rail corridor toward Nigeria's network and Lagos ports. Signed in 2021 with Portugal's Mota-Engil for about USD 1.82 billion — the company's largest contract ever, plus a USD 916 million rolling-stock deal — and bolstered by a USD 350 million AfDB facility in October 2024, the project is targeted by President Tinubu for completion in 2026.","progress":"2025-05：蒂努布总统宣布全线目标2026年建成；2024-10获非洲开发银行3.5亿美元融资，卡诺—道拉首段先行推进。","route":[[8.52,12],[7.6,12.99],[7.23,13.08],[7.1,13.49]],"flagship":false},
  {"id":6576,"name":"达喀尔恩达亚内深水港","en":"Port of Ndayane (Dakar, DP World)","country":"塞内加尔","region":"非洲","cat":"transport","coord":[-17.1,14.54],"cap":"一期840米码头 / 年吞吐120万TEU（5公里航道，靠泊366米级船舶）","inv":12,"invText":"总投资12亿美元（一期8.37亿美元）","status":"在建","year":2028,"updated":"2026-06","owner":"迪拜环球港务（DP World）·塞内加尔政府","desc":"DP World在西非最大投资：达喀尔以南恩达亚内新建深水集装箱港，总投资12亿美元，一期840米码头、120万TEU，2024年12月海工开工、2028年投运。","detail":"恩达亚内港位于达喀尔以南约50公里的波蓬基讷-恩达亚内海岸，是DP World在非洲最大的单笔港口投资（12亿美元），旨在替代拥挤的达喀尔老港、打造西非区域中转枢纽。一期投资8.37亿美元，建设840米集装箱码头与5公里进港航道，可靠泊366米级全球最大集装箱船，年吞吐能力120万TEU；二期再增410米码头。2024年12月挖泥船“Willem Van Rubroeck”号进场启动疏浚，标志海工正式开工，目标2028年投入运营。建设期创造逾1800个岗位，运营后预计支撑塞内加尔全国230万个就业。","descEn":"DP World's largest port investment in Africa: a USD 1.2 billion deepwater container port at Ndayane south of Dakar — an 840 m quay and 5 km channel for 366 m mega-ships, 1.2 million TEU in phase 1, dredging started December 2024 for 2028 operations.","detailEn":"The Port of Ndayane, about 50 km south of Dakar, is DP World's biggest single port investment in Africa at USD 1.2 billion, built to relieve the congested old port of Dakar and create a West African transshipment hub. Phase 1 (USD 837 million) delivers an 840 m container quay and a 5 km access channel for 366 m vessels, with 1.2 million TEU annual capacity; phase 2 adds another 410 m of quay. Maritime works began in December 2024 with the arrival of the dredger Willem Van Rubroeck, targeting operations by 2028, with over 1,800 construction jobs and support for an estimated 2.3 million jobs nationwide.","progress":"2024-12：挖泥船进场、海工正式开工，疏浚5公里航道；一期840米码头瞄准2028年投运。","flagship":false},
  {"id":6577,"name":"乌干达卡鲁马水电站","en":"Karuma Hydroelectric Power Station (600 MW)","country":"乌干达","region":"非洲","cat":"renewable","coord":[32.25,2.25],"cap":"600MW（6台100MW机组，非洲最大地下厂房电站）","inv":17,"invText":"约17亿美元（中国进出口银行贷款约85%）","status":"投运","year":2024,"updated":"2026-06","owner":"乌干达政府/中国水电（Sinohydro）承建","desc":"乌干达最大电站、非洲最大地下水电站：600MW卡鲁马2024年9月全面投运，全国装机跃升至2000MW。","detail":"卡鲁马水电站位于乌干达基里安东戈区、坎帕拉以北约270公里的基奥加尼罗河（维多利亚尼罗河）卡鲁马瀑布，装机600MW（6×100MW），厂房全部建于地下，是非洲最大的地下水电站，也是乌干达最大的发电设施。项目由中国水电（Sinohydro）承建，中国进出口银行提供约85%的贷款，2013年开工，历经多年延期后于2024年9月26日由总统穆塞韦尼主持竣工投运，使乌干达全国装机容量从1400MW跃升至2000MW，为乌干达工业化与电力出口（南苏丹、刚果东部）提供支撑，是中非共建\"一带一路\"能源合作的标志性工程。","descEn":"Uganda's largest power plant and Africa's largest underground power station: the 600 MW Karuma HPP entered full commercial operation in September 2024.","detailEn":"Karuma HPP sits on the Kyoga Nile at Karuma Falls in Kiryandongo district, about 270 km north of Kampala. With six 100 MW units in a fully underground powerhouse, it is Africa's largest underground power station and Uganda's biggest generating facility. Built by Sinohydro with about 85% financing from China EximBank, construction started in 2013 and President Museveni commissioned the plant on 26 September 2024, lifting Uganda's installed capacity from 1,400 MW to 2,000 MW.","progress":"2024年9月26日由总统穆塞韦尼主持全面竣工投运，乌干达全国装机由1400MW增至2000MW；电站同时支撑向南苏丹与刚果（金）东部的电力出口。","flagship":false},

  // ===== 欧洲（6585-6638）=====
  {"id":6585,"name":"波兰巴乌蒂克2&3海上风电（Bałtyk）","en":"Bałtyk 2 & 3 Offshore Wind Farms","country":"波兰","region":"欧洲","cat":"renewable","coord":[17,54.95],"cap":"1440MW（2×720MW，100台SG 14-236风机）","inv":78,"invText":"约72亿欧元（≈78亿美元）","status":"在建","year":2028,"updated":"2025-06","owner":"Equinor/Polenergia","flagship":false,"desc":"Equinor与Polenergia各720MW的两座波罗的海风场2025年5月完成FID与72亿欧元融资，2028年并网。","detail":"波兰波罗的海离岸22–37公里的两座姊妹风场，各装机720MW，合计1440MW，由挪威Equinor与波兰Polenergia各持50%。2025年5月19日作出最终投资决定，5月22日完成约72亿欧元项目融资关闭，约30家金融机构参与，含欧洲投资银行与北欧投资银行（EIB单独提供7亿欧元）。100台西门子歌美飒SG 14-236 DD风机由Cadeler安装，6月底进入海上施工阶段，2028年发电可满足波兰200多万户家庭需求，是2025年欧洲海上风电最大FID批次之一。","descEn":"Twin 720 MW Baltic Sea wind farms by Equinor and Polenergia reached FID and EUR 7.2bn financial close in May 2025, online 2028.","detailEn":"Located 22-37 km off the Polish coast, Bałtyk 2 and Bałtyk 3 total 1,440 MW, owned 50/50 by Equinor and Polenergia. FID was taken on 19 May 2025 and a EUR 7.2 billion financial close followed on 22 May with about 30 institutions including the EIB (EUR 700m) and Nordic Investment Bank. Siemens Gamesa supplies 100 SG 14-236 DD turbines installed by Cadeler; offshore construction began mid-2025, with power for over 2 million Polish households from 2028 — one of Europe's largest offshore wind FIDs of 2025.","progress":"2025年5月完成FID与72亿欧元融资关闭，6月底进入建设阶段，目标2028年全部投运。"},
  {"id":6586,"name":"西班牙安达卢西亚绿氢谷（Moeve）","en":"Moeve Andalusian Green Hydrogen Valley","country":"西班牙","region":"欧洲","cat":"renewable","coord":[-6.89,37.23],"cap":"规划2GW电解槽（一期Onuba 300MW），满产年产绿氢最高30万吨","inv":33,"invText":"全谷总投资超30亿欧元（一期超10亿欧元）","status":"在建","year":2027,"updated":"2025-12","owner":"Moeve（原Cepsa）/Masdar/Enagás Renovable","flagship":false,"desc":"Moeve在韦尔瓦与圣罗克布局2GW电解槽的欧洲旗舰绿氢项目，一期300MW已FID开建。","detail":"西班牙最大绿氢项目，由Moeve（原Cepsa）联合Masdar、Enagás Renovable在安达卢西亚两大能源园区布局：帕洛斯（韦尔瓦）与圣罗克（加的斯坎波德直布罗陀），合计规划电解能力2GW、年产绿氢最高30万吨，总投资超30亿欧元。2025年对一期Onuba 300MW（可选扩105MW）作出最终投资决定，单期投资超10亿欧元，并获西班牙政府NextGenerationEU框架下3.04亿欧元补助。韦尔瓦厂2026年投产、圣罗克厂2027年投运，供应炼化脱碳与绿色船燃。","descEn":"Moeve's flagship 2 GW-electrolysis green hydrogen valley in Andalusia took FID on its first 300 MW phase, with plants online 2026-2027.","detailEn":"Spain's largest green hydrogen scheme, led by Moeve (formerly Cepsa) with Masdar and Enagas Renovable, spans two energy parks at Palos de la Frontera (Huelva) and San Roque (Cadiz), targeting 2 GW of electrolysis and up to 300,000 t/y of green hydrogen with over EUR 3 billion total investment. FID on the first 300 MW Onuba phase (expandable by 105 MW) was taken in 2025 at over EUR 1 billion, supported by a EUR 304 million Spanish NextGenerationEU grant. Huelva starts up in 2026 and San Roque in 2027, decarbonising refining and supplying green marine fuels.","progress":"2025年对一期Onuba 300MW电解槽作出FID并动工，韦尔瓦厂2026年投产、圣罗克厂2027年投运。"},
  {"id":6587,"name":"乌克兰提利古拉风电二期（DTEK）","en":"Tyligulska Wind Farm Phase 2","country":"乌克兰","region":"欧洲","cat":"renewable","coord":[31.25,46.87],"cap":"384MW（64台Vestas V162-6.0），全场达498MW","inv":4.9,"invText":"约4.5亿欧元（≈4.9亿美元）","status":"在建","year":2026,"updated":"2025-01","owner":"DTEK","flagship":false,"desc":"战时乌克兰最大私人能源投资：DTEK投4.5亿欧元在尼古拉耶夫州扩建384MW风电，2026年底建成。","detail":"乌克兰开战以来最大的私人能源投资项目。DTEK在尼古拉耶夫州提利古拉风电场一期114MW（2023年5月战时建成）基础上扩建二期384MW，安装64台维斯塔斯EnVentus V162-6.0风机，总投资约4.5亿欧元，其中3.7亿欧元银行贷款由丹麦国家出口与投资基金（EIFO）担保。全场83台风机建成后年发电最高1.7TWh，可满足70万户家庭用电，距前线仅约百公里，是乌克兰战时能源韧性与分布式重建的标志工程，计划2026年四季度全部投运。","descEn":"DTEK's EUR 450m, 384 MW expansion of Tyligulska wind farm in Mykolaiv — Ukraine's largest private investment since the war began, due end-2026.","detailEn":"The largest private energy investment in wartime Ukraine. DTEK is expanding the Tyligulska wind farm in Mykolaiv oblast (phase 1, 114 MW, completed under fire in May 2023) with a 384 MW second phase of 64 Vestas EnVentus V162-6.0 turbines. Of the ~EUR 450 million cost, EUR 370 million in loans is guaranteed by Denmark's Export and Investment Fund (EIFO). The full 83-turbine, 498 MW farm will generate up to 1.7 TWh a year for 700,000 households, a symbol of Ukraine's energy resilience, with completion targeted for Q4 2026.","progress":"2025年1月敲定4.5亿欧元融资（EIFO担保3.7亿欧元贷款），风机吊装推进，目标2026年四季度建成。"},
  {"id":6588,"name":"乌克兰赫梅利尼茨基核电3&4号机组","en":"Khmelnytskyi NPP Units 3 & 4 Completion","country":"乌克兰","region":"欧洲","cat":"nuclear","coord":[26.64,50.3],"cap":"2×1000MW（3号机组VVER-1000续建，4号机组拟用西屋AP1000）","inv":20,"invText":"续建投资估算约20亿美元+（购保加利亚设备约6亿美元）（估）","status":"规划","year":2030,"updated":"2025-02","owner":"Energoatom（乌克兰国家核电）","flagship":false,"desc":"乌克兰拟购保加利亚贝列内核电设备续建3号机组、联手西屋以AP1000完成4号机组，弥补战时电力缺口。","detail":"乌克兰最大在建核电工程。赫梅利尼茨基核电站3、4号机组苏联时期开工后长期停建，战争摧毁大量火电后续建被提上战略议程：2025年2月乌最高拉达批准购入保加利亚贝列内核电站闲置的VVER-1000设备（约6亿美元）用于3号机组，4号机组及后续机组则与西屋合作采用AP1000技术——2022年双方已签约在乌建设9台AP1000。西屋正开展GAP安全分析，将续建机组安全水平提升至AP1000等级。保加利亚2025年4月一度反悔令设备方案存变数，战时融资与工期仍是最大挑战。","descEn":"Ukraine plans to finish Khmelnytskyi units 3 & 4 using Bulgarian VVER-1000 equipment and Westinghouse AP1000 technology to replace war-damaged capacity.","detailEn":"Ukraine's biggest nuclear construction effort. Units 3 and 4 at Khmelnytskyi, left unfinished since Soviet times, became strategic after Russian strikes destroyed much thermal capacity. In February 2025 the Verkhovna Rada approved buying unused VVER-1000 equipment (~$600m) from Bulgaria's cancelled Belene plant for unit 3, while unit 4 and further units would use Westinghouse AP1000 technology under the 2022 agreement for nine AP1000s in Ukraine. Westinghouse is performing a GAP safety analysis to bring the completed units towards AP1000 safety levels. Bulgaria's April 2025 reversal clouded the equipment deal, and wartime financing and scheduling remain the key risks.","progress":"2025年2月乌议会批准购入保加利亚贝列内设备续建3号机组；西屋开展AP1000化安全分析，保方反悔令方案存变数。"},
  {"id":6589,"name":"瑞典林哈尔斯韦勒SMR新核电（Videberg）","en":"Videberg Kraft SMRs at Ringhals/Varo","country":"瑞典","region":"欧洲","cat":"nuclear","coord":[12.11,57.25],"cap":"约1500MW（5×GE Vernova BWRX-300或3×罗尔斯·罗伊斯SMR）","inv":60,"invText":"投资未披露（估算约500–700亿瑞典克朗，≈60亿美元）（估）","status":"规划","year":2033,"updated":"2025-12","owner":"Vattenfall（Videberg Kraft）","flagship":false,"desc":"瑞典40年来首个新核电：Vattenfall选定GE Vernova与罗罗SMR入围，在林哈尔斯旁韦勒半岛建约1500MW小堆群。","detail":"瑞典重启核电的开篇之作。国有Vattenfall 2025年7月董事会决定，在西海岸林哈尔斯核电站旁的韦勒半岛新建约1500MW小型模块化反应堆群，供应商二选一：GE Vernova BWRX-300（5台）或罗尔斯·罗伊斯SMR（3台）。项目由多数控股子公司Videberg Kraft实施，瑞典工业财团Industrikraft参股，2025年12月23日正式向政府申请国家风险分担融资。选择SMR是因场地紧凑且需兼顾在运机组延寿至80年的物流；下一步还可能在林哈尔斯1、2号机组原址再添约1000MW。目标2030年代前半发出第一度电。","descEn":"Sweden's first new nuclear in 40 years: Vattenfall's Videberg Kraft shortlisted GE Vernova and Rolls-Royce SMRs for ~1,500 MW at the Varo Peninsula next to Ringhals.","detailEn":"The opening move of Sweden's nuclear revival. In July 2025 Vattenfall's board selected GE Vernova and Rolls-Royce SMR as the two candidate suppliers for roughly 1,500 MW of small modular reactors on the Varo Peninsula beside Ringhals — either five BWRX-300s or three Rolls-Royce SMRs. The project vehicle Videberg Kraft, backed by the Industrikraft consortium of Swedish industrials, applied for state risk-sharing financing on 23 December 2025. SMRs suit the tight site while existing Ringhals units are life-extended to 80 years; a further ~1,000 MW could follow on the old Ringhals 1/2 site. First power is targeted for the first half of the 2030s.","progress":"2025年7月选定GE Vernova与罗罗为候选供应商，12月Videberg Kraft正式向瑞典政府申请国家融资支持。"},
  {"id":6590,"name":"黑海海底电缆（格鲁吉亚—罗马尼亚）","en":"Black Sea Submarine Cable (Georgia-Romania)","country":"格鲁吉亚—罗马尼亚","region":"欧洲","cat":"grid","coord":[41.57,42.39],"cap":"±500kV HVDC，1000–1300MW，全长1195公里（海底1100公里）","inv":23,"invText":"初始预算约23亿美元","status":"规划","year":2029,"updated":"2026-02","owner":"GSE/Transelectrica","flagship":true,"desc":"连接格鲁吉亚阿纳克利亚与罗马尼亚康斯坦察的1195公里黑海直流海缆，把高加索绿电送入欧盟。","detail":"欧盟—高加索能源走廊的旗舰工程：从格鲁吉亚阿纳克利亚到罗马尼亚康斯坦察铺设1195公里（海底段1100公里）±500kV高压直流海缆，输电能力1000–1300MW，初始预算约23亿美元，目标2029年投运。项目将阿塞拜疆与格鲁吉亚的风光水绿电直送欧盟，也被视为绕开俄罗斯的战略通道。世界银行2024年批准3500万美元前期资金，项目列入ENTSO-E十年网络发展规划，2025年12月进入欧盟共同利益项目（PMI）程序，2026年2月格罗两国电网公司再签谅解备忘录，推进可研后开发与融资。","descEn":"A 1,195 km HVDC link from Anaklia (Georgia) to Constanta (Romania) bringing Caucasus green power into the EU, targeted for 2029.","detailEn":"Flagship of the EU-Caucasus energy corridor: a 1,195 km (1,100 km subsea) ±500 kV HVDC cable from Anaklia, Georgia to Constanta, Romania with 1,000-1,300 MW capacity and an initial budget of about $2.3 billion, targeting operation by 2029. It would deliver Azerbaijani and Georgian renewable power directly to the EU, bypassing Russia. The World Bank approved $35 million of preparatory funding in 2024; the project is in ENTSO-E's ten-year plans, entered the EU's Projects of Mutual Interest process in December 2025, and in February 2026 GSE and Transelectrica signed a new MoU to advance post-feasibility development and financing.","progress":"2025年12月进入欧盟共同利益项目（PMI）程序，2026年2月两国电网公司签署新谅解备忘录推进开发。","route":[[41.57,42.39],[28.66,44.17]]},
  {"id":6591,"name":"东部绿色链路3（彼得黑德—诺福克HVDC）","en":"Eastern Green Link 3 (EGL3)","country":"英国","region":"欧洲","cat":"grid","coord":[-1.78,57.5],"cap":"2GW ±525kV 海陆混合HVDC","inv":50,"invText":"主合同近30亿英镑，总投资估算约40亿英镑（估）","status":"规划","year":2034,"updated":"2025-12","owner":"National Grid/SSEN Transmission","flagship":false,"desc":"苏格兰彼得黑德至英格兰诺福克的2GW直流'电力高速'，2025年12月获Ofgem提前建设资金。","detail":"英国'大电网升级'东海岸直流环网的第三条干线，由National Grid与SSEN Transmission合资，从苏格兰阿伯丁郡彼得黑德经海底与陆上混合走廊接入诺福克新建Walpole B变电站，输电能力2GW、采用±525kV高压直流，把苏格兰过剩海上风电南送英格兰负荷中心。2025年12月Ofgem批准EGL3与EGL4的早期建设与前期资金（EGL3为更新成本预测的8%），可提前锁定换流阀与海缆等紧俏供应链；National Grid已签署近30亿英镑换流站与电缆合同，目标2034年8月投运。","descEn":"A 2 GW HVDC 'electricity superhighway' from Peterhead, Scotland to a new Walpole B substation in Norfolk, granted Ofgem early-construction funding in December 2025.","detailEn":"The third trunk line of Great Britain's eastern HVDC ring under the Great Grid Upgrade, jointly developed by National Grid and SSEN Transmission. EGL3 runs from Peterhead in Aberdeenshire via subsea and onshore ±525 kV HVDC to a new Walpole B substation in Norfolk, carrying 2 GW of surplus Scottish offshore wind to English demand centres. In December 2025 Ofgem approved early construction and preconstruction funding (8% of EGL3's updated cost forecast), enabling early procurement of scarce converters and cable; National Grid has signed nearly GBP 3 billion of converter and cable contracts, targeting delivery by August 2034.","progress":"2025年12月Ofgem批准提前建设资金，近30亿英镑换流站与海缆合同已签署，目标2034年投运。","route":[[-1.78,57.5],[0.17,52.74]]},
  {"id":6592,"name":"苏格兰厄尔巴抽水蓄能（Earba）","en":"Earba Pumped Storage Hydro","country":"英国","region":"欧洲","cat":"storage","coord":[-4.45,56.92],"cap":"1800MW/40GWh（满功率22小时）","inv":31,"invText":"估算约25亿英镑（估）","status":"规划","year":2031,"updated":"2025-04","owner":"Gilkes Energy","flagship":false,"desc":"英国迄今核准最大抽蓄：苏格兰高地厄尔巴湖1.8GW/40GWh方案2025年4月获规划许可。","detail":"英国'抽蓄复兴'的标杆项目。Gilkes Energy在苏格兰高地凯恩戈姆国家公园边缘、格拉斯哥以北约200公里处开发：以莱文湖为上库、厄尔巴湖为下库，由约3公里隧道连接，装机1800MW、储能40GWh，可在满功率下连续放电22小时，规模超过此前所有英国抽蓄。2025年4月（3月底）获苏格兰政府规划许可，成为英国有史以来核准的最大抽水蓄能工程。项目正等待英国政府与Ofgem的长时储能'上限-下限'（Cap & Floor）收益机制落地后推进投资决定，建设期约5年、平均用工500人。","descEn":"The UK's largest consented pumped storage: Gilkes Energy's 1.8 GW / 40 GWh Earba scheme in the Scottish Highlands won planning consent in April 2025.","detailEn":"The flagship of Britain's pumped-hydro revival. Gilkes Energy's scheme on the edge of the Cairngorms, ~200 km north of Glasgow, uses Loch Leamhain as upper and Loch Earba as lower reservoir, linked by a ~3 km tunnel, for 1,800 MW and 40 GWh — 22 hours of discharge at full power, larger than any existing UK scheme. The Scottish Government granted planning consent in late March/April 2025, making it the largest pumped storage project ever consented in the UK. An investment decision awaits the LDES Cap & Floor revenue mechanism being implemented by the UK government and Ofgem; construction would take about five years with an average workforce of 500.","progress":"2025年4月获苏格兰政府规划许可，等待长时储能Cap & Floor机制落地后作出投资决定。"},
  {"id":6593,"name":"比利时绿龟电池储能园（Green Turtle）","en":"Green Turtle Battery Park","country":"比利时","region":"欧洲","cat":"storage","coord":[5.73,51.03],"cap":"700MW/2800MWh（720组电池+5台高压变压器1500MVA）","inv":6,"invText":"投资未披露（估算约5–6亿欧元）（估）","status":"规划","year":2028,"updated":"2025-10","owner":"GIGA Storage","flagship":false,"desc":"荷兰GIGA Storage在比利时林堡省建设700MW/2.8GWh电池园，欧洲最大BESS之一。","detail":"欧洲最大电池储能项目之一。荷兰开发商GIGA Storage在比利时林堡省迪尔森-斯托克姆Rotem工业区开发，规模700MW/2800MWh，相当于约38.5万户家庭年用电量，由720组电池+逆变器、185台中压变压器与5台合计1500MVA高压变压器组成，紧邻Elia运营的Van Eyck—Gramme 380kV高压走廊新建变电站。项目获许可后由Sweco承担设计（2024年容量从最初方案扩至2.8GWh），计划2025年底开工、2028年建成投运，为比利时核电退役与海上风电消纳提供灵活性。","descEn":"Dutch developer GIGA Storage is building one of Europe's largest battery parks — 700 MW / 2.8 GWh — at Dilsen-Stokkem in Belgian Limburg.","detailEn":"One of Europe's largest battery energy storage systems. GIGA Storage Belgium is developing the Green Turtle park at the Rotem industrial area in Dilsen-Stokkem, Limburg: 700 MW / 2,800 MWh — about the annual consumption of 385,000 households — built from 720 battery-inverter units, 185 MV transformers and five HV transformers totalling 1,500 MVA, next to a new 380 kV substation on Elia's Van Eyck-Gramme line. Permitted and designed by Sweco (expanded to 2.8 GWh in 2024), construction is planned from end-2025 with full operation in 2028, providing flexibility as Belgium retires nuclear units and absorbs offshore wind.","progress":"已获许可并完成Sweco工程设计，计划2025年底开工、2028年全面投运。"},
  {"id":6594,"name":"INEOS安特卫普一号工程乙烷裂解装置","en":"INEOS Project ONE Ethane Cracker","country":"比利时","region":"欧洲","cat":"ci","coord":[4.3,51.3],"cap":"145万吨/年乙烯（欧洲最低碳裂解装置）","inv":44,"invText":"约40亿欧元","status":"在建","year":2026,"updated":"2026-01","owner":"INEOS","flagship":true,"desc":"欧洲25年来最大化工投资：INEOS安特卫普港40亿欧元乙烷裂解装置2026年投产。","detail":"欧洲化工业25年来最大单笔投资。英力士（INEOS）在安特卫普港建设的'一号工程'（Project ONE）乙烷裂解装置投资约40亿欧元，年产乙烯超145万吨，建设高峰用工逾3000人，投产后新增450个直接岗位。装置以乙烷为原料、配套电驱与余热回收，碳足迹仅为欧洲蒸汽裂解装置平均水平的三分之一、优于欧洲最佳10%装置的一半，定位为'欧洲最绿色裂解装置'。项目历经环保诉讼后获安特卫普省许可并完成35亿欧元融资，2026年进入机械竣工与调试投产阶段，被视为欧洲基础化工竞争力的风向标。","descEn":"Europe's biggest chemical investment in 25 years: INEOS's EUR 4bn Project ONE ethane cracker in Antwerp starts up in 2026.","detailEn":"The largest investment in European chemicals in a quarter century. INEOS's Project ONE in the Port of Antwerp is a ~EUR 4 billion ethane cracker producing over 1.45 million tonnes of ethylene a year, employing 3,000+ at construction peak and creating 450 permanent jobs. Running on ethane with electric drives and heat integration, its carbon footprint is a third of the average European steam cracker and less than half of the best 10% — billed as Europe's greenest cracker. After permit litigation it secured EUR 3.5 billion financing and provincial approval, and moves through mechanical completion and commissioning to startup in 2026, a bellwether for European base-chemicals competitiveness.","progress":"装置进入机械竣工与调试冲刺，计划2026年投产，年产乙烯超145万吨。"},
  {"id":6595,"name":"斯洛伐克国轩-InoBat舒拉尼电池工厂（GIB）","en":"Gotion InoBat Batteries (GIB) Surany Gigafactory","country":"斯洛伐克","region":"欧洲","cat":"ci","coord":[18.19,48.09],"cap":"一期20GWh（远期可扩至40GWh）","inv":13,"invText":"约12亿欧元","status":"在建","year":2027,"updated":"2025-10","owner":"国轩高科/InoBat（GIB）","flagship":false,"desc":"斯洛伐克首座电池超级工厂：国轩高科与InoBat合资12亿欧元、一期20GWh，2025年10月动工。","detail":"斯洛伐克首座大规模电池工厂。中国国轩高科（持股80%）与斯洛伐克InoBat（20%）的合资公司GIB在舒拉尼建设占地65公顷的超级工厂，总投资约12亿欧元，一期年产能20GWh、远期可翻倍至40GWh，主要面向欧盟电动车与储能市场。2025年10月28日举行奠基仪式，斯总理菲佐与国轩董事长李缜出席；计划2026年9月试产、2027年量产，一期创造约1300个岗位、终期最多3500人。项目是欧洲电池'幸存者'阵营中由中资技术输出落地的代表案例，也是斯洛伐克汽车工业电动化转型的关键配套。","descEn":"Slovakia's first gigafactory: the Gotion-InoBat JV broke ground at Surany in October 2025 on a EUR 1.2bn, 20 GWh (to 40 GWh) battery plant.","detailEn":"Slovakia's first large-scale battery cell plant. GIB — a JV of China's Gotion High-Tech (80%) and Slovakia's InoBat (20%) — is building a 65-hectare gigafactory at Surany with ~EUR 1.2 billion investment, 20 GWh of first-phase capacity doubling to 40 GWh, serving EU EV and storage markets. Ground was broken on 28 October 2025 with PM Robert Fico and Gotion chairman Li Zhen attending; pilot production is slated for September 2026 and series production in 2027, creating ~1,300 jobs initially and up to 3,500 at full build-out. It is a flagship case of Chinese battery technology localising in Europe and a key enabler of Slovakia's automotive electrification.","progress":"2025年10月28日动工，计划2026年9月试产、2027年量产，一期20GWh。"},
  {"id":6596,"name":"英国南威尔士Vantage AI数据中心园区","en":"Vantage South Wales AI Data Center Campus","country":"英国","region":"欧洲","cat":"datacenter","coord":[-3.58,51.51],"cap":"AI增长区规划超1GW算力负荷（2030年代初投运）","inv":131,"invText":"Vantage约100亿英镑（微软另承诺25亿英镑）","status":"规划","year":2030,"updated":"2025-11","owner":"Vantage Data Centers/微软","flagship":false,"desc":"英国第四个AI增长区落地南威尔士：Vantage拟投100亿英镑沿M4走廊建超大规模AI数据中心群。","detail":"英国政府2025年11月宣布的第四个'AI增长区'，沿纽波特至布里真德的M4走廊布局，目标2030年代初形成超1GW算力容量、带动约100亿英镑投资与至少5000个岗位。核心开发商Vantage Data Centers计划在该区域投入约100亿英镑（其在英120亿英镑承诺的主体），包括将布里真德原福特发动机厂改造为数据中心园区；微软同步承诺25亿英镑在威尔士扩建数据中心（含纽波特站点）。项目使南威尔士跻身欧洲AI基础设施第一梯队，也是英国'算力主权'战略的支柱工程。","descEn":"The UK's fourth AI Growth Zone in South Wales: Vantage plans ~GBP 10bn of hyperscale AI data centers along the M4 corridor, with Microsoft adding GBP 2.5bn.","detailEn":"Announced in November 2025 as Britain's fourth AI Growth Zone, spanning the M4 corridor from Newport to Bridgend and targeting over 1 GW of operational capacity by the early 2030s, ~GBP 10 billion of investment and at least 5,000 jobs. Anchor developer Vantage Data Centers plans to spend about GBP 10 billion there — the bulk of its GBP 12 billion UK commitment — including converting the former Ford engine plant at Bridgend into a campus, while Microsoft has pledged GBP 2.5 billion for Welsh data centers including a Newport site. The zone lifts South Wales into Europe's first tier of AI infrastructure and anchors the UK's compute-sovereignty strategy.","progress":"2025年11月英国政府将南威尔士列为第四个AI增长区，Vantage拟投约100亿英镑、微软承诺25亿英镑。"},
  {"id":6597,"name":"法兰克福机场3号航站楼","en":"Frankfurt Airport Terminal 3","country":"德国","region":"欧洲","cat":"transport","coord":[8.59,50.02],"cap":"1900万人次/年（G/H/J三指廊，远期K指廊扩至2500万）","inv":43,"invText":"约40亿欧元","status":"投运","year":2026,"updated":"2026-04","owner":"Fraport","flagship":false,"desc":"欧洲最大私人融资基建：法兰克福机场40亿欧元T3航站楼2026年4月启用，新增1900万人次年吞吐。","detail":"德国最大机场的世代工程、欧洲最大私人融资基础设施项目。法兰克福机场3号航站楼投资约40亿欧元，建筑面积17.6万平方米，首期含G、H、J三座指廊，年吞吐能力1900万人次，总体规划预留K指廊、可扩至2500万人次。历经十余年建设后于2026年4月22日落成、4月23日投入运营，原2号航站楼全部57家航空公司整体迁入。T3配套全自动行李系统与轨道捷运（Sky Line延伸线），使法兰克福枢纽总容量逼近9000万人次，巩固其欧洲第四大、德国第一大航空门户地位。","descEn":"Europe's largest privately financed infrastructure project: Frankfurt Airport's EUR 4bn Terminal 3 opened in April 2026 with 19 million annual passenger capacity.","detailEn":"A generational expansion of Germany's busiest airport and Europe's largest privately funded infrastructure project. Terminal 3 cost about EUR 4 billion, spans 176,000 m2 and opens with piers G, H and J for 19 million passengers a year, with a provisioned pier K lifting capacity to 25 million. After more than a decade of construction it was inaugurated on 22 April 2026, with regular operations from 23 April; all 57 airlines from Terminal 2 relocate there. With an automated baggage system and an extended Sky Line people mover, T3 pushes the hub's total capacity towards 90 million passengers, cementing Frankfurt as Germany's top aviation gateway.","progress":"2026年4月22日落成启用、23日投入运营，原T2全部57家航空公司迁入。"},
  {"id":6598,"name":"格但斯克波罗的海枢纽T3集装箱码头","en":"Baltic Hub T3 Container Terminal","country":"波兰","region":"欧洲","cat":"transport","coord":[18.71,54.4],"cap":"新增150万TEU/年（港口总能力提升至450万TEU）","inv":5.5,"invText":"约4.7亿欧元（≈5.5亿美元）","status":"投运","year":2025,"updated":"2025-11","owner":"Baltic Hub（PSA国际港务集团）","flagship":false,"desc":"格但斯克Baltic Hub第三码头2025年投运，新增150万TEU年能力，巩固波罗的海集装箱枢纽地位。","detail":"中东欧最大集装箱港的关键扩建。格但斯克Baltic Hub（原DCT）T3深水码头投资约4.7亿欧元，2022年11月开工、2025年6月落成、11月全面投入运营，新增近150万TEU年处理能力，使港口总能力达450万TEU。码头配备7台欧洲最高等级的半自动岸桥（可作业24000TEU+超大型集装箱船）与20台远程操控全电动自动化轨道吊，是波罗的海首个具备规模化自动化作业的码头。T3使格但斯克跃升为波罗的海无可争议的集装箱枢纽与乌克兰重建、中欧班列海铁联运的重要门户。","descEn":"Baltic Hub's EUR 470m T3 deep-water terminal in Gdansk became fully operational in November 2025, adding ~1.5m TEU and lifting capacity to 4.5m TEU.","detailEn":"A pivotal expansion of Central-Eastern Europe's largest container port. The ~EUR 470 million T3 deep-water terminal at Gdansk's Baltic Hub (formerly DCT) broke ground in November 2022, was inaugurated in June 2025 and became fully operational in November 2025, adding nearly 1.5 million TEU and lifting total capacity to 4.5 million TEU. It features seven semi-automatic STS cranes among Europe's tallest — able to work 24,000+ TEU megaships — and 20 remotely operated, fully electric automated RMG cranes, the Baltic's first automated yard at scale. T3 confirms Gdansk as the Baltic's pre-eminent container hub and a key gateway for Ukraine reconstruction and rail-sea intermodal flows.","progress":"2025年6月落成、11月全面投运，港口总能力提升至450万TEU。"},
  {"id":6599,"name":"英国HyNet利物浦湾CCS（Eni）","en":"HyNet Liverpool Bay CCS","country":"英国","region":"欧洲","cat":"petro","coord":[-3.4,53.42],"cap":"一期450万吨/年CO₂封存（2030年代可扩至1000万吨）","inv":31,"invText":"融资规模约25亿英镑（≈31亿美元）","status":"在建","year":2028,"updated":"2025-04","owner":"Eni","flagship":false,"desc":"英国首批CCS集群之一：Eni利物浦湾枯竭气藏封存工程2025年4月完成融资关闭，2028年启动。","detail":"英国西北部HyNet工业集群的碳运输与封存主干网。意大利Eni作为运营商，将英格兰西北与北威尔士各捕集点的CO₂经149公里新建及改造管道（其中35公里新建）输往利物浦湾海床下的枯竭气藏永久封存，一期年封存450万吨、2030年代可扩至1000万吨。2025年4月24日Eni与英国能源安全与净零部（DESNZ）完成约25亿英镑融资关闭，当年开工、计划2028年投运，建设期创造约2000个岗位、供应链合同约20亿英镑。与东海岸集群并列为英国政府'Track-1'首批CCS集群，是欧洲CCS商业化的标志性突破。","descEn":"One of the UK's first CCS clusters: Eni's Liverpool Bay CO2 transport & storage backbone for HyNet reached GBP 2.5bn financial close in April 2025, start-up 2028.","detailEn":"The CO2 transport and storage backbone of the HyNet industrial cluster in north-west England. Operator Eni will pipe CO2 from capture plants across the North West and North Wales through 149 km of new and repurposed pipelines (35 km new) into depleted gas reservoirs beneath Liverpool Bay, storing 4.5 Mt/y in phase one and up to 10 Mt/y in the 2030s. Eni and the UK's DESNZ reached financial close of about GBP 2.5 billion on 24 April 2025, with construction starting the same year and start-up planned for 2028, ~2,000 construction jobs and ~GBP 2 billion of supply-chain awards. Alongside the East Coast Cluster it forms the UK's Track-1 CCS vanguard — a landmark for commercial CCS in Europe.","progress":"2025年4月与英国政府完成约25亿英镑融资关闭并于年内开工，计划2028年启动注入。"},
  {"id":6600,"name":"英国蒂赛德净零电站与北方耐力CCS","en":"Net Zero Teesside Power & Northern Endurance Partnership","country":"英国","region":"欧洲","cat":"petro","coord":[-1.14,54.6],"cap":"742MW燃气+CCS电站，年捕集约200万吨CO₂（封存网起步400万吨/年）","inv":51,"invText":"FID合计约51亿美元（EPC合同约40亿英镑）","status":"在建","year":2028,"updated":"2024-12","owner":"bp/Equinor/TotalEnergies","flagship":false,"desc":"全球首座商业规模燃气+CCS电站：bp与Equinor蒂赛德项目2024年12月FID，2028年投运。","detail":"英国首批进入执行阶段的CCS工程、全球首座商业规模配套碳捕集的燃气电站。2024年12月，bp（NZT Power持股75%、运营方）、Equinor与TotalEnergies对'蒂赛德净零电站'（742MW燃气+CCS，年捕集最高200万吨CO₂）和'北方耐力伙伴'海上封存网（NEP，bp 45%/Equinor 45%/Total 10%）作出最终投资决定并完成融资，合计约51亿美元，九家EPC承包商合同总额约40亿英镑。NEP起步年输送封存400万吨CO₂，随东海岸集群扩展2035年可达2300万吨/年。2025年年中全面开工，2028年投运，为英国工业脱碳树立范本。","descEn":"The world's first commercial-scale gas-fired power plant with CCS: bp and Equinor's Teesside projects took FID in December 2024, online 2028.","detailEn":"The UK's first CCS projects to enter execution and the world's first commercial-scale gas power plant with carbon capture. In December 2024 bp (75% of NZT Power, operator), Equinor and TotalEnergies took FID and reached financial close on Net Zero Teesside Power — a 742 MW gas-fired plant capturing up to 2 Mt of CO2 a year — and the Northern Endurance Partnership offshore storage system (bp 45/Equinor 45/Total 10), together about $5.1 billion with ~GBP 4 billion of EPC contracts across nine contractors. NEP starts at 4 Mt/y of CO2 transport and storage, scalable to ~23 Mt/y by 2035 with East Coast Cluster expansion. Full construction began mid-2025 for start-up in 2028, a template for UK industrial decarbonisation.","progress":"2024年12月FID并完成融资，2025年年中全面开工，目标2028年投运。"},
  {"id":6601,"name":"土耳其萨卡里亚黑海气田二期","en":"Sakarya Gas Field Phase 2","country":"土耳其","region":"欧洲","cat":"petro","coord":[31.95,41.9],"cap":"二期目标4000万立方米/日（约150亿立方米/年）","inv":45,"invText":"二期投资估算约45亿美元（估）","status":"在建","year":2026,"updated":"2026-05","owner":"TPAO（土耳其国家石油）","flagship":false,"desc":"土耳其最大能源工程：萨卡里亚深水气田二期'奥斯曼·加齐'浮式平台2026年投产，黑海产量翻倍。","detail":"土耳其能源自主战略的核心工程。萨卡里亚气田位于黑海菲利奥斯外海约170公里、水深2000米级，为土耳其史上最大天然气发现（探明超7000亿立方米）。一期2023年投产后，2025年4月日产已达约950万立方米；二期A阶段的'奥斯曼·加齐'号浮式生产平台（FPU）2026年年中投运后日产将翻倍至2000万立方米，三季度实现二期首气；满产4000万立方米/日（约150亿立方米/年）还需2028年年中投运的第二座平台（在中国建造、2027年底运抵）。届时可满足土耳其最高30%的天然气需求，显著削减进口依赖。","descEn":"Turkey's flagship energy project: Sakarya Phase 2's Osman Gazi FPU starts up in mid-2026, doubling Black Sea gas output toward 40 mcm/d.","detailEn":"The core of Turkey's energy-independence drive. The Sakarya field lies ~170 km off Filyos in ~2,000 m of Black Sea water and is Turkey's largest-ever gas discovery (over 700 bcm). After Phase 1 started in 2023, output reached ~9.5 mcm/d by April 2025; the Osman Gazi floating production unit of Phase 2A enters service in mid-2026, doubling production to 20 mcm/d with first Phase-2 gas in Q3 2026. Reaching the full 40 mcm/d (~15 bcm/y) requires a second platform — built in China, arriving end-2027 and commissioning by mid-2028 — after which Sakarya could meet up to 30% of Turkey's gas demand and sharply cut import dependence.","progress":"二期A阶段'奥斯曼·加齐'浮式平台2026年年中投产，日产将翻倍至2000万立方米，满产需2028年第二座平台。"},
  {"id":6602,"name":"捷克齐诺维茨锂矿（Cínovec）","en":"Cinovec Lithium Project","country":"捷克","region":"欧洲","cat":"mining","coord":[13.77,50.73],"cap":"约2.9万吨/年电池级碳酸锂（矿山寿命26年+，欧洲最大硬岩锂资源）","inv":14,"invText":"资本开支估算约14亿美元（含捷克政府最高3.6亿欧元补助）（估）","status":"规划","year":2029,"updated":"2025-12","owner":"ČEZ/European Metals","flagship":false,"desc":"欧洲最大硬岩锂资源：捷克Cínovec项目2025年12月完成DFS、获政府3.6亿欧元补助，迈向FID。","detail":"欧洲最大硬岩锂资源、欧盟《关键原材料法》战略项目。位于捷克北部厄尔士山脉（乌斯季州）的Cínovec锂锡矿由捷克国家电力ČEZ（持股51%）与澳交所上市的European Metals（49%）联合开发，定位为26年以上寿命的电池级碳酸锂生产基地，规划年产约2.9万吨。2025年12月发布的确定性可行性研究（DFS）结果积极；捷克政府通过'气候中和经济战略投资'计划承诺最高3.6亿欧元补助——欧盟境内对关键原材料项目最大的直接资助之一。公司正推进欧盟补助与战略债务、商业银行项目融资及与欧洲电池/车企的承购谈判，迈向最终投资决定。","descEn":"Europe's largest hard-rock lithium resource: Czech Cinovec completed a positive DFS in December 2025 and won up to EUR 360m state backing en route to FID.","detailEn":"Europe's largest hard-rock lithium resource and an EU Critical Raw Materials Act strategic project. In the Ore Mountains of Usti region, the Cinovec lithium-tin deposit is developed by state utility CEZ (51%) and ASX-listed European Metals (49%) as a 26+ year producer of battery-grade lithium carbonate (~29 kt/y planned). The Definitive Feasibility Study released in December 2025 was positive, and the Czech government committed up to EUR 360 million under its Strategic Investments for a Climate-Neutral Economy programme — one of the EU's largest direct grants to a critical-raw-materials project. The partners are progressing EU grants, strategic debt, commercial project finance and offtakes with European battery and auto groups toward a final investment decision.","progress":"2025年12月发布积极DFS（矿山寿命26年+），获捷克政府最高3.6亿欧元补助，正推进融资与承购迈向FID。"},
  {"id":6603,"name":"乌克兰多布拉锂矿（Dobra）","en":"Dobra Lithium Project","country":"乌克兰","region":"欧洲","cat":"mining","coord":[31.4,48.35],"cap":"锂辉石矿藏，矿石资源估算8000万–1.05亿吨","inv":1.8,"invText":"首期投资承诺至少1.79亿美元（50年产品分成协议）","status":"规划","year":2030,"updated":"2026-01","owner":"TechMet/The Rock Holdings（Dobra Lithium Holdings JV）","flagship":false,"desc":"美乌矿产协议首个落地项目：TechMet财团中标基洛沃格勒州Dobra锂矿50年产品分成协议。","detail":"2025年4月美乌关键矿产协议与重建投资基金框架下的旗舰首单。乌克兰2025年8月对中部基洛沃格勒州诺沃乌克兰卡区的Dobra锂矿区块启动产品分成协议招标，2026年1月官宣由美国政府参投的矿业投资公司TechMet与The Rock Holdings组成的Dobra Lithium Holdings JV中标，签署50年协议并承诺至少1.79亿美元首期投资。该区块为乌克兰最具潜力的锂资产之一，矿石资源估算8000万至1.05亿吨（锂辉石型），开发将经历勘探确权、可研后进入建设，被视为乌克兰战后重建与欧美关键矿产供应链'去风险'的试金石。","descEn":"First project under the US-Ukraine minerals deal: a TechMet-led consortium won a 50-year PSA for the Dobra lithium block in Kirovohrad with $179m committed.","detailEn":"The flagship first deal under the April 2025 US-Ukraine critical minerals agreement and joint reconstruction fund. Ukraine tendered the Dobra lithium block in Novoukrainka district, Kirovohrad oblast, in August 2025; in January 2026 the government confirmed Dobra Lithium Holdings JV — led by US-government-backed TechMet with The Rock Holdings — as winner of the 50-year production sharing agreement with a committed minimum investment of $179 million. One of Ukraine's most promising lithium assets, with an estimated 80-105 million tonnes of spodumene-bearing ore, it will move through exploration and feasibility before construction — a litmus test for Ukraine's reconstruction and Western critical-minerals de-risking.","progress":"2026年1月乌政府确认TechMet牵头财团中标50年产品分成协议，承诺首期投资至少1.79亿美元。"},
  {"id":6604,"name":"列宁格勒二期核电站7、8号机组（俄罗斯）","en":"Leningrad NPP-II Units 7-8 (VVER-1200)","country":"俄罗斯","region":"欧洲","cat":"nuclear","coord":[29.04,59.83],"cap":"2×1200MW VVER-1200","inv":100,"invText":"约100亿美元（估）","status":"在建","year":2030,"updated":"2025-06","owner":"俄罗斯国家原子能集团（Rosatom）","flagship":false,"desc":"俄本土最大在建核电工程：索斯诺维博尔新建2台VVER-1200，替代RBMK-1000老机组，2030/2032年投运。","detail":"俄罗斯国家原子能集团在列宁格勒州索斯诺维博尔的列宁格勒核电站新建7、8号机组，采用VVER-1200三代压水堆，用于替代即将退役的RBMK-1000型3、4号机组。7号机组2024年3月浇筑第一罐混凝土进入主体施工，8号机组2025年完成基础浇筑，计划分别于2030年和2032年投运，设计寿命60年。该工程是俄罗斯本土当前规模最大的在建核电项目，投资估计约100亿美元。","descEn":"Rosatom is building two VVER-1200 units at Leningrad NPP to replace ageing RBMK-1000 reactors; first concrete for Unit 7 in March 2024, Unit 8 in 2025.","detailEn":"Rosatom is constructing Units 7 and 8 at the Leningrad NPP site in Sosnovy Bor, each a Gen-III VVER-1200, to replace the retiring RBMK-1000 Units 3 and 4. First concrete for Unit 7 was poured in March 2024 and Unit 8's foundation followed in 2025, targeting grid connection in 2030 and 2032 with 60-year design lives. It is currently Russia's largest domestic nuclear construction project, estimated at around USD 10 bn.","progress":"7号机组2024年3月FCD、8号机组2025年浇筑基础，主体施工推进中。"},
  {"id":6605,"name":"荷兰博尔塞勒新建核电机组","en":"Borssele New Nuclear Units (Netherlands)","country":"荷兰","region":"欧洲","cat":"nuclear","coord":[3.72,51.43],"cap":"2×1000~1650MW（另规划2台）","inv":150,"invText":"约150亿美元（估，政府已预留约140亿欧元核电资金）","status":"规划","year":2035,"updated":"2025-10","owner":"荷兰国家核能公司NEO NL","flagship":false,"desc":"荷兰50年来首个新建核电计划：博尔塞勒拟建2台大型机组，2025年10月成立国有公司NEO NL推进。","detail":"荷兰政府计划在泽兰省博尔塞勒现有核电站旁新建两台1000-1650MW级大型压水堆，为该国50年来首个新建核电项目，建成后可供应全国9-13%的电力。2025年10月内阁宣布成立国有核能公司NEO NL负责建设与运营，并推动《核能法》修订以延寿现役博尔塞勒机组；联合政府已为核电计划预留约140亿欧元。因选址程序推迟（2025年3月将埃姆斯哈文重新纳入候选并对四个厂址开展环评），原定2035年投运的目标预计后延。","descEn":"The Netherlands' first new-build in 50 years: two large reactors planned at Borssele, with state company NEO NL created in October 2025 to deliver them.","detailEn":"The Dutch government plans two large PWRs of 1,000-1,650 MW each next to the existing Borssele plant in Zeeland - the country's first nuclear new-build in five decades, expected to supply 9-13% of national electricity. In October 2025 the cabinet created the state-owned Nuclear Energy Organisation of the Netherlands (NEO NL) to build and operate the plants, and earmarked about EUR 14 bn. Site selection slipped after Eemshaven was re-added in March 2025, pushing first power beyond the original 2035 target.","progress":"2025年10月成立国有公司NEO NL，四厂址环评中，最终选址与技术招标待定。"},
  {"id":6606,"name":"斯洛伐克博胡尼采新核电机组（AP1000）","en":"Bohunice New Nuclear Unit (AP1000, Slovakia)","country":"斯洛伐克","region":"欧洲","cat":"nuclear","coord":[17.69,48.49],"cap":"1×约1250MW AP1000","inv":108,"invText":"约100亿欧元（约108亿美元，政府估算）","status":"规划","year":2026,"updated":"2026-01","owner":"JAVYS / 西屋电气（Westinghouse）","flagship":false,"desc":"斯洛伐克与美国2026年1月签署政府间协议，由西屋在博胡尼采建设一台约1250MW的AP1000新机组。","detail":"斯洛伐克政府选定西屋电气AP1000技术，在亚斯洛夫斯凯-博胡尼采厂址新建一台约1250MW国有核电机组。2024年政府批准建设计划，估算造价约100亿欧元、目标2040年前投运；2025年8月总理确认机型，2026年1月斯美两国签署关于新机组建设的政府间协议，项目由国有核公司JAVYS主导。该项目与现役莫霍夫采核电站互补，旨在保持斯洛伐克核电占比60%以上的低碳电力结构。","descEn":"Slovakia and the USA signed an intergovernmental agreement in January 2026 for Westinghouse to build a ~1,250 MW AP1000 unit at Bohunice.","detailEn":"Slovakia selected Westinghouse's AP1000 for a new state-owned unit of about 1,250 MW at the Jaslovske Bohunice site. The government approved the plan in 2024 with an estimated cost of ~EUR 10 bn and operation targeted before 2040; the PM confirmed the design in August 2025, and in January 2026 Slovakia and the USA signed an intergovernmental agreement for the build, led by state nuclear company JAVYS. The unit complements the existing Mochovce plant and keeps nuclear above 60% of Slovak generation.","progress":"2026年1月斯美签署政府间协议，进入工程筹备与融资安排阶段。"},
  {"id":6607,"name":"土耳其锡诺普核电站","en":"Sinop Nuclear Power Plant (Turkey)","country":"土耳其","region":"欧洲","cat":"nuclear","coord":[35.05,42.02],"cap":"规划4台大型机组（约4×1100MW级）","inv":220,"invText":"约220亿美元（估，参照此前四机组方案）","status":"规划","year":2026,"updated":"2025-10","owner":"土耳其能源部 / 候选：KEPCO、西屋、Rosatom","flagship":false,"desc":"土耳其第二核电厂址转向美韩合作：2025年9月美土签核能合作备忘录，KEPCO签框架协议，2026年定承包商。","detail":"锡诺普是土耳其黑海沿岸的第二个核电厂址，规划建设四台大型机组。该项目2023年起曾与俄罗斯Rosatom谈判，但2025年9月25日埃尔多安访美后美土签署民用核能合作备忘录，10月2日土能源部长宣布美国与韩国加入锡诺普项目谈判，韩国KEPCO并已签署框架协议；土方明确厂址工作将引入竞争、不再默认交给俄方，预计2026年决定采用联合体投标还是单一总承包商。参照此前日本三菱方案（4×1120MW、约220亿美元）估算投资。","descEn":"Turkey's second nuclear site pivots from Rosatom to a US-Korea track: a US-Turkey nuclear MoU in September 2025, a KEPCO framework deal, and a contractor decision expected in 2026.","detailEn":"Sinop on the Black Sea coast is Turkey's second nuclear site, planned for four large units. Talks with Rosatom began in 2023, but after President Erdogan's Washington visit on 25 September 2025 Turkey and the USA signed a civil-nuclear MoU; on 2 October the energy minister announced the USA and South Korea had joined the Sinop talks, with KEPCO signing a framework agreement. Ankara says the site will be competed rather than handed to Russia, with a contractor decision expected in 2026. Cost is estimated at ~USD 22 bn based on the earlier 4x1,120 MW Mitsubishi scheme.","progress":"2025年9-10月美土核能备忘录+韩方框架协议，2026年将敲定承包模式。"},
  {"id":6608,"name":"雅库特乌斯季库伊加陆上SMR核电站（俄罗斯）","en":"Yakutia Ust-Kuyga Land-Based SMR (RITM-200N)","country":"俄罗斯","region":"欧洲","cat":"nuclear","coord":[135.55,70.02],"cap":"1×55MW RITM-200N（拟扩为2台）","inv":10,"invText":"约10亿美元（估）","status":"在建","year":2028,"updated":"2025-09","owner":"俄罗斯国家原子能集团（Rosenergoatom/Rusatom Overseas）","flagship":false,"desc":"俄罗斯首座陆基SMR：北极雅库特乌斯季库伊加建RITM-200N破冰船堆改型，2028年投运，拟扩为双堆。","detail":"俄罗斯首座陆上小型模块化核电站位于北极圈内雅库特共和国乌斯季库伊加，采用由破冰船堆改进的RITM-200N反应堆（55MW），目标2028年投运，为乌斯季扬斯克区矿业与居民供电。监管机构2023年4月发放建设许可；2024年完成首座250人施工营地、第二座683人营地及12公里进场道路开工，年内运抵物资9500吨。州与联邦部门正推动将项目扩展为双堆方案。项目由Rosenergoatom任业主运营、Rusatom Overseas开发，投资估计约10亿美元。","descEn":"Russia's first land-based SMR: a 55 MW RITM-200N (icebreaker-derived) unit at Ust-Kuyga in Arctic Yakutia, targeting 2028 commissioning and possible expansion to two units.","detailEn":"Russia's first land-based small modular reactor is being built near Ust-Kuyga in Arctic Yakutia, using the 55 MW RITM-200N derived from icebreaker reactors, with commissioning targeted for 2028 to power mining and communities in the Ust-Yansky district. The construction licence was granted in April 2023; through 2024 the first 250-person camp was completed, a 683-person camp and a 12 km access road advanced, and 9,500 t of cargo delivered. Authorities are working to expand the project to two reactors. Rosenergoatom is operator with Rusatom Overseas as developer; cost is estimated around USD 1 bn.","progress":"2024-2025年营地、道路等准备工程推进，拟扩双堆，目标2028年投运。"},
  {"id":6609,"name":"库尔斯克二期核电站（VVER-TOI首堆）","en":"Kursk II NPP (First VVER-TOI Units)","country":"俄罗斯","region":"欧洲","cat":"nuclear","coord":[35.66,51.66],"cap":"2×1255MW VVER-TOI（在建/调试）","inv":80,"invText":"约80亿美元（估，两台机组）","status":"在建","year":2025,"updated":"2026-02","owner":"俄罗斯国家原子能集团（Rosatom）","flagship":false,"desc":"全球首台VVER-TOI：库尔斯克二期1号机组2025年12月31日并网，2026年2月进入试运行，2号机组2027年投运。","detail":"库尔斯克二期核电站是俄罗斯三代+堆型VVER-TOI的首个工程，用于替代库尔恰托夫市的RBMK老机组。1号机组2018年4月开工，2025年12月31日首次并网（240MW），2026年2月初进入试工业运行并达满功率，已累计发电20亿千瓦时；2号机组2019年4月开工，预计2027年投运。VVER-TOI为优化版大型压水堆（单机1255MW），在造价与工期上较VVER-1200进一步优化，两台机组投资估算约80亿美元。","descEn":"The world's first VVER-TOI: Kursk II Unit 1 was grid-connected on 31 December 2025 and reached full power in pilot operation by February 2026; Unit 2 follows in 2027.","detailEn":"Kursk II is the lead plant for Russia's Gen-III+ VVER-TOI design, replacing the RBMK units at Kurchatov. Unit 1, started in April 2018, was first connected to the grid on 31 December 2025 (240 MW), entered pilot industrial operation in early February 2026, reached full power and has generated 2 billion kWh. Unit 2, begun in April 2019, is expected online in 2027. The VVER-TOI is an optimized 1,255 MW PWR with improved cost and schedule over the VVER-1200; the two units are estimated at ~USD 8 bn.","progress":"1号机组2025年12月31日并网、2026年2月试运行达满功率；2号机组2027年投运。"},
  {"id":6610,"name":"捷克特梅林SMR项目（Rolls-Royce）","en":"Temelin SMR Project (Rolls-Royce, Czech Republic)","country":"捷克","region":"欧洲","cat":"nuclear","coord":[14.38,49.18],"cap":"首台470MW SMR（全国规划最多3GW）","inv":30,"invText":"约30亿美元（估，首台机组）","status":"规划","year":2026,"updated":"2026-04","owner":"ČEZ集团 / Rolls-Royce SMR","flagship":false,"desc":"捷克首座SMR：ČEZ选定并入股Rolls-Royce SMR 20%，2026年4月签特梅林前期工程协议，2030年代中期投运。","detail":"捷克电力集团ČEZ于2024年10月选定英国Rolls-Royce SMR为小堆合作伙伴并收购其20%股权，规划在全国部署最多3GW小堆容量，首台470MW机组落址特梅林现有核电站旁。2026年4月双方签署前期工程协议（Early Works Agreement），启动厂址专项设计、环评及核与建设许可文件编制；ČEZ并与工贸部签署备忘录研究投资者模式与融资来源。首堆目标2030年代中期投运，单台投资估算约30亿美元，斯柯达JS与斗山重工已获关键设备合同。","descEn":"Czechia's first SMR: ČEZ picked Rolls-Royce SMR (taking a 20% stake) and signed a Temelin early-works agreement in April 2026, targeting a 470 MW first unit in the mid-2030s.","detailEn":"Czech utility ČEZ selected Rolls-Royce SMR in October 2024 as its small-reactor partner, taking a 20% equity stake, with plans for up to 3 GW of SMR capacity nationwide. The first 470 MW unit will be sited next to the existing Temelin plant. In April 2026 the parties signed an Early Works Agreement launching site-specific design, the environmental impact assessment and licensing documentation; ČEZ also signed an MoU with the industry ministry on the investor and financing model. First operation is targeted for the mid-2030s at an estimated ~USD 3 bn, with Skoda JS and Doosan Enerbility holding key component contracts.","progress":"2026年4月签署前期工程协议，启动选址设计与许可程序。"},
  {"id":6611,"name":"鹿特丹Porthos碳捕集封存项目","en":"Porthos CCS Rotterdam","country":"荷兰","region":"欧洲","cat":"petro","coord":[4.05,51.95],"cap":"CO2运输封存250万吨/年，总封存3700万吨","inv":14,"invText":"约13亿欧元","status":"在建","year":2026,"updated":"2026-06","owner":"鹿特丹港务局/Gasunie/EBN","flagship":false,"desc":"欧盟首个大规模CCS项目：鹿特丹港工业CO2经管道送北海枯竭气田封存，年250万吨，2026年投运。","detail":"Porthos是欧盟范围内首个实现的大规模二氧化碳运输与封存项目，由鹿特丹港务局、荷兰国家天然气管网公司Gasunie和国家能源公司EBN三方合资。壳牌、埃克森美孚、液化空气、空气产品四家鹿特丹港区工厂捕集的CO2，经2.6公里陆上+20公里海上管道输送至北海枯竭气田，注入海床下3-4公里永久封存，年输送量250万吨、持续15年，总封存3700万吨；陆上管道按1000万吨/年设计，为后续Aramis等项目预留容量。2024年开工，2025年8月海底管道铺设完成，预计2026年投入运营，为欧洲工业脱碳树立标杆。","descEn":"The EU's first large-scale CCS project: CO2 from Rotterdam port industries piped to depleted North Sea gas fields, 2.5 Mtpa from 2026.","detailEn":"Porthos is the first large-scale CO2 transport and storage project realized in the EU, a joint venture of the Port of Rotterdam Authority, Gasunie and EBN. CO2 captured by Shell, ExxonMobil, Air Liquide and Air Products plants in the port is sent through a 2.6-km onshore and 20-km offshore pipeline to depleted North Sea gas fields 3-4 km below the seabed - 2.5 million tonnes per year for 15 years, 37 million tonnes in total. The onshore pipeline is sized for 10 Mtpa to serve future projects. Construction began in 2024, the offshore pipeline was completed in August 2025, and operations start in 2026.","progress":"2025年8月20公里海底管道铺设并掩埋完成，海上平台与压缩站收尾，预计2026年投运。"},
  {"id":6612,"name":"斯德哥尔摩Exergi大型BECCS工厂","en":"Stockholm Exergi Large-Scale BECCS Plant","country":"瑞典","region":"欧洲","cat":"petro","coord":[18.1,59.35],"cap":"生物质能碳捕集80万吨CO2/年","inv":13,"invText":"约130亿瑞典克朗（≈13亿美元）","status":"在建","year":2028,"updated":"2026-06","owner":"Stockholm Exergi（斯德哥尔摩市/APG等）","flagship":false,"desc":"全球首个大规模BECCS项目，2025年3月FID，韦尔坦生物质热电厂年负碳80万吨，微软签333万吨碳移除。","detail":"斯德哥尔摩能源公司Stockholm Exergi于2025年3月27日对全球首个大规模生物质能碳捕集与封存（BECCS）项目作出最终投资决定。项目在斯德哥尔摩韦尔坦（Värtan）生物质热电联产厂加装Capsol热钾碱碳捕集装置，年捕集并永久封存80万吨生物源CO2，实现净负排放，CO2将船运至北欧封存场地。项目获欧盟创新基金1.8亿欧元资助和欧洲投资银行2.6亿欧元贷款；微软签署333万吨、为期十年的永久碳移除采购协议——全球最大单笔碳移除交易，Frontier联盟亦承购约5000万美元。预计2028年投运，开创城市供热负碳商业模式。","descEn":"The world's first large-scale BECCS project, FID March 2025: 800,000 tonnes of biogenic CO2 captured yearly at Stockholm's Värtan biomass CHP plant; Microsoft contracted 3.33 Mt of removals.","detailEn":"Stockholm Exergi took a final investment decision on 27 March 2025 for the world's first large-scale bio-energy carbon capture and storage (BECCS) project. Capsol's hot potassium carbonate capture technology will be retrofitted to the Värtan biomass CHP plant, permanently removing up to 800,000 tonnes of biogenic CO2 per year, shipped to Nordic storage sites. The project won EUR 180m from the EU Innovation Fund and a EUR 260m EIB loan; Microsoft signed the world's largest permanent carbon removal deal at 3.33 million tonnes over ten years, with Frontier adding ~$50m in offtake. Operations begin in 2028.","progress":"2025年3月FID并开工；欧投行2.6亿欧元贷款落地，微软333万吨碳移除协议生效，预计2028年投运。"},
  {"id":6613,"name":"海德堡材料Brevik水泥碳捕集工厂","en":"Heidelberg Materials Brevik CCS","country":"挪威","region":"欧洲","cat":"petro","coord":[9.7,59.05],"cap":"水泥厂碳捕集40万吨CO2/年（占排放50%）","inv":4.5,"invText":"约4.5亿美元（估，挪威Longship计划资助）","status":"投运","year":2025,"updated":"2026-06","owner":"海德堡材料（Heidelberg Materials）","flagship":false,"desc":"全球水泥行业首个工业规模CCS，2025年6月挪威王储揭幕投运，年捕集40万吨CO2，产出全球首款碳捕集水泥evoZero。","detail":"海德堡材料位于挪威南部布雷维克（Brevik）水泥厂的碳捕集设施是全球水泥行业首个工业规模CCS工程，2025年6月18日由挪威王储哈康揭幕投运。设施采用Aker胺法捕集技术，年捕集约40万吨CO2，相当于水泥厂排放量的50%；捕集的CO2液化后船运至挪威西海岸Øygarden接收站，经北极光（Northern Lights）海底管道注入北海地下储层永久封存，2025年8月开始注入。项目是挪威国家'长船'（Longship）全链条CCS计划的核心捕集端。依托该设施，海德堡推出全球首款碳捕集净零水泥evoZero，2025年10月起向欧洲客户交付。","descEn":"The world's first industrial-scale CCS in the cement industry, inaugurated June 2025 in Brevik, Norway: 400,000 tonnes of CO2 captured yearly, enabling evoZero, the first carbon-captured cement.","detailEn":"Heidelberg Materials' carbon capture facility at its Brevik cement plant in southern Norway is the cement industry's first industrial-scale CCS, inaugurated by Crown Prince Haakon on 18 June 2025. Using Aker's amine capture technology, it captures about 400,000 tonnes of CO2 per year - half the plant's emissions. The liquefied CO2 is shipped to the Øygarden terminal and injected via Northern Lights' subsea pipelines into North Sea reservoirs, with injection starting August 2025. Brevik is the capture anchor of Norway's state-backed Longship full-chain CCS program. It enables evoZero, the world's first carbon-captured net-zero cement, delivered to European customers since October 2025.","progress":"2025年6月正式投运，8月CO2开始经北极光注入封存；evoZero水泥2025年10月起交付欧洲客户。"},
  {"id":6614,"name":"德国EWE埃姆登320MW绿氢电解工厂","en":"EWE Emden 320 MW Green Hydrogen Electrolyzer","country":"德国","region":"欧洲","cat":"renewable","coord":[7.2,53.36],"cap":"320MW PEM电解（西门子能源280MW系统），绿氢2.6万吨/年","inv":9,"invText":"超8亿欧元（≈9亿美元）","status":"在建","year":2027,"updated":"2026-06","owner":"EWE（Clean Hydrogen Coastline计划）","flagship":false,"desc":"德国最大在建绿氢工厂之一：埃姆登320MW PEM电解槽利用北海风电制氢，2025年11月开工，2027年底投运。","detail":"德国公用事业公司EWE在下萨克森州埃姆登建设的320MW电解水制氢工厂，是其'清洁氢海岸线'（Clean Hydrogen Coastline）IPCEI计划四个子项目的核心，总投资超过8亿欧元。项目采用西门子能源280MW PEM电解系统（含十年服务协议），利用北海海上风电绿电年产约2.6万吨绿氢，经管网输往鲁尔区钢铁、化工与炼化用户，并接入德国国家氢气核心管网。2025年11月正式开工建设，Bilfinger承担主体安装，ReiCat供应氢气提纯系统，预计2027年底投入运营，是德国本土规模最大的在建电解槽项目之一。","descEn":"One of Germany's largest electrolyzers under construction: a 320 MW PEM plant in Emden using North Sea wind power, producing 26,000 t/y of green hydrogen; groundbreaking November 2025, operations by end-2027.","detailEn":"German utility EWE is building a 320 MW water electrolysis plant in Emden, Lower Saxony - the core of its IPCEI-funded Clean Hydrogen Coastline program - with investment exceeding EUR 800 million. Siemens Energy supplies a 280 MW PEM electrolysis system with a 10-year service contract. Powered by North Sea offshore wind, the plant will produce about 26,000 tonnes of green hydrogen annually for steel, chemical and refining customers, feeding into Germany's hydrogen core network. Construction officially started in November 2025, with operations expected by the end of 2027.","progress":"2025年11月正式开工；西门子能源280MW PEM电解系统、Bilfinger安装与ReiCat提纯系统合同均已落定，预计2027年底投运。"},
  {"id":6615,"name":"SACOI3 撒丁—科西嘉—意大利本土直流更新工程","en":"SACOI3 Sardinia-Corsica-Italy HVDC Link Renewal","country":"意大利—法国","region":"欧洲","cat":"grid","coord":[9.5,42.5],"cap":"400MW 多端高压直流（撒丁—科西嘉—托斯卡纳）","inv":14.7,"invText":"13.5亿欧元（约14.7亿美元）","status":"在建","year":2029,"updated":"2026-06","owner":"Terna/EDF","desc":"意大利Terna牵头改造升级运行半个世纪的撒丁—科西嘉—意大利本土多端直流线路，输送能力提升至400MW。","detail":"SACOI3是对1960年代投运的撒丁岛—科西嘉—意大利本土多端高压直流系统的整体更新与扩容，新建换流站并铺设新海缆，正常工况下撒丁岛与意大利本土间可输送300MW，科西嘉分接最多100MW，总投资约13.5亿欧元，其中约2亿欧元来自欧盟REPowerEU计划。2025年初陆上段开工：撒丁岛圣特雷莎加卢拉的海缆登陆点工地率先开建，托斯卡纳萨利沃利段于2025年3月跟进（夏季旅游季停工、10月复工以减少扰动）。项目为欧盟共同利益项目（PCI），预计2029年前后投入商业运行。","descEn":"Terna-led renewal of the 1960s-era Sardinia-Corsica-mainland Italy multi-terminal HVDC link, lifting transfer capability to 400 MW.","detailEn":"SACOI3 replaces end-of-life assets of the multi-terminal HVDC system linking Sardinia, Corsica and Tuscany with new converter stations and submarine cables; under normal conditions it will carry up to 300 MW between Sardinia and the mainland with up to 100 MW tapped by Corsica. Total investment is about EUR 1.35 billion, with roughly EUR 200 million from REPowerEU. Onshore construction began in early 2025 at Santa Teresa Gallura (Sardinia) and Salivoli (Tuscany). An EU Project of Common Interest, commercial operation is expected around 2029.","progress":"2025年初陆上段开工，撒丁岛与托斯卡纳两端海缆登陆点工地相继开建，预计2029年投运。","route":[[10.5,43],[9.45,42.6],[9.2,41.25],[8.7,40.66]],"flagship":false},
  {"id":6616,"name":"德国NordOstLink直流走廊（石荷州—梅前州）","en":"NordOstLink HVDC Corridor (Schleswig-Holstein to Mecklenburg), Germany","country":"德国","region":"欧洲","cat":"grid","coord":[10.2,53.9],"cap":"约190km 525kV直流地下电缆 / 2GW（远期可扩至4GW）","inv":35,"invText":"约35亿美元（估）","status":"规划","year":2032,"updated":"2026-06","owner":"50Hertz/TenneT","desc":"德国南北输电网新一代地下直流走廊：海德（迪特马尔申）至什未林附近克莱因罗加恩，输送北部风电。","detail":"NordOstLink由50Hertz与TenneT联合规划建设，自石勒苏益格-荷尔斯泰因州海德（迪特马尔申）至梅克伦堡-前波莫瑞州什未林附近的克莱因罗加恩，全长约190公里，采用525kV直流地下电缆，输电能力2GW（按双沟六缆预留可扩至4GW），用于把德国北部及北海风电送往东部负荷区。两家运营商已依据《电网扩建加速法》（NABEG）向联邦网络局提交许可申请；50Hertz在2025年与NKT、普睿司曼签署总额46亿欧元的海陆电缆框架合同（含本项目用缆），电缆生产安装自2025年起排产。计划2028年开工、2032年前后投运。","descEn":"A new-generation underground HVDC corridor from Heide (Dithmarschen) to Klein Rogahn near Schwerin, moving northern wind power into eastern Germany.","detailEn":"Jointly planned by 50Hertz and TenneT, NordOstLink runs about 190 km from Heide in Schleswig-Holstein to Klein Rogahn near Schwerin, using 525 kV underground DC cables with 2 GW capacity (expandable toward 4 GW with six cables in two trenches). The permit application under Germany's NABEG acceleration act has been filed with the Federal Network Agency, and 50Hertz's EUR 4.6 billion cable framework with NKT and Prysmian covers the project, with cable production scheduled from 2025. Construction is planned from 2028 and commissioning around 2032.","progress":"已向联邦网络局提交NABEG许可申请；2025年电缆框架合同签订并排产，计划2028年开工、2032年投运。","route":[[9.1,54.2],[10.3,53.9],[11.4,53.6]],"flagship":false},
  {"id":6617,"name":"GRITA 2 希腊—意大利第二回直流互联","en":"GRITA 2 Second Greece-Italy HVDC Interconnector","country":"希腊—意大利","region":"欧洲","cat":"grid","coord":[18.9,39.9],"cap":"1000MW（2×500MW）/ 约300km（含240km海缆）","inv":20.7,"invText":"约19亿欧元（约20.7亿美元）","status":"规划","year":2031,"updated":"2026-06","owner":"IPTO（ADMIE）/Terna","desc":"希腊IPTO与意大利Terna签署谅解备忘录，共建1000MW希意第二回海底直流互联，补充2002年投运的500MW老线。","detail":"在意希政府间峰会期间，两国电网公司IPTO与Terna于罗马签署为期三年的谅解备忘录，确定希腊—意大利第二回电力互联（GRITA 2）的设计开发框架：输电能力最高1000MW（2×500MW），线路总长约300公里、其中海缆约240公里，意方登陆点为莱切省梅伦杜尼奥、换流站设在加拉蒂纳，总投资约19亿欧元，目标2031年前投运。双方将组建联合项目治理机构，统筹电缆与换流站招标及工程实施。该线与2002年投运的500MW既有互联并行，将显著提升希腊可再生电力向意大利及中欧外送能力。","descEn":"IPTO and Terna signed an MoU to build GRITA 2, a 1,000 MW second subsea HVDC link between Greece and Italy complementing the 500 MW line in service since 2002.","detailEn":"Signed in Rome during the Italy-Greece intergovernmental summit, the three-year MoU frames the design and development of GRITA 2: up to 1,000 MW (2x500 MW) over about 300 km including roughly 240 km of subsea cable, landing at Melendugno with a new converter station at Galatina in Lecce province. Terna and IPTO expect to invest about EUR 1.9 billion, with the second link due by 2031. A joint governance structure will coordinate procurement of cables and converter stations and project implementation.","progress":"IPTO与Terna签署三年期谅解备忘录并组建联合治理机构，启动设计与招标筹备，目标2031年投运。","route":[[18.34,40.27],[19.2,39.9],[20.2,39.5]],"flagship":false},
  {"id":6618,"name":"爱沙尼亚Zero Terrain帕尔迪斯基地下抽水蓄能","en":"Zero Terrain Paldiski Underground Pumped Hydro Storage","country":"爱沙尼亚","region":"欧洲","cat":"storage","coord":[24.08,59.33],"cap":"500MW/6000MWh（12小时循环）","inv":8.7,"invText":"约8亿欧元（≈8.7亿美元）","status":"规划","year":2032,"updated":"2026-06","owner":"Energiasalv (Zero Terrain)","flagship":true,"desc":"欧洲首个平原全地下抽水蓄能：帕尔迪斯基地下花岗岩层中建500MW/6GWh下水库，波罗的海地区最大储能，欧盟PCI项目。","detail":"Zero Terrain帕尔迪斯基项目是爱沙尼亚首个抽水蓄能电站，采用独创的平原全地下方案：在波罗的海沿岸帕尔迪斯基地下数百米花岗岩层中开挖下水库，与地表水库构成500MW/6GWh（12小时）循环系统，无需山地地形。项目为欧盟共同利益项目（PCI），造价约8亿欧元，2022年12月获建设许可，2024年获政府资助并与气候部签署谅解备忘录，已在国际平台发出设计施工联盟总承包招标，一期目标2032年建成，支撑波罗的海三国脱离俄电网后的风电消纳与系统稳定。","descEn":"Europe's first flat-land fully underground pumped hydro: a 500MW/6GWh plant carved into granite beneath Paldiski, the Baltics' largest storage facility and an EU PCI project.","detailEn":"Zero Terrain Paldiski is Estonia's first pumped hydro storage plant, using a novel flat-land design: a lower reservoir excavated in granite hundreds of meters beneath the Baltic coast town of Paldiski paired with a surface reservoir, forming a 500MW/6GWh (12-hour) cycle without mountains. An EU Project of Common Interest costing about EUR 800 million, it received its construction permit in December 2022, state grants and a Ministry of Climate MOU in 2024, and has tendered an international design-build alliance for the main works. Phase one targets 2032, underpinning Baltic wind integration after desynchronization from the Russian grid.","progress":"2024—2025年完成主体工程国际招标与开发阶段，获政府198万欧元资助及1100万欧元追加融资；原计划2025年二季度启动施工，一期目标2032年投运。"},
  {"id":6619,"name":"希腊安菲洛希亚抽水蓄能电站","en":"Amfilochia Pumped Storage Hydropower","country":"希腊","region":"欧洲","cat":"storage","coord":[21.17,38.86],"cap":"680MW（发电）/730MW（抽水），双上库共用下库","inv":6.5,"invText":"超6亿欧元（约6.5亿美元）","status":"在建","year":2028,"updated":"2026-06","owner":"TERNA Energy","desc":"希腊迄今最大储能投资：Agios Georgios与Pyrgos双系统共用卡斯特拉基湖下库的680MW抽蓄，欧盟复苏基金支持，2028年建成。","detail":"安菲洛希亚抽水蓄能位于希腊西部，由TERNA Energy开发，是希腊迄今最大的储能投资（超6亿欧元，获欧盟复苏与韧性基金支持）。项目由Agios Georgios与Pyrgos两套独立系统组成，各有独立上水库与引水道，共用卡斯特拉基湖作为下水库，发电模式680MW、抽水模式730MW，安德里茨供应水泵水轮机组。项目经历多年许可拖延后已全面开工，目标2028年底建成，将成为希腊高比例可再生能源消纳与电网调节的核心设施，开启希腊新一轮水电储能时代。","descEn":"Greece's largest storage investment: a 680MW pumped storage scheme with twin upper reservoirs (Agios Georgios and Pyrgos) sharing Kastraki Lake, EU recovery-funded, due 2028.","detailEn":"The Amfilochia pumped storage project in western Greece, developed by TERNA Energy, is the country's largest energy storage investment to date (over EUR 600 million, supported by the EU Recovery and Resilience Facility). It comprises two independent systems, Agios Georgios and Pyrgos, each with its own upper reservoir and waterway, sharing Kastraki Lake as the lower reservoir - 680MW in generation and 730MW in pumping mode, with Andritz pump-turbines. After years of licensing delays it is in full construction, targeting completion by end-2028 as a cornerstone of Greek renewables integration.","progress":"2025—2026年土建全面推进，岩土工程进入关键阶段，安德里茨机组供货落实；业主称2028年底完工目标'非常紧张'，部分系统或2027年先期投运。","flagship":false},
  {"id":6620,"name":"波兰扎尔诺维茨电池储能电站","en":"PGE Zarnowiec Battery Energy Storage","country":"波兰","region":"欧洲","cat":"storage","coord":[18.1,54.77],"cap":"262MW/981MWh","inv":4,"invText":"约15亿兹罗提（≈4亿美元）","status":"在建","year":2027,"updated":"2026-06","owner":"PGE集团","desc":"波兰最大电池储能：262MW/981MWh，毗邻扎尔诺维茨抽蓄电站，LG波兰工厂供应本地产LFP电池，2027年二季度投运。","detail":"波兰国有电力集团PGE于2025年9月19日在波美拉尼亚省扎尔诺维茨抽水蓄能电站旁开工建设波兰最大、欧洲领先的电池储能电站，规模262MW/981MWh，投资约15亿兹罗提（约3.5亿欧元）。LG新能源弗罗茨瓦夫工厂中标供应波兰本地生产的电网级磷酸铁锂电池。电站将在波罗的海海上风电与光伏出力过剩时充电、用电高峰时放电，与既有抽蓄机组协同调节北部电网，计划2027年第二季度建成投运，是波兰电网灵活性改造的标志性工程。","descEn":"Poland's largest battery storage: 262MW/981MWh next to the Zarnowiec pumped storage plant, with locally made LG LFP batteries, online Q2 2027.","detailEn":"Polish state utility PGE broke ground on September 19, 2025 on Poland's largest battery energy storage facility - 262MW/981MWh - adjacent to its Zarnowiec pumped storage plant in Pomerania, at a cost of about PLN 1.5 billion (roughly EUR 353 million). LG Energy Solution Wroclaw won the tender to supply locally manufactured grid-scale LFP batteries. The plant will charge on surplus Baltic offshore wind and solar output and discharge at peak, working in tandem with the existing pumped storage units. Completion is scheduled for Q2 2027, a flagship of Poland's grid flexibility push.","progress":"2025年9月19日开工，LG新能源弗罗茨瓦夫工厂供应本地产LFP电池；计划2027年二季度完工投运。","flagship":false},
  {"id":6621,"name":"德国菲利普斯堡电池储能电站","en":"EnBW Philippsburg Battery Energy Storage","country":"德国","region":"欧洲","cat":"storage","coord":[8.44,49.25],"cap":"400MW/800MWh","inv":3,"invText":"约3亿美元（估）","status":"规划","year":2027,"updated":"2026-06","owner":"EnBW","desc":"德国最大在建电池储能之一：EnBW在菲利普斯堡退役核电站址建400MW/800MWh储能，2026年夏开工、2027年投运。","detail":"德国能源巨头EnBW已对菲利普斯堡能源园400MW/800MWh电池储能项目作出最终投资决定（FID），选址巴登-符腾堡州菲利普斯堡退役核电站旧址——利用核电时代遗留的强大电网接入点。项目2026年初夏开工，计划2027年建成投运，与RWE林根400MW/800MWh、LEAG延施瓦尔德1GW/4GWh等项目共同标志德国正式进入大规模电网级储能时代。电站将平抑南德光伏出力波动、提供调频与备用容量，是德国退役核电站址转型储能的代表性案例。","descEn":"One of Germany's largest batteries under development: EnBW's 400MW/800MWh BESS at the decommissioned Philippsburg nuclear plant site, construction from summer 2026, online 2027.","detailEn":"German utility EnBW has taken a final investment decision on a 400MW/800MWh battery energy storage system at its Philippsburg Energy Park in Baden-Wuerttemberg - the site of the decommissioned Philippsburg nuclear plant, reusing its powerful grid connection. Construction launches in early summer 2026 with commissioning planned for 2027. Together with RWE's 400MW/800MWh Lingen BESS and LEAG's 1GW/4GWh Jaenschwalde project, it marks Germany's entry into the large-scale grid storage era, smoothing southern German solar output and providing frequency response and reserve capacity - a flagship case of converting retired nuclear sites to storage.","progress":"已作出最终投资决定（FID），2026年初夏开工建设，计划2027年投运。","flagship":false},
  {"id":6622,"name":"芬兰拉彭兰塔Nebius AI工厂","en":"Nebius Lappeenranta 310MW AI Factory","country":"芬兰","region":"欧洲","cat":"datacenter","coord":[28.19,61.06],"cap":"310 MW（IT负载，分期建设）","inv":20,"invText":"约20亿美元（估）","status":"规划","year":2027,"updated":"2026-06","owner":"Nebius","desc":"Nebius在芬兰东南部拉彭兰塔新建310 MW AI工厂，建成后将是北欧最大AI算力设施之一。","detail":"纳斯达克上市AI云公司Nebius（前Yandex国际业务）宣布在芬兰拉彭兰塔建设全新AI工厂园区，规划IT容量最高310 MW，分多期建设，首批算力预计2027年交付客户。芬兰凉爽气候、富余水电与成熟电网使其成为欧洲AI算力洼地；该项目与Nebius既有的玛恩塔拉（Mantsala）数据中心形成芬兰双节点。园区将部署最新一代英伟达GPU集群，面向欧洲企业与主权AI需求，投资额未披露（按同类项目估算约20亿美元）。","descEn":"Nebius is building a new 310 MW AI factory in Lappeenranta, south-eastern Finland — set to be one of the Nordics' largest AI compute sites.","detailEn":"Nasdaq-listed AI cloud company Nebius announced a greenfield AI factory campus in Lappeenranta, Finland, with up to 310 MW of IT capacity built in phases; first capacity is expected to serve customers in 2027. Finland's cool climate, abundant hydropower and strong grid make it a European AI compute haven. The site complements Nebius's existing Mantsala data center and will host latest-generation NVIDIA GPU clusters for European enterprise and sovereign AI demand. Investment undisclosed (est. ~$2bn).","progress":"2026年宣布；选址拉彭兰塔，规划310 MW，首批算力2027年上线。","flagship":false},
  {"id":6623,"name":"芬兰库沃拉TikTok数据中心","en":"TikTok Kouvola Data Center (HyperCo)","country":"芬兰","region":"欧洲","cat":"datacenter","coord":[26.7,60.87],"cap":"规划约100 MW","inv":11,"invText":"10亿欧元（约11亿美元）","status":"在建","year":2026,"updated":"2026-06","owner":"TikTok（字节跳动）/ HyperCo","desc":"TikTok投资10亿欧元在芬兰库沃拉建设其首个芬兰数据中心，由本土开发商HyperCo承建运营。","detail":"TikTok（字节跳动旗下）宣布投资10亿欧元在芬兰东南部库沃拉建设数据中心园区，是其在芬兰的首个重大基础设施投资，由芬兰开发商HyperCo Oy开发，利用当地富余清洁电力与凉爽气候。该项目是TikTok'欧洲数据本地化'（Project Clover）战略的延伸，与挪威、爱尔兰节点共同承载欧洲用户数据与AI推荐算力。园区规划容量约100 MW，分期交付。","descEn":"TikTok is investing EUR 1 billion in its first Finnish data center in Kouvola, developed and operated by local developer HyperCo.","detailEn":"TikTok (ByteDance) announced a EUR 1 billion data center campus in Kouvola, south-eastern Finland — its first major infrastructure investment in the country, developed by Finnish firm HyperCo Oy and powered by abundant clean electricity. The project extends TikTok's European data-localization strategy (Project Clover) alongside its Norway and Ireland nodes, hosting EU user data and AI recommendation compute. The campus is planned at roughly 100 MW, delivered in phases.","progress":"2025年公布、随后开工；由HyperCo开发，一期预计2026—2027年投运。","flagship":false},
  {"id":6624,"name":"意大利EdgeConneX伦巴第数据中心群","en":"EdgeConneX Lombardy Data Center Campuses (Lodi/South Milan)","country":"意大利","region":"欧洲","cat":"datacenter","coord":[9.5,45.31],"cap":"300+ MW（三个园区）","inv":33,"invText":"30亿欧元（约33亿美元）","status":"规划","year":2031,"updated":"2026-06","owner":"EdgeConneX","desc":"EdgeConneX投资30亿欧元在米兰以南洛迪地区建设三个新一代数据中心园区，总容量超300 MW，获意大利'国家战略利益'认定。","detail":"2026年5月14日，意大利总理梅洛尼主持的部长会议批准EdgeConneX在伦巴第大区投资30亿欧元的数据中心计划，认定其具有'国家战略利益'并指派特别专员加速审批。项目将在洛迪省与米兰南部建设三个新一代AI-ready数据中心园区，总容量超过300 MW，计划2026年三季度开工、2031年全部建成，建设期年均创造约1500个就业岗位，并有望带动约50亿欧元间接投资，是意大利迄今最大的数据中心单笔投资之一。","descEn":"EdgeConneX will invest EUR 3 billion in three next-generation data center campuses (300+ MW) in Lodi province and southern Milan, designated of 'national strategic interest' by Italy.","detailEn":"On May 14, 2026 Italy's council of ministers, chaired by PM Giorgia Meloni, endorsed EdgeConneX's EUR 3 billion plan as being of 'national strategic interest', appointing a special commissioner to fast-track permits. The project comprises three AI-ready campuses with over 300 MW of capacity across Lodi province and southern Milan, with construction starting Q3 2026 and completion by 2031 — about 1,500 construction jobs per year and an expected EUR 5 billion in indirect investment, one of Italy's largest-ever data center commitments.","progress":"2026年5月获意大利政府'国家战略利益'认定并走快速审批通道，计划2026年Q3开工。","flagship":false},
  {"id":6625,"name":"希腊斯帕塔EDGNEX-PPC数据中心","en":"EDGNEX-PPC Data In Scale Data Center, Spata (Athens)","country":"希腊","region":"欧洲","cat":"datacenter","coord":[23.91,37.96],"cap":"一期12.5 MW（规划25 MW）","inv":1.65,"invText":"一期1.5亿欧元（约1.65亿美元）","status":"在建","year":2027,"updated":"2026-06","owner":"DAMAC EDGNEX / 希腊公共电力公司（PPC）","desc":"迪拜DAMAC旗下EDGNEX与希腊电力公司PPC合资在雅典斯帕塔建设12.5 MW（远期25 MW）数据中心。","detail":"EDGNEX Data Centers（迪拜DAMAC旗下）与希腊公共电力公司PPC于2024年12月宣布成立合资公司Data In Scale（DAMAC占55%、PPC占45%），在东阿提卡斯帕塔（雅典国际机场附近）建设先进数据中心：一期投资1.5亿欧元、容量12.5 MW，2025年一季度开工、约两年内投运，远期扩至25 MW。项目依托PPC清洁电力，瞄准希腊作为欧亚非海缆交汇点的区位优势，是希腊AI数据中心热潮的代表项目之一。","descEn":"Dubai's EDGNEX (DAMAC) and Greek utility PPC are building a 12.5 MW (25 MW at full build) data center in Spata, East Attica via their Data In Scale JV.","detailEn":"EDGNEX Data Centers by DAMAC and Greece's Public Power Corporation (PPC) announced the Data In Scale joint venture (DAMAC 55% / PPC 45%) in December 2024 to build a state-of-the-art data center in Spata, East Attica near Athens airport: EUR 150m phase one delivering 12.5 MW, construction from Q1 2025 with operations in about two years, scaling to 25 MW. Powered by PPC clean energy, it leverages Greece's position at the Europe-Asia-Africa subsea cable crossroads and headlines Greece's AI data center wave.","progress":"2025年初开工建设，一期12.5 MW预计2027年投运。","flagship":false},
  {"id":6626,"name":"德国吕贝瑙Schwarz Digits主权AI数据中心","en":"Schwarz Digits Luebbenau Sovereign AI Data Center","country":"德国","region":"欧洲","cat":"datacenter","coord":[13.96,51.86],"cap":"首期接入容量约200 MW（可容纳约10万颗AI芯片）","inv":120,"invText":"110亿欧元（约120亿美元）","status":"在建","year":2027,"updated":"2026-06","owner":"Schwarz Digits（施瓦茨集团）","flagship":true,"desc":"Lidl母公司施瓦茨集团投资110亿欧元在勃兰登堡吕贝瑙建设欧洲最大主权AI数据中心，首期200 MW、可容纳约10万颗GPU。","detail":"施瓦茨集团（Lidl/Kaufland母公司）数字部门Schwarz Digits宣布投资110亿欧元，在柏林以南约90公里的勃兰登堡州吕贝瑙建设大型AI数据中心园区——集团史上最大单笔投资，也是欧洲'数字主权'旗舰工程。首期接入容量约200 MW，2027年底建成，满载可容纳约10万颗专用AI芯片，由集团云部门StackIT运营，余热将接入当地区域供热管网。项目已举行奠基仪式，定位为德国及欧盟主权云与AI算力的骨干设施，服务对美国超大规模云商的替代需求。","descEn":"Lidl owner Schwarz Group is investing EUR 11 billion in Europe's flagship sovereign AI data center in Luebbenau, Brandenburg — 200 MW first phase hosting up to 100,000 AI chips.","detailEn":"Schwarz Digits, the IT arm of Schwarz Group (Lidl/Kaufland), is investing EUR 11 billion — the group's largest-ever single investment — in a giant AI data center campus in Luebbenau, Brandenburg, about 90 km south of Berlin. The first phase, due by end-2027, provides roughly 200 MW of connection capacity and room for up to 100,000 specialized AI chips, operated by cloud division StackIT, with waste heat feeding the local district heating network. Ground has been broken; the project anchors Germany's and the EU's digital-sovereignty push as an alternative to US hyperscalers.","progress":"已奠基开工，首期200 MW目标2027年底建成；获德国政府与欧盟AI基础设施议程背书。"},
  {"id":6627,"name":"丘卡卢-佩吉铜金矿下部矿带扩建","en":"Cukaru Peki Lower Zone Expansion","country":"塞尔维亚","region":"欧洲","cat":"mining","coord":[22.08,44.02],"cap":"下部矿带含铜约220万吨；塞紫金整体目标年产铜45万吨","inv":38,"invText":"38亿美元","status":"在建","year":2029,"updated":"2026-06","owner":"紫金矿业","desc":"紫金矿业斥资38亿美元开发丘卡卢-佩吉深部斑岩铜金矿带（块状崩落法），与博尔铜矿协同后塞尔维亚年产铜45万吨，剑指欧洲最大铜生产商。","detail":"丘卡卢-佩吉铜金矿位于塞尔维亚东部博尔市附近，上部高品位矿带已于2021年投产。紫金矿业计划再投资38亿美元，以块状崩落法开发埋深逾460米、含铜约220万吨的下部斑岩矿带，并同步推进博尔铜矿扩建——塞紫金两公司2024年合计产铜已达45万吨（2023年为41.8万吨）。下部矿带建成后将进一步巩固紫金作为欧洲最大铜生产商的地位，是中资矿业在欧洲最大单体投资之一。","descEn":"Zijin Mining is investing $3.8bn to block-cave the Lower Zone porphyry (2.2 Mt contained copper, below 460 m) at Cukaru Peki, Serbia, alongside Bor expansions targeting 450,000 t/y of copper — Europe's largest copper producer.","detailEn":"Cukaru Peki near Bor in eastern Serbia saw its high-grade Upper Zone enter production in 2021. Zijin Mining now plans a further $3.8bn to develop the Lower Zone porphyry — about 2.2 Mt of contained copper below 460 m depth — as a block cave, in parallel with expansions at the Bor copper complex. Combined output from Zijin's two Serbian units reached 450,000 t in 2024 (418,000 t in 2023), positioning Zijin as Europe's largest copper producer and one of the biggest Chinese mining investments in Europe.","progress":"下部矿带38亿美元扩建推进中，塞紫金2024年合计铜产量已达45万吨。","flagship":false},
  {"id":6628,"name":"维斯卡里亚铜矿复产（瑞典基律纳）","en":"Viscaria Copper Mine Restart","country":"瑞典","region":"欧洲","cat":"mining","coord":[20.15,67.86],"cap":"年产铜精矿约2.6万吨（金属量），瑞典第二大铜生产商","inv":5.5,"invText":"约5.5亿美元（估）","status":"在建","year":2027,"updated":"2026-06","owner":"Gruvaktiebolaget Viscaria","desc":"瑞典基律纳Viscaria铜矿复产：环境许可终审生效，选厂2026年春开建、2027年建成，年产约2.6万吨铜，瑞典铜产量将增三分之一。","detail":"维斯卡里亚（Viscaria）铜矿位于瑞典最北部基律纳市郊，1997年关闭后由Gruvaktiebolaget Viscaria推动复产，是欧盟关键原材料自给战略下的代表性铜矿项目。瑞典最高法院驳回对环境许可的上诉，许可正式生效；美卓（Metso）已供应两台卧式磨机，Nordec中标选厂土建与钢结构，选厂2026年春开工、2027年建成，整体2027-28年投产，年产铜（精矿金属量）约2.6万吨，将使瑞典铜矿产量提高约三分之一，成为瑞典第二大铜生产商，并就近供应北欧绿色工业集群。","descEn":"The Viscaria mine outside Kiruna is being reopened after its environmental permit cleared Sweden's Supreme Court: processing-plant construction starts spring 2026 for 2027 completion, targeting ~26,000 t/y of copper — lifting Sweden's mined copper by a third.","detailEn":"Viscaria, closed in 1997 on the outskirts of Kiruna in Arctic Sweden, is a flagship of the EU's critical-raw-materials push. With the environmental permit now final after the Supreme Court declined the last appeal, Metso is supplying two grinding mills and Nordec is building the concentrator structure from spring 2026, for completion in 2027 and start-up in 2027-28. At about 26,000 t/y of copper in concentrate, Viscaria will become Sweden's second-largest copper producer and raise national mined output by roughly a third.","progress":"环境许可终审生效；2026年初签订磨机与选厂土建合同，选厂2026年春开建、2027年完工。","flagship":false},
  {"id":6629,"name":"塞浦路斯Cronos气田开发","en":"Cronos Gas Field Development (Cyprus)","country":"塞浦路斯","region":"欧洲","cat":"petro","coord":[32.7,33.6],"cap":"储量约3.1万亿立方英尺","inv":12,"invText":"约12亿美元（估）","status":"规划","year":2027,"updated":"2026-06","owner":"Eni（50%，作业者）/道达尔能源（50%）","desc":"塞浦路斯首个投入开发的海上气田：Eni的6区块Cronos气田经Zohr海底设施输往埃及Damietta液化厂出口，目标2027年首气。","detail":"Cronos气田位于塞浦路斯专属经济区6区块，发现资源量约3.1万亿立方英尺，Eni与道达尔能源各持50%。开发方案为快速回接：气流借用为埃及Zohr气田铺设的海底管道之一进入Zohr岸上处理设施，再经新建专线直供Damietta LNG液化厂出口欧洲，绕开埃及国内电网。2026年4月利马索尔东地中海能源大会上，Eni与埃及EGAS等签署处理运输协议（HTPA）、Damietta代加工合同及费率协议三份商业协议，最终投资决定预计2026年上半年作出，目标2027年（更稳妥为2028年）实现首气，将是塞浦路斯首个投产的海上气田。","descEn":"Cyprus's first offshore gas development: Eni's Cronos field in Block 6 will flow via Zohr's subsea pipelines to Egypt's Damietta LNG plant for export, targeting first gas in 2027.","detailEn":"Cronos, in Block 6 of Cyprus's EEZ with ~3.1 tcf of discovered resources (Eni 50% operator, TotalEnergies 50%), will be fast-tracked via one of the Zohr subsea pipelines into Zohr's onshore facilities in Egypt and a new line direct to the Damietta LNG plant. Three commercial agreements (HTPA, Damietta tolling, tariff) were signed in April 2026; FID is expected in H1 2026 with first gas targeted for 2027 (2028 seen as more realistic).","progress":"2026年4月：Eni与埃及方面签署HTPA、Damietta代加工与费率三份商业协议，FID预计2026年上半年，力争2027年首气。","flagship":false},
  {"id":6630,"name":"Fram Sør海底回接开发（北海）","en":"Fram Sor Subsea Development","country":"挪威","region":"欧洲","cat":"petro","coord":[3.5,61],"cap":"可采约1.16亿桶油当量（75%原油），回接Troll C平台","inv":21,"invText":"210亿挪威克朗（约21亿美元）","status":"在建","year":2029,"updated":"2026-06","owner":"Equinor（45%）/Vår Energi（40%）/INPEX Idemitsu（15%）","desc":"Equinor 2025年6月批准并提交210亿克朗Fram Sør开发方案：海底回接Troll C平台，开采1.16亿桶油当量，挪威大陆架首个全电动水下采油树项目，2029年底投产。","detail":"Fram Sør是挪威北海Troll-Fram区域的海底回接开发项目，Equinor及伙伴2025年6月26日作出投资决定并向挪威能源部提交开发运营计划（PDO），投资逾210亿挪威克朗（约21亿美元）。项目开发多个卫星油气藏，可采资源约1.16亿桶油当量（75%为原油、25%为天然气），通过海底设施回接既有Troll C平台处理后外输，气经管网供应欧洲。由于Troll C采用岸电供电，生产排放极低；项目还将首次在挪威大陆架使用全电动水下采油树，免除液压油系统。计划2029年底投产，开发期可为挪威供应链创造约4500个全时岗位。","descEn":"Equinor and partners approved the NOK 21bn ($2.1bn) Fram Sor subsea tieback in June 2025: ~116 MMboe tied back to the shore-powered Troll C platform, the first all-electric subsea trees on the Norwegian shelf, online by end-2029.","detailEn":"Fram Sor, in the Troll-Fram area of the Norwegian North Sea, was sanctioned on 26 June 2025 with a PDO submitted to Norway's energy ministry. The >NOK 21 billion project develops ~116 million boe (75% oil, 25% gas) via subsea tiebacks to the existing shore-powered Troll C platform, giving very low production emissions, and pioneers all-electric subsea christmas trees on the NCS. Production starts by end-2029; partners are Equinor (45%), Var Energi (40%) and INPEX Idemitsu (15%).","progress":"2025年6月26日：合作方批准投资并提交PDO，投资逾210亿克朗；目标2029年底投产，经Troll C平台外输。","flagship":false},
  {"id":6631,"name":"Argo-Cassiopea气田（西西里海峡）","en":"Argo-Cassiopea Gas Field","country":"意大利","region":"欧洲","cat":"petro","coord":[14.1,36.6],"cap":"峰值约15亿立方米/年，储量约100亿立方米","inv":10,"invText":"约10亿美元（估）","status":"投运","year":2024,"updated":"2026-06","owner":"Eni（作业者）/Energean","desc":"意大利最重要的天然气开发项目：西西里海峡全水下开发，4口海底井经60公里管道接Gela处理厂，2024年8月投产，峰值15亿方/年。","detail":"Argo-Cassiopea是意大利近年最重要的天然气开发项目，位于西西里海峡，由Eni作业、Energean参股。气田储量约100亿立方米，采用全水下开发方案：4口海底井的天然气经60公里海底管道输往西西里岛Gela岸上处理厂，海面无任何永久设施、视觉零影响。2024年8月19日开工仅三年后实现投产，峰值年产约15亿立方米，全部供应意大利国内市场，提升本土气源自给。配套建设3.6MWp光伏电站，使项目范围一、二碳排放实现中和，是地中海低碳气田开发的样板工程。","descEn":"Italy's most important gas development: a fully subsea project in the Strait of Sicily with four wells tied back 60 km to the Gela plant, online since August 2024 with peak output of 1.5 bcm/yr.","detailEn":"Argo-Cassiopea, operated by Eni in JV with Energean, holds ~10 bcm of reserves in the Strait of Sicily. The fully subsea development — four wells flowing through a 60 km pipeline to the onshore Gela processing plant, with no surface facilities — started production on 19 August 2024, three years after construction began. Peak output is ~1.5 bcm/yr, all for the Italian market, and a dedicated 3.6 MWp solar plant makes the project carbon-neutral for Scope 1 and 2 emissions.","progress":"2024年8月19日投产，开工仅三年建成；产量爬坡至峰值约15亿立方米/年，全部供应意大利国内市场。","flagship":false},
  {"id":6632,"name":"英国东西铁路（牛津—剑桥）","en":"East West Rail (Oxford-Cambridge)","country":"英国","region":"欧洲","cat":"transport","coord":[-0.45,52.05],"cap":"牛津—剑桥走廊全长约140公里","inv":85,"invText":"约67亿英镑（约85亿美元，估）","status":"在建","year":2025,"updated":"2026-06","owner":"英国运输部·East West Railway Company","desc":"重建牛津—剑桥“知识弧”铁路走廊：一期Bicester—Bletchley新线2025年通车，政府追加25亿英镑推进至贝德福德、剑桥，全程目标2030年代。","detail":"东西铁路（EWR）旨在恢复并新建牛津—米尔顿凯恩斯—贝德福德—剑桥约140公里铁路走廊，串联英国“牛剑弧”科创带，总投资约67亿英镑。一期Bicester—Bletchley段提前且低于预算建成，2025年开行牛津—米尔顿凯恩斯客运服务（受工会争议影响延迟开通）；配套的剑桥南站预计2026年中启用。2024—2025年政府两度背书并追加25亿英镑，2025年11月公布优化设计的下一阶段方案，贝德福德—剑桥新建段处于规划审批阶段，全线贯通目标2030年代，预计为走廊带来数百亿英镑增长。","descEn":"Rebuilding the Oxford-Cambridge 'knowledge arc' railway: the Bicester-Bletchley first stage opened for Oxford-Milton Keynes services in 2025, with GBP 2.5 billion of new government funding pushing the roughly GBP 6.7 billion corridor on to Bedford and Cambridge in the 2030s.","detailEn":"East West Rail restores and builds about 140 km of railway linking Oxford, Milton Keynes, Bedford and Cambridge along the UK's premier science corridor, at a programme cost of roughly GBP 6.7 billion. Stage one (Bicester-Bletchley) was delivered early and under budget, enabling Oxford-Milton Keynes services from 2025 (start-up delayed by a union dispute), with Cambridge South station due to open from mid-2026. The government committed an extra GBP 2.5 billion and unveiled the next-phase design in November 2025; the new Bedford-Cambridge section is in consenting, targeting full opening in the 2030s.","progress":"2025-11：一期牛津—米尔顿凯恩斯段建成、2025年开行服务；政府追加25亿英镑并公布贝德福德—剑桥段优化方案，剑桥南站2026年中启用。","route":[[-1.27,51.753],[-0.736,52],[-0.466,52.136],[0.121,52.205]],"flagship":false},
  {"id":6633,"name":"安卡拉—伊兹密尔高速铁路","en":"Ankara-Izmir High-Speed Railway","country":"土耳其","region":"欧洲","cat":"transport","coord":[29.5,38.7],"cap":"约530公里双线电气化 / 设计时速250公里","inv":35,"invText":"意企EPC+融资合同约21亿欧元，全线投资约35亿美元（估）","status":"在建","year":2027,"updated":"2026-06","owner":"土耳其国家铁路（TCDD）","desc":"连接首都与第三大城市的530公里高铁，时速250公里，建成后安卡拉—伊兹密尔由14小时压缩至3.5小时；2025年意大利三企获21亿欧元EPC合同，2026年先通至阿菲永。","detail":"安卡拉—伊兹密尔高铁全长约530公里（正线503公里），双线电气化、设计时速250公里，经波拉特勒、阿菲永卡拉希萨尔、乌沙克、马尼萨至伊兹密尔，建成后两市旅行时间从14小时以上压缩至约3.5小时，预计年运送旅客1300万人次、货物9000万吨。项目分段推进多年后，2025年5月意大利GCF、Tratos、SAFET三家企业联合获得约21亿欧元的EPC+融资合同负责轨道、电气化与信号；土耳其交通部计划2026年先开通安卡拉—阿菲永段，全线目标2027—2028年贯通，是土耳其高铁网向爱琴海延伸的骨干工程。","descEn":"A 530-km, 250-km/h line linking the capital with Turkey's third city, cutting Ankara-Izmir from over 14 hours to about 3.5; Italian firms won a EUR 2.1 billion EPCF contract in 2025, with the Afyonkarahisar section targeted for 2026.","detailEn":"The Ankara-Izmir HSR comprises about 530 km of electrified double track (503 km mainline) via Polatli, Afyonkarahisar, Usak and Manisa, designed for 250 km/h and forecast to carry 13 million passengers and 90 million tonnes of freight a year. In May 2025 the Italian trio GCF, Tratos and SAFET secured a roughly EUR 2.1 billion EPC-plus-financing contract for track, electrification and signalling. Turkey aims to open Ankara-Afyonkarahisar in 2026, with the full line to Izmir targeted around 2027-2028, extending the national HSR grid to the Aegean.","progress":"2025-05：意大利GCF/Tratos/SAFET联合体获约21亿欧元EPC+融资合同；交通部计划2026年先开通至阿菲永卡拉希萨尔段。","route":[[32.85,39.92],[30.54,38.76],[29.41,38.68],[27.43,38.61],[27.14,38.42]],"flagship":false},
  {"id":6634,"name":"那不勒斯—巴里高速铁路","en":"Naples-Bari High-Speed Railway","country":"意大利","region":"欧洲","cat":"transport","coord":[15.5,41.2],"cap":"约145公里新建高速/高承载线（时速250公里）","inv":67,"invText":"总投资61亿欧元（PNRR欧盟复苏基金支持）","status":"在建","year":2028,"updated":"2026-06","owner":"意大利铁路网公司（RFI）·Webuild承建","desc":"意大利南部干线工程：那不勒斯—巴里高速/高承载铁路总投资61亿欧元，建成后两市2小时直达、罗马—巴里3小时，分段通车、2028年全线运营。","detail":"那不勒斯—巴里高速/高承载铁路是意大利“连接南方”战略与欧盟PNRR复苏计划的旗舰工程，由RFI业主、Webuild等承建，总投资约61亿欧元（其中超过65%已落实），沿线新建坎切洛—弗伦托、伊尔皮尼亚、奥尔萨拉、罗凯塔等长大隧道群，设计时速250公里。建成后那不勒斯—巴里旅行时间压缩至2小时、罗马—巴里约3小时，将南部亚得里亚海岸纳入全国高铁网。项目经特别政府专员机制提速，格罗塔米纳尔达隧道已掘进约60%，两台新TBM正组装投入罗凯塔（6.4公里）与奥尔萨拉（10公里）隧道；分段陆续开通，全线完工2027年、2028年全面运营。","descEn":"Italy's flagship southern rail link: the EUR 6.1 billion Naples-Bari high-speed/high-capacity line will put Bari two hours from Naples and three from Rome, opening in stages to full service in 2028.","detailEn":"The Naples-Bari HS/HC railway, owned by RFI and built largely by Webuild under Italy's PNRR recovery plan, carries a total investment of about EUR 6.1 billion, over 65% already funded. The 250-km/h route requires major tunnels (Cancello-Frasso, Hirpinia, Orsara, Rocchetta); Grottaminarda tunnel is about 60% excavated and two new TBMs are being assembled for the 6.4-km Rocchetta and 10-km Orsara bores. Sections are opening progressively, with works completing in 2027 and full operation in 2028, bringing southern Adriatic Italy onto the national high-speed network.","progress":"2026-04：格罗塔米纳尔达隧道掘进约60%，两台新TBM组装投入罗凯塔与奥尔萨拉隧道；全线完工2027年、2028年全面运营。","route":[[14.27,40.85],[15.06,41.07],[15.55,41.46],[16.87,41.12]],"flagship":false},
  {"id":6635,"name":"罗马尼亚达马（Dama）1044MW光伏电站","en":"Dama Solar (1,044 MW, Arad)","country":"罗马尼亚","region":"欧洲","cat":"renewable","coord":[21.4,46.3],"cap":"1044MW（约160万块组件，年发电约150万MWh）","inv":7,"invText":"约7亿美元（估）","status":"规划","year":2028,"updated":"2026-06","owner":"Rezolv Energy","desc":"欧洲最大单体光伏电站：罗马尼亚阿拉德县1044MW，已获731.2MW差价合约，2026年开工。","detail":"Rezolv Energy从Monsson手中收购开发权的达马（Dama）光伏项目位于罗马尼亚西部阿拉德县，规划装机1044MW，建成后将是欧洲最大的单体光伏电站。项目将安装约160万块光伏组件，年发电约150万MWh，可满足37万户家庭用电。2025年8月，项目中731.2MW容量在罗马尼亚第二轮差价合约（CfD）拍卖中中标，锁定长期电价；计划2026年进入建设阶段。项目强调农光互补，建成后土地恢复牧场功能、以羊群放牧管理植被。","descEn":"Europe's largest single-site solar plant: 1,044 MW in Arad County, Romania; 731.2 MW secured CfDs, construction from 2026.","detailEn":"Acquired from Monsson by Rezolv Energy, the Dama Solar project in Arad County, western Romania, will reach 1,044 MW - Europe's largest single-site solar plant once built. Around 1.6 million panels will generate about 1.5 TWh a year, enough for 370,000 households. In August 2025 the project won contracts-for-difference for 731.2 MW in Romania's second CfD auction; construction is planned from 2026, with agrivoltaic sheep grazing restoring the over-farmed land.","progress":"2025年8月在罗马尼亚第二轮CfD拍卖中为731.2MW容量锁定差价合约；计划2026年开工建设，建成后为欧洲最大单体光伏电站。","flagship":false},
  {"id":6636,"name":"阿塞拜疆比拉苏瓦尔445MW光伏电站","en":"Bilasuvar Solar PV (445 MW)","country":"阿塞拜疆","region":"欧洲","cat":"renewable","coord":[48.45,39.43],"cap":"445MW（年发电约8.97亿千瓦时）","inv":3,"invText":"约3亿美元（估）","status":"在建","year":2026,"updated":"2026-06","owner":"Masdar/SOCAR Green","desc":"阿塞拜疆最大光伏电站：Masdar与SOCAR合作445MW，2025年8月开工，力争2026年底并网。","detail":"比拉苏瓦尔光伏电站是阿塞拜疆在建的全国最大光伏项目，装机445MW，由阿联酋Masdar与阿塞拜疆国家石油公司旗下SOCAR Green合作开发，与315MW内夫切拉光伏、240MW风电同属760MW一揽子开发计划。项目2024年11月COP29巴库峰会期间完成融资关闭，欧洲复兴开发银行（EBRD）、亚洲开发银行（ADB）与亚投行（AIIB）联合贷款；2025年8月12日开工。建成后年发电8.97亿千瓦时，可满足17.9万户家庭用电、年节省天然气1.93亿立方米，阿能源部预计2026年底建成并网。","descEn":"Azerbaijan's largest solar plant: 445 MW by Masdar and SOCAR Green, under construction since August 2025, grid connection targeted by end-2026.","detailEn":"The Bilasuvar plant is Azerbaijan's largest solar project under construction at 445 MW, developed by Masdar with SOCAR Green as part of a 760 MW package alongside the 315 MW Neftchala PV and a 240 MW wind project. Financial close was reached at COP29 in Baku in November 2024 with EBRD, ADB and AIIB lending; construction began on 12 August 2025. It will generate 897 GWh a year for 179,000 homes, saving 193 mcm of gas; the Energy Ministry expects commissioning by end-2026.","progress":"2025年8月12日开工建设；EBRD/ADB/AIIB联合融资已于COP29期间关闭，阿能源部2026年2月表示力争2026年底建成并网。","flagship":false},
  {"id":6637,"name":"芬兰拉亚迈恩屈莱（Rajamäenkylä）陆上风电场","en":"Rajamaenkyla Onshore Wind Farm (367 MW, OX2/Amazon PPA)","country":"芬兰","region":"欧洲","cat":"renewable","coord":[21.9,62.3],"cap":"367MW（54台Nordex N175/6.8；与Honkakangas 105MW同批FID合计472MW）","inv":8,"invText":"约8亿美元（两场打包，7亿欧元）","status":"在建","year":2028,"updated":"2026-06","owner":"OX2","desc":"北欧2025年最大陆上风电FID：OX2投资7亿欧元建设472MW，亚马逊签购电协议，2028年建成。","detail":"瑞典开发商OX2于2025年对芬兰两座陆上风电场作出最终投资决定（FID），合计装机472MW、投资约7亿欧元，是北欧当年最大的陆上风电投资之一：主体拉亚迈恩屈莱风电场位于南博滕区卡里约基与伊索约基，安装54台Nordex N175/6.8机组、装机367MW，计划2028年建成；配套的Honkakangas风电场（哈尔苏阿，16台、约105MW）2027年完工。亚马逊已为472MW容量签署长期购电协议，绿电将主要供给其北欧云数据中心。OX2同年还对芬兰另外三座合计277MW的风电场作出投资决定。","descEn":"The Nordics' biggest onshore wind FID of 2025: OX2 committed EUR 700 m to 472 MW in Finland, backed by an Amazon PPA; Rajamaenkyla (367 MW) completes in 2028.","detailEn":"Swedish developer OX2 took final investment decisions on two Finnish onshore wind farms totalling 472 MW with about EUR 700 m of investment. The flagship Rajamaenkyla wind farm in Karijoki and Isojoki (South Ostrobothnia) will install 54 Nordex N175/6.8 turbines for 367 MW by 2028, while Honkakangas in Halsua (about 105 MW) completes in 2027. Amazon signed a long-term PPA for the 472 MW, mainly powering its Nordic data centres.","progress":"2025年完成FID并开工，亚马逊为472MW签署长期购电协议；Honkakangas计划2027年、拉亚迈恩屈莱计划2028年建成。","flagship":false},
  {"id":6638,"name":"保加利亚特内沃（Tenevo）光储混合电站","en":"Tenevo Solar + Storage Hybrid (315 MW / 760 MWh)","country":"保加利亚","region":"欧洲","cat":"renewable","coord":[26.57,42.35],"cap":"315MW光伏 + 760MWh电池储能","inv":3,"invText":"约3亿美元（估）","status":"在建","year":2026,"updated":"2026-06","owner":"Renalfa IPP","desc":"保加利亚最大光储混合电站：315MW光伏+760MWh储能，一期2025年并网、二期2026年初投运。","detail":"特内沃光储混合电站位于保加利亚东南部扬博尔州通贾市镇，规划315MW光伏与760MWh电池储能，是保加利亚乃至东南欧最大的光储一体化项目之一，由保加利亚-奥地利合资的Renalfa IPP开发。项目一期已于2025年并入保加利亚输电网（ESO），二期计划2026年初投运。2025年保加利亚新增光伏装机达1416MW，特内沃与塞拉诺夫齐（59.8MW光伏+107.3MWh储能）等混合项目是当年最大的新增并网项目，标志着保加利亚光伏进入\"光伏+储能\"规模化阶段，为巴尔干电网调峰提供支撑。","descEn":"Bulgaria's largest solar-plus-storage hybrid: 315 MW of PV with 760 MWh of batteries; phase 1 grid-connected in 2025, phase 2 online in early 2026.","detailEn":"The Tenevo hybrid in Tundzha municipality, Yambol province, pairs 315 MW of solar PV with a 760 MWh battery system - one of the largest solar-plus-storage projects in Bulgaria and Southeast Europe, developed by Bulgarian-Austrian Renalfa IPP. Phase 1 was connected to the ESO transmission grid in 2025, with phase 2 scheduled for early 2026, headlining the record 1,416 MW of solar Bulgaria added in 2025.","progress":"一期已于2025年并网（当年保加利亚最大新增项目之一），二期计划2026年初投运；2025年保加利亚新增光伏1416MW创纪录。","flagship":false},

  // ===== 大洋洲（6645-6659）=====
  {"id":6645,"name":"蓝鲭鱼海上风电（吉普斯兰）","en":"Blue Mackerel Offshore Wind","country":"澳大利亚","region":"大洋洲","cat":"renewable","coord":[147.3,-38.55],"cap":"约1GW","inv":32,"invText":"≈50亿澳元（估）","status":"规划","year":2029,"updated":"2025-12","owner":"Parkwind（JERA Nex 旗下）","flagship":false,"desc":"维州吉普斯兰海域约1GW海上风电，澳首个获批可行性阶段管理计划的项目，2025年12月获联邦重大项目地位。","detail":"位于维多利亚州吉普斯兰海岸约10公里海域（Seaspray 与 Woodside 之间），规划容量约1GW，开发商为比利时 Parkwind（隶属 JERA Nex）。它是澳大利亚首个获海上基础设施监管局（OIR）批准可行性阶段管理计划的海上风电项目：2025年3月完成地球物理与岩土海上勘察并布设风浪监测浮标，7月启动为期两年的海洋环境基线监测（含海洋哺乳动物航测与被动声学监测），12月获联邦政府授予'重大项目地位'。若环评与最终投资决定顺利，预计2029年开工、2032年首次发电，接入拉特罗布谷电网，支撑维州2040年9GW海上风电目标。","epc":"EPC未授标(可行性许可阶段)","epcStatus":"未招标","descEn":"~1GW offshore wind project about 10 km off Victoria's Gippsland coast; first Australian offshore wind project with an approved feasibility-stage management plan, awarded federal Major Project Status in December 2025.","detailEn":"Developed by Parkwind (part of JERA Nex), Blue Mackerel sits about 10 km offshore between Seaspray and Woodside in the Gippsland declared area, with around 1GW of planned capacity. It became the first Australian offshore wind project to receive feasibility-stage management plan approval from the Offshore Infrastructure Regulator. Geophysical and geotechnical marine surveys plus wind-wave monitoring were completed in March 2025, a two-year environmental baseline campaign began in July 2025, and federal Major Project Status was granted in December 2025. Subject to approvals and FID, construction would start in 2029 with first power targeted for 2032, feeding the Latrobe Valley grid.","progress":"2025年12月获联邦重大项目地位，两年期环境基线监测进行中，目标2029年开工、2032年首发电。"},
  {"id":6646,"name":"梅里诺光储混合项目（古尔本）","en":"Merino Solar Farm & BESS","country":"澳大利亚","region":"大洋洲","cat":"renewable","coord":[149.72,-34.85],"cap":"450MW光伏+450MW/1800MWh储能","inv":10,"invText":"≈15亿澳元（估）","status":"规划","year":2028,"updated":"2025-10","owner":"EDP Renewables（葡电新能源）","flagship":false,"desc":"新州古尔本附近450MW光伏配套1.8GWh电池的大型混合项目，2025年10月中标联邦CIS第四轮招标。","detail":"位于新南威尔士州南部古尔本附近，由葡电新能源（EDP Renewables APAC）开发，规划450MW光伏并同址配套450MW/1800MWh四小时电池储能，是2025年10月澳联邦容量投资计划（CIS）第四轮招标的中标项目之一——该轮共授出6.6GW，光储混合项目首次包揽主要份额。EDP 同期与昆士兰投资公司（QIC）签署合作推进旗下1.7GW光储组合。项目预计2026年下半年达到'可开工'状态，2030年前须建成交付，建成后将成为堪培拉—悉尼走廊上重要的可调度清洁电源。","epc":"EPC未招标","epcStatus":"未招标","descEn":"450MW solar plus 450MW/1,800MWh battery hybrid near Goulburn, NSW; winner of Australia's Capacity Investment Scheme Tender 4 in October 2025.","detailEn":"Developed by EDP Renewables APAC near Goulburn in southern New South Wales, the Merino hybrid project pairs 450MW of solar with a co-located 450MW/1,800MWh four-hour battery. It was among 20 winners of Capacity Investment Scheme (CIS) Tender 4 announced in October 2025, a round dominated by solar-battery hybrids totalling 6.6GW. EDP is fast-tracking 1.7GW of solar and storage in Australia following the award, partnering with QIC on the battery component. Merino is expected to reach ready-to-build status in H2 2026 and must be delivered by 2030 under the 20-year CIS underwriting agreement.","progress":"2025年10月中标CIS第四轮并获20年收入保障，预计2026年下半年达到可开工状态。"},
  {"id":6647,"name":"蒂米希地热电站二期（新西兰）","en":"Te Mihi Geothermal Stage 2","country":"新西兰","region":"大洋洲","cat":"renewable","coord":[176.08,-38.64],"cap":"101MW","inv":4.2,"invText":"≈7.1亿新西兰元","status":"在建","year":2027,"updated":"2024-11","owner":"Contact Energy（新西兰康塔能源）","flagship":false,"desc":"陶波怀拉基地热田101MW新机组，替代运行60余年的老电站，目标2027年9月投产。","detail":"新西兰北岛陶波（Taupō）怀拉基地热田的更新换代工程：Contact Energy 于2024年11月作出投资决定，投资约7.1亿新西兰元在蒂米希电站旁新建101MW地热机组（Te Mihi Stage 2），以替代1958年投运、即将退役的怀拉基老电站，EPC 由以色列奥玛特（Ormat）承担。项目与陶哈拉（174MW）、Te Huka 三号机组等共同构成 Contact 的地热扩张组合，建成后新西兰地热装机将突破1.2GW。机组采用双循环+蒸汽联合技术，提高地热流体利用率并大幅降低排放，目前土建与设备制造同步推进，计划2027年9月并网发电。","descEn":"101MW geothermal unit at the Wairakei field near Taupō, replacing the 1958 Wairakei station; NZ$712m FID taken in November 2024, commissioning targeted for September 2027.","detailEn":"Contact Energy took FID in November 2024 on Te Mihi Stage 2, a ~NZ$712 million, 101MW geothermal plant beside the existing Te Mihi station in the Wairakei field near Taupō, replacing the retiring 1958-vintage Wairakei power station. Ormat holds the EPC contract for the binary-plus-steam unit, which uses geothermal fluid more efficiently and cuts emissions. Together with Tauhara (174MW) and Te Huka 3, it anchors Contact's geothermal build-out that will push New Zealand's geothermal fleet beyond 1.2GW. Civil works and equipment fabrication are under way, with commissioning targeted for September 2027.","progress":"在建，奥玛特承担EPC，机组制造与土建并行，目标2027年9月并网。"},
  {"id":6648,"name":"蒂纳河水电站（所罗门群岛）","en":"Tina River Hydropower Project","country":"所罗门群岛","region":"大洋洲","cat":"renewable","coord":[160.06,-9.55],"cap":"15MW","inv":2.4,"invText":"≈2.4亿美元","status":"在建","year":2028,"updated":"2026-05","owner":"Tina Hydropower Ltd（韩国水资源公社/现代工程）","flagship":false,"desc":"所罗门群岛首个大型基建项目：15MW水电站将供应霍尼亚拉近70%电力，2026年5月整体进度30.6%。","detail":"所罗门群岛史上最大基础设施项目，位于瓜达尔卡纳尔岛蒂纳河上游、距首都霍尼亚拉约20公里。装机15MW，总投资约2.4亿美元，由世界银行、亚开行、绿色气候基金、韩国进出口银行等联合融资，韩国水资源公社（K-water）与现代工程组成的 Tina Hydropower Ltd 以 BOOT 模式开发。建成后可满足霍尼亚拉近70%的电力需求，替代昂贵的柴油发电并显著降低电价。项目2022年开工，进场道路完成超95%，隧道掘进机（TBM）2025年运抵并于11月启动全断面掘进，大坝主体2026年开浇，截至2026年5月10日整体进度30.6%，计划2028年初投入商运。","descEn":"Solomon Islands' largest-ever infrastructure project: a 15MW, ~US$240m hydropower plant on the Tina River that will supply nearly 70% of Honiara's electricity; 30.6% complete as of May 2026, commissioning in early 2028.","detailEn":"Located on the upper Tina River about 20 km from Honiara on Guadalcanal, this 15MW, ~US$240 million plant is the Solomon Islands' first large infrastructure project, financed by the World Bank, ADB, Green Climate Fund and K-EXIM, and developed under a BOOT model by Tina Hydropower Ltd (K-water and Hyundai Engineering). Once online it will cover nearly 70% of Honiara's power demand, displacing costly diesel generation. Over 95% of access roads are complete, the tunnel boring machine arrived in 2025 and began full tunnelling in November, and main dam works started in 2026. Overall progress reached 30.6% by 10 May 2026, with commercial operation targeted for early 2028.","progress":"截至2026年5月整体进度30.6%，TBM引水隧洞掘进与大坝主体施工推进中，目标2028年初投产。"},
  {"id":6649,"name":"穆奇亚电池储能（西澳）","en":"Muchea Battery Energy Storage System","country":"澳大利亚","region":"大洋洲","cat":"storage","coord":[115.98,-31.58],"cap":"164MW/905MWh","inv":3,"invText":"≈4.5亿澳元（估）","status":"在建","year":2027,"updated":"2025-10","owner":"Neoen","flagship":false,"desc":"Neoen 在珀斯以北穆奇亚开建164MW/905MWh长时电池，支撑西澳SWIS电网退煤。","detail":"法国 Neoen 在西澳珀斯以北约50公里的穆奇亚（Muchea）开发的164MW/905MWh（约5.5小时）电池储能电站，2025年10月宣布开工，是其继科利（Collie）超级电池之后在西澳的又一大型项目。西澳西南互联电网（SWIS）孤立于国家电力市场之外，州政府计划2030年前关停全部国有燃煤机组，长时电池成为顶替晚高峰出力的关键资产。该项目与 Neoen 同期推进的2.2GWh在建组合（含新州、西澳多个站点）共同使其澳洲储能版图突破数吉瓦时，建成后将参与容量市场与频率辅助服务。","epc":"EPC牵头：Tesla Energy；土建/变电站EPC：UGL(CIMIC旗下)；电池 Tesla Megapack 2XL(252台)","epcStatus":"已授标","descEn":"Neoen's 164MW/905MWh (~5.5-hour) battery at Muchea north of Perth, which began construction in October 2025 to back Western Australia's SWIS grid as state-owned coal plants retire by 2030.","detailEn":"Neoen began construction in October 2025 on the 164MW/905MWh Muchea BESS, about 50 km north of Perth — its next major Western Australian asset after the Collie super battery. The isolated South West Interconnected System (SWIS) is phasing out all state-owned coal generation by 2030, making long-duration batteries critical for evening peak capacity. Muchea is part of roughly 2.2GWh of storage Neoen currently has in construction across Australia, and will provide capacity-market and frequency services once energised.","progress":"2025年10月宣布开工建设，为西澳SWIS电网2030年退煤计划提供约5.5小时长时容量。"},
  {"id":6650,"name":"布林克沃思电池储能（南澳）","en":"Brinkworth BESS","country":"澳大利亚","region":"大洋洲","cat":"storage","coord":[138.4,-33.7],"cap":"250MW/1000MWh（铭牌）","inv":3.6,"invText":"≈5.5亿澳元（估）","status":"规划","year":2029,"updated":"2026-05","owner":"Akaysha Energy（贝莱德旗下）","flagship":false,"desc":"Akaysha 250MW/1GWh大电池，2026年5月在南澳首轮FERM容量招标中赢得15年协议。","detail":"贝莱德旗下 Akaysha Energy 在南澳中北部布林克沃思（Brinkworth）规划的250MW/1000MWh电池储能项目。2026年5月29日，南澳首轮'坚强能源可靠性机制'（FERM）招标揭晓，六个电池项目共获1334MW/5336MWh的15年政府支持协议，以在2026年北部电厂（Torrens Island B 之后）退役、需求增长背景下托底系统可靠性；布林克沃思以92MW承诺出力/736MWh中标第二类（2029年11月交付档）。项目毗邻 ElectraNet 主干网，将采用四小时级配置，与 Akaysha 旗下瓦拉塔超级电池、奥拉纳等组成其超4GWh的澳洲在建/在运组合。","epc":"EPC未招标","epcStatus":"未招标","descEn":"Akaysha Energy's 250MW/1,000MWh battery at Brinkworth, South Australia, awarded a 15-year agreement in SA's first FERM tender (May 2026) with operations targeted for November 2029.","detailEn":"BlackRock-backed Akaysha Energy's 250MW/1,000MWh nameplate BESS at Brinkworth in South Australia's Mid North. In the state's first Firm Energy Reliability Mechanism (FERM) tender, announced on 29 May 2026, six battery projects totalling 1,334MW/5,336MWh won 15-year supported agreements to underpin reliability as ageing gas units retire and demand grows. Brinkworth was awarded in Category 2 with 92MW committed output and 736MWh, targeting November 2029 operations. Sitting next to ElectraNet's backbone, it joins Akaysha's 4GWh-plus Australian fleet that includes the Waratah Super Battery and Orana BESS.","progress":"2026年5月在南澳首轮FERM招标中获15年支持协议，目标2029年11月投运。"},
  {"id":6651,"name":"珀达曼卡拉萨尿素厂（Ceres 项目）","en":"Perdaman Ceres Urea Plant (Karratha)","country":"澳大利亚","region":"大洋洲","cat":"ci","coord":[116.78,-20.62],"cap":"200万吨/年尿素","inv":42,"invText":"≈65亿澳元","status":"在建","year":2027,"updated":"2025-12","owner":"Perdaman Chemicals & Fertilisers","flagship":true,"desc":"65亿澳元、200万吨/年的澳大利亚最大尿素厂，以伍德赛德天然气为原料，2025年建设进度过半。","detail":"位于西澳卡拉萨西北约20公里的布鲁普（Burrup）半岛，总投资约65亿澳元，建成后年产约200万吨尿素，将是澳大利亚最大、全球单系列规模领先的尿素工厂。项目以伍德赛德20年期天然气供应协议为原料保障，并与 Incitec Pivot 签订长期承购；获北澳基础设施基金（NAIF）、澳出口融资局等政策性融资支持，EPC 由意大利 Webuild/Saipem 联合体承担，建设高峰雇佣约2000人。2023年动工，截至2025年整体进度约50%，计划2027年投产。项目把皮尔巴拉的天然气就地转化为高附加值化肥出口，亦为后续布鲁普化工集群（含氨等）奠定公用工程基础。","epc":"EPC：Saipem+Clough 50/50联合体(约27亿美元,Clough破产后由Webuild承接份额)；工艺技术 Topsoe SynCOR+Snamprogetti","epcStatus":"已授标","descEn":"Australia's largest urea plant: a ~A$6.5bn, 2 Mtpa facility on the Burrup Peninsula near Karratha, fed by a 20-year Woodside gas deal; construction passed 50% in 2025 with first production due 2027.","detailEn":"Perdaman's Project Ceres, about 20 km north-west of Karratha on Western Australia's Burrup Peninsula, is a ~A$6.5 billion plant that will produce roughly 2 million tonnes of urea per year — Australia's largest. Feedstock is secured under a 20-year gas supply agreement with Woodside, with offtake contracted to Incitec Pivot, and financing support from NAIF and Export Finance Australia. The Webuild/Saipem-built project broke ground in 2023, employs about 2,000 construction workers at peak, reached ~50% completion in 2025 and targets first production in 2027, converting Pilbara gas into high-value fertiliser exports.","progress":"截至2025年建设进度约50%，机械设备安装推进中，计划2027年投产。"},
  {"id":6652,"name":"Firmus 南门 AI 数据中心（朗塞斯顿）","en":"Firmus Project Southgate AI Factory (Launceston)","country":"澳大利亚","region":"大洋洲","cat":"datacenter","coord":[147.18,-41.45],"cap":"一期90MW（约3.68万颗英伟达GB300）","inv":14,"invText":"一期1a约21亿澳元；总体计划约45亿美元","status":"在建","year":2026,"updated":"2026-04","owner":"Firmus Technologies（英伟达参投）","flagship":true,"desc":"英伟达参投的塔斯马尼亚水电'AI工厂'：一期90MW、约3.68万颗GB300，2026年底建成并筹备ASX上市。","detail":"英伟达参投的澳企 Firmus 在塔斯马尼亚朗塞斯顿圣伦纳兹（St Leonards）建设的绿色'AI工厂'园区，即'南门计划'（Project Southgate）旗舰站点：一期1a投资约21亿澳元、44MW，1b 翻倍至90MW，部署约3.68万颗英伟达 GB300 GPU，采用浸没式液冷并依托塔州以水电为主的低碳电网，计划2026年底建成。Southgate 总体为约45亿美元的首期建设计划并向墨尔本等地扩展，已签下全球超大规模云厂商多年期协议。2026年4月公司完成5.05亿美元股权融资（Coatue 领投、英伟达跟投），估值达55亿美元，并获黑石约100亿美元债务支持，拟于年中在澳交所IPO募资约20亿美元。","epc":"业主自管交付，总承包未公开","epcStatus":"未公开","descEn":"Nvidia-backed Firmus is building its 'Project Southgate' AI factory at St Leonards, Launceston: 90MW and ~36,800 GB300 GPUs by late 2026 on Tasmania's hydro-powered grid, with a ~US$4.5bn initial programme and an ASX IPO planned.","detailEn":"Firmus Technologies' flagship Project Southgate campus in St Leonards, Launceston, anchors a ~US$4.5 billion initial construction programme. Stage 1a (~A$2.1bn, 44MW) is under construction, with Stage 1b doubling capacity to 90MW by late 2026, hosting roughly 36,800 Nvidia GB300 GPUs in immersion-cooled halls powered by Tasmania's predominantly hydro grid. Firmus has signed a multi-year agreement with a global hyperscaler, raised US$505m in April 2026 (led by Coatue, with Nvidia participating) at a US$5.5bn valuation, secured ~US$10bn of Blackstone debt, and is preparing a ~US$2bn ASX IPO.","progress":"2026年4月完成5.05亿美元融资（估值55亿美元），一期1a建设中、年底扩至90MW，并筹备澳交所IPO。"},
  {"id":6653,"name":"微软新西兰北部云区域（奥克兰）","en":"Microsoft New Zealand North Cloud Region","country":"新西兰","region":"大洋洲","cat":"datacenter","coord":[174.6,-36.82],"cap":"三可用区超大规模云区域","inv":6,"invText":"≈10亿新西兰元（估）","status":"投运","year":2024,"updated":"2024-12","owner":"微软","flagship":false,"desc":"新西兰首个本土超大规模云区域，2024年12月在奥克兰启用，累计投入约10亿新西兰元。","detail":"微软'新西兰北部'（New Zealand North）云区域2024年12月正式启用，是新西兰首个本土超大规模数据中心区域，采用三可用区架构，主站点位于奥克兰西北 Westgate（Kakano 路，购地约1.8亿新西兰元），客户包括恒天然、ASB 银行等。据微软新西兰2024财年报表，土地、数据中心建筑及服务器等固定资产投入已超10亿新西兰元。该区域使 Azure 与 AI 服务实现数据本地驻留，满足政府与金融业合规要求，建设期支持约300个岗位、运营期新增约50个全职岗位，是新西兰迄今最大的数字基础设施投资之一，也带动 AWS、CDC 等相继跟进在奥克兰布局。","descEn":"Microsoft's New Zealand North region — the country's first in-country hyperscale cloud region, a three-availability-zone build centred on Westgate, Auckland — formally launched in December 2024 with over NZ$1bn invested.","detailEn":"Launched in December 2024, Microsoft's New Zealand North is the country's first hyperscale cloud region, built as a full three-availability-zone region with its anchor site at Kakano Road, Westgate, in Auckland's north-west (land purchased for ~NZ$180m). Microsoft NZ's FY2024 accounts show more than NZ$1 billion of plant, property and equipment including data centre buildings and servers. The region gives Azure and AI workloads in-country data residency for customers such as Fonterra and ASB Bank, supported ~300 construction jobs and ~50 ongoing roles, and ranks among New Zealand's largest digital-infrastructure investments.","progress":"2024年12月正式启用并对外提供 Azure 三可用区服务，后续扩容建设持续推进。"},
  {"id":6654,"name":"阳光海岸直达铁路一期（The Wave）","en":"The Wave – Direct Sunshine Coast Rail Line Stage 1","country":"澳大利亚","region":"大洋洲","cat":"transport","coord":[153.1,-26.79],"cap":"贝尔瓦—卡伦德拉新建双线客运铁路（一期约19公里）","inv":40,"invText":"55–70亿澳元（一期）","status":"规划","year":2032,"updated":"2026-06","owner":"昆士兰州政府/澳联邦政府","flagship":false,"desc":"昆州'The Wave'阳光海岸直达铁路一期（贝尔瓦—卡伦德拉），造价55–70亿澳元，2026年6月授出首批合同。","detail":"昆士兰州'The Wave'计划的核心工程：从北海岸线贝尔瓦（Beerwah）新建双线客运铁路经贝尔斯溪（Aura）、卡伦德拉延伸至比尔廷亚，一期（贝尔瓦—卡伦德拉）造价估算55–70亿澳元，联邦与州政府各出资27.5亿澳元。2025年3月州政府确认交付方案；2026年6月授出三大合同——Georgiou/Hatch/Laing O'Rourke 联合体负责既有线改造段、Acciona/Georgiou 联合体负责绿地新建段、阿尔斯通/UGL 负责 ETCS 信号系统，主体工程2026年内开工，目标在2032年布里斯班奥运会前建成通车，填补澳大利亚增长最快地区之一的轨道空白。","epc":"EPC未授标(前期规划)","epcStatus":"未招标","descEn":"Stage 1 of Queensland's 'The Wave' direct Sunshine Coast rail line (Beerwah–Caloundra), costed at A$5.5–7bn with A$2.75bn each from federal and state governments; first design and pre-construction contracts awarded in June 2026, targeting delivery before the 2032 Olympics.","detailEn":"The centrepiece of Queensland's 'The Wave' program: a new dual-track passenger line from Beerwah towards Birtinya, with Stage 1 (Beerwah–Caloundra, stations at Bells Creek/Aura, Caloundra and beyond) estimated at A$5.5–7 billion, jointly funded with A$2.75bn each from the Australian and Queensland governments. The delivery commitment was confirmed in March 2025, and in June 2026 three major contracts were awarded — Beerwah Coast Connect (Georgiou/Hatch/Laing O'Rourke) for brownfield works, CoastalTraX (Acciona/Georgiou) for greenfield works, and Alstom/UGL for ETCS signalling. Major construction starts in 2026, targeting services before the Brisbane 2032 Olympics.","progress":"2026年6月授出一期设计与前期施工三大合同，主体工程年内开工，目标2032年奥运前通车。"},
  {"id":6655,"name":"怀齐亚天然气项目二期（珀斯盆地）","en":"Waitsia Gas Project Stage 2","country":"澳大利亚","region":"大洋洲","cat":"petro","coord":[115.1,-29.32],"cap":"250TJ/日天然气处理厂","inv":8,"invText":"≈12亿澳元（估）","status":"投运","year":2025,"updated":"2025-12","owner":"Beach Energy/三井（50:50）","flagship":false,"desc":"珀斯盆地最大陆上气田之一：250TJ/日新气厂2025年12月产出首气，富余气经西北大陆架出口LNG。","detail":"位于西澳珀斯盆地东加拉（Dongara）附近的怀齐亚气田，是澳大利亚最大的陆上常规气田之一，由 Beach Energy 与三井 E&P 各持50%。二期新建250TJ/日处理厂并配套13口开发井，工程几经延期与承包商克拉夫（Clough）破产波折后，于2025年12月实现首气。项目最大亮点是获准将富余天然气经管网输往卡拉萨气厂代加工，成为少数通过西北大陆架设施出口LNG的陆上气源——首船LNG已于此前以预购气形式售出。2026年随第三台压缩机投运，产量爬坡至200TJ/日并向铭牌250TJ/日迈进，同时履行西澳本地市场供气义务。","epc":"EPC：Clough(2020授标)，其破产后由Webuild接续建成(2025投产)","epcStatus":"已授标","descEn":"One of Australia's largest onshore gas fields: the 250 TJ/day Waitsia Stage 2 plant in the Perth Basin achieved first gas in December 2025, with surplus gas exported as LNG via the North West Shelf's Karratha Gas Plant.","detailEn":"The Waitsia field near Dongara in Western Australia's Perth Basin, owned 50:50 by Beach Energy and Mitsui E&P, is among Australia's largest onshore conventional gas fields. Stage 2 added a 250 TJ/day processing plant and 13 development wells; after delays including contractor Clough's collapse, first gas was achieved in December 2025. Uniquely, surplus gas is tolled through the North West Shelf's Karratha Gas Plant, making Waitsia one of the few onshore fields exporting LNG. With the third compressor commissioned, output has ramped to 200 TJ/day en route to nameplate, alongside domestic supply commitments to the WA market.","progress":"2025年12月实现首气，第三台压缩机投运后产量达200TJ/日，正向250TJ/日满产爬坡并经西北大陆架出口LNG。"},
  {"id":6656,"name":"赫米金矿（皮尔巴拉）","en":"Hemi Gold Project","country":"澳大利亚","region":"大洋洲","cat":"mining","coord":[118.08,-20.78],"cap":"前10年年产黄金约53万盎司","inv":10,"invText":"≈16亿澳元（估）","status":"规划","year":2029,"updated":"2026-05","owner":"Northern Star Resources（北方之星）","flagship":false,"desc":"澳大利亚数十年来最大新建金矿之一：前10年年产约53万盎司，2026年5月获西澳环境批准。","detail":"位于西澳皮尔巴拉黑德兰港西南约85公里的马利纳（Mallina）金矿带，是澳大利亚数十年来发现的最大未开发金矿之一，资源量超1100万盎司。北方之星（Northern Star）2025年5月以约50亿澳元对价通过法院安排完成对 De Grey Mining 的并购获得该项目。2023年DFS显示露天开采前10年年产约53万盎司、初始资本开支约13亿澳元（最新估算约16亿澳元）。2026年5月项目获西澳环境部长批准（附条件实施），联邦环评与项目融资推进中，最终投资决定预计2027年作出，建设期约两年半、2029年前后产出首金，将跻身澳洲产量前列的单体金矿。⚡ 供电：规划离网混合电站（燃气+光储），位于Port Hedland以南皮尔巴拉离网带。","epc":"EPC未授标(DFS由GR Engineering等参与)","epcStatus":"未招标","descEn":"One of Australia's largest undeveloped gold projects: ~530koz/yr over the first decade at Mallina in the Pilbara; WA environmental approval granted in May 2026, FID due 2027 under owner Northern Star.","detailEn":"Hemi, in the Mallina gold corridor about 85 km south-west of Port Hedland in WA's Pilbara, is one of Australia's biggest undeveloped gold discoveries in decades with over 11Moz of resources. Northern Star acquired the project via its ~A$5bn court-approved takeover of De Grey Mining in May 2025. The 2023 DFS outlined open-pit production of ~530koz/yr for the first ten years with ~A$1.3bn pre-production capex (now estimated around A$1.6bn). The WA environment minister approved the project subject to conditions in May 2026; federal approval and debt financing are progressing toward an FID in 2027, a ~2.5-year build and first gold around 2029.","progress":"2026年5月获西澳环境部长批准，联邦审批与融资推进中，FID预计2027年作出。"},
  {"id":6657,"name":"伊娃铜矿（西北昆士兰）","en":"Eva Copper Project","country":"澳大利亚","region":"大洋洲","cat":"mining","coord":[140.25,-20.1],"cap":"前5年年产铜约6.5万吨、伴生金1.9万盎司","inv":16,"invText":"15.5–17.5亿美元","status":"规划","year":2028,"updated":"2025-11","owner":"Harmony Gold（哈莫尼黄金）","flagship":false,"desc":"哈莫尼黄金2025年11月批准FID的西北昆士兰最大铜矿：投资15.5–17.5亿美元，2028年下半年投产。","detail":"位于昆士兰州西北部克朗克里以北的芒特艾萨铜矿带，南非哈莫尼黄金100%持有（2022年收购自 Copper Mountain）。2025年11月25日董事会完成可研更新并批准最终投资决定，资本开支15.5–17.5亿美元，将建成西北昆士兰最大铜矿：低剥采比露天开采，前5年年产精矿含铜约6.5万吨，全矿龄15年均产铜约6万吨、金1.9万盎司。昆州政府将其列入快速审批通道并签订本地参与协议，建设期创造约1000个岗位、运营期约450人，预计为州生产总值贡献逾170亿澳元。承包商2027年初进场施工，2028年下半年产出首批精矿，是哈莫尼从黄金向铜战略多元化的关键落子。⚡ 供电：邻近Mount Isa局域网与CopperString走廊，供电方案随重启可研确定。","epc":"EPC未授标(重启可研阶段)","epcStatus":"未招标","descEn":"Harmony Gold's US$1.55–1.75bn Eva Copper project in north-west Queensland, FID-approved in November 2025: a low-strip open pit producing ~65ktpa copper in its first five years, with construction from early 2027 and first production in H2 2028.","detailEn":"Located in the Mount Isa copper belt north of Cloncurry, Eva Copper is 100%-owned by Harmony Gold (acquired from Copper Mountain in 2022). On 25 November 2025 Harmony's board approved the updated feasibility study and final investment decision, committing US$1.55–1.75 billion to build north-west Queensland's largest copper mine — a low-strip-ratio open pit producing ~65kt of copper in concentrate annually in the first five years, averaging ~60kt copper plus 19koz gold over a 15-year life. Queensland fast-tracked approvals and secured local-content commitments; ~1,000 construction and 450 operational jobs are expected. Contractors mobilise in early 2027, with first production in H2 2028 — Harmony's signature diversification from gold into copper.","progress":"2025年11月董事会批准最终投资决定，承包商2027年初进场，2028年下半年投产。"},
  {"id":6658,"name":"瓦菲-戈尔普铜金矿（巴新）","en":"Wafi-Golpu Copper-Gold Project","country":"巴布亚新几内亚","region":"大洋洲","cat":"mining","coord":[146.62,-7.05],"cap":"年产铜约15万吨+黄金32万盎司（矿龄28年）","inv":54,"invText":"≈54亿美元（估）","status":"规划","year":2026,"updated":"2025-03","owner":"哈莫尼黄金/纽蒙特（50:50）","flagship":false,"desc":"巴新最大待开发铜金矿：12百万盎司金+300万吨铜的块状崩落矿山，特别采矿租约谈判进入关键阶段。","detail":"位于巴布亚新几内亚莫罗贝省莱城西南约65公里，由哈莫尼黄金与纽蒙特各持50%的合资项目，是巴新最大的待开发矿山：资源量约1200万盎司黄金、300万吨铜，储量2亿吨（金0.86克/吨、铜1.2%），拟采用地下块状崩落法开采，矿龄28年，年均产铜约15万吨、黄金32万盎司，开发资本开支估算约54亿美元。项目2023年与政府更新框架协议后重回正轨，目前合资双方与巴新政府就特别采矿租约（SML）条款（含国家最高30%参股）持续谈判；按约定获颁租约后30个月内须作出最终投资决定。若落地，将是继瓦菲气田之后巴新最大的资源类外商投资之一，深海尾矿排放方案仍是环境争议焦点。","descEn":"PNG's largest undeveloped mine: a 50:50 Harmony–Newmont block-cave copper-gold project (12Moz gold, 3Mt copper) near Lae, producing ~150ktpa copper and 320koz gold over 28 years; special mining lease negotiations with the PNG government are at a decisive stage.","detailEn":"Wafi-Golpu, 65 km south-west of Lae in Morobe Province, is a 50:50 joint venture between Harmony Gold and Newmont and Papua New Guinea's largest undeveloped mine — roughly 12Moz of gold and 3Mt of copper, with reserves of 200Mt at 0.86g/t gold and 1.2% copper. The planned block-cave underground operation would produce about 150kt of copper and 320koz of gold annually over a 28-year life, with development capex estimated around US$5.4 billion. After a 2023 framework agreement put the project back on track, the JV is negotiating special mining lease terms (including up to 30% state equity) with the PNG government; once the SML is granted the partners have 30 months to reach FID. Deep-sea tailings placement remains the key environmental issue.","progress":"与巴新政府的特别采矿租约（SML）谈判持续推进，获颁租约后30个月内须作出最终投资决定。"},
  {"id":6659,"name":"翁斯洛铁矿（MinRes西皮尔巴拉）","en":"Onslow Iron Project","country":"澳大利亚","region":"大洋洲","cat":"mining","coord":[115.9,-22],"cap":"年产铁矿石3500万吨，矿山寿命30年以上","inv":20,"invText":"约30亿澳元（约20亿美元）","status":"投运","year":2024,"updated":"2026-06","owner":"Mineral Resources / 宝武 / AMCI / POSCO","desc":"西皮尔巴拉『坑到船』新铁矿：Ken's Bore矿山经150公里专用公路至阿什伯顿港转运出口，2024年5月首船提前发运（售予宝武），2025年达产3500万吨/年。","detail":"翁斯洛铁矿（Onslow Iron）由Mineral Resources代表Red Hill合资体（含中国宝武、AMCI、POSCO）开发，位于西澳西皮尔巴拉地区，通过『坑到船』创新物流——Ken's Bore矿山、150公里专用运输公路、阿什伯顿港转运驳船——盘活了长期被视为搁浅资产的矿区。2024年5月首船矿石提前发运（销往宝武），2025年达到3500万吨/年铭牌产能，矿山寿命超过30年，是澳大利亚近年新增产能最大的铁矿项目，也是中澳铁矿石合资的代表案例。⚡ 供电：MinRes自建离网微网：燃气机组+光伏混合，供矿区、破碎与营地负荷。","epc":"MinRes自建(旗下CSI等自任EPC，固定价格自包干)","epcStatus":"已授标","descEn":"MinRes' pit-to-ship Onslow Iron in the West Pilbara — Ken's Bore mine, a 150 km private haul road and transhippers at the Port of Ashburton — shipped first ore to Baowu in May 2024 and hit its 35 Mtpa nameplate in 2025 over a 30+ year life.","detailEn":"Onslow Iron is developed by Mineral Resources on behalf of the Red Hill Iron JV with Baowu, AMCI and POSCO. Its innovative pit-to-ship chain — the Ken's Bore mine, a 150 km dedicated haul road and transhipment at the Port of Ashburton — unlocked deposits long considered stranded in WA's West Pilbara. First ore shipped ahead of schedule in May 2024 (sold to Baowu) and the project reached its 35 Mtpa nameplate in 2025 with a mine life beyond 30 years, Australia's largest new iron-ore capacity addition in years and a showcase China-Australia JV.","progress":"2024年5月首船发运，2025年达产3500万吨/年；运输车队与转运系统持续优化。","flagship":false},

  // ===== 北美（6665-6699）=====
  {"id":6665,"name":"Clear Fork 光伏电站（Meta 包销）","en":"Clear Fork Solar Project","country":"美国","region":"北美","cat":"renewable","coord":[-98.08,29.17],"cap":"600 MW","inv":9,"invText":"9亿美元","status":"在建","year":2027,"updated":"2025-07","owner":"Enbridge（安桥）","flagship":false,"desc":"安桥在德州圣安东尼奥附近建设的600MW大型光伏电站，全部电力由Meta长期包销供其数据中心使用。","detail":"2025年7月22日安桥对Clear Fork光伏项目作出最终投资决定，项目位于德州威尔逊县、圣安东尼奥东南，占地约4600英亩私有土地，装机600MW，资本开支约9亿美元。Meta签署长期购电协议包销项目100%绿电，用于支撑其德州数据中心运营，是科技巨头以PPA驱动新建可再生能源的典型案例。项目已开工建设，预计2027年夏季投运，投运后即对安桥现金流和每股收益形成增厚。","descEn":"Enbridge's 600 MW utility-scale solar farm near San Antonio, Texas, with 100% of output contracted to Meta for its data centers.","detailEn":"Enbridge reached FID on the Clear Fork solar project on July 22, 2025. Located on ~4,600 acres in Wilson County, Texas, southeast of San Antonio, the 600 MW facility carries an estimated capital cost of US$0.9 billion. Meta Platforms signed a long-term PPA for 100% of the renewable output to power its Texas data center operations. Construction is underway with commercial operation expected in summer 2027.","progress":"2025年7月通过FID并开工，Meta包销全部600MW绿电，预计2027年夏季投运。"},
  {"id":6666,"name":"Cowboy 光伏+储能项目（怀俄明）","en":"Cowboy Solar I & II and BESS Project","country":"美国","region":"北美","cat":"renewable","coord":[-104.82,41.1],"cap":"365 MW光伏 + 200 MW/1600 MWh储能","inv":12,"invText":"12亿美元","status":"在建","year":2027,"updated":"2026-05","owner":"Enbridge（安桥）/ Meta","flagship":false,"desc":"安桥与Meta在怀俄明夏延附近共建的365MW光伏+1.6GWh特斯拉电池储能项目，为Meta数据中心供电。","detail":"2026年5月安桥宣布Cowboy项目，位于怀俄明州夏延附近，含365MW光伏与200MW/1600MWh电池储能，特斯拉负责电池供货与运维，安桥投资约12亿美元，预计2027年底投运。电力经Cheyenne Light, Fuel and Power依据怀俄明大用户电力合同（LPCS）输送给Meta在当地的数据中心。该项目使安桥与Meta在北美的合作容量累计达约1.6GW，是「AI数据中心+光储」绑定开发模式在落基山区域的标志性落地。","descEn":"Enbridge's Cowboy Project near Cheyenne, Wyoming: 365 MW of solar plus a 200 MW/1,600 MWh Tesla battery system supplying Meta's data centers.","detailEn":"Announced in May 2026, the Cowboy Project pairs 365 MW of solar generation with a 200 MW/1,600 MWh BESS (supplied and serviced by Tesla) near Cheyenne, Wyoming. Enbridge expects to invest about US$1.2 billion, with in-service by end-2027. Cheyenne Light, Fuel and Power will deliver the output to Meta under Wyoming's Large Power Contract Service tariff, bringing the Enbridge–Meta partnership to roughly 1.6 GW across North America.","progress":"2026年5月宣布并启动建设，特斯拉供应1.6GWh电池，预计2027年底投运。"},
  {"id":6667,"name":"V.C. Summer 核电2/3号机组复建","en":"V.C. Summer Units 2&3 Completion","country":"美国","region":"北美","cat":"nuclear","coord":[-81.32,34.3],"cap":"2×1117 MW AP1000（共约2234 MW）","inv":100,"invText":"完建成本未最终披露（市场估算百亿美元级，估）","status":"规划","year":2031,"updated":"2026-05","owner":"Santee Cooper / Brookfield / The Nuclear Company","flagship":true,"desc":"美国最著名的核电烂尾工程复活：Brookfield牵头续建南卡V.C. Summer两台AP1000机组。","detail":"V.C. Summer 2/3号机组2013年开工，2017年西屋破产后在已投入约90亿美元后停建，成为美国核电史上最大烂尾案。2025年Santee Cooper公开遴选Brookfield接盘续建，12月签署谅解备忘录；2026年5月Brookfield与The Nuclear Company组建合资公司负责项目管理，承诺2028年前提交最终投资决定（FID）包。两台1117MW AP1000若完建将新增约2234MW零碳电力，瞄准美国东南部AI数据中心负荷潮，目标2030年代初投运。","descEn":"America's most famous abandoned nuclear build is being revived: Brookfield leads the completion of two AP1000 units at V.C. Summer in South Carolina.","detailEn":"Construction of V.C. Summer Units 2&3 began in 2013 and was abandoned in 2017 after Westinghouse's bankruptcy, with about $9 billion already spent. In 2025 Santee Cooper selected Brookfield to take over the project, signing an MOU in December 2025; in May 2026 Brookfield and The Nuclear Company formed a JV to project-manage completion, committing to deliver an FID package by 2028. The two 1,117 MW AP1000 units would add ~2,234 MW of carbon-free power targeting the US Southeast's AI-driven load growth, with start-up targeted for the early 2030s.","progress":"2025年12月Santee Cooper与Brookfield签署MOU，2026年5月Brookfield联合The Nuclear Company组建合资公司推进复建，FID包计划2028年前提交。"},
  {"id":6668,"name":"Propel NY Energy 输电工程（纽约）","en":"Propel NY Energy Transmission Project","country":"美国","region":"北美","cat":"grid","coord":[-73.6,40.75],"cap":"6条345 kV+1条138 kV，约145公里地下/海底电缆，新建3座变电站","inv":32.6,"invText":"32.6亿美元","status":"规划","year":2030,"updated":"2026-05","owner":"纽约电力局（NYPA）/ New York Transco","flagship":false,"desc":"纽约电力局与New Transco共建的32.6亿美元长岛—纽约市—威彻斯特地下输电网，为海上风电接入打通通道。","detail":"Propel NY Energy由纽约电力局（NYPA）与New York Transco合作开发，总投资32.6亿美元，将新建6条345kV和1条138kV输电线路，约90英里（145公里）全部采用地下与海底电缆，途经威彻斯特县、布朗克斯、皇后区至长岛拿骚、萨福克县，并新建3座变电站、改造4座既有变电站。工程实现长岛电网与纽约主网的双向互济，是接纳海上风电、提升纽约都会区供电可靠性的骨干工程，年均创造约2000个就业岗位。计划2026年内开工，2030年5月前全部投运。","descEn":"A $3.26 billion NYPA / New York Transco underground transmission build linking Long Island, New York City and Westchester to unlock offshore wind delivery.","detailEn":"Propel NY Energy will install six new 345 kV lines and one 138 kV line — roughly 90 miles of underground and submarine cable — running from Westchester through the Bronx and Queens to Nassau and Suffolk counties, with three new substations and upgrades at four existing stations. The $3.26 billion project enables bidirectional power flow between Long Island and the mainland grid and supports offshore wind integration. Construction starts in 2026 with full in-service targeted by May 2030.","progress":"2026年进入开工准备阶段，计划年内动工、2030年5月前投运。"},
  {"id":6669,"name":"安大略抽水蓄能电站（米福德）","en":"Ontario Pumped Storage Project (Meaford)","country":"加拿大","region":"北美","cat":"storage","coord":[-80.59,44.61],"cap":"1000 MW / 约11小时（≈11 GWh）","inv":33,"invText":"约45亿加元（≈33亿美元，估）","status":"规划","year":2030,"updated":"2026-03","owner":"TC Energy / 安大略省","flagship":false,"desc":"TC Energy在安大略乔治亚湾米福德军事训练区规划的1000MW抽水蓄能电站，可为百万户家庭供电约11小时。","detail":"安大略抽水蓄能项目（OPSP）选址米福德第四加拿大师训练中心内、乔治亚湾岸边，利用湖水与高位水库落差建设1000MW抽蓄机组，满发可持续约11小时，是安大略省应对核电改造期与电气化负荷增长的关键调节电源。安大略省已承诺最高2.85亿加元用于前期勘察（含湖上钻探），项目总投资市场估算约45亿加元。2026年3月6日项目正式进入加拿大联邦影响评估（IAAC）程序并启动公众意见征询，目标2030年代初投运。","descEn":"TC Energy's 1,000 MW pumped storage plant proposed at the Meaford military training centre on Georgian Bay, Ontario — enough to power a million homes for ~11 hours.","detailEn":"The Ontario Pumped Storage Project would build a 1,000 MW pumped hydro facility at the 4th Canadian Division Training Centre in Meaford, using Georgian Bay as the lower reservoir. Ontario committed up to C$285 million for pre-development studies, with total cost estimated around C$4.5 billion. The project formally entered Canada's federal Impact Assessment (IAAC) process on March 6, 2026, targeting in-service in the early 2030s as key flexible capacity for Ontario's electrifying grid.","progress":"2026年3月正式进入加拿大联邦影响评估程序，省政府已拨2.85亿加元支持前期工作。"},
  {"id":6670,"name":"SK海力士印第安纳先进封装厂","en":"SK hynix West Lafayette Advanced Packaging Fab","country":"美国","region":"北美","cat":"ci","coord":[-86.92,40.44],"cap":"HBM高带宽内存先进封装与研发基地（2028年量产）","inv":38.7,"invText":"38.7亿美元（获CHIPS法案最高4.58亿美元补贴）","status":"在建","year":2028,"updated":"2025-10","owner":"SK海力士","flagship":false,"desc":"SK海力士在印第安纳西拉法叶投资38.7亿美元建设美国首座HBM先进封装厂，补齐美国AI芯片供应链关键缺口。","detail":"SK海力士2024年4月宣布在印第安纳州西拉法叶（普渡大学旁）投资约38.7亿美元，建设美国首座面向AI的HBM高带宽内存先进封装制造与研发设施，获美国商务部CHIPS法案最高4.58亿美元直接补贴，创造逾千个岗位。2025年5月西拉法叶市议会通过用地变更，2025年下半年完成设计许可并破土动工，2026—2027年进行厂房建设与设备安装，2028年下半年量产。HBM是英伟达等AI GPU的核心存储芯片，该厂将首次把2.5D先进封装产能落地美国本土。","descEn":"SK hynix's $3.87 billion advanced packaging fab and R&D facility in West Lafayette, Indiana — the first US plant to package HBM memory for AI GPUs.","detailEn":"Announced in April 2024, SK hynix is investing about $3.87 billion in West Lafayette, Indiana (adjacent to Purdue University) to build the first US advanced packaging fab for high-bandwidth memory (HBM), backed by up to $458 million in CHIPS Act funding. Land-use approval passed in May 2025, groundbreaking followed in H2 2025, with plant construction and tool install through 2026–2027 and mass production targeted for H2 2028. The fab plugs a critical hole in the US AI memory supply chain.","progress":"2025年下半年破土动工，2026—2027年厂房建设与设备安装，2028年下半年量产HBM。"},
  {"id":6671,"name":"纽柯西弗吉尼亚Apple Grove薄板钢厂","en":"Nucor Apple Grove Sheet Mill","country":"美国","region":"北美","cat":"ci","coord":[-82.1,38.83],"cap":"300万吨/年薄板钢（电弧炉）","inv":31,"invText":"31亿美元","status":"在建","year":2026,"updated":"2026-04","owner":"Nucor（纽柯钢铁）","flagship":false,"desc":"纽柯钢铁公司史上最大单笔投资：西弗吉尼亚梅森县31亿美元、年产300万吨的电弧炉薄板钢厂。","detail":"纽柯在西弗吉尼亚州梅森县Apple Grove沿俄亥俄河建设年产300万吨的电弧炉薄板钢厂，投资由最初27亿美元上调至31亿美元，是纽柯公司历史上最大单笔投资，也是西弗吉尼亚州史上最大制造业投资，将创造约800个直接岗位。产品面向汽车、家电、建筑与新能源行业，采用废钢电弧炉短流程工艺，碳强度显著低于传统高炉。截至2026年4月工程完成约85%，调试贯穿2026年全年，预计2027年初实现商业出货。","descEn":"Nucor's largest-ever investment: a $3.1 billion, 3-million-ton-per-year EAF sheet steel mill at Apple Grove, Mason County, West Virginia.","detailEn":"Nucor is building a 3 Mtpa electric-arc-furnace sheet mill on the Ohio River at Apple Grove, West Virginia. The net cash outlay rose from $2.7 billion to $3.1 billion, making it both Nucor's largest investment and the biggest manufacturing investment in West Virginia history, employing ~800 workers. Serving automotive, appliance, construction and energy markets with low-carbon scrap-based steelmaking, the mill was about 85% complete as of April 2026, with commissioning through 2026 and commercial shipments expected in early 2027.","progress":"2026年4月工程完成约85%，调试持续至年底，2027年初商业出货。"},
  {"id":6672,"name":"AWS 北卡罗来纳Richmond County数据中心园区","en":"AWS Richmond County Data Center Campus","country":"美国","region":"北美","cat":"datacenter","coord":[-79.72,34.91],"cap":"20栋数据中心楼（每栋约2万平方米），占地约800英亩","inv":100,"invText":"100亿美元","status":"在建","year":2027,"updated":"2025-12","owner":"亚马逊AWS","flagship":false,"desc":"亚马逊在北卡Richmond County投资100亿美元建设20栋楼的AI数据中心园区，为北卡州史上最大单体资本项目。","detail":"2025年6月亚马逊宣布在北卡罗来纳州Richmond County（Hamlet—Rockingham地区）投资约100亿美元建设AI云基础设施园区，选址Energy Way工业园近800英亩土地，规划20栋数据中心楼、每栋约20万—22.5万平方英尺，是北卡州历史上最大单体资本项目，未来五年创造至少500个高技能岗位。亚马逊同步与社区学院合作开设数据中心运维、光纤熔接等定向培训。2025年底园区动工，2026年进入场平与首批楼宇建设阶段，支撑AWS生成式AI算力扩张。","descEn":"Amazon's $10 billion, 20-building AI data center campus in Richmond County, North Carolina — the largest single capital project in state history.","detailEn":"Announced in June 2025, AWS is investing an estimated $10 billion in a data center campus on nearly 800 acres at the Energy Way Industrial Park near Hamlet/Rockingham, Richmond County, NC. Plans call for 20 buildings of 200,000–225,000 sq ft each, creating 500+ high-skilled jobs over five years, with workforce training run with NC community colleges. Groundbreaking occurred in late 2025, with site preparation and early buildout through 2026 to expand Amazon's AI infrastructure.","progress":"2025年底动工，2026年推进场平与首批数据中心楼建设。"},
  {"id":6673,"name":"Google 俄克拉荷马Stillwater数据中心园区","en":"Google Stillwater Data Center Campus (Oklahoma)","country":"美国","region":"北美","cat":"datacenter","coord":[-97.06,36.12],"cap":"新建Stillwater园区（一期2027年建成）+ Pryor既有园区扩建","inv":90,"invText":"90亿美元（两年内，含Pryor扩建）","status":"在建","year":2027,"updated":"2025-08","owner":"Google（Alphabet）","flagship":false,"desc":"Google宣布两年内在俄克拉荷马投入90亿美元，新建Stillwater数据中心园区并扩建Pryor园区。","detail":"2025年8月13日Google宣布未来两年在俄克拉荷马州新增90亿美元云与AI基础设施投资，核心是在Stillwater建设全新数据中心园区（2025年3月确认Google为该园区申请方，一期计划2027年建成），同时扩建Pryor既有超大型园区。配套投入包括俄克拉荷马大学与俄克拉荷马州立大学加入Google AI教育加速器、为电工培训联盟提供资金以将该州电气技工人才管道扩大135%。该项目是AI算力竞赛向中部低成本电力州扩散的代表案例。","descEn":"Google's $9 billion, two-year cloud and AI infrastructure push in Oklahoma: a new Stillwater data center campus plus expansion of the existing Pryor site.","detailEn":"On August 13, 2025 Google announced an additional $9 billion investment in Oklahoma over two years, anchored by a new data center campus in Stillwater (Google was confirmed as the applicant in March 2025; phase one targeted for 2027) and expansion of its existing Pryor mega-campus. The package includes AI education programs with OU and OSU and funding to grow the state's electrical workforce pipeline by 135%, exemplifying the AI buildout's spread into low-cost-power heartland states.","progress":"2025年8月宣布90亿美元投资，Stillwater新园区一期目标2027年建成。"},
  {"id":6674,"name":"xAI Colossus 2 超算园区（孟菲斯）","en":"xAI Colossus 2","country":"美国","region":"北美","cat":"datacenter","coord":[-90.05,35],"cap":"规划2 GW、约55.5万块GPU（全球最大AI训练基地）","inv":180,"invText":"约180亿美元（GPU采购口径，含电力基建更高，估）","status":"在建","year":2026,"updated":"2026-03","owner":"xAI","flagship":true,"desc":"马斯克xAI在孟菲斯的第二座超算园区，全球首个吉瓦级AI数据中心，规划扩至2GW、55.5万块GPU。","detail":"Colossus 2是xAI在孟菲斯地区的第二座AI超算园区，被称为全球首个吉瓦级AI数据中心：上线6个月即达200MW，2026年初突破1GW；2026年1月马斯克宣布购入第三栋建筑扩至2GW，累计采购约55.5万块英伟达GPU、金额约180亿美元。电力依托密西西比Southaven前杜克能源电厂场址自建燃机，Solaris计划2027年二季度运行超1.1GW机组。2026年3月为新厂房提交6.59亿美元建筑许可，6月Google同意租用部分算力。","descEn":"xAI's second Memphis-area supercomputer campus — the world's first gigawatt-class AI data center, scaling to 2 GW and ~555,000 GPUs.","detailEn":"Colossus 2 is xAI's second campus in the Memphis area and the world's first gigawatt-scale AI data center: 200 MW was live within six months, surpassing 1 GW in early 2026. In January 2026 Musk announced a third building taking the site to 2 GW, with ~555,000 NVIDIA GPUs purchased for roughly $18 billion. Power comes partly from gas turbines at a former Duke Energy plant in Southaven, Mississippi, with Solaris targeting 1.1+ GW of turbines by Q2 2027. A $659 million building permit was filed in March 2026, and Google agreed in June 2026 to rent part of its capacity.","progress":"2026年初算力突破1GW并宣布扩至2GW，3月提交6.59亿美元新厂房建筑许可，6月Google租用部分算力。"},
  {"id":6675,"name":"Bell AI Fabric 主权AI数据中心群（不列颠哥伦比亚）","en":"Bell AI Fabric (British Columbia)","country":"加拿大","region":"北美","cat":"datacenter","coord":[-120.33,50.67],"cap":"6座设施共约500 MW（水电供电AI算力）","inv":25,"invText":"投资未披露（按500MW集群估算约25亿美元+，估）","status":"在建","year":2027,"updated":"2025-06","owner":"Bell Canada / Groq","flagship":false,"desc":"贝尔加拿大在BC省打造的全国最大主权AI算力网络：6座水电供电数据中心共约500MW，Groq独家提供推理算力。","detail":"2025年5月贝尔加拿大发布Bell AI Fabric计划，在不列颠哥伦比亚省建设6座由清洁水电供电的AI数据中心，总算力容量约500MW，号称加拿大最大主权AI算力项目。首座7MW设施2025年6月在坎卢普斯投运，由Groq LPU推理芯片驱动（Groq为独家推理算力伙伴），随后在梅里特再建一座；两座26MW数据中心分别于2026、2027年在坎卢普斯落成，另有一座26MW设施与汤普森河大学（TRU）合作于2026年底前上线。项目主打数据主权与低碳算力，服务加拿大政企AI需求。","descEn":"Bell Canada's sovereign AI compute network in British Columbia: six hydro-powered AI data centres totalling ~500 MW, with Groq as exclusive inference provider.","detailEn":"Unveiled in May 2025, Bell AI Fabric is Canada's largest sovereign AI compute project: six AI data centres in British Columbia powered by clean hydroelectricity, providing upwards of 500 MW. The first 7 MW Groq-powered facility opened in Kamloops in June 2025, followed by one in Merritt; two 26 MW Kamloops data centres follow in 2026 and 2027, plus a 26 MW facility with Thompson Rivers University by end-2026. Groq is the exclusive inference partner for the network, which targets Canadian data-sovereign AI demand.","progress":"首座7MW坎卢普斯设施2025年6月投运，两座26MW数据中心2026—2027年陆续建成。"},
  {"id":6676,"name":"BART 硅谷二期延伸线（圣何塞）","en":"BART Silicon Valley Phase II Extension","country":"美国","region":"北美","cat":"transport","coord":[-121.89,37.33],"cap":"9.7公里延伸、含8公里单洞大直径隧道、4座车站","inv":127,"invText":"127亿美元","status":"在建","year":2037,"updated":"2026-01","owner":"圣克拉拉谷交通局（VTA）","flagship":false,"desc":"127亿美元的BART湾区捷运硅谷二期：6英里延伸线穿越圣何塞市中心，采用全美首条单洞大直径地铁隧道。","detail":"BART硅谷二期延伸线由圣克拉拉谷交通局（VTA）建设，从Berryessa/北圣何塞站延伸6英里（9.7公里）至圣克拉拉市，其中约5.5英里采用全美首例单洞大直径（single-bore）地铁隧道方案，新设28街/小葡萄牙、圣何塞市中心、Diridon三座地下站及圣克拉拉地面站，总投资127亿美元，Bechtel担任施工管理。项目把湾区捷运环线最后一块拼图接入硅谷核心区。隧道掘进机始发井已于2025年开挖，主体隧道掘进计划2026年启动，目标2037年通车。","descEn":"The $12.7 billion BART Silicon Valley Phase II: a 6-mile extension through downtown San Jose using the first single-bore big-diameter subway tunnel in the US.","detailEn":"Built by VTA, the Phase II extension runs 6 miles from Berryessa/North San Jose to Santa Clara, with about 5.5 miles in the first single-bore large-diameter subway tunnel in the US. It adds three underground stations (28th Street/Little Portugal, Downtown San Jose, Diridon) and a surface station in Santa Clara, at a cost of $12.7 billion with Bechtel as construction manager. TBM launch-pit excavation began in 2025, major tunneling starts in 2026, and revenue service is targeted for 2037, completing BART's link into the heart of Silicon Valley.","progress":"盾构始发井2025年开挖，主隧道掘进2026年启动，目标2037年通车。"},
  {"id":6677,"name":"弗朗西斯·斯科特·基大桥重建（巴尔的摩）","en":"Francis Scott Key Bridge Rebuild","country":"美国","region":"北美","cat":"transport","coord":[-76.53,39.22],"cap":"斜拉桥方案，桥面净空约70米，配重型桥墩防撞系统","inv":48,"invText":"43–52亿美元（联邦全额拨款）","status":"在建","year":2030,"updated":"2025-11","owner":"马里兰州交通管理局（MDTA）","flagship":false,"desc":"2024年被集装箱船撞塌的巴尔的摩基大桥重建工程，造价升至43–52亿美元，2030年底建成通车。","detail":"2024年3月巴尔的摩弗朗西斯·斯科特·基大桥被失控集装箱船「Dali」号撞塌，造成6人遇难并切断巴尔的摩港外环通道。重建采用斜拉桥方案，桥面高约230英尺（70米）以满足大型集装箱船通航，并配备重型桥墩防撞保护系统。受材料涨价与防撞系统加码影响，造价从早期估算翻倍至43亿—52亿美元，通车时间由2028年秋推迟至2030年底，联邦政府承担全部费用。项目14个月内完成70%设计（同类项目平均需七年），设计与施工并行推进。","descEn":"Rebuild of Baltimore's Key Bridge, destroyed by the Dali containership strike in March 2024 — now estimated at $4.3–5.2 billion, opening late 2030.","detailEn":"After the March 2024 collapse that killed six people and severed the Baltimore harbor crossing, Maryland's MDTA is rebuilding the Key Bridge as a cable-stayed span with ~230 ft of navigational clearance and a robust pier-protection system against ship strikes. Costs have more than doubled to $4.3–5.2 billion and the opening slipped two years to late 2030, fully federally funded. Design reached 70% within 14 months — versus a seven-year average for comparable projects — while early construction proceeds in parallel.","progress":"2025年11月最新估算造价升至43–52亿美元、通车推迟到2030年底，设计完成70%并即将主体动工。"},
  {"id":6678,"name":"bp Kaskida 深水油田（墨西哥湾）","en":"bp Kaskida Deepwater Project","country":"美国","region":"北美","cat":"petro","coord":[-92,26.5],"cap":"8万桶/日（一期6口井，资源量≥2.75亿桶）","inv":50,"invText":"约50亿美元（一期）","status":"在建","year":2029,"updated":"2025-12","owner":"bp","flagship":false,"desc":"bp在墨西哥湾的第六个作业枢纽：50亿美元开发Kaskida超高压深水油田，2029年投产8万桶/日。","detail":"2024年7月bp对Kaskida深水油田作出最终投资决定，这是其在墨西哥湾的第六个自营枢纽，位于新奥尔良西南约250英里的Keathley Canyon区块。一期投资不超过50亿美元，新建浮式生产平台，6口井开发至少2.75亿桶资源，设计产能8万桶/日，2029年投产；项目采用20000psi超高压开发技术，获BOEM核准，打开Kaskida与Tiber汇水区高达100亿桶资源的开发空间。bp随后又批准了毗邻的Tiber-Guadalupe项目（2030年投产），形成美湾「古近系」超深超压开发集群。","descEn":"bp's sixth operated hub in the Gulf of Mexico: the $5 billion, 20,000-psi Kaskida deepwater development, producing 80,000 b/d from 2029.","detailEn":"bp took FID on Kaskida in July 2024 — its sixth operated Gulf hub, in Keathley Canyon ~250 miles southwest of New Orleans. Phase 1 costs under $5 billion, with a new floating production platform and six wells developing at least 275 million barrels at 80,000 b/d capacity, starting up in 2029. BOEM approved the 20,000-psi development, unlocking up to 10 billion barrels across the Kaskida–Tiber catchment; bp subsequently sanctioned the adjacent $5 billion Tiber-Guadalupe project for 2030 startup.","progress":"浮式平台建造推进中，目标2029年投产；姊妹项目Tiber-Guadalupe亦已通过FID、2030年投产。"},
  {"id":6679,"name":"Trion 超深水油田（墨西哥湾佩尔迪多）","en":"Trion Ultra-Deepwater Project","country":"墨西哥","region":"北美","cat":"petro","coord":[-94.9,25.7],"cap":"10万桶/日（FPU设计产能），18口超深水井","inv":72,"invText":"72亿美元","status":"在建","year":2028,"updated":"2026-03","owner":"Woodside（60%，作业者）/ Pemex（40%）","flagship":false,"desc":"墨西哥首个超深水油田开发项目：Woodside与Pemex合作72亿美元开发佩尔迪多带Trion油田，2028年投产。","detail":"Trion油田位于墨西哥湾墨方水域佩尔迪多褶皱带、水深约2500米，是墨西哥首个超深水油田开发项目，由Woodside（60%、作业者）与墨西哥国油Pemex（40%）合资，总投资约72亿美元，2023年通过FID。浮式生产装置（FPU）在韩国建造、2027年调试，FSO储油船在中国建造；SLB获三年18口超深水井钻完井大合同。2025年底项目整体进度达50%，2026年3月「Deepwater Thalassa」钻井船抵达墨西哥水域启动钻井作业，目标2028年实现首油、稳产10万桶/日。","descEn":"Mexico's first ultra-deepwater oil development: Woodside (60%) and Pemex (40%) are investing $7.2 billion in the Trion field in the Perdido belt, with first oil in 2028.","detailEn":"Trion sits in ~2,500 m of water in the Perdido fold belt on the Mexican side of the Gulf. Sanctioned in 2023, the $7.2 billion JV between operator Woodside (60%) and Pemex (40%) is Mexico's first ultra-deepwater development. The FPU is being fabricated in South Korea for 2027 commissioning and the FSO in China; SLB holds the contract for 18 ultra-deepwater wells over three years. The project passed 50% completion at end-2025, the Deepwater Thalassa drillship arrived in March 2026 to begin drilling, and first oil is targeted for 2028 at 100,000 b/d.","progress":"2025年底整体进度过半，2026年3月钻井船抵达启动18口井钻井作业，2028年首油。"},
  {"id":6680,"name":"Pikka 一期油田（阿拉斯加北坡）","en":"Pikka Phase 1 Oil Project","country":"美国","region":"北美","cat":"petro","coord":[-150.9,70.3],"cap":"8万桶/日","inv":26,"invText":"26亿美元","status":"投运","year":2026,"updated":"2026-05","owner":"Santos（51%，作业者）/ Repsol（49%）","flagship":false,"desc":"数十年来阿拉斯加北坡最大新油田：Santos与Repsol的26亿美元Pikka一期2026年5月产出首油。","detail":"Pikka一期位于阿拉斯加北坡，由澳大利亚Santos（51%、作业者）与西班牙Repsol（49%）合资开发，2022年8月通过FID，总投资26亿美元，被称为数十年来北坡最大的新建油田项目，建设期创造逾2600个岗位、运营期逾500个。2026年5月项目提前实现首油，原油经计量并入销售管道（接入跨阿拉斯加管道系统），计划2026年三季度达到8万桶/日的稳产平台。该项目与Willow一道，标志着北坡油气开发在高油价与本州财政诉求推动下重新活跃。","descEn":"The biggest new North Slope oil project in decades: Santos and Repsol's $2.6 billion Pikka Phase 1 achieved first oil in May 2026.","detailEn":"Pikka Phase 1 on Alaska's North Slope is operated by Santos (51%) with Repsol (49%). Sanctioned in August 2022 at US$2.6 billion gross, it created 2,600+ construction jobs and 500+ operating roles. First oil was achieved in May 2026, with crude flowing through the LACT meter into the sales pipeline feeding the Trans-Alaska Pipeline System; plateau production of 80,000 b/d is expected in Q3 2026. Together with Willow, Pikka marks the revival of large-scale North Slope development.","progress":"2026年5月实现首油，计划三季度达到8万桶/日稳产。"},
  {"id":6681,"name":"高地谷铜矿延寿扩建（不列颠哥伦比亚）","en":"Highland Valley Copper Mine Life Extension","country":"加拿大","region":"北美","cat":"mining","coord":[-121.03,50.49],"cap":"年均13.7万吨铜，矿山寿命延至2046年","inv":17,"invText":"21–24亿加元（≈17亿美元）","status":"在建","year":2028,"updated":"2025-08","owner":"泰克资源（Teck Resources）","flagship":false,"desc":"泰克资源批准21–24亿加元延寿加拿大最大铜矿高地谷至2046年，BC省史上最大关键矿产投资。","detail":"2025年7月泰克资源董事会批准高地谷铜矿（HVC）延寿项目，投资21亿—24亿加元，将加拿大最大铜矿的服务年限延长约18年至2046年，延寿期内年均产铜约13.7万吨。项目2025年6月取得环评证书与各项许可，8月全面开工，是不列颠哥伦比亚省历史上最大的关键矿产投资，保留约1500个直接岗位、建设期新增约2900个岗位。泰克称该项目是其「2030年前铜产量翻番」战略的基石，呼应北美新能源与电网建设对铜的强劲需求。","descEn":"Teck approved the C$2.1–2.4 billion life extension of Highland Valley Copper — Canada's largest copper mine — to 2046, BC's biggest critical-minerals investment ever.","detailEn":"In July 2025 Teck's board sanctioned the Highland Valley Copper Mine Life Extension, adding ~18 years of operation to 2046 at an average ~137,000 t/y of copper. The environmental assessment certificate and permits were issued in June 2025 and full construction began in August 2025. At C$2.1–2.4 billion it is the largest critical-minerals investment in British Columbia's history, preserving ~1,500 direct jobs and creating ~2,900 construction jobs — foundational to Teck's strategy to double copper output by 2030.","progress":"2025年8月全面开工建设，矿山寿命将延长至2046年。"},
  {"id":6682,"name":"加拿大韦斯利维尔新建核电站（安大略）","en":"Wesleyville New Nuclear Project (Ontario)","country":"加拿大","region":"北美","cat":"nuclear","coord":[-78.4,43.95],"cap":"最多10000MW（10GW）","inv":500,"invText":"投资未披露；10GW规模估算逾500亿美元（估），预计贡献安省GDP 2350亿加元","status":"规划","year":2026,"updated":"2026-02","owner":"安大略发电公司（OPG）","flagship":true,"desc":"拟建“全球最大核电站”：OPG在安大略港霍普Wesleyville厂址规划最多10GW核电，2026年2月签市政伙伴协议。","detail":"2025年1月安大略省政府指示OPG在港霍普市Wesleyville厂址（安大略湖畔约1300英亩，70年代曾建油电站但从未运行）研究大型核电开发，规划最多10000MW、运行78年，若建成将成为全球最大核电站。2026年2月OPG与港霍普市签署伙伴协议，联邦影响评估程序启动；候选堆型包括西屋AP1000、EDF EPR、Candu Monark和GE日立BWRX-300，计划2030年代初中期开工、2040年代中期投运，预计支撑安省1.05万个就业岗位。","descEn":"Ontario's bid for the world's largest nuclear station: OPG plans up to 10 GW at the Wesleyville site in Port Hope, with a municipal partnership signed in February 2026 and impact assessment underway.","detailEn":"In January 2025 Ontario directed OPG to pursue large-scale new nuclear at the 1,300-acre Wesleyville site in Port Hope on Lake Ontario. The project envisages up to 10,000 MW operating for 78 years - potentially the world's largest nuclear station. In February 2026 OPG signed a partnership agreement with Port Hope and the federal impact assessment began. Candidate designs include AP1000, EPR, Candu Monark and BWRX-300, with construction eyed for the early-mid 2030s and operation in the mid-2040s, supporting ~10,500 Ontario jobs.","progress":"2026年2月与港霍普市签约、影响评估启动，堆型未定。"},
  {"id":6683,"name":"美国Orano橡树岭铀浓缩厂（Project IKE）","en":"Orano Project IKE Uranium Enrichment Facility (Oak Ridge)","country":"美国","region":"北美","cat":"nuclear","coord":[-84.27,35.96],"cap":"约75万平方英尺厂房，北美最大铀浓缩厂之一","inv":45,"invText":"45亿美元（田纳西州史上最大单笔投资）","status":"规划","year":2031,"updated":"2025-07","owner":"Orano USA（法国欧安诺）","flagship":false,"desc":"法国欧安诺在田纳西橡树岭建45亿美元铀浓缩厂，田纳西州史上最大投资，2030年代初投产。","detail":"2024年9月法国欧安诺（Orano USA）选定田纳西州橡树岭建设新铀浓缩厂“Project IKE”，投资45亿美元，为田纳西州历史上最大单笔投资，建成后将是北美最大铀浓缩设施之一（厂房约75万平方英尺），为现役及下一代反应堆供应浓缩铀、降低对俄罗斯核燃料依赖。2024年12月完成NRC预许可会议，2025年6月5日橡树岭项目办公室剪彩，2025年7月州及地方政府批准销售税减免；获州府600万美元核发展基金资助，预计2030年代初投产。","descEn":"Orano USA's USD 4.5 bn Project IKE enrichment plant in Oak Ridge, Tennessee - the largest investment in state history - targets production in the early 2030s to cut reliance on Russian fuel.","detailEn":"In September 2024 Orano USA selected Oak Ridge, Tennessee for Project IKE, a USD 4.5 bn uranium enrichment facility - the largest single investment in Tennessee history and one of North America's biggest enrichment plants (~750,000 sq ft). It will supply enriched uranium for current and next-generation reactors and reduce dependence on Russian fuel. The NRC pre-licensing meeting was completed in December 2024, the Oak Ridge project office opened on 5 June 2025, and state/local tax abatements were approved in July 2025, with production targeted for the early 2030s.","progress":"2025年6月项目办公室启用、NRC许可推进，目标2030年代初投产。"},
  {"id":6684,"name":"CF Industries Blue Point低碳氨综合体","en":"CF Industries Blue Point Low-Carbon Ammonia Complex","country":"美国","region":"北美","cat":"petro","coord":[-90.95,30.15],"cap":"低碳氨140万吨/年（ATR自热重整+CCS）","inv":40,"invText":"约40亿美元","status":"在建","year":2029,"updated":"2026-06","owner":"CF Industries(40%)/JERA(35%)/三井物产(25%)","flagship":false,"desc":"美国路易斯安那州阿森松堂区40亿美元蓝氨合资项目，2025年4月FID，年产140万吨CCS低碳氨，2029年投产。","detail":"CF Industries与日本JERA、三井物产组建合资公司，2025年4月8日对路易斯安那州Blue Point综合体低碳氨项目作出最终投资决定（FID），总投资约40亿美元。项目采用自热重整（ATR）制氨工艺并配套二氧化碳脱水压缩装置，捕集的CO2经管道送往地下封存，氨年产能约140万吨，是全球最大的在建低碳氨设施之一。日本国际协力银行（JBIC）牵头提供最高1500亿日元贷款，三井住友、瑞穗等参与联合融资。产品主要面向日本电力氨混烧及国际清洁燃料市场，预计2029年前后投入商业运营。","descEn":"A $4bn blue ammonia JV in Ascension Parish, Louisiana by CF Industries, JERA and Mitsui; FID in April 2025, 1.4 Mtpa CCS-based ammonia, startup around 2029.","detailEn":"CF Industries, Japan's JERA and Mitsui took a final investment decision in April 2025 on the ~$4 billion Blue Point low-carbon ammonia complex in Ascension Parish, Louisiana. The autothermal reforming (ATR) plant with CO2 dehydration and compression will produce about 1.4 million tonnes of CCS-based ammonia per year, with captured CO2 sequestered underground. JBIC leads a loan of up to JPY150bn co-financed by SMBC, Mizuho and SBI Shinsei. Output targets Japanese ammonia co-firing and global clean fuel markets, with commercial operations expected around 2029.","progress":"2025年4月FID并组建合资公司；2025年JBIC牵头完成超10亿美元项目贷款，场地工程推进，预计2029年投产。"},
  {"id":6685,"name":"1PointFive Stratos直接空气捕集工厂","en":"1PointFive STRATOS Direct Air Capture Facility","country":"美国","region":"北美","cat":"petro","coord":[-102.52,31.78],"cap":"直接空气捕集CO2 50万吨/年","inv":13,"invText":"约13亿美元","status":"投运","year":2025,"updated":"2026-06","owner":"西方石油(Occidental)/1PointFive/贝莱德","flagship":true,"desc":"全球最大直接空气捕集（DAC）工厂，得州埃克托县，年捕集CO2 50万吨，2025年底投入运营。","detail":"西方石油子公司1PointFive与贝莱德合资建设的Stratos项目位于得克萨斯州二叠纪盆地埃克托县，是全球最大的直接空气捕集（DAC）设施，设计年捕集二氧化碳50万吨，总投资约13亿美元。2025年4月获美国环保署（EPA）首批针对DAC来源CO2的Class VI封存许可，捕集的CO2将注入地下永久封存并出售碳移除信用，微软、亚马逊等已签署碳移除采购协议。项目2025年底启动商业运营，标志着DAC技术首次达到数十万吨级工业规模，是全球碳移除产业的里程碑工程。","descEn":"The world's largest direct air capture plant in Ector County, Texas, capturing 500,000 tonnes of CO2 per year; commercial operations began at the end of 2025.","detailEn":"Developed by Occidental's subsidiary 1PointFive in a joint venture with BlackRock, STRATOS in Ector County, Texas is the world's largest direct air capture facility, designed to capture 500,000 tonnes of CO2 annually at a cost of about $1.3 billion. In April 2025 the US EPA issued the first-ever Class VI permits for sequestering DAC-sourced CO2. Captured CO2 is permanently stored underground and monetized through carbon removal credits purchased by Microsoft, Amazon and others. Operations began in late 2025, marking the first industrial-scale deployment of DAC technology.","progress":"2025年4月获EPA Class VI封存许可；2025年底投入商业运营，逐步爬坡至50万吨/年满负荷。"},
  {"id":6686,"name":"Infinium Roadrunner电制燃料工厂","en":"Infinium Project Roadrunner eFuels Facility","country":"美国","region":"北美","cat":"renewable","coord":[-103.49,31.42],"cap":"电制燃料2.3万吨/年（eSAF为主）/100MW电解槽","inv":10,"invText":"约10亿美元（估）","status":"在建","year":2027,"updated":"2026-06","owner":"Infinium/布鲁克菲尔德/Breakthrough Energy","flagship":false,"desc":"得州里夫斯县全球最大在建e-fuel工厂，年产2.3万吨电制航空燃料，美航/IAG包销，2027年投产。","detail":"美国电制燃料公司Infinium在得克萨斯州里夫斯县佩科斯附近建设的Roadrunner项目，建成后将是全球最大的eFuels（电制燃料）生产设施，年产约2.3万吨（760万加仑）电制可持续航空燃料（eSAF）及其他电制燃料产品。项目利用西得州富余风光绿电与捕集CO2合成燃料，配套Electric Hydrogen的100MW HYPRPlant电解槽。布鲁克菲尔德资产管理与Breakthrough Energy Catalyst完成股权投资实现融资关闭，2025年6月又获汇丰银行项目融资。美国航空、IAG（英航母公司）等已签署包销协议，预计2027年投入商业运营。","descEn":"The world's largest eFuels plant under construction near Pecos, Texas, producing 23,000 tonnes per year of eSAF; offtake by American Airlines and IAG, startup in 2027.","detailEn":"Infinium's Project Roadrunner in Reeves County, Texas will be the world's largest eFuels production facility, making about 23,000 tonnes (7.6 million gallons) per year of e-sustainable aviation fuel and other eFuels from West Texas renewable power and captured CO2, using Electric Hydrogen's 100 MW HYPRPlant electrolyzer. The project reached financial close with Brookfield Asset Management and Breakthrough Energy Catalyst, plus HSBC project financing in June 2025. American Airlines and IAG have signed offtake agreements; commercial operations are expected in 2027.","progress":"2025年5月宣布开工建设，6月获汇丰项目融资；电解槽与合成装置安装中，预计2027年投产。"},
  {"id":6687,"name":"壳牌Polaris碳捕集与Atlas封存枢纽","en":"Shell Polaris CCS & Atlas Carbon Storage Hub","country":"加拿大","region":"北美","cat":"petro","coord":[-113.13,53.78],"cap":"捕集CO2 65万吨/年，22公里管道+地下2公里封存","inv":12,"invText":"约12亿美元（估）","status":"在建","year":2028,"updated":"2026-06","owner":"壳牌/ATCO EnPower","flagship":false,"desc":"壳牌2024年6月FID的加拿大艾伯塔CCS项目，Scotford炼化园年捕集65万吨CO2，2028年底投运。","detail":"壳牌2024年6月26日对加拿大艾伯塔省两个碳捕集项目作出最终投资决定：Polaris碳捕集项目将从壳牌Scotford能源化工园（炼厂+化工综合体）年捕集约65万吨二氧化碳；配套的Atlas碳封存枢纽由壳牌与ATCO EnPower各持股50%，捕集的CO2经约22公里管道输送至两口封存井，注入地下约2公里深的Basal Cambrian Sands地层永久封存——与壳牌Quest CCS项目使用同一成熟地层。项目享受加拿大联邦CCUS投资税收抵免，建设期创造约2000个就业岗位，预计2028年底投入运营，是壳牌继Quest之后在加拿大的第二个大型CCS工程。","descEn":"Shell's CCS project at the Scotford complex in Alberta, FID June 2024, capturing 650,000 tonnes of CO2 per year with the Atlas storage hub; operations from late 2028.","detailEn":"Shell took final investment decisions in June 2024 on the Polaris carbon capture project at its Scotford Energy and Chemicals Park in Alberta and the Atlas Carbon Storage Hub (50/50 with ATCO EnPower). Polaris will capture about 650,000 tonnes of CO2 annually from the refinery and chemicals complex, sent via a 22-km pipeline to two wells for permanent storage roughly 2 km underground in the Basal Cambrian Sands - the same formation used by Shell's Quest CCS. Supported by Canada's federal CCUS investment tax credit, operations are expected to begin in late 2028.","progress":"2024年6月FID；2025年进入主体施工与封存井钻探阶段，预计2028年底投运。"},
  {"id":6688,"name":"加拿大基瓦利克水电光纤联络线（曼尼托巴—努纳武特）","en":"Kivalliq Hydro-Fibre Link (Manitoba-Nunavut), Canada","country":"加拿大","region":"北美","cat":"grid","coord":[-94,60],"cap":"1200km输电线 / 150MW + 光纤","inv":24,"invText":"约33亿加元（约24亿美元）","status":"规划","year":2032,"updated":"2026-06","owner":"Nukik Corporation（因纽特控股）","desc":"因纽特人主导的1200公里输电+光纤走廊，首次把努纳武特基瓦利克地区接入曼尼托巴水电网和北美大电网。","detail":"基瓦利克水电光纤联络线由因纽特控股的Nukik公司开发，拟建1200公里、150MW输电线并随线敷设光纤，把曼尼托巴水电送往努纳武特基瓦利克地区的5个社区和至少1座金矿，总投资约33亿加元，是加拿大\"国家建设工程\"候选项目和北极主权战略支点。2025年4月努纳武特与曼尼托巴两省区宣布合作推进；2025年11月Nukik向曼尼托巴水电公司提交输电服务申请（TSR）并与努纳武特公用事业公司Qulliq敲定关键商务条款，曼水电已正式启动审查；Nukik还成为北美首个获MISO认证的北极输电开发商。计划2028年开工、2032年送电。","descEn":"An Inuit-led 1,200 km, 150 MW transmission plus fibre corridor connecting Nunavut's Kivalliq region to Manitoba's hydro grid and the North American grid for the first time.","detailEn":"Developed by Inuit-owned Nukik Corporation, the CAD 3.3 billion Kivalliq Hydro-Fibre Link would deliver Manitoba hydropower to five Kivalliq communities and at least one gold mine while bringing fibre-optic backbone north. In April 2025 Nunavut and Manitoba declared a partnership; in November 2025 Nukik filed a Transmission Service Request with Manitoba Hydro (now formally under review) and aligned key commercial terms with Qulliq Energy. Nukik is also the first Arctic developer certified by MISO. Construction is targeted for 2028 with power flowing by 2032.","progress":"2025年11月：向曼尼托巴水电提交输电服务申请并获正式受理，与Qulliq敲定商务条款；获MISO认证；目标2028年开工。","route":[[-94.6,56.3],[-94.2,58.8],[-94.05,61.1],[-92.1,62.8]],"flagship":false},
  {"id":6689,"name":"美国贝尔菲尔德光储一体化项目","en":"Bellefield Solar + Storage (AES/Amazon)","country":"美国","region":"北美","cat":"storage","coord":[-118.2,35.03],"cap":"1000MW光伏＋1000MW/4000MWh电池储能（两期）","inv":25,"invText":"约25亿美元（估）","status":"在建","year":2026,"updated":"2026-06","owner":"AES（亚马逊包销）","desc":"美国最大光储一体化项目：加州克恩县1GW光伏+1GW/4GWh储能，亚马逊15年包销，一期2025年投运、二期2026年建成。","detail":"贝尔菲尔德（Bellefield）项目位于加州克恩县莫哈维沙漠，由AES开发，是美国最大的光储一体化设施：分两期各建500MW光伏与500MW/2000MWh四小时电池储能，合计1GW光伏＋1GW/4GWh储能，全部电力由亚马逊以15年合同包销，用于其加州数据中心与物流体系的清洁供电。一期1GW（500MW光伏+500MW储能）已于2025年完成建设并在下半年投入运营，二期2026年建成。项目是美国企业PPA驱动超大型光储开发模式的标杆。","descEn":"The largest US solar-plus-storage project: 1GW solar + 1GW/4GWh BESS in Kern County, California, fully contracted to Amazon for 15 years; phase 1 online 2025, phase 2 due 2026.","detailEn":"Bellefield, developed by AES in the Mojave Desert of Kern County, California, is the largest solar-plus-storage facility in the United States: two phases each pairing 500MW of solar with a 500MW/2,000MWh four-hour battery, totaling 1GW solar and 1GW/4GWh of storage. All output is contracted to Amazon under a 15-year PPA supplying its California data centers and logistics operations. Phase one (1GW) completed construction in June 2025 and entered service in H2 2025; phase two is due in 2026. The project is the benchmark for corporate-PPA-driven mega solar-storage development in the US.","progress":"2025年6月一期建成、下半年投运；二期施工中，计划2026年完工，届时成为全美最大光储一体化电站。","flagship":false},
  {"id":6690,"name":"加拿大卡尔加里eStruxture CAL-3数据中心","en":"eStruxture CAL-3 AI Data Center, Calgary","country":"加拿大","region":"北美","cat":"datacenter","coord":[-114.06,51.15],"cap":"90 MW","inv":5.5,"invText":"7.5亿加元（约5.5亿美元）","status":"在建","year":2026,"updated":"2026-06","owner":"eStruxture / CoreWeave（主力租户）","desc":"eStruxture投资7.5亿加元在卡尔加里北郊建设90 MW AI数据中心CAL-3，阿尔伯塔省最大，CoreWeave为一期主力租户。","detail":"加拿大最大本土数据中心运营商eStruxture（总部蒙特利尔）在卡尔加里以北约5公里的Rocky View County建设CAL-3数据中心：投资7.5亿加元、IT容量90 MW、面积约30万平方英尺，Tier III设计，单机柜功率密度超125 kW，面向大规模AI集群，2026年秋投运，将是阿尔伯塔省最大数据中心。AI云商CoreWeave已签约成为一期主力租户。项目依托阿尔伯塔富余天然气电力与凉爽气候，是加拿大AI算力西移浪潮的代表。","descEn":"eStruxture is building CAL-3, a C$750m, 90 MW AI-ready data center in Rocky View County north of Calgary — Alberta's largest — with CoreWeave as phase-one anchor tenant.","detailEn":"eStruxture, Canada's largest homegrown data center operator, is building CAL-3 about 5 km north of Calgary in Rocky View County: a C$750m, 90 MW, ~300,000 sq ft Tier III-designed facility with rack densities above 125 kW, built for large AI clusters and opening in fall 2026 as Alberta's largest data center. AI cloud provider CoreWeave has signed as the phase-one anchor tenant. Alberta's abundant gas-fired power and cool climate are drawing Canada's AI compute build-out westward.","progress":"在建，CoreWeave签约一期主力租户，目标2026年秋投运。","flagship":false},
  {"id":6691,"name":"鲁克一号铀矿（Rook I/Arrow）","en":"Rook I (Arrow) Uranium Project","country":"加拿大","region":"北美","cat":"mining","coord":[-109.55,57.76],"cap":"年产氧化铀(U3O8)最高3000万磅，约占全球供应20%","inv":16,"invText":"约16亿美元（C$22亿，估）","status":"在建","year":2030,"updated":"2026-06","owner":"NexGen Energy","desc":"加拿大最大在开发铀矿：萨斯喀彻温阿萨巴斯卡盆地Arrow高品位矿床，2026年3月获联邦建设许可，夏季动工，2030年代初投产。","detail":"鲁克一号（Rook I）项目位于加拿大萨斯喀彻温省阿萨巴斯卡盆地西南缘，核心是2014年发现的Arrow超高品位铀矿床，为加拿大规模最大的在开发铀矿。2026年2月联邦两阶段听证结束，3月5日加拿大核安全委员会批准环评并颁发场地准备与建设许可，公司已作出最终投资决定，2026年夏正式开工，建设期约四年，2030年代初投产。达产后年产氧化铀最高3000万磅，约占当前全球供应20%以上、西方世界产量一半以上，将重塑全球铀供应格局。","descEn":"Canada's largest development-stage uranium mine: NexGen's high-grade Arrow deposit in the Athabasca Basin received its federal construction licence in March 2026, with build starting summer 2026 and production in the early 2030s.","detailEn":"The Rook I project in southwestern Saskatchewan's Athabasca Basin centres on the exceptionally high-grade Arrow deposit discovered in 2014. On 5 March 2026 the Canadian Nuclear Safety Commission approved the environmental assessment and issued the licence to prepare site and construct; NexGen has taken FID with construction starting in summer 2026 over roughly four years. At up to 30 million lb of U3O8 per year — over 20% of global supply and more than half of Western output — Rook I is set to reshape the world uranium market.","progress":"2026年3月获加拿大核安全委员会建设许可，最终投资决定已作出，2026年夏开工、建设期约4年。","flagship":false},
  {"id":6692,"name":"科泰金矿（安大略Côté Gold）","en":"Côté Gold Mine","country":"加拿大","region":"北美","cat":"mining","coord":[-81.87,47.5],"cap":"日处理矿石3.6万吨，年产黄金约36万盎司（达产）","inv":30,"invText":"建设投资约30亿美元（估）","status":"投运","year":2024,"updated":"2026-06","owner":"IAMGOLD / 住友金属矿山","desc":"加拿大安大略省大型露天金矿，IAMGOLD与住友合资，2024年3月首次出金、8月商业化投产，全自动驾驶矿卡车队为全球矿业标杆。","detail":"科泰（Côté）金矿位于加拿大安大略省苏德伯里与蒂明斯之间的戈加马附近，由IAMGOLD（运营方）与日本住友金属矿山合资开发，是加拿大近年投产的最大新建金矿之一。2024年3月31日首次浇铸黄金，8月2日达成商业化生产，2024年底磨机产能利用率达设计值（日处理3.6万吨）的90%，达产后年产黄金约36万盎司，矿山寿命18年以上。项目采用全自动驾驶矿卡车队与自动钻机，是全球数字化矿山的标杆案例；IAMGOLD已回购住友所持部分权益，恢复70%控股。","descEn":"One of Canada's largest new gold mines: the IAMGOLD-Sumitomo Côté open pit in Ontario poured first gold in March 2024 and reached commercial production that August, running a fully autonomous haul fleet at 36,000 t/d design throughput.","detailEn":"Côté Gold, near Gogama between Sudbury and Timmins in Ontario, is operated by IAMGOLD in joint venture with Sumitomo Metal Mining. First gold was poured on 31 March 2024 and commercial production declared on 2 August 2024; the mill exited the year at ~90% of its 36,000 t/d nameplate. At steady state the mine produces about 360,000 oz of gold a year over an 18+ year life, with a fully autonomous truck and drill fleet making it a global showcase for digital mining. IAMGOLD has bought back part of Sumitomo's stake to return to 70% ownership.","progress":"2024年8月商业化投产，2025年爬坡至设计产能；全自动矿卡车队规模持续扩大。","flagship":false},
  {"id":6693,"name":"MP Materials芒廷帕斯稀土扩建与10X磁体厂","en":"MP Materials Mountain Pass Expansion & 10X Magnet Facility","country":"美国","region":"北美","cat":"mining","coord":[-115.53,35.48],"cap":"美国磁体总产能将达1万吨/年；芒廷帕斯增建重稀土分离线","inv":20,"invText":"合计约20亿美元（国防部一揽子投资+10亿美元银行融资，估）","status":"在建","year":2028,"updated":"2026-06","owner":"MP Materials / 美国国防部","flagship":true,"desc":"美国稀土独立标志性工程：国防部入股MP Materials并设NdPr价格下限，芒廷帕斯矿增建重稀土分离，第二座『10X』磁体厂2028年试产，美国磁体产能达万吨级。","detail":"2025年7月，MP Materials与美国国防部达成『转型级』公私合作：国防部以4亿美元优先股入股（另承诺最高3.5亿美元增持与1.5亿美元贷款），设立为期十年的NdPr价格下限与磁体包销协议；摩根大通与高盛另提供10亿美元融资，用于建设公司第二座磁体厂『10X Facility』，2028年开始试产后美国稀土磁体总产能将达约1万吨/年。加州芒廷帕斯矿同步增建重稀土分离产能，形成美国本土『采矿-分离-精炼-磁体』全链条，是美国摆脱稀土进口依赖的标志性工程。","descEn":"The flagship of US rare-earth independence: a DoD public-private partnership (equity, price floor, offtake) plus $1bn bank financing fund heavy rare-earth separation at Mountain Pass and the second '10X' magnet plant, lifting US magnet capacity to ~10,000 t/y from 2028.","detailEn":"In July 2025 MP Materials struck a transformational partnership with the US Department of Defense: a $400m preferred-equity investment (plus up to $350m more and a $150m loan), a 10-year NdPr price floor and a 10-year magnet offtake. JPMorgan and Goldman Sachs committed $1bn to build the company's second magnet plant, the '10X Facility', commissioning from 2028 and lifting total US magnet capacity to about 10,000 t/y. Mountain Pass in California is adding heavy rare-earth separation, completing a mine-to-magnet supply chain on US soil.","progress":"2025年7月与国防部签署一揽子协议；重稀土分离扩建推进中，10X磁体厂2028年试产。"},
  {"id":6694,"name":"萨宾帕斯LNG五期扩建（SPL Expansion）","en":"Sabine Pass LNG Stage 5 Expansion","country":"美国","region":"北美","cat":"petro","coord":[-93.87,29.74],"cap":"约2000万吨/年LNG（含脱瓶颈增量）","inv":250,"invText":"约250亿美元（估）","status":"规划","year":2030,"updated":"2026-06","owner":"Cheniere Energy","flagship":true,"desc":"Cheniere在路易斯安那州萨宾帕斯现有6条生产线旁扩建约2000万吨/年LNG产能，美国最大在审LNG扩建项目之一，目标2030年首批出口。","detail":"切尼尔能源（Cheniere）2024年2月向FERC提交萨宾帕斯五期扩建（SPL Expansion/Stage 5）申请，在现有3000万吨/年的萨宾帕斯基地旁新增约2000万吨/年峰值LNG产能（含脱瓶颈），是美国当前最大的在审LNG扩建项目之一。2026年FERC已发布环评草案，公司预计2026年底取得许可、2027年作出最终投资决定（FID），已锁定约700万吨/年长期购销协议（第7列车基本签满并完成第8列车第二份长协）。计划2026年底启动一期施工，最早2030年实现首批增量LNG出口。","descEn":"Cheniere's ~20 mtpa Stage 5 expansion adjacent to the existing Sabine Pass LNG plant in Louisiana, one of the largest US LNG expansions under review, targeting first exports around 2030.","detailEn":"Cheniere filed the Sabine Pass Stage 5 expansion with FERC in February 2024, adding up to ~20 mtpa of peak LNG capacity (including debottlenecking) next to the existing 30 mtpa Sabine Pass terminal. FERC issued a draft EIS in 2026; Cheniere expects the permit in late 2026 and FID in 2027, has contracted ~7 mtpa of offtake, and aims to start Phase 1 construction in late 2026 with first incremental exports as soon as 2030.","progress":"2026年6月：FERC已发布环评草案，Cheniere预计2026年底获联邦许可、2027年FID；已签约约700万吨/年长协，力争2026年底开工、2030年首批增量出口。"},
  {"id":6695,"name":"Ballymore深水油田（墨西哥湾）","en":"Ballymore Deepwater Oil Field","country":"美国","region":"北美","cat":"petro","coord":[-88.3,28.4],"cap":"7.5万桶/日","inv":16,"invText":"16亿美元","status":"投运","year":2025,"updated":"2026-06","owner":"雪佛龙（60%）/道达尔能源（40%）","desc":"雪佛龙在墨西哥湾Norphlet层系的首个开发项目，2025年4月投产，3口井回接Blind Faith平台，峰值7.5万桶/日，投资16亿美元。","detail":"Ballymore油田位于美国墨西哥湾密西西比峡谷区块，水深约2000米，距新奥尔良东南约260公里，是雪佛龙在墨西哥湾Norphlet地质层系的首个开发项目。项目采用3英里海底回接方案，将3口开发井接入雪佛龙运营的Blind Faith现有平台，省去新建浮式设施，投资约16亿美元。2025年4月实现首油，峰值产量可达7.5万桶/日，可采资源约1.5亿桶油当量。雪佛龙持股60%（作业者），道达尔能源持股40%，是雪佛龙2026年将墨西哥湾净产量提升至30万桶油当量/日目标的重要拼图。","descEn":"Chevron's first development in the Gulf of Mexico Norphlet trend started up in April 2025: a $1.6bn, three-well subsea tieback to the Blind Faith platform producing up to 75,000 b/d.","detailEn":"Ballymore sits in Mississippi Canyon in ~2,000 m of water, ~260 km southeast of New Orleans. The $1.6 billion project ties three wells back three miles to the existing Chevron-operated Blind Faith platform, avoiding a new floating facility. First oil was achieved in April 2025, with capacity of up to 75,000 b/d and ~150 million boe of recoverable resources. Chevron operates with 60%, TotalEnergies holds 40%.","progress":"2025年4月：Ballymore实现首油，经由Blind Faith平台外输；雪佛龙借此向2026年墨西哥湾30万桶油当量/日产量目标迈进。","flagship":false},
  {"id":6696,"name":"Shenandoah深水油田（墨西哥湾）","en":"Shenandoah Deepwater Oil Field","country":"美国","region":"北美","cat":"petro","coord":[-90.7,26.6],"cap":"12万桶/日（铭牌产能）","inv":20,"invText":"约20亿美元（估）","status":"投运","year":2025,"updated":"2026-06","owner":"Beacon Offshore Energy（Blackstone支持）","desc":"全球首批20000psi超高压深水开发之一，2025年7月在墨西哥湾Walker Ridge投产，10月达产10万桶/日，浮式平台产能12万桶/日。","detail":"Shenandoah油田位于美国墨西哥湾Walker Ridge 52区块、距路易斯安那海岸约240公里，储层埋深约9100米，是全球首批采用20000psi（138MPa）超高压完井技术的深水开发项目之一。Beacon Offshore Energy（黑石支持）运营的半潜式浮式生产平台铭牌产能12万桶油/日、1.4亿立方英尺气/日。2025年7月25日首油，10月即爬坡至10万桶/日（11.7万桶油当量/日）。二期（2025–2028年）计划再开发约1.1亿桶油当量，Shenandoah South回接预计2028年二季度投产，合作方包括HEQ Deepwater与Navitas Petroleum。","descEn":"One of the world's first 20,000-psi deepwater developments started up in July 2025 in Walker Ridge, Gulf of Mexico, ramping to 100,000 b/d by October on a 120,000 b/d FPS.","detailEn":"Shenandoah, in Walker Ridge 52 ~150 miles off Louisiana with reservoirs at ~30,000 ft TVD, is among the first projects using 20,000-psi completion technology. Beacon Offshore Energy's semi-submersible FPS has nameplate capacity of 120,000 b/d and 140 MMcf/d. First oil flowed on 25 July 2025 and output reached 100,000 b/d (117,000 boe/d) in October 2025. Phase 2 (2025–2028) adds ~110 MMboe, with the Shenandoah South tieback due online in Q2 2028.","progress":"2025年10月：投产仅两个多月即达10万桶/日目标产量；二期及Shenandoah South回接推进中，后者预计2028年投产。","flagship":false},
  {"id":6697,"name":"墨西哥城—AIFA—帕丘卡客运铁路","en":"Mexico City-AIFA-Pachuca Passenger Railway","country":"墨西哥","region":"北美","cat":"transport","coord":[-98.95,19.85],"cap":"约110公里电气化双线（含AIFA—帕丘卡段58公里）","inv":41,"invText":"约740亿墨西哥比索（约41亿美元，估）","status":"在建","year":2027,"updated":"2026-06","owner":"墨西哥国防部（SEDENA）·联邦铁路局","desc":"辛鲍姆政府客运铁路复兴计划首发线：墨西哥城布埃纳维斯塔经费利佩·安赫莱斯机场（AIFA）至帕丘卡，约110公里电气化双线，日客流预计10.7万人次。","detail":"该线是墨西哥总统辛鲍姆“全国客运铁路复兴计划”（规划3393公里）的首发工程，由国防部工程兵承建：南起墨西哥城布埃纳维斯塔站，经莱切里亚接入费利佩·安赫莱斯国际机场（AIFA），再以58.12公里电气化双线延至伊达尔戈州首府帕丘卡，全程约110公里、设多座车站，AIFA—帕丘卡段日客流预计10.7万人次。莱切里亚—AIFA段投资约270亿比索、AIFA—帕丘卡段约470亿比索。布埃纳维斯塔—AIFA段2025年12月先行通车；至2026年4月帕丘卡段进度约30%、创造1万个就业岗位，全线计划2027年建成。","descEn":"The first line of President Sheinbaum's national passenger-rail revival: about 110 km of electrified double track from Mexico City's Buenavista via Felipe Angeles Airport (AIFA) to Pachuca, built by army engineers for roughly MXN 74 billion.","detailEn":"Flagship of Mexico's passenger-rail revival plan (3,393 km nationwide), the line runs from Buenavista station in Mexico City via Lecheria into Felipe Angeles International Airport and on to Pachuca, Hidalgo over a 58.12-km electrified double-track extension — about 110 km in total, with 107,000 daily riders forecast on the AIFA-Pachuca leg. Lecheria-AIFA is budgeted at MXN 27 billion and AIFA-Pachuca at MXN 47 billion. The Buenavista-AIFA section opened in December 2025; the Pachuca stretch reached about 30% completion by April 2026, with full service targeted for 2027.","progress":"2026-04：全线进度约30%、创造1万个就业岗位；布埃纳维斯塔—AIFA段已于2025年12月先行通车，帕丘卡段瞄准2027年。","route":[[-99.152,19.447],[-99.097,19.625],[-99.02,19.74],[-98.873,19.95],[-98.762,20.102]],"flagship":false},
  {"id":6698,"name":"达拉斯—沃斯堡机场F航站楼","en":"DFW Airport Terminal F","country":"美国","region":"北美","cat":"transport","coord":[-97.04,32.89],"cap":"一期15个登机口（全建成31个登机口）","inv":40,"invText":"约40亿美元（DFW Forward 120亿美元扩建计划核心工程）","status":"在建","year":2027,"updated":"2026-06","owner":"DFW机场管理局·美国航空","desc":"全美最繁忙枢纽之一DFW的第六座航站楼：从16亿美元15门方案扩容至40亿美元31门，创纪录模块化施工，一期2027年启用、专供美国航空。","detail":"F航站楼是达拉斯—沃斯堡国际机场近半个世纪以来首座全新航站楼，也是机场120亿美元“DFW Forward”资本计划的核心：项目从最初16亿美元、15个登机口的方案扩容为约40亿美元、31个登机口，全部由美国航空独家运营，支撑其全球最大枢纽的扩张。工程2024年11月动工，采用美国机场史上规模最大的模块化建造——接近足球场大小的整体模块在夜间用自行式模块运输车就位，至2025年8月已完成6次模块移位。一期15个登机口计划2027年投入使用，全部建成后DFW国际通达能力将显著提升。","descEn":"DFW's sixth terminal — and its first all-new terminal in decades — scaled up from a USD 1.6 billion, 15-gate concept to a USD 4 billion, 31-gate American Airlines facility built with record-setting modular construction, phase 1 opening in 2027.","detailEn":"Terminal F anchors DFW Airport's USD 12 billion 'DFW Forward' capital programme. Expanded from a USD 1.6 billion, 15-gate plan to roughly USD 4 billion and 31 gates operated exclusively by American Airlines, it broke ground in November 2024 and uses the largest modular airport construction effort in US history — football-field-sized modules moved overnight on self-propelled transporters, with six module moves completed by August 2025. The 15-gate first phase opens in 2027, expanding the hub's international capacity.","progress":"2025-08：完成6次大型模块移位，主体加速成形；方案已扩容至40亿美元31登机口，一期15门瞄准2027年启用。","flagship":false},
  {"id":6699,"name":"多米尼加科托佩里（Cotoperí）光伏综合体","en":"Cotoperi Solar Complex (162.6 MWp)","country":"多米尼加","region":"北美","cat":"renewable","coord":[-68.98,18.58],"cap":"162.6MW（三座电站，年发电约2.86亿千瓦时）","inv":1.5,"invText":"约1.5亿美元（估）","status":"投运","year":2025,"updated":"2026-06","owner":"Acciona Energía/Cotosolar","desc":"中美洲与加勒比地区最大光伏综合体：162.6MWp，2025年11月由多米尼加副总统揭幕投运。","detail":"科托佩里光伏综合体位于多米尼加共和国东部拉罗马纳省瓜伊马特，由三座光伏电站组成，总装机162.6MWp，是中美洲与加勒比地区目前最大的光伏设施。西班牙Acciona Energía持股51%，其余49%由含JMMB可持续能源基金、Grupo Pais等本地投资者的Cotosolar控股持有。项目2025年11月27日由副总统拉克尔·培尼亚主持揭幕、12月正式并网，年发电约2.86亿千瓦时，可避免逾21万吨二氧化碳排放，建设期创造600多个直接与间接就业岗位，是多米尼加电力结构去化石化的标志性工程。","descEn":"The largest PV complex in Central America and the Caribbean: 162.6 MWp inaugurated in La Romana, Dominican Republic, in late 2025.","detailEn":"The Cotoperi solar complex in Guaymate, La Romana province, comprises three PV plants totalling 162.6 MWp - the largest PV installation in Central America and the Caribbean. Acciona Energia holds 51%, with local investors (JMMB FES, Grupo Pais and others) holding 49% via Cotosolar. Inaugurated by Vice President Raquel Pena on 27 November 2025 and brought online in December, it will generate about 286 GWh a year, avoiding over 210,000 t of CO2.","progress":"2025年11月27日揭幕、12月正式并网投运，成为中美洲与加勒比地区最大光伏综合体，年发电约2.86亿千瓦时。","flagship":false},

  // ===== 南美（6705-6728）=====
  {"id":6705,"name":"埃赫曼森特纳里奥锂盐湖（阿根廷）","en":"Eramet Centenario Lithium Plant","country":"阿根廷","region":"南美","cat":"mining","coord":[-66.78,-25.05],"cap":"一期2.4万吨碳酸锂当量/年（二期+3万吨申请中）","inv":8.7,"invText":"一期8.7亿美元","status":"投运","year":2025,"updated":"2026-06","owner":"埃赫曼(Eramet)/青山控股","flagship":false,"desc":"法国埃赫曼与青山控股在萨尔塔省合建的全球首批商业规模DLE直接提锂工厂，一期年产2.4万吨电池级碳酸锂。","detail":"项目位于阿根廷萨尔塔省森特纳里奥-拉托内斯盐湖（Centenario-Ratones），可采资源量超1500万吨LCE、卤水锂浓度407mg/L，为阿根廷品位最好的盐湖之一。一期投资8.7亿美元，2024年7月落成、当年底投产，是全球首批商业规模直接提锂（DLE）工厂之一，满产2.4万吨/年电池级碳酸锂。埃赫曼持股50.1%、青山持股49.9%。公司已为二期3万吨/年扩建申请许可，远期合计产能逾5万吨，将巩固阿根廷锂三角的全球地位。","descEn":"Eramet and Tsingshan's Centenario plant in Salta is among the world's first commercial-scale direct lithium extraction (DLE) operations, with Phase 1 capacity of 24,000 t/y battery-grade lithium carbonate.","detailEn":"Located on the Centenario-Ratones salar in Salta province, the deposit holds over 15 Mt LCE of drainable resources at 407 mg/L lithium. The US$870m Phase 1 plant was inaugurated in July 2024 and is ramping up to 24,000 t/y of battery-grade lithium carbonate. Eramet holds 50.1% and Tsingshan 49.9%. Permits are being sought for a 30,000 t/y Phase 2, taking total capacity above 50,000 t/y.","progress":"2025年产能持续爬坡，埃赫曼已为二期3万吨/年扩建提交许可申请，拟于近年开工。"},
  {"id":6706,"name":"森蒂内拉铜矿二号选矿厂（智利）","en":"Centinela Second Concentrator","country":"智利","region":"南美","cat":"mining","coord":[-69.05,-23.03],"cap":"新增铜当量17万吨/年（铜14.4万吨+金13万盎司+钼3500吨）","inv":44,"invText":"44亿美元","status":"在建","year":2027,"updated":"2026-06","owner":"Antofagasta Minerals","flagship":true,"desc":"安托法加斯塔矿业44亿美元的森蒂内拉二号选矿厂，是智利近十年最大矿业投资之一，2027年投产后新增铜当量17万吨/年。","detail":"森蒂内拉矿区位于安托法加斯塔大区谢拉戈尔达附近，二号选矿厂2023年底获批、投资44亿美元，建设高峰期用工超1.3万人。投产后年增铜14.4万吨、金13万盎司、钼3500吨（合计铜当量约17万吨），矿山寿命延长逾30年至36年。项目已落实25亿美元项目融资，使用海水淡化与100%可再生电力。2025年7月配套的Encuentro硫化矿项目再获批10亿美元。计划2027年投产，是智利铜业扩产周期的旗舰工程。","descEn":"Antofagasta Minerals' US$4.4bn second concentrator at Centinela—one of Chile's largest mining investments in a decade—adds 170,000 t/y copper-equivalent from 2027.","detailEn":"Located in the Antofagasta region, the second concentrator was approved in late 2023 with US$4.4bn capex and over 13,000 workers at peak construction. It adds 144,000 t/y copper, 130,000 oz gold and 3,500 t molybdenum, extending mine life beyond 30 years. The project secured US$2.5bn in financing and runs on desalinated water and 100% renewable power. The US$1bn Encuentro Sulphides project was approved in July 2025. Start-up is targeted for 2027.","progress":"工程过半推进中，2025年7月配套Encuentro硫化矿获批10亿美元，整体瞄准2027年投产。"},
  {"id":6707,"name":"圣加布里埃尔金矿（秘鲁）","en":"San Gabriel Gold Mine","country":"秘鲁","region":"南美","cat":"mining","coord":[-70.52,-16.22],"cap":"年产金10万-12万盎司，储量逾180万盎司","inv":7.5,"invText":"约7.5亿美元","status":"投运","year":2025,"updated":"2026-06","owner":"Compañía de Minas Buenaventura","flagship":false,"desc":"布埃纳文图拉在莫克瓜省伊丘尼亚的地下金矿，2025年12月产出首根金锭，是秘鲁近年最大的新建贵金属矿山。","detail":"圣加布里埃尔金矿位于秘鲁南部莫克瓜大区伊丘尼亚区，海拔约4600米，为布埃纳文图拉全资地下矿。金储量逾180万盎司、测定+推断资源逾240万盎司，总投资约7.5亿美元（较最初40-43亿核算大幅上调）。2025年12月23日产出首根多雷金锭，满产后年产金10万-12万盎司，扩产方案可达15万盎司。新勘探显示矿山寿命有望再延长16年，是秘鲁矿业由铜向金多元化的代表项目。","descEn":"Buenaventura's wholly-owned underground gold mine in Ichuña, Moquegua poured first gold in December 2025—Peru's largest new precious-metals mine in years.","detailEn":"San Gabriel, at about 4,600 m elevation in the Moquegua region, hosts over 1.8 Moz of gold reserves and 2.4 Moz of resources. Total capex reached roughly US$750m versus an original US$400-430m estimate. The first doré bar was produced on 23 December 2025, with output ramping to 100,000-120,000 oz/y and potentially 150,000 oz/y under expanded throughput. New exploration suggests mine life could be extended by up to 16 years.","progress":"2025年12月23日产出首根多雷金锭，2026年爬坡至满产，年产量将突破10万盎司。"},
  {"id":6708,"name":"天狼星海上气田（哥伦比亚）","en":"Sirius Offshore Gas Field","country":"哥伦比亚","region":"南美","cat":"petro","coord":[-73.9,11.5],"cap":"天然气资源量约6万亿立方英尺","inv":50,"invText":"约50亿美元","status":"规划","year":2029,"updated":"2026-06","owner":"巴西国油Petrobras(44.4%作业者)/哥伦比亚国油Ecopetrol(55.6%)","flagship":false,"desc":"哥伦比亚加勒比海域最大天然气发现，资源量约6万亿立方英尺、总投资约50亿美元，被视为该国能源自给的关键。","detail":"Sirius气田（原Uchuva发现）位于哥伦比亚加勒比海Tayrona区块深水区，距圣玛尔塔外海约30余公里，由巴西国油作业（44.4%）、哥伦比亚国油持股55.6%。资源量约6万亿立方英尺，为哥伦比亚历史上最大天然气发现，可在国内气田快速递减、被迫进口LNG的背景下大幅提升自给能力。整体开发投资约50亿美元，计划2029-2030年投产。2025年10月两家国油签署天然气联合营销协议，项目正推进土著与地方社区的事前咨询程序。","descEn":"Colombia's largest-ever gas discovery in the deepwater Tayrona block offshore the Caribbean coast, holding about 6 tcf and requiring some US$5bn to develop.","detailEn":"The Sirius field (formerly Uchuva), operated by Petrobras (44.4%) with Ecopetrol holding 55.6%, lies roughly 30 km offshore Santa Marta. With about 6 tcf of gas it is Colombia's biggest discovery and key to restoring gas self-sufficiency as onshore fields decline. Total development investment is near US$5bn with start-up targeted for 2029-2030. In October 2025 the partners signed a joint gas-marketing agreement; prior consultations with local communities are about half complete.","progress":"2025年10月两国油签署联合营销协议，社区事前咨询完成近半，瞄准2029-2030年投产。"},
  {"id":6709,"name":"圭亚那威尔士气电一体化项目","en":"Guyana Wales Gas-to-Energy Project","country":"圭亚那","region":"南美","cat":"petro","coord":[-58.19,6.69],"cap":"300MW联合循环电站+NGL分离厂+约225公里海底输气管道","inv":19,"invText":"约19亿美元（估，含海底管道）","status":"在建","year":2026,"updated":"2026-06","owner":"圭亚那政府/Lindsayca-CH4(EPC)/埃克森美孚(管道)","flagship":false,"desc":"圭亚那将Stabroek区块伴生气经225公里海底管道引上岸，在威尔士建300MW气电站+NGL厂，电价有望减半。","detail":"气电一体化（GtE）是圭亚那独立以来最大公共基建项目：埃克森美孚铺设约225公里海底管道，把Liza油田伴生气输往德梅拉拉河西岸威尔士工业园；Lindsayca/CH4联合体以约8.6亿美元（原7.59亿）建设300MW联合循环电站和天然气凝液（NGL）厂，配套230kV输电网与国家调度中心，政府总预算约10亿美元、全项目约19亿美元。因地基不稳等问题工期推迟约两年，2026年5月整体进度约68%、电站约74%，承诺2026年底首批燃机并网，2027年6月完成联合循环，全国电价有望下降约一半。","descEn":"Guyana's largest-ever public infrastructure project pipes Stabroek associated gas 225 km onshore to a 300 MW combined-cycle plant and NGL facility at Wales, expected to halve power costs.","detailEn":"ExxonMobil laid the ~225 km offshore pipeline from the Liza fields while a Lindsayca/CH4 consortium builds the 300 MW CCGT and NGL plant (contract raised to ~US$860m from US$759m), plus 230 kV transmission and a national control center; total project cost is around US$1.9bn. After roughly two years of delay due to unstable coastal clay, the project was about 68% complete in May 2026 (power plant 74%), with first power promised by end-2026 and full combined-cycle operation by June 2027.","progress":"2026年5月整体进度约68%、电站74%，承包商承诺2026年底首批电力并网，2027年中实现联合循环。"},
  {"id":6710,"name":"龙气田跨海开发（委内瑞拉—特立尼达）","en":"Dragon Gas Field Development","country":"委内瑞拉","region":"南美","cat":"petro","coord":[-61.95,10.95],"cap":"储量约4.2万亿立方英尺","inv":10,"invText":"约10亿美元（估）","status":"规划","year":2027,"updated":"2026-06","owner":"壳牌/特立尼达国家天然气公司(NGC)/委内瑞拉PDVSA","flagship":false,"desc":"壳牌与特立尼达NGC开发委内瑞拉帕里亚半岛外海4.2万亿立方英尺的Dragon气田，输气至特立尼达Atlantic LNG填补原料缺口。","detail":"Dragon气田位于委内瑞拉帕里亚半岛以北、临近特委海上边界，储量约4.2万亿立方英尺，是委内瑞拉首个对外输出的天然气项目。委政府2023年向壳牌与特立尼达NGC颁发30年许可；美国财政部2025年10月8日重新发放分三阶段、有效期至2026年4月的OFAC许可，并要求美国企业参与。壳牌正快速推进开发并修建跨海管道，目标2026-2027年实现首气，气源将供给特立尼达Atlantic LNG（其产能因缺气闲置约400万吨/年）。项目政治与制裁风险仍高，但被视为加勒比能源安全的关键拼图。","descEn":"Shell and Trinidad's NGC are developing Venezuela's 4.2 tcf Dragon field north of the Paria Peninsula, piping gas to Trinidad's underfed Atlantic LNG plant.","detailEn":"Dragon holds about 4.2 tcf near the Venezuela-Trinidad maritime border. Venezuela granted Shell and NGC a 30-year license in 2023, and on 8 October 2025 the US Treasury issued a new three-stage OFAC license valid through April 2026 requiring US company participation. Shell is fast-tracking development and a cross-border pipeline targeting first gas in 2026-2027, feeding Atlantic LNG, which runs some 4 Mt/y below capacity for lack of gas. Sanctions and political risk remain elevated.","progress":"2025年10月美国财政部重发分阶段OFAC许可，壳牌快速推进开发，目标2026-2027年实现首气。"},
  {"id":6711,"name":"巴拿马城地铁3号线（单轨）","en":"Panama Metro Line 3 Monorail","country":"巴拿马","region":"南美","cat":"transport","coord":[-79.62,8.98],"cap":"约25公里单轨、14座车站、26列6节编组列车","inv":31.5,"invText":"31.5亿美元（含4.5公里运河隧道）","status":"在建","year":2027,"updated":"2026-06","owner":"巴拿马地铁公司/现代建设-浦项-现代工程(HPH)联合体","flagship":false,"desc":"巴拿马运河以来最大基建项目：28亿美元单轨地铁3号线连接首都与西岸拉乔雷拉，并以4.5公里隧道下穿巴拿马运河。","detail":"3号线自阿尔布鲁克站向西延伸约25公里至拉乔雷拉，设14站，采用日立-三菱26列6节编组单轨列车，主合同28亿美元，由现代建设、浦项、现代工程（HPH）联合体承建；另以3.5亿美元增建4.5公里运河下穿隧道，为中美洲最深隧道之一。2026年4月起以全部26列车开展动态测试，5月整体进度约75%：一期85%（预计2027年4月完工）、二期58%（2028年10月商业运营）。建成后西岸通勤时间将从约90分钟缩至45分钟，日运量可达50万人次。","descEn":"Panama's largest infrastructure project since the Canal: a US$2.8bn, ~25 km monorail from Albrook to La Chorrera, crossing under the Panama Canal via a 4.5 km tunnel.","detailEn":"Line 3 runs west from Albrook with 14 stations, using 26 six-car Hitachi-Mitsubishi monorail trainsets. The HPH consortium (Hyundai E&C, Posco, Hyundai Engineering) holds the US$2.8bn main contract plus a US$350m, 4.5 km canal tunnel. Dynamic testing with the full fleet began in April 2026; overall progress was 75% in May 2026, with Phase 1 (85%) due April 2027 and commercial operations in October 2028. The line will halve West Panama commute times and carry up to 500,000 passengers daily.","progress":"2026年4月全线26列车启动动态测试，5月整体进度约75%，一期2027年完工、2028年10月商业运营。"},
  {"id":6712,"name":"巴拿马运河里奥印迪奥水库","en":"Panama Canal Rio Indio Reservoir","country":"巴拿马","region":"南美","cat":"transport","coord":[-80.1,8.95],"cap":"库容约15.8亿立方米，支撑每日新增约15次过闸","inv":16,"invText":"16亿美元（含4亿美元社会安置）","status":"规划","year":2027,"updated":"2026-06","owner":"巴拿马运河管理局(ACP)","flagship":false,"desc":"巴拿马运河应对干旱的核心工程：在里奥印迪奥流域筑坝建库并以约8公里隧道向加通湖调水，保障通航与首都供水。","detail":"2023-2024年历史性干旱迫使巴拿马运河削减吃水与日通行量，运河管理局遂将里奥印迪奥水库列为国家水安全最优先项目。工程投资约16亿美元，其中至少4亿用于社会补偿、移民安置与环境治理（约2000人需搬迁），水库蓄水约15.8亿立方米、淹没约45平方公里，并经约8公里输水隧道接入加通湖，每年新增可靠水量可支撑约15次/日的额外过闸。董事会2025年批准专项拨款，2026年启动管理与施工招标，计划2027年开工、2032年建成，是运河85亿美元现代化计划的核心。","descEn":"The Panama Canal's flagship drought-resilience project: a US$1.6bn dam and reservoir on the Rio Indio with a transfer tunnel to Gatun Lake, securing transits and Panama City's water supply.","detailEn":"After the 2023-24 drought forced draft and transit restrictions, the Panama Canal Authority made the Rio Indio reservoir its top water-security priority. The US$1.6bn project—including US$400m+ for resettlement of some 2,000 residents and environmental mitigation—will store about 1.58 billion m3, flooding ~45 km2, with a ~8 km tunnel to Gatun Lake adding water for roughly 15 extra daily transits. The board approved funding in 2025, tenders begin in 2026, and construction is planned for 2027-2032 as the core of an US$8.5bn modernization program.","progress":"2025年董事会批准拨款，2026年5月启动项目管理招标，计划2027年开工、2032年建成。"},
  {"id":6713,"name":"利马地铁2号线（秘鲁）","en":"Lima Metro Line 2","country":"秘鲁","region":"南美","cat":"transport","coord":[-77.03,-12.06],"cap":"27公里全地下、27座车站、35列车（含4号线支线8公里）","inv":58,"invText":"58.4亿美元","status":"在建","year":2028,"updated":"2026-06","owner":"利马地铁2号线特许公司(ACS/FCC/Webuild/Iridium等)","flagship":false,"desc":"秘鲁最大在建基建项目：58亿美元的利马地铁2号线横贯首都东西27公里全地下线路，并含4号线机场支线。","detail":"2号线自东部阿特区至西部卡亚俄横穿利马，全长27公里、27站全部地下，配28座通风竖井、车辆段与35列无人驾驶列车，并包含4号线8公里机场方向支线，总投资约58.4亿美元，由ACS、FCC、Webuild等组成的特许财团以PPP模式建设运营。首段5站2023年起载客、累计客流已超2000万人次。2026年3月整体进度约80%：1B段83%（隧道掘进全部完成）、二期约72%。全线贯通后东西向通勤将从约2小时缩至45分钟，与1号线及在建机场新航站楼衔接。","descEn":"Peru's largest infrastructure project under construction: the US$5.8bn, fully underground 27 km Line 2 crossing Lima east-west, plus an 8 km Line 4 airport branch.","detailEn":"Line 2 runs 27 km from Ate to Callao with 27 underground stations, 28 shafts, a depot and 35 driverless trains, built under a PPP by an ACS/FCC/Webuild-led concession with total costs of US$5.84bn. The first five stations have operated since 2023, carrying over 20 million riders. As of March 2026 overall progress was 80%—Phase 1B at 83% with tunneling complete and Phase 2 at 72%. Full opening around 2028 will cut east-west commutes from two hours to 45 minutes.","progress":"2026年3月整体进度达80%、1B段隧道全部贯通，2026年计划再投入逾5亿美元，全线力争2028年通车。"},
  {"id":6714,"name":"圣安东尼奥外港扩建（智利）","en":"San Antonio Outer Port Expansion","country":"智利","region":"南美","cat":"transport","coord":[-71.62,-33.59],"cap":"新增产能至600万TEU/年（约6000万吨），可泊8艘400米级集装箱船","inv":44.5,"invText":"44.5亿美元（公私合营）","status":"规划","year":2026,"updated":"2026-06","owner":"圣安东尼奥港务局(EPSA)+私营码头特许商","flagship":false,"desc":"智利最大港口扩建工程获环评批准：44.5亿美元的圣安东尼奥外港将把全国第一大港产能提升至600万TEU。","detail":"2026年5月瓦尔帕莱索大区环评委员会批准圣安东尼奥外港（Puerto Exterior）环境许可。项目总投资44.5亿美元：港务局EPSA出资约19.5亿建设防波堤、疏浚、陆域与公路接入，其余约25亿由未来码头特许运营商投入。建成后圣安东尼奥产能将增至600万TEU/年（约6000万吨），可同时停靠8艘400米级船舶，巩固其南美西岸枢纽地位、与秘鲁钱凯港竞争。一期865米泊位（150万TEU）预计2030年代中期投用，全球主要码头运营商已完成投标预资格审查。","descEn":"Chile's biggest-ever port expansion cleared its environmental permit: the US$4.45bn San Antonio Outer Port will triple capacity at the country's largest port to 6 million TEU.","detailEn":"In May 2026 the Valparaiso environmental commission approved the Puerto Exterior project. State port authority EPSA will invest about US$1.95bn in the breakwater, dredging, land works and road access, with some US$2.5bn from future private terminal concessionaires. Capacity will rise to 6 million TEU (~60 Mt) a year, berthing up to eight 400 m ships, reinforcing San Antonio as the west-coast hub competing with Peru's Chancay. The first 865 m berth (1.5 M TEU) is expected around the mid-2030s; global operators have prequalified to bid.","progress":"2026年5月环评获批，码头特许招标推进中，一期865米泊位瞄准2030年代中期投用。"},
  {"id":6715,"name":"帕拉塞尔纸浆厂（巴拉圭）","en":"Paracel Pulp Mill","country":"巴拉圭","region":"南美","cat":"ci","coord":[-57.43,-23.42],"cap":"漂白桉木浆180万吨/年","inv":36,"invText":"总投资36亿美元","status":"在建","year":2026,"updated":"2026-06","owner":"Paracel S.A.（Zapag集团/瑞典Girindus）","flagship":false,"desc":"巴拉圭史上最大私人投资：36亿美元的帕拉塞尔纸浆厂在康塞普西翁动工，年产180万吨漂白桉木浆。","detail":"Paracel项目位于巴拉圭北部康塞普西翁省，由本土Zapag集团与瑞典Girindus等股东推进，是该国第一座大型纸浆厂，也是史上最大私人投资：含纸浆厂、桉树人工林、河港、输电线与道路物流在内总投资约36亿美元。项目已七年累计投入15亿美元、植树超1.1亿株，2026年5月工业厂区正式动工。建成后年产180万吨漂白桉木硫酸盐浆（BEKP），副产生物质绿电外送电网，预计创造逾4万个直接间接就业，并使巴拉圭出口结构发生历史性变化。IDB Invest等多边机构参与融资评估。","descEn":"Paraguay's largest-ever private investment: the US$3.6bn Paracel mill broke ground in Concepcion to produce 1.8 Mt/y of bleached eucalyptus kraft pulp.","detailEn":"Developed by the local Zapag group with Sweden's Girindus, Paracel is Paraguay's first large-scale pulp mill, with total costs (mill, plantations, river port, power lines, logistics) of about US$3.6bn. After seven years and US$1.5bn invested—including 110 million trees planted—industrial-site construction formally began in May 2026. The mill will produce 1.8 Mt/y of BEKP pulp, export surplus biomass power, and create over 40,000 direct and indirect jobs, transforming Paraguay's export base. IDB Invest is assessing financing.","progress":"2026年5月21日康塞普西翁工业厂区正式动工，前期已投入15亿美元、植树超1.1亿株。"},
  {"id":6716,"name":"ATOME比列塔绿色化肥厂（巴拉圭）","en":"ATOME Villeta Green Fertilizer Plant","country":"巴拉圭","region":"南美","cat":"renewable","coord":[-57.56,-25.51],"cap":"145MW电解制氢，绿色硝酸铵钙肥26.4万吨/年","inv":6.65,"invText":"6.65亿美元","status":"在建","year":2028,"updated":"2026-06","owner":"ATOME plc","flagship":false,"desc":"全球首批专用绿色化肥厂：ATOME用伊泰普水电制绿氢，在巴拉圭比列塔年产26.4万吨零碳氮肥，2026年达成FID。","detail":"英国ATOME公司的比列塔项目位于亚松森以南的比列塔工业区，利用伊泰普水电站100%基荷绿电驱动145MW电解槽制氢，再合成零碳氨并加工为26.4万吨/年绿色硝酸铵钙（CAN）肥料，投产时将是全球最大的专用绿色化肥设施。项目2026年4月达成最终投资决定，完成6.65亿美元股债融资，欧洲投资银行、IDB Invest、IFC与绿色气候基金等多边机构参与，全生命周期可减排约1250万吨二氧化碳，2028年投产，瞄准南美农业大国的进口化肥替代市场。","descEn":"One of the world's first dedicated green-fertilizer plants: ATOME will use Itaipu hydropower and a 145 MW electrolyser at Villeta to make 264,000 t/y of zero-carbon CAN fertilizer.","detailEn":"ATOME's flagship project in Villeta, south of Asuncion, runs a 145 MW electrolyser on 100% baseload Itaipu hydropower to produce green hydrogen and ammonia, converted into 264,000 t/y of calcium ammonium nitrate. FID was reached in April 2026 with US$665m of debt and equity completed, backed by the EIB, IDB Invest, IFC and the Green Climate Fund. The plant, due online in 2028, is estimated to displace up to 12.5 Mt of CO2 over its life, substituting imported fertilizer in South America's farm belt.","progress":"2026年4月达成最终投资决定并完成6.65亿美元融资，目标2028年投产。"},
  {"id":6717,"name":"HIF帕伊桑杜电燃料工厂（乌拉圭）","en":"HIF Global Paysandu e-Fuels Facility","country":"乌拉圭","region":"南美","cat":"renewable","coord":[-58.08,-32.32],"cap":"电燃料/电甲醇最终产能88万吨/年（分四期）","inv":53,"invText":"53亿美元","status":"规划","year":2028,"updated":"2026-06","owner":"HIF Global","flagship":true,"desc":"乌拉圭史上最大外商投资：HIF Global拟投53亿美元在帕伊桑杜建绿氢电燃料厂，终期年产88万吨、2028年首批交付。","detail":"HIF Global（智利电燃料先驱、曾建成全球首座Haru Oni示范厂）计划在乌拉圭帕伊桑杜省以绿氢+回收二氧化碳合成电燃料/电甲醇，分四期建设，终期产能88万吨/年，相当于为40多万辆汽车脱碳，总投资逾53亿美元，超过UPM纸浆厂成为乌拉圭史上最大外商直接投资。2025年7月公布新设计方案，12月19日与乌拉圭政府签署加速协议，确定投资决策前的技术与制度路径；已选定庄信万丰eMERALD电甲醇工艺，并与德国e-Fuel One签订10万吨/年供货协议。计划2026年主电解-合成装置动工、2028年交付首批燃料，建设期创造约1400个岗位。","descEn":"Uruguay's largest-ever foreign investment: HIF Global's US$5.3bn Paysandu plant will combine green hydrogen with recycled CO2 to make up to 880,000 t/y of e-fuels.","detailEn":"HIF Global, builder of Chile's pioneering Haru Oni plant, plans a four-phase e-fuels/e-methanol complex in Paysandu reaching 880,000 t/y—enough to decarbonize over 400,000 vehicles—with investment above US$5.3bn, topping UPM's pulp mill as Uruguay's biggest FDI. A new design was unveiled in July 2025 and an acceleration agreement was signed with the government on 19 December 2025. Johnson Matthey's eMERALD technology was selected and 100,000 t/y is contracted to Germany's e-Fuel One. Groundbreaking on the main electrolysis and synthesis plant is planned for 2026, with first deliveries in 2028 and ~1,400 construction jobs.","progress":"2025年12月19日与乌拉圭政府签署加速协议，计划2026年主装置动工、2028年交付首批电燃料。"},
  {"id":6718,"name":"HNH马加拉内斯绿氨项目（智利）","en":"HNH Energy Green Ammonia Project","country":"智利","region":"南美","cat":"renewable","coord":[-70.1,-52.6],"cap":"风电约1.4GW，绿氢27万吨/年、绿氨100万吨/年","inv":110,"invText":"110亿美元","status":"规划","year":2030,"updated":"2026-06","owner":"Austria Energy/Okowind/哥本哈根基础设施基金(CIP)","flagship":false,"desc":"欧洲财团在麦哲伦圣格雷戈里奥推进110亿美元绿氨一体化项目，年产100万吨绿氨，是麦哲伦区首个进入环评的绿氨工程。","detail":"HNH Energy由奥地利Okowind、Austria Energy与丹麦哥本哈根基础设施基金（CIP）组成，项目落址麦哲伦区圣格雷戈里奥（蓬塔阿雷纳斯东北约120公里的格雷戈里奥湾），利用巴塔哥尼亚优质风资源建设约1.4GW风电、电解制氢27万吨/年并合成100万吨/年绿氨，配套专用出口码头，总投资约110亿美元，是麦哲伦区第一个进入环评程序的绿氨项目。2024年提交环境影响评估、2025年9月提交补充文件（Adenda）并强化生态保护承诺；计划取得许可后2027年上半年开工、2030年下半年投运，目标欧亚航运燃料与化肥市场。","descEn":"A European consortium's US$11bn integrated wind-to-ammonia project at San Gregorio, Magallanes—the first green-ammonia scheme to enter Chile's environmental review—targeting 1 Mt/y of green ammonia.","detailEn":"Backed by Austria's Okowind and Austria Energy with Copenhagen Infrastructure Partners, HNH Energy will harness Patagonian winds (~1.4 GW) at Gregorio Bay, 120 km northeast of Punta Arenas, to produce 270,000 t/y of green hydrogen and 1 Mt/y of ammonia with a dedicated export terminal. The EIA was filed in 2024 and an addendum with strengthened conservation commitments in September 2025. Construction is planned for H1 2027 after permitting, with operations from H2 2030, serving shipping-fuel and fertilizer markets.","progress":"2025年9月提交环评补充文件并强化保护承诺，目标2027年上半年开工、2030年下半年投运。"},
  {"id":6719,"name":"科尔本卡马罗内斯Celda Solar储能（智利）","en":"Colbun Celda Solar BESS","country":"智利","region":"南美","cat":"storage","coord":[-70.2,-19.1],"cap":"228MW/912MWh（200台特斯拉Megapack）","inv":2.6,"invText":"2.6亿美元","status":"在建","year":2026,"updated":"2026-06","owner":"科尔本(Colbun)/特斯拉","flagship":false,"desc":"智利发电商科尔本与特斯拉合作的228MW/912MWh独立储能电站，位于阿里卡南部卡马罗内斯，2026年投运。","detail":"Celda Solar储能项目位于阿里卡-帕里纳科塔大区卡马罗内斯市镇（阿里卡以南约80公里），由智利第二大发电商科尔本投资2.6亿美元建设，采用200台特斯拉Megapack，规模228MW/912MWh、4小时时长，可将北部白天过剩的光伏电力移至夜间，惠及约5.5万户家庭。2024年12月与特斯拉签约、2025年1月开工，2025年8月首批240个电池柜经阿里卡港到场，计划2026年投运。科尔本同时在阿塔卡马迭戈德阿尔马格罗推进同等规模的Diego de Almagro Sur储能（2亿美元、Canadian Solar SolBank，2026年12月投运），合计储能规模居智利前列。","descEn":"Colbun's 228 MW/912 MWh standalone BESS with 200 Tesla Megapacks at Camarones, south of Arica—one of Chile's largest battery projects, online in 2026.","detailEn":"Located in Camarones commune, ~80 km south of Arica, the US$260m Celda Solar project uses 200 Tesla Megapacks for 228 MW/912 MWh of four-hour storage, shifting surplus northern solar to evening peaks for some 55,000 households. The Tesla supply deal was signed in December 2024, construction began in January 2025, and the first 240 battery units arrived via Arica port in August 2025, targeting 2026 operation. Colbun is also building the twin 228 MW/912 MWh Diego de Almagro Sur BESS (US$200m, Canadian Solar SolBank) due December 2026.","progress":"2025年8月首批240台特斯拉Megapack运抵阿里卡港，安装推进中，计划2026年投运。"},
  {"id":6720,"name":"阿图查ACR-300小型模块堆群（阿根廷）","en":"ACR-300 Small Modular Reactors at Atucha","country":"阿根廷","region":"南美","cat":"nuclear","coord":[-59.21,-33.97],"cap":"规划4×300MW（合计1.2GW）","inv":30,"invText":"未正式披露（估约30亿美元级）","status":"规划","year":2030,"updated":"2026-06","owner":"INVAP/阿根廷核电公司(NA-SA)/美资私营财团","flagship":false,"desc":"米莱政府国家核计划首阶段：拟在阿图查核电基地建4台国产ACR-300小堆共1.2GW，瞄准AI数据中心供电，首堆目标2030年。","detail":"2024年底阿根廷政府宣布国家核计划（Plan Nuclear Argentino），第一阶段拟在布宜诺斯艾利斯省阿图查核电基地新建4台由INVAP设计的ACR-300小型模块堆，合计约1.2GW，定位为巴塔哥尼亚AI数据中心等新增负荷供电。2025年3月核委员会确认选址阿图查、首堆瞄准2030年并网；美国投资基金已获得ACR-300专利授权并与INVAP美国子公司组建合资公司负责设计制造，政府明确国家不直接出资、以私人资本推进，并同步推动与美国新一代反应堆合作及国内铀矿重启。该设计仍处早期工程阶段，2030年时间表被独立专家认为偏紧。","descEn":"Phase one of Argentina's national nuclear plan: four INVAP-designed ACR-300 SMRs (1.2 GW total) at the Atucha site, privately financed and aimed at powering AI data centers, with the first unit targeted for 2030.","detailEn":"In late 2024 the Milei government unveiled the Plan Nuclear Argentino, whose first stage calls for four ACR-300 small modular reactors (about 1.2 GW combined) at the Atucha complex, 120 km northwest of Buenos Aires. In March 2025 the Nuclear Council confirmed the site and a 2030 target for the first unit. A US investment firm acquired the ACR-300 patent and formed a JV with INVAP's US subsidiary; the state will not invest directly. The design remains at an early engineering stage and independent experts question the 2030 timeline.","progress":"2025年确认阿图查选址与美资合资架构，尚未开工；工程细化设计推进中，2030年首堆目标存不确定性。"},
  {"id":6721,"name":"微软智利Central云区域（圣地亚哥）","en":"Microsoft Chile Central Cloud Region","country":"智利","region":"南美","cat":"datacenter","coord":[-70.7,-33.45],"cap":"3个独立可用区多座数据中心，100%可再生能源供电","inv":33,"invText":"约33亿美元（估）","status":"投运","year":2025,"updated":"2026-06","owner":"微软/AES Andes(绿电)","flagship":false,"desc":"微软2025年在圣地亚哥上线智利首个超大规模主权云区域Chile Central，三可用区全绿电，为其入智33年来最大投资。","detail":"微软Chile Central云区域2025年6月正式上线，位于圣地亚哥大都会区，由3个物理独立站点的多座数据中心组成，是智利首个本土超大规模主权云区域，也是微软1992年入智以来最大投资，资本开支估计约33亿美元，预计四年内带动约350亿美元下游生态收入。区域通过AES Andes长期购电协议实现100%可再生能源供电，被称为拉美最清洁的超大规模部署。叠加AWS 40亿美元自建区域与谷歌扩建，2025年下半年圣地亚哥在运数据中心容量从182MW增至279MW、空置率降至4.3%，智利正成为南美AI算力枢纽。","descEn":"Microsoft's Chile Central sovereign cloud region went live in Santiago in 2025—three availability zones on 100% renewable power and the company's largest Chilean investment since 1992.","detailEn":"Launched in June 2025, Chile Central comprises multiple data centers across three physically independent sites in the Santiago metropolitan region, Chile's first hyperscale sovereign cloud region. Estimated capex is about US$3.3bn, expected to unlock some US$35bn in downstream ecosystem revenue over four years. Powered 100% by renewables via AES Andes, it is called Latin America's cleanest hyperscale deployment. Together with AWS's US$4bn region and Google's expansion, Santiago capacity jumped from 182 MW to 279 MW in H2 2025 with vacancy at 4.3%.","progress":"2025年6月正式上线运营，与AWS、谷歌扩建共同推动圣地亚哥在运容量半年内增近百兆瓦。"},
  {"id":6722,"name":"阿根廷AMBA I 500千伏输电工程","en":"AMBA I 500kV Transmission Project","country":"阿根廷","region":"南美","cat":"grid","coord":[-59,-34.7],"cap":"500kV/220kV线路500余公里，释放约1000MW供电能力","inv":5,"invText":"未披露（估约5亿美元，全私人资本）","status":"规划","year":2029,"updated":"2026-06","owner":"阿根廷能源部/私营特许商(IDB担保)","flagship":false,"desc":"阿根廷20年来首个大型输电新建工程：AMBA I以500余公里500kV/220kV线路为布宜诺斯艾利斯都会区释放约1000MW供电能力。","detail":"布宜诺斯艾利斯都会区（AMBA）占阿根廷全国用电约40%，电网瓶颈已多年制约供电并引发夏季限电。米莱政府以全新的全私人资本特许模式推出AMBA I工程：新建500kV与220kV线路合计500余公里及配套变电站，可释放约1000MW的新增供电能力，是该国约20年来首个大型输电扩建项目，泛美开发银行（IDB）提供担保与招标设计支持以增强可融资性。技术招标文件于2026年3-4月发布，年内完成正式招标授标，建设周期约3年，投资额由市场报价确定（业界估算约5亿美元级）。该工程也是Vaca Muerta气电与新增可再生能源送入负荷中心的关键一环。","descEn":"Argentina's first major new transmission build in two decades: AMBA I adds over 500 km of 500/220 kV lines to unlock ~1,000 MW of supply for Greater Buenos Aires, under a fully private concession backed by IDB guarantees.","detailEn":"The Buenos Aires metro area consumes about 40% of Argentina's electricity and faces chronic grid bottlenecks. Under Milei's reforms, AMBA I will be tendered as a fully privately financed concession—no state funding—with the IDB acting as guarantor and helping design the tender. Technical bidding documents were released around April 2026 with the formal tender later in 2026; construction takes roughly three years (industry estimates near US$500m). The project is key to delivering Vaca Muerta gas-fired and renewable power into the load center.","progress":"2026年3-4月发布技术招标文件，年内启动正式招标，IDB提供担保支持。"},
  {"id":6723,"name":"智利迭戈德阿尔马格罗南电池储能","en":"Colbun Diego de Almagro Sur BESS","country":"智利","region":"南美","cat":"storage","coord":[-70.05,-26.37],"cap":"228MW/912MWh（5小时）","inv":2,"invText":"约2亿美元","status":"在建","year":2026,"updated":"2026-06","owner":"Colbún","desc":"智利Colbún第二个GWh级储能：阿塔卡马大区232MW光伏电站旁228MW/912MWh电池，e-STORAGE供货，2026年12月投运。","detail":"迭戈德阿尔马格罗南（Diego de Almagro Sur）电池储能项目位于智利阿塔卡马大区，由Colbún开发，依托其2022年投运的232MW同名光伏电站建设228MW/912MWh（5小时）独立调节储能，投资约2亿美元。阿特斯子公司e-STORAGE于2025年4月中标供应SolBank 3.0磷酸铁锂液冷系统。2025年6月场地开工，2026年2月首批电池到场，计划2026年12月商业投运，是继卡马罗内斯Celda Solar之后Colbún第二个大型储能项目。","descEn":"Colbun's second GWh-scale battery in Chile: a 228MW/912MWh five-hour BESS at its 232MW Diego de Almagro Sur solar plant in Atacama, supplied by e-STORAGE, COD December 2026.","detailEn":"The Diego de Almagro Sur BESS in Chile's Atacama region, developed by Colbun, adds a 228MW/912MWh (five-hour) battery at its 232MW solar plant operating since 2022, at a cost of about USD 200 million. Canadian Solar subsidiary e-STORAGE won the April 2025 contract to supply SolBank 3.0 liquid-cooled LFP systems - 201 battery units in 160 containers. Site works began in June 2025 and the first batteries arrived in February 2026, targeting commercial operation in December 2026, enough to power some 80,000 homes for five hours. It is Colbun's second large-scale storage project after Celda Solar in Camarones.","progress":"2025年6月场地施工启动；2026年2月首批70/201台电池单元到场，计划2026年12月商业投运。","flagship":false},
  {"id":6724,"name":"马里马卡铜矿（智利MOD）","en":"Marimaca Copper (MOD) Project","country":"智利","region":"南美","cat":"mining","coord":[-70.18,-23.13],"cap":"年产阴极铜约5万吨（氧化矿堆浸）","inv":5.9,"invText":"初始资本5.87亿美元","status":"规划","year":2028,"updated":"2026-06","owner":"Marimaca Copper","desc":"智利安托法加斯塔近海岸氧化铜项目：堆浸工艺、初始资本仅5.87亿美元，已获环评批复，2026年下半年FID并开工，约2028-29年投产。","detail":"马里马卡氧化铜项目（MOD）位于智利安托法加斯塔大区、梅希约内斯港以东约25公里，是近年智利少有的低资本强度绿地铜矿：依托近海岸基础设施与简单堆浸工艺，初始资本仅5.87亿美元，远低于同类项目逾10亿美元的行业均值。项目已取得环评批复，2026年5月启动债务融资程序，计划2026年下半年作出最终投资决定并开工，建设24-30个月后投产，年产阴极铜约5万吨，将成为智利新一轮中型铜矿开发的标杆。","descEn":"A low-capex coastal oxide copper project near Mejillones, Chile: heap-leach design, $587m initial capex, environmental approval in hand, FID and construction targeted for H2 2026 with ~50,000 t/y cathode from 2028-29.","detailEn":"The Marimaca Oxide Development (MOD) sits about 25 km east of the port of Mejillones in Chile's Antofagasta region. Leveraging coastal infrastructure, a low strip ratio and simple heap-leach processing, initial capex is just US$587m versus industry averages above US$1bn. With environmental approval secured and debt financing launched in May 2026, Marimaca targets FID in H2 2026, a 24-30 month build and roughly 50,000 t/y of copper cathode, a benchmark for Chile's next wave of mid-size copper builds.","progress":"2026年5月启动MOD债务融资，目标2026年四季度敲定融资方案、下半年FID并开工。","flagship":false},
  {"id":6725,"name":"紫金3Q锂盐湖（阿根廷Tres Quebradas）","en":"Zijin 3Q (Tres Quebradas) Lithium Project","country":"阿根廷","region":"南美","cat":"mining","coord":[-68.6,-27.1],"cap":"一期年产碳酸锂2万吨，二期再增4万吨（合计6-8万吨）","inv":10,"invText":"合计约10亿美元（一期约3.8亿美元，估）","status":"投运","year":2025,"updated":"2026-06","owner":"紫金矿业（Liex）","desc":"紫金矿业在阿根廷卡塔马卡省菲安巴拉的高原盐湖提锂项目，2025年9月一期2万吨碳酸锂投产，为该省第三座投产锂矿，二期将再扩4万吨。","detail":"3Q（Tres Quebradas）锂盐湖位于阿根廷卡塔马卡省菲安巴拉高原、海拔逾4000米的安第斯山区，是紫金矿业2022年2月收购Liex公司获得的核心锂资产。2025年9月12日一期工程投产，年产电池级碳酸锂2万吨，成为卡塔马卡省第三座投产锂矿；二期规划再增4万吨产能，两期达产后年产碳酸锂合计6-8万吨，将跻身全球最大盐湖提锂项目之列。项目是中国矿企在『锂三角』布局的代表作，强化了阿根廷在全球电池供应链中的地位。","descEn":"Zijin Mining's high-altitude brine project in Fiambala, Catamarca: Phase 1 (20,000 t/y lithium carbonate) entered production in September 2025 — the province's third operating lithium mine — with Phase 2 adding 40,000 t/y.","detailEn":"The Tres Quebradas (3Q) salar lies above 4,000 m in the Andes of Catamarca, Argentina, acquired by Zijin Mining with Liex in February 2022. Phase 1 began production on 12 September 2025 at 20,000 t/y of battery-grade lithium carbonate, Catamarca's third lithium mine in operation. A Phase 2 expansion will add 40,000 t/y, taking combined output to 60,000-80,000 t/y at design rates and ranking 3Q among the world's largest brine-lithium operations — a landmark Chinese investment in the Lithium Triangle.","progress":"2025年9月一期2万吨/年碳酸锂投产，二期4万吨/年扩建推进中。","flagship":false},
  {"id":6726,"name":"Manatee海上气田开发（特立尼达）","en":"Manatee Gas Field Development","country":"特立尼达和多巴哥","region":"南美","cat":"petro","coord":[-60.55,10.05],"cap":"高峰约604百万立方英尺/日（约10.4万桶油当量/日），储量2.7万亿立方英尺","inv":20,"invText":"约20亿美元（估）","status":"在建","year":2027,"updated":"2026-06","owner":"壳牌（100%）","desc":"壳牌2024年7月对特立尼达东海岸2.7万亿立方英尺Manatee气田作出FID，无人值守平台+8口井，2027年投产，供Atlantic LNG出口与国内市场。","detail":"Manatee是横跨特立尼达—委内瑞拉海上边界的Loran-Manatee大气田的特立尼达侧部分（6D区块，壳牌100%权益），可采资源约2.7万亿立方英尺。壳牌2024年7月作出最终投资决定：建设一座常态无人值守平台和8口开发井，通过110公里32英寸海底管道接入岸上Beachfield处理设施，再输往Atlantic LNG液化厂出口并供应国内气市。计划2027年投产，高峰产量约6.04亿立方英尺/日（约10.4万桶油当量/日），是特立尼达扭转气量下滑、稳住LNG出口地位的关键项目。","descEn":"Shell took FID in July 2024 on the 2.7 tcf Manatee field off Trinidad's east coast; an unmanned platform with 8 wells will start up in 2027, feeding Atlantic LNG and the domestic market.","detailEn":"Manatee is the Trinidad side of the cross-border Loran-Manatee field (sub-Block 6D, Shell 100%). The July 2024 FID covers a normally unattended platform and eight wells tied back via a 110 km, 32-inch pipeline to the onshore Beachfield facility, feeding Atlantic LNG exports and domestic gas. First gas is targeted for 2027 with peak output of ~604 MMscf/d (~104,000 boe/d).","progress":"2026年4月：项目建设推进中，壳牌寻求2027年实现Manatee首气，并研究后续提产方案；与bp的Cypre等项目共同支撑特立尼达2027年产量回升。","flagship":false},
  {"id":6727,"name":"波哥大地铁2号线","en":"Bogota Metro Line 2","country":"哥伦比亚","region":"南美","cat":"transport","coord":[-74.1,4.71],"cap":"15.5公里（全地下）/ 11座车站","inv":88,"invText":"总成本约88亿美元（含多边银行融资）","status":"规划","year":2027,"updated":"2026-06","owner":"波哥大地铁公司（Empresa Metro de Bogotá）","desc":"波哥大首条全地下地铁线，15.5公里连接市中心与西北部Suba/Engativá，总成本约88亿美元；首轮招标2026年1月流标后于3月重启，拟2027年初授标。","detail":"波哥大地铁2号线自72街起向西北延伸15.5公里至Suba与Engativá区，全线地下、设11座车站，服务约250万人口走廊，总成本约88亿美元（资本开支40亿美元以上，另获美洲开发银行、世界银行、欧洲投资银行与拉美开发银行约50亿美元融资承诺）。资格预审曾剩中、西两家联合体，但中方联合体2025年10月以汇率波动风险为由退出，2026年1月20日截标时无人投标、招标流标；市府于2026年3月3日重启国际招标，最终报价截止2026年11月30日，计划2027年一季度授标，2030年代初通车。","descEn":"Bogota's first fully underground metro line: 15.5 km and 11 stations from Calle 72 northwest to Suba and Engativa, costed at about USD 8.8 billion; after a void tender in January 2026 the bid was relaunched in March 2026 for award in early 2027.","detailEn":"Metro Line 2 extends 15.5 km underground from Calle 72 to the densely populated Suba and Engativa districts with 11 stations, serving a corridor of 2.5 million people. Total cost is about USD 8.8 billion — over USD 4 billion of capex plus roughly USD 5 billion in financing from the IDB, World Bank, EIB and CAF. A Chinese-led consortium withdrew in October 2025 citing FX risk and the tender was declared void on 20 January 2026 with no bids; the city relaunched the international tender on 3 March 2026, with final offers due 30 November 2026 and award targeted for Q1 2027.","progress":"2026-03：首轮招标1月流标（中方联合体此前退出）后，3月3日重启国际招标，2026年11月底截标、2027年一季度授标。","route":[[-74.066,4.658],[-74.09,4.69],[-74.118,4.717],[-74.137,4.745]],"flagship":false},
  {"id":6728,"name":"哥伦比亚首轮海上风电巴兰基亚场址（CIP）","en":"Colombia First Offshore Wind Round - Barranquilla Site (CIP)","country":"哥伦比亚","region":"南美","cat":"renewable","coord":[-74.95,11.15],"cap":"规划装机约1GW（估，加勒比海预调查区约1000平方公里）","inv":20,"invText":"约20亿美元（估）","status":"规划","year":2030,"updated":"2026-06","owner":"Copenhagen Infrastructure Partners (CIP)","desc":"南美首个海上风电海域招标落定：CIP独家中标巴兰基亚外海场址，哥伦比亚海上风电从零起步。","detail":"哥伦比亚2024年启动南美洲首个海上风电海域租赁招标，招标区位于加勒比海巴兰基亚与卡塔赫纳外海，总面积逾9000平方公里（其中约1000平方公里完成预调查）。8家国际开发商通过资格预审、提名69个场址，最终丹麦哥本哈根基础设施基金（CIP）成为唯一投标方；2025年12月16日国家碳氢化合物局（ANH）公布最终合格名单，CIP子公司获巴兰基亚外海场址开发许可，规划装机吉瓦级，配套15年期购电合同框架，目标2030年前后建成南美首个商业化海上风电场。","descEn":"South America's first offshore wind leasing round concluded: CIP is the sole eligible bidder for the site off Barranquilla, kick-starting Colombian offshore wind.","detailEn":"Colombia launched South America's first offshore wind seabed tender covering 9,000+ km2 off Barranquilla and Cartagena in the Caribbean. Eight developers prequalified and nominated 69 sites; CIP ended up the sole bidder, and on 16 December 2025 the ANH named CIP's subsidiary as the eligible bidder for the Barranquilla site. The GW-scale project comes with a 15-year contract framework, targeting South America's first commercial offshore wind farm around 2030.","progress":"2025年12月16日ANH公布最终名单，CIP子公司成为巴兰基亚外海场址唯一合格中标方，南美首个海上风电海域租赁授出。","flagship":false}
]);
